import { getPersistence } from '@/app/backend/persistence/db';
import { mapRunRecord } from '@/app/backend/persistence/stores/conversation/runs/runStoreMapper';
import { nowIso } from '@/app/backend/persistence/stores/shared/utils';
import type { RunRecord } from '@/app/backend/persistence/types';
import type {
    ProviderAuthMethod,
    RunStatus,
    RuntimeProviderId,
    RuntimeRunOptions,
} from '@/app/backend/runtime/contracts';
import type { ProviderRuntimeTransportFamily } from '@/app/backend/providers/types';
import { createEntityId } from '@/app/backend/runtime/identity/entityIds';

export interface CreateRunInput {
    profileId: string;
    sessionId: string;
    prompt: string;
    providerId: RuntimeProviderId;
    modelId: string;
    authMethod: ProviderAuthMethod | 'none';
    runtimeOptions: RuntimeRunOptions;
    cache: {
        applied: boolean;
        key?: string;
        reason?: string;
    };
    transport: {
        selected?: ProviderRuntimeTransportFamily;
        degradedReason?: string;
    };
}

export interface FinalizeRunInput {
    status: Extract<RunStatus, 'completed' | 'aborted' | 'error'>;
    errorCode?: string;
    errorMessage?: string;
}

export interface UpdateRunRuntimeMetadataInput {
    cacheApplied?: boolean;
    cacheSkipReason?: string;
    transportSelected?: ProviderRuntimeTransportFamily;
    transportDegradedReason?: string;
}

export class RunStore {
    async create(input: CreateRunInput): Promise<RunRecord> {
        const { db } = getPersistence();
        const runId = createEntityId('run');
        const now = nowIso();

        await db
            .insertInto('runs')
            .values({
                id: runId,
                session_id: input.sessionId,
                profile_id: input.profileId,
                prompt: input.prompt,
                status: 'running',
                provider_id: input.providerId,
                model_id: input.modelId,
                auth_method: input.authMethod,
                reasoning_effort: input.runtimeOptions.reasoning.effort,
                reasoning_summary: input.runtimeOptions.reasoning.summary,
                reasoning_include_encrypted: input.runtimeOptions.reasoning.includeEncrypted ? 1 : 0,
                cache_strategy: input.runtimeOptions.cache.strategy,
                cache_key: input.cache.key ?? null,
                cache_applied: input.cache.applied ? 1 : 0,
                cache_skip_reason: input.cache.reason ?? null,
                transport_requested_family: input.runtimeOptions.transport.family,
                transport_selected: input.transport.selected ?? null,
                transport_degraded_reason: input.transport.degradedReason ?? null,
                started_at: now,
                completed_at: null,
                aborted_at: null,
                error_code: null,
                error_message: null,
                created_at: now,
                updated_at: now,
            })
            .execute();

        const row = await db.selectFrom('runs').selectAll().where('id', '=', runId).executeTakeFirstOrThrow();
        return mapRunRecord(row);
    }

    async getById(runId: string): Promise<RunRecord | null> {
        const { db } = getPersistence();
        const row = await db.selectFrom('runs').selectAll().where('id', '=', runId).executeTakeFirst();
        return row ? mapRunRecord(row) : null;
    }

    async listBySession(profileId: string, sessionId: string): Promise<RunRecord[]> {
        const { db } = getPersistence();
        const rows = await db
            .selectFrom('runs')
            .selectAll()
            .where('profile_id', '=', profileId)
            .where('session_id', '=', sessionId)
            .orderBy('created_at', 'asc')
            .execute();

        return rows.map(mapRunRecord);
    }

    async listByProfile(profileId: string): Promise<RunRecord[]> {
        const { db } = getPersistence();
        const rows = await db
            .selectFrom('runs')
            .selectAll()
            .where('profile_id', '=', profileId)
            .orderBy('created_at', 'asc')
            .execute();

        return rows.map(mapRunRecord);
    }

    async updateRuntimeMetadata(runId: string, input: UpdateRunRuntimeMetadataInput): Promise<RunRecord | null> {
        const { db } = getPersistence();
        const now = nowIso();

        const values: {
            updated_at: string;
            cache_applied?: 0 | 1;
            cache_skip_reason?: string | null;
            transport_selected?: ProviderRuntimeTransportFamily | null;
            transport_degraded_reason?: string | null;
        } = {
            updated_at: now,
        };

        if (input.cacheApplied !== undefined) {
            values.cache_applied = input.cacheApplied ? 1 : 0;
        }
        if (input.cacheSkipReason !== undefined) {
            values.cache_skip_reason = input.cacheSkipReason;
        }
        if (input.transportSelected !== undefined) {
            values.transport_selected = input.transportSelected;
        }
        if (input.transportDegradedReason !== undefined) {
            values.transport_degraded_reason = input.transportDegradedReason;
        }

        const row = await db.updateTable('runs').set(values).where('id', '=', runId).returningAll().executeTakeFirst();
        return row ? mapRunRecord(row) : null;
    }

    async finalize(runId: string, input: FinalizeRunInput): Promise<RunRecord | null> {
        const { db } = getPersistence();
        const now = nowIso();

        const row = await db
            .updateTable('runs')
            .set({
                status: input.status,
                updated_at: now,
                completed_at: input.status === 'completed' ? now : null,
                aborted_at: input.status === 'aborted' ? now : null,
                error_code: input.errorCode ?? null,
                error_message: input.errorMessage ?? null,
            })
            .where('id', '=', runId)
            .returningAll()
            .executeTakeFirst();

        return row ? mapRunRecord(row) : null;
    }

    async deleteById(runId: string): Promise<boolean> {
        const { db } = getPersistence();
        const row = await db.deleteFrom('runs').where('id', '=', runId).returning('id').executeTakeFirst();
        return Boolean(row);
    }
}

export const runStore = new RunStore();

import { randomUUID } from 'node:crypto';

import type { ProfileStoreDb } from '@/app/backend/persistence/stores/profile/profileStoreHelpers/types';
import { canonicalizeProviderModelId, kiloFrontierModelId } from '@/shared/kiloModels';
import { isJsonString, parseJsonValue } from '@/app/backend/persistence/stores/shared/utils';

const FALLBACK_DEFAULT_PROVIDER_ID = 'kilo';
const FALLBACK_DEFAULT_MODEL_ID = kiloFrontierModelId;

async function resolveDefaultProviderAndModel(
    tx: ProfileStoreDb,
    templateProfileId: string
): Promise<{ providerId: string; modelId: string }> {
    const rows = await tx
        .selectFrom('settings')
        .select(['key', 'value_json'])
        .where('profile_id', '=', templateProfileId)
        .where('key', 'in', ['default_provider_id', 'default_model_id'])
        .execute();

    const valueByKey = new Map(rows.map((row) => [row.key, row.value_json]));

    const providerRaw = valueByKey.get('default_provider_id');
    const modelRaw = valueByKey.get('default_model_id');

    const providerId =
        typeof providerRaw === 'string'
            ? parseJsonValue(providerRaw, FALLBACK_DEFAULT_PROVIDER_ID, isJsonString)
            : FALLBACK_DEFAULT_PROVIDER_ID;
    const modelId =
        typeof modelRaw === 'string'
            ? parseJsonValue(modelRaw, FALLBACK_DEFAULT_MODEL_ID, isJsonString)
            : FALLBACK_DEFAULT_MODEL_ID;

    return {
        providerId:
            typeof providerId === 'string' && providerId.trim().length > 0 ? providerId : FALLBACK_DEFAULT_PROVIDER_ID,
        modelId:
            typeof modelId === 'string' && modelId.trim().length > 0
                ? canonicalizeProviderModelId(
                      typeof providerId === 'string' && providerId.trim().length > 0
                          ? providerId
                          : FALLBACK_DEFAULT_PROVIDER_ID,
                      modelId
                  )
                : FALLBACK_DEFAULT_MODEL_ID,
    };
}

async function copyDefaultSettings(
    tx: ProfileStoreDb,
    sourceProfileId: string,
    targetProfileId: string,
    timestamp: string
): Promise<void> {
    const defaults = await resolveDefaultProviderAndModel(tx, sourceProfileId);
    await tx
        .insertInto('settings')
        .values([
            {
                id: `setting_${randomUUID()}`,
                profile_id: targetProfileId,
                key: 'default_provider_id',
                value_json: JSON.stringify(defaults.providerId),
                updated_at: timestamp,
            },
            {
                id: `setting_${randomUUID()}`,
                profile_id: targetProfileId,
                key: 'default_model_id',
                value_json: JSON.stringify(defaults.modelId),
                updated_at: timestamp,
            },
        ])
        .execute();
}

async function copyAllSettings(
    tx: ProfileStoreDb,
    sourceProfileId: string,
    targetProfileId: string,
    timestamp: string
): Promise<void> {
    const rows = await tx
        .selectFrom('settings')
        .select(['key', 'value_json'])
        .where('profile_id', '=', sourceProfileId)
        .execute();

    if (rows.length === 0) {
        await copyDefaultSettings(tx, sourceProfileId, targetProfileId, timestamp);
        return;
    }

    await tx
        .insertInto('settings')
        .values(
            rows.map((row) => ({
                id: `setting_${randomUUID()}`,
                profile_id: targetProfileId,
                key: row.key,
                value_json: row.value_json,
                updated_at: timestamp,
            }))
        )
        .execute();
}

export async function copyProfileSettings(input: {
    tx: ProfileStoreDb;
    sourceProfileId: string;
    targetProfileId: string;
    timestamp: string;
    copyAllSettings: boolean;
}): Promise<void> {
    if (input.copyAllSettings) {
        await copyAllSettings(input.tx, input.sourceProfileId, input.targetProfileId, input.timestamp);
        return;
    }

    await copyDefaultSettings(input.tx, input.sourceProfileId, input.targetProfileId, input.timestamp);
}

import { getPersistence } from '@/app/backend/persistence/db';
import { settingsStore } from '@/app/backend/persistence/stores/profile/settingsStore';
import {
    providerCatalogStore,
    type InvalidProviderModelDiagnostic,
    type PersistedProviderModelReadState,
} from '@/app/backend/persistence/stores/provider/providerCatalogStore';
import { parseEnumValue } from '@/app/backend/persistence/stores/shared/rowParsers';
import { isJsonRecord, isJsonString, isJsonUnknownArray } from '@/app/backend/persistence/stores/shared/utils';
import type { ProviderModelRecord, ProviderRecord } from '@/app/backend/persistence/types';
import {
    getProviderSpecialistDefaultKey,
    isSupportedProviderSpecialistDefaultTarget,
    type ProviderSpecialistDefaultModeKey,
    type ProviderSpecialistDefaultTopLevelTab,
    providerIds,
} from '@/app/backend/runtime/contracts';
import type { ProviderSpecialistDefaultRecord } from '@/app/backend/runtime/contracts/types/provider';
import type { RuntimeProviderId } from '@/app/backend/runtime/contracts';
import { canonicalizeProviderModelId } from '@/shared/kiloModels';

const SPECIALIST_DEFAULTS_KEY = 'specialist_defaults';

function isPersistedSpecialistDefaultRecord(value: unknown): value is ProviderSpecialistDefaultRecord {
    if (!isJsonRecord(value)) {
        return false;
    }

    if (
        !isJsonString(value.topLevelTab) ||
        !isJsonString(value.modeKey) ||
        !isJsonString(value.providerId) ||
        !isJsonString(value.modelId)
    ) {
        return false;
    }

    if (!providerIds.includes(value.providerId as RuntimeProviderId)) {
        return false;
    }

    const target = {
        topLevelTab: value.topLevelTab,
        modeKey: value.modeKey,
    };

    return isSupportedProviderSpecialistDefaultTarget(target);
}

function isPersistedSpecialistDefaultRecordArray(value: unknown): value is ProviderSpecialistDefaultRecord[] {
    return isJsonUnknownArray(value) && value.every(isPersistedSpecialistDefaultRecord);
}

function canonicalizeSpecialistDefaultRecord(
    value: ProviderSpecialistDefaultRecord
): ProviderSpecialistDefaultRecord {
    return {
        ...value,
        modelId: canonicalizeProviderModelId(value.providerId, value.modelId),
    };
}

export class ProviderStore {
    async listProviders(): Promise<ProviderRecord[]> {
        const { db } = getPersistence();

        const rows = await db
            .selectFrom('providers')
            .select(['id', 'label', 'supports_byok'])
            .orderBy('label', 'asc')
            .execute();

        return rows.map((row) => ({
            id: parseEnumValue(row.id, 'providers.id', providerIds),
            label: row.label,
            supportsByok: row.supports_byok === 1,
        }));
    }

    async listModels(profileId: string, providerId: RuntimeProviderId): Promise<ProviderModelRecord[]> {
        return providerCatalogStore.listModels(profileId, providerId);
    }

    async listModelsByProfile(profileId: string): Promise<ProviderModelRecord[]> {
        return providerCatalogStore.listByProfile(profileId);
    }

    async getDefaults(profileId: string): Promise<{ providerId: string; modelId: string }> {
        const [providerId, modelId] = await Promise.all([
            settingsStore.getStringRequired(profileId, 'default_provider_id'),
            settingsStore.getStringRequired(profileId, 'default_model_id'),
        ]);

        return {
            providerId,
            modelId,
        };
    }

    async setDefaults(profileId: string, providerId: RuntimeProviderId, modelId: string): Promise<void> {
        await Promise.all([
            settingsStore.setString(profileId, 'default_provider_id', providerId),
            settingsStore.setString(profileId, 'default_model_id', modelId),
        ]);
    }

    async getSpecialistDefaults(profileId: string): Promise<ProviderSpecialistDefaultRecord[]> {
        const persisted =
            (await settingsStore.getJsonOptional(
                profileId,
                SPECIALIST_DEFAULTS_KEY,
                isPersistedSpecialistDefaultRecordArray
            )) ?? [];

        return persisted.map(canonicalizeSpecialistDefaultRecord);
    }

    async setSpecialistDefault(
        profileId: string,
        input: {
            topLevelTab: ProviderSpecialistDefaultTopLevelTab;
            modeKey: ProviderSpecialistDefaultModeKey;
            providerId: RuntimeProviderId;
            modelId: string;
        }
    ): Promise<ProviderSpecialistDefaultRecord[]> {
        const nextRecord = canonicalizeSpecialistDefaultRecord({
            topLevelTab: input.topLevelTab,
            modeKey: input.modeKey,
            providerId: input.providerId,
            modelId: input.modelId,
        });
        const current = await this.getSpecialistDefaults(profileId);
        const nextRecords = [
            nextRecord,
            ...current.filter(
                (value) => getProviderSpecialistDefaultKey(value) !== getProviderSpecialistDefaultKey(nextRecord)
            ),
        ];
        await settingsStore.setJson(profileId, SPECIALIST_DEFAULTS_KEY, nextRecords);
        return nextRecords;
    }

    async providerExists(providerId: RuntimeProviderId): Promise<boolean> {
        const { db } = getPersistence();
        const row = await db.selectFrom('providers').select('id').where('id', '=', providerId).executeTakeFirst();

        return Boolean(row);
    }

    async modelExists(profileId: string, providerId: RuntimeProviderId, modelId: string): Promise<boolean> {
        return providerCatalogStore.modelExists(profileId, providerId, modelId);
    }

    async getModel(profileId: string, providerId: RuntimeProviderId, modelId: string): Promise<ProviderModelRecord | null> {
        return providerCatalogStore.getModel(profileId, providerId, modelId);
    }

    async getModelReadState(
        profileId: string,
        providerId: RuntimeProviderId,
        modelId: string
    ): Promise<PersistedProviderModelReadState | null> {
        return providerCatalogStore.getModelReadState(profileId, providerId, modelId);
    }

    async listInvalidModelDiagnostics(
        profileId: string,
        providerId: RuntimeProviderId
    ): Promise<InvalidProviderModelDiagnostic[]> {
        return providerCatalogStore.listInvalidModelDiagnostics(profileId, providerId);
    }

    async getModelCapabilities(profileId: string, providerId: RuntimeProviderId, modelId: string) {
        return providerCatalogStore.getModelCapabilities(profileId, providerId, modelId);
    }
}

export const providerStore = new ProviderStore();

