import type {
    ProviderByIdInput,
    ProviderCancelAuthInput,
    ProviderClearAuthInput,
    ProviderCompleteAuthInput,
    ProviderGetCredentialInput,
    ProviderGetExecutionPreferenceInput,
    ProviderGetConnectionProfileInput,
