import { writeFileSync } from 'node:fs';

import { describe, expect, it, vi } from 'vitest';

import { memoryStore } from '@/app/backend/persistence/stores';
import type { ModeDefinition } from '@/app/backend/runtime/contracts';
import { memoryService } from '@/app/backend/runtime/services/memory/service';
import { advancedMemoryDerivationService } from '@/app/backend/runtime/services/memory/advancedDerivation';
import { memoryRetrievalService } from '@/app/backend/runtime/services/memory/retrieval';
import { buildRunContext } from '@/app/backend/runtime/services/runExecution/contextBuilder';
import { errOp } from '@/app/backend/runtime/services/common/operationalError';
import {
    createCaller,
    createSessionInScope,
    registerRuntimeContractHooks,
    requireEntityId,
    runtimeContractProfileId,
} from '@/app/backend/trpc/__tests__/runtime-contracts.shared';

registerRuntimeContractHooks();

function createResolvedMode(modeKey: string, topLevelTab: 'chat' | 'agent' | 'orchestrator'): { mode: ModeDefinition } {
    return {
        mode: {
            id: `mode_${topLevelTab}_${modeKey}`,
            profileId: runtimeContractProfileId,
            topLevelTab,
            modeKey,
            label: `${topLevelTab} ${modeKey}`,
            prompt: {},
            executionPolicy: {},
            source: 'system',
            enabled: true,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            assetKey: `${topLevelTab}-${modeKey}`,
            sourceKind: 'system_seed',
            scope: 'system',
            tags: [] as string[],
            precedence: 0,
        },
    };
}

describe('memoryRetrievalService', () => {
    const profileId = runtimeContractProfileId;

    it('orders exact scope matches before prompt matches and excludes disabled or superseded memory', async () => {
        const caller = createCaller();
        const current = await createSessionInScope(caller, profileId, {
            scope: 'workspace',
            workspaceFingerprint: 'wsf_memory_retrieval_current',
            title: 'Current retrieval thread',
            kind: 'local',
            topLevelTab: 'agent',
        });
        const currentThreadId = requireEntityId(current.thread.id, 'thr', 'Expected current retrieval thread id.');
        const other = await createSessionInScope(caller, profileId, {
            scope: 'workspace',
            workspaceFingerprint: 'wsf_memory_retrieval_other',
            title: 'Other retrieval thread',
            kind: 'local',
            topLevelTab: 'agent',
        });
        const otherThreadId = requireEntityId(other.thread.id, 'thr', 'Expected other retrieval thread id.');

        await caller.memory.create({
            profileId,
            memoryType: 'procedural',
            scopeKind: 'thread',
            createdByKind: 'user',
            threadId: currentThreadId,
            title: 'Current thread memory',
            bodyMarkdown: 'Use the current-thread procedure.',
        });
        await caller.memory.create({
            profileId,
            memoryType: 'semantic',
            scopeKind: 'workspace',
            createdByKind: 'user',
            workspaceFingerprint: 'wsf_memory_retrieval_current',
            title: 'Workspace memory',
            bodyMarkdown: 'Workspace truth.',
        });
        await caller.memory.create({
            profileId,
            memoryType: 'semantic',
            scopeKind: 'global',
            createdByKind: 'user',
            title: 'Global memory',
            bodyMarkdown: 'Global default.',
        });
        const disabledMemory = await memoryStore.create({
            profileId,
            memoryType: 'procedural',
            scopeKind: 'thread',
            state: 'disabled',
            createdByKind: 'user',
            threadId: currentThreadId,
            title: 'Disabled memory',
            bodyMarkdown: 'Should never be retrieved.',
        });
        const supersededOriginal = await caller.memory.create({
            profileId,
            memoryType: 'procedural',
            scopeKind: 'thread',
            createdByKind: 'user',
            threadId: otherThreadId,
            title: 'Superseded zebra memory',
            bodyMarkdown: 'Old zebra instruction.',
        });
        await caller.memory.supersede({
            profileId,
            memoryId: supersededOriginal.memory.id,
            createdByKind: 'user',
            title: 'Superseded zebra memory v2',
            bodyMarkdown: 'New zebra instruction.',
        });
        const promptMatch = await caller.memory.create({
            profileId,
            memoryType: 'procedural',
            scopeKind: 'thread',
            createdByKind: 'user',
            threadId: otherThreadId,
            title: 'Zebra fallback procedure',
            bodyMarkdown: 'Use the zebra fallback when asked.',
        });

        const retrieved = await memoryRetrievalService.retrieveRelevantMemory({
            profileId,
            sessionId: current.session.id,
            topLevelTab: 'agent',
            modeKey: 'code',
            workspaceFingerprint: 'wsf_memory_retrieval_current',
            prompt: 'Please use the zebra procedure for this task.',
        });

        expect(retrieved.summary?.records.slice(0, 3).map((record) => record.title)).toEqual([
            'Current thread memory',
            'Workspace memory',
            'Global memory',
        ]);
        expect(retrieved.summary?.records.some((record) => record.memoryId === disabledMemory.id)).toBe(false);
        expect(
            retrieved.summary?.records.some((record) => record.memoryId === supersededOriginal.memory.id)
        ).toBe(false);
        expect(retrieved.summary?.records.some((record) => record.memoryId === promptMatch.memory.id)).toBe(true);
        expect(retrieved.summary?.records.some((record) => record.title === 'Superseded zebra memory v2')).toBe(true);
    });

    it('includes retrieved memory in the built run context and digest', async () => {
        const caller = createCaller();
        const created = await createSessionInScope(caller, profileId, {
            scope: 'detached',
            title: 'Digest retrieval thread',
            kind: 'local',
            topLevelTab: 'chat',
        });

        const memory = await caller.memory.create({
            profileId,
            memoryType: 'semantic',
            scopeKind: 'global',
            createdByKind: 'user',
            title: 'Digest memory',
            bodyMarkdown: 'First digest body.',
        });

        const firstContext = await buildRunContext({
            profileId,
            sessionId: created.session.id,
            prompt: 'Use the available memory.',
            topLevelTab: 'chat',
            providerId: 'openai',
            modelId: 'openai/gpt-5',
            resolvedMode: createResolvedMode('chat', 'chat'),
        });
        expect(firstContext.isOk()).toBe(true);
        if (firstContext.isErr() || !firstContext.value) {
            throw new Error(firstContext.isErr() ? firstContext.error.message : 'Expected first run context.');
        }
        expect(firstContext.value.retrievedMemory?.records.map((record) => record.title)).toEqual(['Digest memory']);
        expect(firstContext.value.messages.some((message) => JSON.stringify(message).includes('Retrieved memory'))).toBe(
            true
        );

        const updated = await memoryService.updateMemory({
            profileId,
            memoryId: memory.memory.id,
            title: 'Digest memory updated',
            bodyMarkdown: 'Second digest body.',
        });
        expect(updated.isOk()).toBe(true);

        const secondContext = await buildRunContext({
            profileId,
            sessionId: created.session.id,
            prompt: 'Use the available memory.',
            topLevelTab: 'chat',
            providerId: 'openai',
            modelId: 'openai/gpt-5',
            resolvedMode: createResolvedMode('chat', 'chat'),
        });
        expect(secondContext.isOk()).toBe(true);
        if (secondContext.isErr() || !secondContext.value) {
            throw new Error(secondContext.isErr() ? secondContext.error.message : 'Expected second run context.');
        }
        expect(secondContext.value.digest).not.toBe(firstContext.value.digest);
        expect(secondContext.value.retrievedMemory?.records[0]?.title).toBe('Digest memory updated');
    });

    it('does not mutate pending projection edits while retrieving memory', async () => {
        const caller = createCaller();
        const created = await createSessionInScope(caller, profileId, {
            scope: 'workspace',
            workspaceFingerprint: 'wsf_memory_retrieval_projection_safety',
            title: 'Projection safety thread',
            kind: 'local',
            topLevelTab: 'agent',
        });
        const threadId = requireEntityId(created.thread.id, 'thr', 'Expected projection safety thread id.');
        const memory = await caller.memory.create({
            profileId,
            memoryType: 'procedural',
            scopeKind: 'thread',
            createdByKind: 'user',
            threadId,
            title: 'Projection safety memory',
            bodyMarkdown: 'Original body.',
        });

        const synced = await caller.memory.syncProjection({
            profileId,
            workspaceFingerprint: 'wsf_memory_retrieval_projection_safety',
            threadId,
        });
        const projected = synced.projectedMemories.find((record) => record.memory.id === memory.memory.id);
        if (!projected) {
            throw new Error('Expected projected memory for retrieval safety test.');
        }

        const editedContent =
            `---\n` +
            `id: "${memory.memory.id}"\n` +
            `memoryType: "procedural"\n` +
            `scopeKind: "thread"\n` +
            `state: "active"\n` +
            `title: "Projection safety memory edited"\n` +
            `threadId: "${threadId}"\n` +
            `workspaceFingerprint: "wsf_memory_retrieval_projection_safety"\n` +
            `metadata: {"edited":true}\n` +
            `---\n` +
            `Edited body that retrieval must not touch.\n`;
        writeFileSync(projected.absolutePath, editedContent, 'utf8');

        const beforeRetrieval = await caller.memory.scanProjectionEdits({
            profileId,
            workspaceFingerprint: 'wsf_memory_retrieval_projection_safety',
            threadId,
        });
        expect(beforeRetrieval.proposals).toHaveLength(1);

        const retrieved = await memoryRetrievalService.retrieveRelevantMemory({
            profileId,
            sessionId: created.session.id,
            topLevelTab: 'agent',
            modeKey: 'code',
            workspaceFingerprint: 'wsf_memory_retrieval_projection_safety',
            prompt: 'Use the projection safety memory.',
        });
        expect(retrieved.summary?.records.some((record) => record.memoryId === memory.memory.id)).toBe(true);

        const afterRetrieval = await caller.memory.scanProjectionEdits({
            profileId,
            workspaceFingerprint: 'wsf_memory_retrieval_projection_safety',
            threadId,
        });
        expect(afterRetrieval.proposals).toHaveLength(1);
        expect(afterRetrieval.proposals[0]?.proposedTitle).toBe('Projection safety memory edited');
    });

    it('falls back to scoped retrieval when the derived layer fails', async () => {
        const caller = createCaller();
        const created = await createSessionInScope(caller, profileId, {
            scope: 'workspace',
            workspaceFingerprint: 'wsf_memory_retrieval_fail_soft',
            title: 'Derived fail-soft thread',
            kind: 'local',
            topLevelTab: 'agent',
        });
        const threadId = requireEntityId(created.thread.id, 'thr', 'Expected derived fail-soft thread id.');

        const scopedMemory = await caller.memory.create({
            profileId,
            memoryType: 'procedural',
            scopeKind: 'thread',
            createdByKind: 'user',
            threadId,
            title: 'Fail-soft scoped memory',
            bodyMarkdown: 'Use the scoped memory even if derivation breaks.',
        });

        const expandSpy = vi
            .spyOn(advancedMemoryDerivationService, 'expandMatchedMemories')
            .mockResolvedValue(errOp('request_failed', 'Derived retrieval failed.'));
        const summariesSpy = vi
            .spyOn(advancedMemoryDerivationService, 'getDerivedSummaries')
            .mockResolvedValue(errOp('request_failed', 'Derived summaries failed.'));

        try {
            const retrieved = await memoryRetrievalService.retrieveRelevantMemory({
                profileId,
                sessionId: created.session.id,
                topLevelTab: 'agent',
                modeKey: 'code',
                workspaceFingerprint: 'wsf_memory_retrieval_fail_soft',
                prompt: 'Use the fail-soft scoped memory.',
            });

            expect(retrieved.summary?.records.map((record) => record.memoryId)).toContain(scopedMemory.memory.id);
            expect(retrieved.summary?.records.some((record) => record.matchReason === 'derived_temporal')).toBe(false);
        } finally {
            expandSpy.mockRestore();
            summariesSpy.mockRestore();
        }
    });
});

import { memoryStore, threadStore } from '@/app/backend/persistence/stores';
import { parseEntityId } from '@/app/backend/persistence/stores/shared/rowParsers';
import type { MemoryRecord } from '@/app/backend/persistence/types';
import type {
    EntityId,
    RetrievedMemoryMatchReason,
    RetrievedMemoryRecord,
    RetrievedMemorySummary,
    TopLevelTab,
} from '@/app/backend/runtime/contracts';
import { advancedMemoryDerivationService } from '@/app/backend/runtime/services/memory/advancedDerivation';
import { createTextMessage } from '@/app/backend/runtime/services/runExecution/contextParts';
import type { RunContextMessage } from '@/app/backend/runtime/services/runExecution/types';

const MAX_RETRIEVED_MEMORY_RECORDS = 6;
const MAX_RETRIEVED_MEMORY_TEXT_LENGTH = 6_000;
const MEMORY_ENTRY_TEXT_LIMIT = 1_000;
const PROMPT_TERM_MIN_LENGTH = 4;
const PROMPT_STOP_WORDS = new Set([
    'about',
    'after',
    'again',
    'agent',
    'also',
    'because',
    'before',
    'between',
    'chat',
    'code',
    'debug',
    'from',
    'have',
    'into',
    'just',
    'mode',
    'more',
    'orchestrator',
    'over',
    'that',
    'their',
    'them',
    'then',
    'there',
    'these',
    'this',
    'those',
    'what',
    'when',
    'where',
    'which',
    'while',
    'with',
    'would',
]);

interface RetrieveRelevantMemoryInput {
    profileId: string;
    sessionId: EntityId<'sess'>;
    topLevelTab: TopLevelTab;
    modeKey: string;
    prompt: string;
    workspaceFingerprint?: string;
    runId?: EntityId<'run'>;
}

interface RetrievedMemoryCandidate {
    memory: MemoryRecord;
    matchReason: RetrievedMemoryMatchReason;
    priority: number;
    sourceMemoryId?: EntityId<'mem'>;
    annotations?: string[];
}

interface RetrieveRelevantMemoryResult {
    summary?: RetrievedMemorySummary;
    messages: RunContextMessage[];
}

function normalizeWhitespace(value: string): string {
    return value.replace(/\s+/g, ' ').trim();
}

function normalizeSearchText(value: string): string {
    return normalizeWhitespace(value).toLowerCase();
}

function uniquePromptTerms(prompt: string): string[] {
    const normalizedPrompt = normalizeSearchText(prompt);
    if (normalizedPrompt.length === 0) {
        return [];
    }

    return Array.from(
        new Set(
            normalizedPrompt
                .split(/[^a-z0-9_/-]+/i)
                .map((value) => value.trim())
                .filter((value) => value.length >= PROMPT_TERM_MIN_LENGTH)
                .filter((value) => !PROMPT_STOP_WORDS.has(value))
        )
    );
}

function collectMetadataStrings(value: unknown): string[] {
    if (typeof value === 'string') {
        const normalized = normalizeSearchText(value);
        return normalized.length > 0 ? [normalized] : [];
    }
    if (typeof value === 'number' || typeof value === 'boolean') {
        return [String(value).toLowerCase()];
    }
    if (Array.isArray(value)) {
        return value.flatMap((item) => collectMetadataStrings(item));
    }
    if (value && typeof value === 'object') {
        return Object.values(value).flatMap((item) => collectMetadataStrings(item));
    }

    return [];
}

function scopePriority(scopeKind: MemoryRecord['scopeKind']): number {
    switch (scopeKind) {
        case 'run':
            return 0;
        case 'thread':
            return 1;
        case 'workspace':
            return 2;
        case 'global':
            return 3;
    }
}

function isExactScopeMatch(input: {
    memory: MemoryRecord;
    runId?: EntityId<'run'>;
    threadIds?: EntityId<'thr'>[];
    workspaceFingerprint?: string;
}): RetrievedMemoryMatchReason | null {
    if (input.runId && input.memory.runId === input.runId) {
        return 'exact_run';
    }
    if (input.threadIds?.some((threadId) => input.memory.threadId === threadId)) {
        return 'exact_thread';
    }
    if (input.workspaceFingerprint && input.memory.workspaceFingerprint === input.workspaceFingerprint) {
        return 'exact_workspace';
    }
    if (input.memory.scopeKind === 'global') {
        return 'exact_global';
    }

    return null;
}

function matchesStructuredContext(input: {
    memory: MemoryRecord;
    topLevelTab: TopLevelTab;
    modeKey: string;
    workspaceFingerprint?: string;
    threadIds?: EntityId<'thr'>[];
    runId?: EntityId<'run'>;
}): boolean {
    const contextualNeedles = [
        input.topLevelTab,
        input.modeKey,
        input.workspaceFingerprint,
        ...(input.threadIds ?? []),
        input.runId,
    ]
        .filter((value): value is string => typeof value === 'string' && value.length > 0)
        .map((value) => normalizeSearchText(value));
    if (contextualNeedles.length === 0) {
        return false;
    }

    const title = normalizeSearchText(input.memory.title);
    const summary = normalizeSearchText(input.memory.summaryText ?? '');
    const metadataStrings = collectMetadataStrings(input.memory.metadata);

    return contextualNeedles.some(
        (needle) => title.includes(needle) || summary.includes(needle) || metadataStrings.some((value) => value === needle)
    );
}

function countPromptTermMatches(memory: MemoryRecord, promptTerms: string[]): number {
    if (promptTerms.length === 0) {
        return 0;
    }

    const haystacks = [
        normalizeSearchText(memory.title),
        normalizeSearchText(memory.summaryText ?? ''),
        normalizeSearchText(memory.bodyMarkdown),
    ].filter((value) => value.length > 0);

    return promptTerms.filter((term) => haystacks.some((haystack) => haystack.includes(term))).length;
}

function describeMemoryProvenance(memory: MemoryRecord): string {
    const segments = [
        `scope=${memory.scopeKind}`,
        ...(memory.runId ? [`run=${memory.runId}`] : []),
        ...(memory.threadId ? [`thread=${memory.threadId}`] : []),
        ...(memory.workspaceFingerprint ? [`workspace=${memory.workspaceFingerprint}`] : []),
    ];

    return segments.join(', ');
}

function formatMemoryBody(memory: MemoryRecord, remainingBudget: number): string {
    const normalizedSummary = normalizeWhitespace(memory.summaryText ?? '');
    const normalizedBody = normalizeWhitespace(memory.bodyMarkdown);
    const candidate = normalizedSummary.length > 0 ? `${normalizedSummary}\n\n${normalizedBody}` : normalizedBody;
    const boundedLength = Math.max(0, Math.min(MEMORY_ENTRY_TEXT_LIMIT, remainingBudget));
    if (candidate.length <= boundedLength) {
        return candidate;
    }
    if (boundedLength <= 3) {
        return candidate.slice(0, boundedLength);
    }

    return `${candidate.slice(0, boundedLength - 3)}...`;
}

function buildRetrievedMemoryMessage(records: RetrievedMemoryRecord[], memoriesById: Map<string, MemoryRecord>): {
    message: RunContextMessage;
    injectedTextLength: number;
} | null {
    const lines: string[] = ['Retrieved memory', ''];

    for (const record of records) {
        const memory = memoriesById.get(record.memoryId);
        if (!memory) {
            continue;
        }

        const currentText = lines.join('\n');
        const remainingBudget = MAX_RETRIEVED_MEMORY_TEXT_LENGTH - currentText.length;
        if (remainingBudget <= 0) {
            break;
        }

        const excerpt = formatMemoryBody(memory, remainingBudget);
        lines.push(
            `${record.order}. ${memory.title}`,
            `Type: ${memory.memoryType}`,
            `Scope: ${memory.scopeKind}`,
            `Match reason: ${record.matchReason}`,
            `Provenance: ${describeMemoryProvenance(memory)}`,
            ...(record.annotations && record.annotations.length > 0 ? [`Notes: ${record.annotations.join(' ')}`] : []),
            'Details:',
            excerpt,
            ''
        );
    }

    const text = lines.join('\n').trim();
    if (text === 'Retrieved memory') {
        return null;
    }

    return {
        message: createTextMessage('system', text),
        injectedTextLength: text.length,
    };
}

export class MemoryRetrievalService {
    async retrieveRelevantMemory(input: RetrieveRelevantMemoryInput): Promise<RetrieveRelevantMemoryResult> {
        const sessionThread = await threadStore.getBySessionId(input.profileId, input.sessionId);
        const threadId = sessionThread
            ? parseEntityId(sessionThread.thread.id, 'threads.id', 'thr')
            : undefined;
        const inheritedRootThreadId =
            sessionThread &&
            sessionThread.thread.delegatedFromOrchestratorRunId &&
            sessionThread.thread.rootThreadId !== sessionThread.thread.id
                ? parseEntityId(sessionThread.thread.rootThreadId, 'threads.root_thread_id', 'thr')
                : undefined;
        const threadIds = Array.from(
            new Set(
                [threadId, inheritedRootThreadId].filter(
                    (value): value is EntityId<'thr'> => typeof value === 'string' && value.length > 0
                )
            )
        );
        const workspaceFingerprint = input.workspaceFingerprint ?? sessionThread?.workspaceFingerprint;
        const promptTerms = uniquePromptTerms(input.prompt);
        const activeMemories = await memoryStore.listByProfile({
            profileId: input.profileId,
            state: 'active',
        });

        const candidates: RetrievedMemoryCandidate[] = [];
        for (const memory of activeMemories) {
            const exactMatchReason = isExactScopeMatch({
                memory,
                ...(input.runId ? { runId: input.runId } : {}),
                ...(threadIds.length > 0 ? { threadIds } : {}),
                ...(workspaceFingerprint ? { workspaceFingerprint } : {}),
            });
            if (exactMatchReason) {
                candidates.push({
                    memory,
                    matchReason: exactMatchReason,
                    priority: scopePriority(memory.scopeKind),
                });
                continue;
            }

            if (
                matchesStructuredContext({
                    memory,
                    topLevelTab: input.topLevelTab,
                    modeKey: input.modeKey,
                    ...(workspaceFingerprint ? { workspaceFingerprint } : {}),
                    ...(threadIds.length > 0 ? { threadIds } : {}),
                    ...(input.runId ? { runId: input.runId } : {}),
                })
            ) {
                candidates.push({
                    memory,
                    matchReason: 'structured',
                    priority: 10 + scopePriority(memory.scopeKind),
                });
            }
        }

        const baseCandidates = candidates
            .sort((left, right) => {
                if (left.priority !== right.priority) {
                    return left.priority - right.priority;
                }
                if (left.memory.updatedAt !== right.memory.updatedAt) {
                    return right.memory.updatedAt.localeCompare(left.memory.updatedAt);
                }

                return left.memory.id.localeCompare(right.memory.id);
            });
        const baseMemoryIds = Array.from(new Set(baseCandidates.map((candidate) => candidate.memory.id)));
        const derivedExpansion = await advancedMemoryDerivationService.expandMatchedMemories({
            profileId: input.profileId,
            prompt: input.prompt,
            matchedMemories: baseCandidates.map((candidate) => candidate.memory),
        });
        const derivedSummaryById = derivedExpansion.isOk() ? derivedExpansion.value.summaries : new Map();
        const candidateMemoryIds = new Set(baseMemoryIds);
        const combinedCandidates: RetrievedMemoryCandidate[] = [
            ...baseCandidates.map((candidate) => ({
                ...candidate,
                ...(derivedSummaryById.get(candidate.memory.id)
                    ? { annotations: derivedSummaryById.get(candidate.memory.id)?.hasTemporalHistory ? ['Current fact has temporal history.'] : [] }
                    : {}),
            })),
        ];

        if (derivedExpansion.isOk()) {
            for (const derivedCandidate of derivedExpansion.value.candidates) {
                if (candidateMemoryIds.has(derivedCandidate.memory.id)) {
                    continue;
                }

                combinedCandidates.push({
                    memory: derivedCandidate.memory,
                    matchReason: derivedCandidate.matchReason,
                    priority: derivedCandidate.matchReason === 'derived_temporal' ? 15 : 16,
                    sourceMemoryId: derivedCandidate.sourceMemoryId,
                    annotations: derivedCandidate.annotations,
                });
                candidateMemoryIds.add(derivedCandidate.memory.id);
            }
        }

        for (const memory of activeMemories) {
            if (candidateMemoryIds.has(memory.id)) {
                continue;
            }

            const promptMatchCount = countPromptTermMatches(memory, promptTerms);
            if (promptMatchCount <= 0) {
                continue;
            }

            combinedCandidates.push({
                memory,
                matchReason: 'prompt',
                priority: 20 + scopePriority(memory.scopeKind) * 10 - promptMatchCount,
            });
        }

        const orderedCandidates = combinedCandidates
            .sort((left, right) => {
                if (left.priority !== right.priority) {
                    return left.priority - right.priority;
                }
                if (left.memory.updatedAt !== right.memory.updatedAt) {
                    return right.memory.updatedAt.localeCompare(left.memory.updatedAt);
                }

                return left.memory.id.localeCompare(right.memory.id);
            })
            .slice(0, MAX_RETRIEVED_MEMORY_RECORDS);

        if (orderedCandidates.length === 0) {
            return {
                messages: [],
            };
        }

        const finalDerivedSummaries = await advancedMemoryDerivationService.getDerivedSummaries(
            input.profileId,
            orderedCandidates.map((candidate) => candidate.memory.id)
        );
        const finalDerivedSummaryById = finalDerivedSummaries.isOk() ? finalDerivedSummaries.value : new Map();

        const retrievedRecords: RetrievedMemoryRecord[] = orderedCandidates.map((candidate, index) => ({
            memoryId: candidate.memory.id,
            title: candidate.memory.title,
            memoryType: candidate.memory.memoryType,
            scopeKind: candidate.memory.scopeKind,
            matchReason: candidate.matchReason,
            order: index + 1,
            ...(candidate.sourceMemoryId ? { sourceMemoryId: candidate.sourceMemoryId } : {}),
            ...(candidate.annotations && candidate.annotations.length > 0 ? { annotations: candidate.annotations } : {}),
            ...(finalDerivedSummaryById.get(candidate.memory.id)
                ? { derivedSummary: finalDerivedSummaryById.get(candidate.memory.id) }
                : {}),
        }));
        const memoriesById = new Map(orderedCandidates.map((candidate) => [candidate.memory.id, candidate.memory] as const));
        const injectedMessage = buildRetrievedMemoryMessage(retrievedRecords, memoriesById);
        if (!injectedMessage) {
            return {
                messages: [],
            };
        }

        return {
            summary: {
                records: retrievedRecords,
                injectedTextLength: injectedMessage.injectedTextLength,
            },
            messages: [injectedMessage.message],
        };
    }
}

export const memoryRetrievalService = new MemoryRetrievalService();

import type { ProviderRuntimePart, ProviderRuntimeTransportSelection, ProviderRuntimeUsage } from '@/app/backend/providers/types';
import type { RuntimeProviderId, TopLevelTab } from '@/app/backend/runtime/contracts';
import { neonObservabilityService } from '@/app/backend/runtime/services/observability/service';
import type { EntityId } from '@/shared/contracts';

interface ObservabilityRunContext {
    profileId: string;
    sessionId: EntityId<'sess'>;
    runId: EntityId<'run'>;
    providerId: RuntimeProviderId | string;
    modelId: string;
}

function publishStreamChunk(
    context: ObservabilityRunContext,
    source: 'provider.stream' | 'runtime.run_execution' | 'runtime.terminal_state',
    chunk:
        | {
              kind: 'text_delta';
              text: string;
          }
        | {
              kind: 'reasoning_delta';
              text: string;
              summary: boolean;
          }
        | {
              kind: 'tool_call';
              toolCallId: string;
              toolName: string;
              argumentsText: string;
          }
        | {
              kind: 'tool_result';
              toolCallId: string;
              toolName: string;
              outputText: string;
              isError: boolean;
          }
        | {
              kind: 'status';
              code?: string;
              label: string;
              elapsedMs?: number;
          }
        | ({
              kind: 'usage';
          } & {
              inputTokens?: number;
              outputTokens?: number;
              cachedTokens?: number;
              reasoningTokens?: number;
              totalTokens?: number;
              latencyMs?: number;
              costMicrounits?: number;
          })
        | {
              kind: 'done';
          }
        | {
              kind: 'error';
              code: string;
              message: string;
          }
): void {
    neonObservabilityService.publish({
        ...context,
        kind: 'stream_chunk',
        source,
        chunk,
    });
}

export function publishRunStartedObservabilityEvent(input: ObservabilityRunContext & {
    topLevelTab: TopLevelTab;
    modeKey: string;
}): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'run_started',
        source: 'runtime.run_execution',
    });
}

export function publishRunCompletedObservabilityEvent(input: ObservabilityRunContext): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'run_completed',
        source: 'runtime.run_execution',
    });
    publishStreamChunk(input, 'runtime.run_execution', {
        kind: 'done',
    });
}

export function publishRunFailedObservabilityEvent(input: ObservabilityRunContext & {
    errorCode: string;
    errorMessage: string;
}): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'run_failed',
        source: 'runtime.terminal_state',
        errorCode: input.errorCode,
        errorMessage: input.errorMessage,
    });
    publishStreamChunk(input, 'runtime.terminal_state', {
        kind: 'error',
        code: input.errorCode,
        message: input.errorMessage,
    });
}

export function publishRunAbortedObservabilityEvent(input: ObservabilityRunContext): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'run_aborted',
        source: 'runtime.terminal_state',
    });
    publishStreamChunk(input, 'runtime.terminal_state', {
        kind: 'error',
        code: 'aborted',
        message: 'Run aborted.',
    });
}

export function publishTransportSelectedObservabilityEvent(
    input: ObservabilityRunContext & {
        selection: ProviderRuntimeTransportSelection;
    }
): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'transport_selected',
        source: 'runtime.transport',
        requestedTransportFamily: input.selection.requested,
        selectedTransportFamily: input.selection.selected,
        degraded: input.selection.degraded,
        ...(input.selection.degradedReason ? { degradedReason: input.selection.degradedReason } : {}),
    });
}

export function publishProviderPartObservabilityEvent(
    input: ObservabilityRunContext & {
        part: ProviderRuntimePart;
    }
): void {
    const part = input.part;

    if (part.partType === 'text') {
        const text = part.payload['text'];
        if (typeof text === 'string' && text.length > 0) {
            publishStreamChunk(input, 'provider.stream', {
                kind: 'text_delta',
                text,
            });
        }
        return;
    }

    if (part.partType === 'reasoning' || part.partType === 'reasoning_summary') {
        const text = part.payload['text'];
        if (typeof text === 'string' && text.length > 0) {
            publishStreamChunk(input, 'provider.stream', {
                kind: 'reasoning_delta',
                text,
                summary: part.partType === 'reasoning_summary',
            });
        }
        return;
    }

    if (part.partType === 'tool_call') {
        const toolCallId = part.payload['callId'];
        const toolName = part.payload['toolName'];
        const argumentsText = part.payload['argumentsText'];
        if (typeof toolCallId === 'string' && typeof toolName === 'string' && typeof argumentsText === 'string') {
            publishStreamChunk(input, 'provider.stream', {
                kind: 'tool_call',
                toolCallId,
                toolName,
                argumentsText,
            });
        }
        return;
    }

    if (part.partType === 'tool_result') {
        const toolCallId = part.payload['callId'];
        const toolName = part.payload['toolName'];
        const outputText = part.payload['outputText'];
        const isError = part.payload['isError'];
        if (
            typeof toolCallId === 'string' &&
            typeof toolName === 'string' &&
            typeof outputText === 'string' &&
            typeof isError === 'boolean'
        ) {
            publishStreamChunk(input, 'provider.stream', {
                kind: 'tool_result',
                toolCallId,
                toolName,
                outputText,
                isError,
            });
        }
        return;
    }

    if (part.partType === 'status') {
        const label = part.payload['label'];
        const code = part.payload['code'];
        const elapsedMs = part.payload['elapsedMs'];
        if (typeof label === 'string' && label.length > 0) {
            publishStreamChunk(input, 'provider.stream', {
                kind: 'status',
                label,
                ...(typeof code === 'string' ? { code } : {}),
                ...(typeof elapsedMs === 'number' ? { elapsedMs } : {}),
            });
        }
        return;
    }

    if (part.partType === 'error') {
        const message = part.payload['message'];
        const code = part.payload['code'];
        if (typeof message === 'string' && message.length > 0) {
            publishStreamChunk(input, 'provider.stream', {
                kind: 'error',
                code: typeof code === 'string' ? code : 'provider_error',
                message,
            });
        }
    }
}

export function publishUsageObservabilityEvent(input: ObservabilityRunContext & {
    usage: ProviderRuntimeUsage;
}): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'usage_updated',
        source: 'provider.stream',
        usage: input.usage,
    });
    publishStreamChunk(input, 'provider.stream', {
        kind: 'usage',
        ...input.usage,
    });
}

export function publishToolStateChangedObservabilityEvent(input: ObservabilityRunContext & {
    toolCallId: string;
    toolName: string;
    state:
        | 'proposed'
        | 'input_complete'
        | 'approval_required'
        | 'approved'
        | 'denied'
        | 'executing'
        | 'completed'
        | 'failed'
        | 'cancelled';
    argumentsText?: string;
    requestId?: string;
    error?: string;
    policySource?: string;
}): void {
    neonObservabilityService.publish({
        ...input,
        kind: 'tool_state_changed',
        source: 'runtime.tool_execution',
        toolCallId: input.toolCallId,
        toolName: input.toolName,
        state: input.state,
        ...(input.argumentsText ? { argumentsText: input.argumentsText } : {}),
        ...(input.requestId ? { requestId: input.requestId } : {}),
        ...(input.error ? { error: input.error } : {}),
        ...(input.policySource ? { policySource: input.policySource } : {}),
    });
}

export function publishToolResultChunkObservabilityEvent(input: ObservabilityRunContext & {
    toolCallId: string;
    toolName: string;
    outputText: string;
    isError: boolean;
}): void {
    publishStreamChunk(input, 'runtime.run_execution', {
        kind: 'tool_result',
        toolCallId: input.toolCallId,
        toolName: input.toolName,
        outputText: input.outputText,
        isError: input.isError,
    });
}

