import {
    conversationStore,
    runStore,
    sessionAttachedRuleStore,
    sessionAttachedSkillStore,
    sessionStore,
    threadStore,
} from '@/app/backend/persistence/stores';
import { parseEntityId } from '@/app/backend/persistence/stores/shared/rowParsers';
import type {
    ConversationRecord,
    OrchestratorStepRecord,
    PlanRecord,
    SessionSummaryRecord,
    ThreadRecord,
} from '@/app/backend/persistence/types';
import type { EntityId, OrchestratorStartInput, ResolvedWorkspaceContext } from '@/app/backend/runtime/contracts';
import { eventMetadata } from '@/app/backend/runtime/services/common/logContext';
import { workspaceContextService } from '@/app/backend/runtime/services/workspaceContext/service';
import { runtimeUpsertEvent } from '@/app/backend/runtime/services/runtimeEventEnvelope';
import { runtimeEventLogService } from '@/app/backend/runtime/services/runtimeEventLog';
import { runExecutionService } from '@/app/backend/runtime/services/runExecution/service';

type WorkspaceExecutionTarget = Extract<ResolvedWorkspaceContext, { kind: 'workspace' | 'sandbox' }>;

interface OrchestratorRootExecutionContext {
    bucket: ConversationRecord;
    rootThread: ThreadRecord;
    executionTarget: WorkspaceExecutionTarget;
}

export interface OrchestratorChildRunStart {
    childThreadId: EntityId<'thr'>;
    childSessionId: EntityId<'sess'>;
    runId: EntityId<'run'>;
}

function toSingleLine(value: string): string {
    return value
        .split('\n')
        .map((line) => line.trim())
        .filter((line) => line.length > 0)
        .join(' ');
}

function buildChildThreadTitle(step: OrchestratorStepRecord): string {
    const titleSource = toSingleLine(step.description);
    const titleSuffix = titleSource.length > 0 ? titleSource : 'Delegated worker task';
    const title = `Step ${String(step.sequence)}: ${titleSuffix}`;
    return title.length <= 88 ? title : `${title.slice(0, 85).trimEnd()}...`;
}

export function buildStepPrompt(plan: PlanRecord, step: OrchestratorStepRecord): string {
    return [
        `Execute step ${String(step.sequence)} from approved orchestrator plan.`,
        '',
        'Plan summary:',
        plan.summaryMarkdown,
        '',
        'Step task:',
        step.description,
    ].join('\n');
}

export async function resolveOrchestratorRootExecutionContext(input: {
    profileId: string;
    sessionId: EntityId<'sess'>;
}): Promise<OrchestratorRootExecutionContext | null> {
    const initialSessionThread = await threadStore.getBySessionId(input.profileId, input.sessionId);
    if (!initialSessionThread) {
        return null;
    }

    const bucket = await conversationStore.getBucketById(input.profileId, initialSessionThread.thread.conversationId);
    if (!bucket) {
        return null;
    }

    const executionTarget = await workspaceContextService.resolveForSession({
        profileId: input.profileId,
        sessionId: input.sessionId,
        topLevelTab: initialSessionThread.thread.topLevelTab,
        allowLazySandboxCreation: true,
    });
    if (!executionTarget || executionTarget.kind === 'detached') {
        return null;
    }
    if (executionTarget.kind === 'workspace' && executionTarget.executionEnvironmentMode === 'new_sandbox') {
        return null;
    }

    const refreshedSessionThread = await threadStore.getBySessionId(input.profileId, input.sessionId);
    if (!refreshedSessionThread) {
        return null;
    }

    return {
        bucket,
        rootThread: refreshedSessionThread.thread,
        executionTarget,
    };
}

function buildChildExecutionBinding(executionTarget: WorkspaceExecutionTarget): {
    executionEnvironmentMode: ThreadRecord['executionEnvironmentMode'];
    sessionKind: SessionSummaryRecord['kind'];
    sandboxId?: EntityId<'sb'>;
} {
    if (executionTarget.kind === 'sandbox') {
        return {
            executionEnvironmentMode: 'sandbox',
            sessionKind: 'sandbox',
            sandboxId: executionTarget.sandbox.id,
        };
    }

    return {
        executionEnvironmentMode: 'local',
        sessionKind: 'local',
    };
}

async function copyRootSessionAttachmentsToChildSession(input: {
    profileId: string;
    rootSessionId: EntityId<'sess'>;
    childSessionId: EntityId<'sess'>;
}): Promise<void> {
    const [attachedRules, attachedSkills] = await Promise.all([
        sessionAttachedRuleStore.listBySession(input.profileId, input.rootSessionId),
        sessionAttachedSkillStore.listBySession(input.profileId, input.rootSessionId),
    ]);

    await Promise.all([
        sessionAttachedRuleStore.replaceForSession({
            profileId: input.profileId,
            sessionId: input.childSessionId,
            assetKeys: attachedRules.map((attachedRule) => attachedRule.assetKey),
        }),
        sessionAttachedSkillStore.replaceForSession({
            profileId: input.profileId,
            sessionId: input.childSessionId,
            assetKeys: attachedSkills.map((attachedSkill) => attachedSkill.assetKey),
        }),
    ]);
}

async function appendDelegatedChildLaneEvents(input: {
    profileId: string;
    bucket: ConversationRecord;
    thread: ThreadRecord;
    session: SessionSummaryRecord;
}): Promise<void> {
    await runtimeEventLogService.append(
        runtimeUpsertEvent({
            entityType: 'thread',
            domain: 'thread',
            entityId: input.thread.id,
            eventType: 'conversation.thread.created',
            payload: {
                profileId: input.profileId,
                bucket: input.bucket,
                thread: input.thread,
            },
            ...eventMetadata({
                origin: 'runtime.orchestrator.delegateChildLane',
            }),
        })
    );

    await runtimeEventLogService.append(
        runtimeUpsertEvent({
            entityType: 'session',
            domain: 'session',
            entityId: input.session.id,
            eventType: 'session.created',
            payload: {
                session: input.session,
            },
            ...eventMetadata({
                origin: 'runtime.orchestrator.delegateChildLane',
            }),
        })
    );
}

export async function startDelegatedChildRun(input: {
    profileId: string;
    orchestratorRunId: EntityId<'orch'>;
    rootContext: OrchestratorRootExecutionContext;
    plan: PlanRecord;
    step: OrchestratorStepRecord;
    startInput: OrchestratorStartInput;
}): Promise<{ accepted: true; started: OrchestratorChildRunStart } | { accepted: false; reason: string }> {
    const childExecutionBinding = buildChildExecutionBinding(input.rootContext.executionTarget);
    const createdThread = await threadStore.create({
        profileId: input.profileId,
        conversationId: input.rootContext.bucket.id,
        title: buildChildThreadTitle(input.step),
        topLevelTab: 'agent',
        parentThreadId: input.rootContext.rootThread.id,
        rootThreadId: input.rootContext.rootThread.id,
        delegatedFromOrchestratorRunId: input.orchestratorRunId,
        executionEnvironmentMode: childExecutionBinding.executionEnvironmentMode,
        ...(childExecutionBinding.sandboxId ? { sandboxId: childExecutionBinding.sandboxId } : {}),
    });
    if (createdThread.isErr()) {
        return {
            accepted: false,
            reason: createdThread.error.message,
        };
    }

    const createdSession = await sessionStore.create(input.profileId, createdThread.value.id, childExecutionBinding.sessionKind, {
        delegatedFromOrchestratorRunId: input.orchestratorRunId,
    });
    if (!createdSession.created) {
        await threadStore.deleteDelegatedChildLane({
            profileId: input.profileId,
            threadId: parseEntityId(createdThread.value.id, 'threads.id', 'thr'),
            orchestratorRunId: input.orchestratorRunId,
        });
        return {
            accepted: false,
            reason: `Delegated child session could not be created: ${createdSession.reason}.`,
        };
    }

    await copyRootSessionAttachmentsToChildSession({
        profileId: input.profileId,
        rootSessionId: input.plan.sessionId,
        childSessionId: createdSession.session.id,
    });

    const startedRun = await runExecutionService.startRun({
        profileId: input.startInput.profileId,
        sessionId: createdSession.session.id,
        prompt: buildStepPrompt(input.plan, input.step),
        topLevelTab: 'agent',
        modeKey: 'code',
        runtimeOptions: input.startInput.runtimeOptions,
        ...(input.startInput.providerId ? { providerId: input.startInput.providerId } : {}),
        ...(input.startInput.modelId ? { modelId: input.startInput.modelId } : {}),
        ...(input.rootContext.bucket.workspaceFingerprint
            ? { workspaceFingerprint: input.rootContext.bucket.workspaceFingerprint }
            : {}),
    });

    if (!startedRun.accepted) {
        await threadStore.deleteDelegatedChildLane({
            profileId: input.profileId,
            threadId: parseEntityId(createdThread.value.id, 'threads.id', 'thr'),
            sessionId: createdSession.session.id,
            orchestratorRunId: input.orchestratorRunId,
        });
        return {
            accepted: false,
            reason: startedRun.reason,
        };
    }

    await appendDelegatedChildLaneEvents({
        profileId: input.profileId,
        bucket: input.rootContext.bucket,
        thread: createdThread.value,
        session: createdSession.session,
    });

    return {
        accepted: true,
        started: {
            childThreadId: parseEntityId(createdThread.value.id, 'threads.id', 'thr'),
            childSessionId: createdSession.session.id,
            runId: startedRun.runId,
        },
    };
}

export async function abortDelegatedChildRun(profileId: string, childSessionId: EntityId<'sess'>): Promise<void> {
    await runExecutionService.abortRun(profileId, childSessionId);
}

export async function waitForRunTerminal(runId: EntityId<'run'>): Promise<'completed' | 'aborted' | 'error'> {
    for (;;) {
        const run = await runStore.getById(runId);
        if (!run) {
            return 'error';
        }

        if (run.status === 'completed' || run.status === 'aborted' || run.status === 'error') {
            return run.status;
        }

        await new Promise((resolve) => setTimeout(resolve, 200));
    }
}

import { mkdtempSync, mkdirSync, rmSync, writeFileSync } from 'node:fs';
import os from 'node:os';
import path from 'node:path';

import { afterEach, describe, expect, it } from 'vitest';

import { resolveProjectInstructionDocuments } from '@/app/backend/runtime/services/projectInstructions/service';

describe('resolveProjectInstructionDocuments', () => {
    const temporaryRoots: string[] = [];

    afterEach(() => {
        for (const rootPath of temporaryRoots.splice(0)) {
            rmSync(rootPath, { recursive: true, force: true });
        }
    });

    it('loads AGENTS.md first, loads recursive .agents markdown files in sorted order, and strips frontmatter', async () => {
        const workspaceRoot = mkdtempSync(path.join(os.tmpdir(), 'nc-project-instructions-'));
        temporaryRoots.push(workspaceRoot);

        writeFileSync(
            path.join(workspaceRoot, 'AGENTS.md'),
            `---
title: ignored
---
# Primary Instructions

Use AGENTS first.
`,
            'utf8'
        );
        mkdirSync(path.join(workspaceRoot, '.agents', 'nested'), { recursive: true });
        writeFileSync(
            path.join(workspaceRoot, '.agents', 'z-last.md'),
            '# Z Last\n\nLoad after nested/a-first because of lexical sort.',
            'utf8'
        );
        writeFileSync(
            path.join(workspaceRoot, '.agents', 'nested', 'a-first.md'),
            `---
description: ignored
---
# A First

Nested content.
`,
            'utf8'
        );
        writeFileSync(path.join(workspaceRoot, '.agents', 'ignore.txt'), 'ignored', 'utf8');

        const documents = await resolveProjectInstructionDocuments({
            workspaceRootPath: workspaceRoot,
        });

        expect(documents.map((document) => document.displayPath)).toEqual([
            'AGENTS.md',
            '.agents/nested/a-first.md',
            '.agents/z-last.md',
        ]);
        expect(documents[0]?.bodyMarkdown).toBe('# Primary Instructions\n\nUse AGENTS first.');
        expect(documents[1]?.bodyMarkdown).toBe('# A First\n\nNested content.');
        expect(documents[2]?.bodyMarkdown).toBe('# Z Last\n\nLoad after nested/a-first because of lexical sort.');
    });

    it('returns an empty list when the workspace has no AGENTS inputs', async () => {
        const workspaceRoot = mkdtempSync(path.join(os.tmpdir(), 'nc-project-instructions-empty-'));
        temporaryRoots.push(workspaceRoot);

        const documents = await resolveProjectInstructionDocuments({
            workspaceRootPath: workspaceRoot,
        });

        expect(documents).toEqual([]);
    });
});

import { readdir } from 'node:fs/promises';
import path from 'node:path';

import { readRegistryMarkdownBody } from '@/app/backend/runtime/services/registry/filesystem';

export interface ProjectInstructionDocument {
    displayPath: string;
    bodyMarkdown: string;
}

async function listMarkdownFiles(rootPath: string, relativePrefix = ''): Promise<string[]> {
    let dirents: Array<{
        name: string;
        isDirectory: () => boolean;
        isFile: () => boolean;
    }>;
    try {
        dirents = (await readdir(rootPath, { withFileTypes: true, encoding: 'utf8' })).map((dirent) => ({
            name: String(dirent.name),
            isDirectory: () => dirent.isDirectory(),
            isFile: () => dirent.isFile(),
        }));
    } catch (error) {
        if (
            error instanceof Error &&
            'code' in error &&
            (error.code === 'ENOENT' || error.code === 'ENOTDIR')
        ) {
            return [];
        }
        throw error;
    }

    const relativePaths: string[] = [];
    for (const dirent of dirents) {
        const absolutePath = path.join(rootPath, dirent.name);
        const relativePath = relativePrefix.length > 0 ? path.join(relativePrefix, dirent.name) : dirent.name;
        if (dirent.isDirectory()) {
            relativePaths.push(...(await listMarkdownFiles(absolutePath, relativePath)));
            continue;
        }

        if (dirent.isFile() && path.extname(dirent.name).toLowerCase() === '.md') {
            relativePaths.push(relativePath.replace(/\\/g, '/'));
        }
    }

    return relativePaths.sort((leftPath, rightPath) => leftPath.localeCompare(rightPath));
}

async function readOptionalInstructionDocument(input: {
    absolutePath: string;
    displayPath: string;
}): Promise<ProjectInstructionDocument | undefined> {
    try {
        const bodyMarkdown = (await readRegistryMarkdownBody(input.absolutePath)).trim();
        if (bodyMarkdown.length === 0) {
            return undefined;
        }

        return {
            displayPath: input.displayPath,
            bodyMarkdown,
        };
    } catch (error) {
        if (
            error instanceof Error &&
            'code' in error &&
            (error.code === 'ENOENT' || error.code === 'ENOTDIR')
        ) {
            return undefined;
        }

        return undefined;
    }
}

export async function resolveProjectInstructionDocuments(input: {
    workspaceRootPath?: string;
}): Promise<ProjectInstructionDocument[]> {
    if (!input.workspaceRootPath) {
        return [];
    }

    const documents: ProjectInstructionDocument[] = [];
    const agentsDocument = await readOptionalInstructionDocument({
        absolutePath: path.join(input.workspaceRootPath, 'AGENTS.md'),
        displayPath: 'AGENTS.md',
    });
    if (agentsDocument) {
        documents.push(agentsDocument);
    }

    const agentsDirectoryPath = path.join(input.workspaceRootPath, '.agents');
    const relativePaths = await listMarkdownFiles(agentsDirectoryPath);
    const modularDocuments = await Promise.all(
        relativePaths.map(async (relativePath) =>
            readOptionalInstructionDocument({
                absolutePath: path.join(agentsDirectoryPath, relativePath),
                displayPath: `.agents/${relativePath}`,
            })
        )
    );
    for (const document of modularDocuments) {
        if (document) {
            documents.push(document);
        }
    }

    return documents;
}

import { access, mkdir, rename, unlink, writeFile } from 'node:fs/promises';
import path from 'node:path';

import type { ModeDefinitionRecord } from '@/app/backend/persistence/types';
import { slugifyAssetKey, resolveRegistryPaths } from '@/app/backend/runtime/services/registry/filesystem';

import { toolCapabilities as knownToolCapabilities, type ToolCapability, type TopLevelTab } from '@/app/backend/runtime/contracts';

export interface CanonicalCustomModePayload {
    slug: string;
    name: string;
    description?: string;
    roleDefinition?: string;
    customInstructions?: string;
    whenToUse?: string;
    tags?: string[];
    toolCapabilities?: ToolCapability[];
}

export interface PortableCustomModePayload {
    slug: string;
    name: string;
    description?: string;
    roleDefinition?: string;
    customInstructions?: string;
    whenToUse?: string;
    groups?: string[];
}

const portableModeAllowedKeys = new Set([
    'slug',
    'name',
    'description',
    'roleDefinition',
    'customInstructions',
    'whenToUse',
    'groups',
]);

const portableModeUnsupportedKeys = new Set(['topLevelTab']);

const portableGroupCapabilityMap = {
    read: ['filesystem_read'],
    edit: ['filesystem_read', 'filesystem_write'],
    command: ['shell'],
} as const satisfies Record<string, ToolCapability[]>;

const unsupportedPortableGroups = new Set(['browser', 'mcp', 'ask', 'modes']);

function readOptionalPortableString(
    value: unknown,
    field:
        | keyof PortableCustomModePayload
        | keyof CanonicalCustomModePayload
): string | undefined {
    if (value === undefined) {
        return undefined;
    }
    if (typeof value !== 'string') {
        throw new Error(`Invalid "${field}": expected string.`);
    }

    return value.trim().length > 0 ? value.replace(/\r\n?/g, '\n').trim() : undefined;
}

function readOptionalPortableStringArray(value: unknown, field: 'groups' | 'tags'): string[] | undefined {
    if (value === undefined) {
        return undefined;
    }
    if (!Array.isArray(value)) {
        throw new Error(`Invalid "${field}": expected string array.`);
    }

    const items = value.map((item, index) => {
        if (Array.isArray(item)) {
            throw new Error(`Unsupported "${field}[${String(index)}]": restricted tuple forms are not supported in this slice.`);
        }
        if (typeof item !== 'string') {
            throw new Error(`Invalid "${field}": expected string array.`);
        }

        return item.trim();
    });
    const filteredItems = items.filter((item) => item.length > 0);
    return filteredItems.length > 0 ? Array.from(new Set(filteredItems)) : undefined;
}

function readOptionalToolCapabilities(value: unknown, field: 'toolCapabilities'): ToolCapability[] | undefined {
    if (value === undefined) {
        return undefined;
    }
    if (!Array.isArray(value)) {
        throw new Error(`Invalid "${field}": expected string array.`);
    }

    const capabilities = value.map((item) => {
        if (typeof item !== 'string' || !knownToolCapabilities.includes(item as ToolCapability)) {
            throw new Error(`Invalid "${field}": expected only ${knownToolCapabilities.join(', ')}.`);
        }

        return item as ToolCapability;
    });
    return capabilities.length > 0 ? Array.from(new Set(capabilities)) : undefined;
}

function normalizeCanonicalCustomModePayload(input: CanonicalCustomModePayload): CanonicalCustomModePayload {
    const slug = readOptionalPortableString(input.slug, 'slug');
    if (!slug) {
        throw new Error('Invalid "slug": expected non-empty string.');
    }
    const name = readOptionalPortableString(input.name, 'name');
    if (!name) {
        throw new Error('Invalid "name": expected non-empty string.');
    }

    const description = readOptionalPortableString(input.description, 'description');
    const roleDefinition = readOptionalPortableString(input.roleDefinition, 'roleDefinition');
    const customInstructions = readOptionalPortableString(input.customInstructions, 'customInstructions');
    const whenToUse = readOptionalPortableString(input.whenToUse, 'whenToUse');
    const tags = readOptionalPortableStringArray(input.tags, 'tags');
    const toolCapabilities = readOptionalToolCapabilities(input.toolCapabilities, 'toolCapabilities');

    return {
        slug,
        name,
        ...(description ? { description } : {}),
        ...(roleDefinition ? { roleDefinition } : {}),
        ...(customInstructions ? { customInstructions } : {}),
        ...(whenToUse ? { whenToUse } : {}),
        ...(tags ? { tags } : {}),
        ...(toolCapabilities ? { toolCapabilities } : {}),
    };
}

function normalizePortableCustomModePayload(input: PortableCustomModePayload): PortableCustomModePayload {
    const slug = readOptionalPortableString(input.slug, 'slug');
    if (!slug) {
        throw new Error('Invalid "slug": expected non-empty string.');
    }
    const name = readOptionalPortableString(input.name, 'name');
    if (!name) {
        throw new Error('Invalid "name": expected non-empty string.');
    }

    const description = readOptionalPortableString(input.description, 'description');
    const roleDefinition = readOptionalPortableString(input.roleDefinition, 'roleDefinition');
    const customInstructions = readOptionalPortableString(input.customInstructions, 'customInstructions');
    const whenToUse = readOptionalPortableString(input.whenToUse, 'whenToUse');
    const groups = readOptionalPortableStringArray(input.groups, 'groups');

    return {
        slug,
        name,
        ...(description ? { description } : {}),
        ...(roleDefinition ? { roleDefinition } : {}),
        ...(customInstructions ? { customInstructions } : {}),
        ...(whenToUse ? { whenToUse } : {}),
        ...(groups ? { groups } : {}),
    };
}

function convertPortableGroupsToToolCapabilities(groups: string[] | undefined): ToolCapability[] | undefined {
    if (!groups || groups.length === 0) {
        return undefined;
    }

    const capabilities = new Set<ToolCapability>();
    for (const group of groups) {
        if (unsupportedPortableGroups.has(group)) {
            throw new Error(`Unsupported portable tool group "${group}".`);
        }
        const mappedCapabilities = portableGroupCapabilityMap[group as keyof typeof portableGroupCapabilityMap];
        if (!mappedCapabilities) {
            throw new Error(`Unsupported portable tool group "${group}".`);
        }

        mappedCapabilities.forEach((capability) => capabilities.add(capability));
    }

    return capabilities.size > 0 ? Array.from(capabilities) : undefined;
}

function convertToolCapabilitiesToPortableGroups(toolCapabilities: ToolCapability[] | undefined): string[] | undefined {
    if (!toolCapabilities || toolCapabilities.length === 0) {
        return undefined;
    }

    const capabilitySet = new Set(toolCapabilities);
    if (capabilitySet.has('git')) {
        throw new Error('Portable export does not support the "git" tool capability in this slice.');
    }
    if (capabilitySet.has('filesystem_write') && !capabilitySet.has('filesystem_read')) {
        throw new Error('Portable export cannot represent "filesystem_write" without "filesystem_read".');
    }

    const groups: string[] = [];
    if (capabilitySet.has('filesystem_write')) {
        groups.push('edit');
        capabilitySet.delete('filesystem_write');
        capabilitySet.delete('filesystem_read');
    } else if (capabilitySet.has('filesystem_read')) {
        groups.push('read');
        capabilitySet.delete('filesystem_read');
    }
    if (capabilitySet.has('shell')) {
        groups.push('command');
        capabilitySet.delete('shell');
    }
    if (capabilitySet.size > 0) {
        throw new Error(`Portable export cannot represent tool capabilities: ${Array.from(capabilitySet).join(', ')}.`);
    }

    return groups.length > 0 ? groups : undefined;
}

export function parsePortableCustomModeJson(jsonText: string): PortableCustomModePayload {
    let parsed: unknown;
    try {
        parsed = JSON.parse(jsonText);
    } catch (error) {
        throw new Error(`Invalid custom mode JSON: ${(error as Error).message}`);
    }

    if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
        throw new Error('Invalid custom mode JSON: expected object.');
    }

    const source = parsed as Record<string, unknown>;
    for (const key of Object.keys(source)) {
        if (portableModeUnsupportedKeys.has(key)) {
            throw new Error(`Unsupported custom mode field "${key}" is not supported in this slice.`);
        }
        if (!portableModeAllowedKeys.has(key)) {
            throw new Error(`Invalid custom mode field "${key}".`);
        }
    }

    return normalizePortableCustomModePayload({
        slug: source.slug as string,
        name: source.name as string,
        ...(typeof source.description === 'string' ? { description: source.description } : {}),
        ...(typeof source.roleDefinition === 'string' ? { roleDefinition: source.roleDefinition } : {}),
        ...(typeof source.customInstructions === 'string' ? { customInstructions: source.customInstructions } : {}),
        ...(typeof source.whenToUse === 'string' ? { whenToUse: source.whenToUse } : {}),
        ...(source.groups !== undefined ? { groups: source.groups as string[] } : {}),
    });
}

export function toCanonicalCustomModePayload(input: PortableCustomModePayload): CanonicalCustomModePayload {
    const payload = normalizePortableCustomModePayload(input);
    const toolCapabilities = convertPortableGroupsToToolCapabilities(payload.groups);

    return normalizeCanonicalCustomModePayload({
        slug: payload.slug,
        name: payload.name,
        ...(payload.description ? { description: payload.description } : {}),
        ...(payload.roleDefinition ? { roleDefinition: payload.roleDefinition } : {}),
        ...(payload.customInstructions ? { customInstructions: payload.customInstructions } : {}),
        ...(payload.whenToUse ? { whenToUse: payload.whenToUse } : {}),
        ...(toolCapabilities ? { toolCapabilities } : {}),
    });
}

export function toPortableModePayload(mode: ModeDefinitionRecord): PortableCustomModePayload {
    const groups = convertToolCapabilitiesToPortableGroups(mode.executionPolicy.toolCapabilities);

    return normalizePortableCustomModePayload({
        slug: mode.modeKey,
        name: mode.label,
        ...(mode.description ? { description: mode.description } : {}),
        ...(mode.prompt.roleDefinition ? { roleDefinition: mode.prompt.roleDefinition } : {}),
        ...(mode.prompt.customInstructions ? { customInstructions: mode.prompt.customInstructions } : {}),
        ...(mode.whenToUse ? { whenToUse: mode.whenToUse } : {}),
        ...(groups ? { groups } : {}),
    });
}

export function buildCanonicalCustomModePayload(input: CanonicalCustomModePayload): CanonicalCustomModePayload {
    return normalizeCanonicalCustomModePayload(input);
}

function stringifyFrontmatterValue(value: string): string {
    return JSON.stringify(value.replace(/\r\n?/g, '\n'));
}

export function renderCanonicalModeMarkdown(input: {
    topLevelTab: TopLevelTab;
    payload: CanonicalCustomModePayload;
}): { modeKey: string; fileContent: string } {
    const payload = normalizeCanonicalCustomModePayload(input.payload);
    const modeKey = slugifyAssetKey(payload.slug).replace(/\//g, '_');
    if (modeKey.length === 0) {
        throw new Error('Invalid "slug": could not derive a file-backed mode key.');
    }

    const lines = [
        '---',
        `topLevelTab: ${input.topLevelTab}`,
        `modeKey: ${modeKey}`,
        `label: ${stringifyFrontmatterValue(payload.name)}`,
        ...(payload.description
            ? [`description: ${stringifyFrontmatterValue(payload.description)}`]
            : []),
        ...(payload.whenToUse ? [`whenToUse: ${stringifyFrontmatterValue(payload.whenToUse)}`] : []),
        ...(payload.tags ? ['tags:', ...payload.tags.map((tag) => `  - ${stringifyFrontmatterValue(tag)}`)] : []),
        ...(payload.toolCapabilities
            ? ['toolCapabilities:', ...payload.toolCapabilities.map((capability) => `  - ${capability}`)]
            : []),
        ...(payload.roleDefinition
            ? [`roleDefinition: ${stringifyFrontmatterValue(payload.roleDefinition)}`]
            : []),
        '---',
    ];
    const body = payload.customInstructions?.replace(/\r\n?/g, '\n').trim() ?? '';

    return {
        modeKey,
        fileContent: body.length > 0 ? `${lines.join('\n')}\n${body}\n` : `${lines.join('\n')}\n`,
    };
}

export async function resolveCustomModeDirectory(input: {
    profileId: string;
    scope: 'global' | 'workspace';
    workspaceFingerprint?: string;
}): Promise<string> {
    const paths = await resolveRegistryPaths({
        profileId: input.profileId,
        ...(input.workspaceFingerprint ? { workspaceFingerprint: input.workspaceFingerprint } : {}),
    });

    if (input.scope === 'workspace') {
        if (!paths.workspaceAssetsRoot || !input.workspaceFingerprint) {
            throw new Error('Workspace mode import requires a selected workspace.');
        }

        const directory = path.join(paths.workspaceAssetsRoot, 'modes');
        await mkdir(directory, { recursive: true });
        return directory;
    }

    const directory = path.join(paths.globalAssetsRoot, 'modes');
    await mkdir(directory, { recursive: true });
    return directory;
}

export async function writePortableModeFile(input: {
    absolutePath: string;
    fileContent: string;
}): Promise<void> {
    const directory = path.dirname(input.absolutePath);
    await mkdir(directory, { recursive: true });
    const tempPath = `${input.absolutePath}.tmp`;
    await writeFile(tempPath, input.fileContent, 'utf8');
    await rename(tempPath, input.absolutePath);
}

export async function deletePortableModeFile(absolutePath: string): Promise<void> {
    await unlink(absolutePath);
}

export async function fileExists(absolutePath: string): Promise<boolean> {
    try {
        await access(absolutePath);
        return true;
    } catch {
        return false;
    }
}

