describe('resolveKiloModeHeader', () => {
    it.each([
        ['agent', 'ask', 'ask'],
        ['agent', 'code', 'code'],
        ['agent', 'debug', 'debug'],
        ['chat', 'chat', 'general'],
        ['orchestrator', 'orchestrate', 'orchestrator'],
        ['orchestrator', 'debug', 'debug'],
    ] as const)('maps %s/%s to %s', (topLevelTab, modeKey, expected) => {
        expect(resolveKiloModeHeader(createMode(topLevelTab, modeKey))).toBe(expected);
    });

    it('returns undefined for modes outside the Kilo mode-header contract', () => {
        expect(resolveKiloModeHeader(createMode('agent', 'plan'))).toBeUndefined();
    });
});

import type { ModeDefinition } from '@/app/backend/runtime/contracts';
import type { KiloModeHeader } from '@/shared/kiloModels';

export function resolveKiloModeHeader(mode: ModeDefinition): KiloModeHeader | undefined {
    if (mode.topLevelTab === 'chat' && mode.modeKey === 'chat') {
        return 'general';
    }

    if (mode.topLevelTab === 'agent') {
        if (mode.modeKey === 'ask' || mode.modeKey === 'code' || mode.modeKey === 'debug') {
            return mode.modeKey;
        }

        return undefined;
    }

    if (mode.topLevelTab === 'orchestrator') {
        if (mode.modeKey === 'orchestrate') {
            return 'orchestrator';
        }
        if (mode.modeKey === 'debug') {
            return 'debug';
        }
    }

    return undefined;
}

