import { beforeEach, describe, expect, it, vi } from 'vitest';

import { kiloFrontierModelId } from '@/shared/kiloModels';

const providerStoreMock = vi.hoisted(() => ({
    getDefaults: vi.fn(),
    getSpecialistDefaults: vi.fn(),
    modelExists: vi.fn(),
}));

vi.mock('@/app/backend/persistence/stores', () => ({
    providerStore: providerStoreMock,
}));

import {
    resolveRequestedOrDefaultRunTarget,
    verifyResolvedRunTargetAvailability,
} from '@/app/backend/runtime/services/runExecution/resolveRunTarget';

describe('resolveRunTarget boundaries', () => {
    beforeEach(() => {
        vi.clearAllMocks();
        providerStoreMock.getDefaults.mockResolvedValue({
            providerId: 'openai',
            modelId: 'openai/gpt-5',
        });
        providerStoreMock.getSpecialistDefaults.mockResolvedValue([]);
    });

    it('fails closed when a verified explicit model is unavailable for the provider', async () => {
        providerStoreMock.modelExists.mockResolvedValue(false);

        const resolvedTarget = await resolveRequestedOrDefaultRunTarget({
            profileId: 'profile_default',
            providerId: 'openai',
            modelId: 'openai/gpt-missing',
        });
        expect(resolvedTarget.isOk()).toBe(true);
        if (resolvedTarget.isErr()) {
            throw new Error(resolvedTarget.error.message);
        }

        const result = await verifyResolvedRunTargetAvailability({
            profileId: 'profile_default',
            target: resolvedTarget.value,
        });

        expect(result.isErr()).toBe(true);
        if (result.isOk()) {
            throw new Error('Expected explicit unavailable model to be rejected.');
        }
        expect(result.error.code).toBe('provider_model_not_available');
        expect(result.error.message).toContain('openai/gpt-missing');
    });

    it('uses the saved default only when the caller omitted both provider and model', async () => {
        const result = await resolveRequestedOrDefaultRunTarget({
            profileId: 'profile_default',
        });

        expect(result.isOk()).toBe(true);
        if (result.isErr()) {
            throw new Error(result.error.message);
        }
        expect(result.value).toEqual({
            providerId: 'openai',
            modelId: 'openai/gpt-5',
        });
    });

    it('prefers the matching specialist default over the shared fallback for runnable presets', async () => {
        providerStoreMock.getSpecialistDefaults.mockResolvedValue([
            {
                topLevelTab: 'agent',
                modeKey: 'code',
                providerId: 'kilo',
                modelId: kiloFrontierModelId,
            },
        ]);
        const result = await resolveRequestedOrDefaultRunTarget({
            profileId: 'profile_default',
            topLevelTab: 'agent',
            modeKey: 'code',
        });

        expect(result.isOk()).toBe(true);
        if (result.isErr()) {
            throw new Error(result.error.message);
        }
        expect(result.value).toEqual({
            providerId: 'kilo',
            modelId: kiloFrontierModelId,
        });
    });

    it('does not depend on shared-default lookup when the caller provides an explicit target', async () => {
        const result = await resolveRequestedOrDefaultRunTarget({
            profileId: 'profile_default',
            providerId: 'openai',
            modelId: 'openai/gpt-5',
        });

        expect(result.isOk()).toBe(true);
        if (result.isErr()) {
            throw new Error(result.error.message);
        }
        expect(providerStoreMock.getDefaults).not.toHaveBeenCalled();
        expect(providerStoreMock.getSpecialistDefaults).not.toHaveBeenCalled();
        expect(result.value).toEqual({
            providerId: 'openai',
            modelId: 'openai/gpt-5',
        });
    });
});

import { providerStore } from '@/app/backend/persistence/stores';
import { toSupportedProviderIdResult } from '@/app/backend/providers/registry';
import {
    findProviderSpecialistDefault,
    isSupportedProviderSpecialistDefaultTarget,
    type RuntimeProviderId,
    type TopLevelTab,
} from '@/app/backend/runtime/contracts';
import {
    errRunExecution,
    okRunExecution,
    type RunExecutionResult,
} from '@/app/backend/runtime/services/runExecution/errors';
import type { ResolvedRunTarget } from '@/app/backend/runtime/services/runExecution/types';
import { canonicalizeProviderModelId } from '@/shared/kiloModels';

function tryAssertProviderId(value: string): RuntimeProviderId | undefined {
    const supportedProviderIdResult = toSupportedProviderIdResult(value);
    if (supportedProviderIdResult.isErr()) {
        return undefined;
    }

    return supportedProviderIdResult.value;
}

export async function resolveRequestedOrDefaultRunTarget(input: {
    profileId: string;
    providerId?: string;
    modelId?: string;
    topLevelTab?: TopLevelTab;
    modeKey?: string;
}): Promise<RunExecutionResult<ResolvedRunTarget>> {
    let providerId: RuntimeProviderId | undefined;
    if (input.providerId) {
        const assertedProviderId = tryAssertProviderId(input.providerId);
        if (!assertedProviderId) {
            return errRunExecution('provider_not_supported', `Provider "${input.providerId}" is not supported.`);
        }
        providerId = assertedProviderId;
    }

    let modelId = input.modelId;
    if (!providerId && modelId) {
        const inferredProviderToken = modelId.split('/')[0] ?? '';
        const inferredProviderId = tryAssertProviderId(inferredProviderToken);
        if (!inferredProviderId) {
            return errRunExecution('provider_not_supported', `Provider "${inferredProviderToken}" is not supported.`);
        }
        providerId = inferredProviderId;
    }

    if (providerId && modelId) {
        return okRunExecution({
            providerId,
            modelId: canonicalizeProviderModelId(providerId, modelId),
        });
    }

    const [defaults, specialistDefaults] = await Promise.all([
        providerStore.getDefaults(input.profileId),
        providerStore.getSpecialistDefaults(input.profileId),
    ]);

    const specialistTarget =
        input.topLevelTab && input.modeKey
            ? {
                  topLevelTab: input.topLevelTab,
                  modeKey: input.modeKey,
              }
            : undefined;
    const specialistDefault =
        specialistTarget && isSupportedProviderSpecialistDefaultTarget(specialistTarget)
            ? findProviderSpecialistDefault(specialistDefaults, specialistTarget)
            : undefined;

    const defaultProviderId = specialistDefault?.providerId ?? defaults.providerId;
    providerId = tryAssertProviderId(defaultProviderId);
    if (!providerId) {
        return errRunExecution('provider_not_supported', `Provider "${defaultProviderId}" is not supported.`);
    }

    const defaultModelId =
        specialistDefault?.providerId === providerId && specialistDefault.modelId.trim().length > 0
            ? specialistDefault.modelId
            : defaults.providerId === providerId && defaults.modelId.trim().length > 0
              ? defaults.modelId
              : '';

    if (defaultModelId.trim().length === 0) {
        return errRunExecution('provider_model_missing', 'No explicit provider/model target could be resolved.');
    }

    return okRunExecution({
        providerId,
        modelId: canonicalizeProviderModelId(providerId, defaultModelId),
    });
}

export async function verifyResolvedRunTargetAvailability(input: {
    profileId: string;
    target: ResolvedRunTarget;
}): Promise<RunExecutionResult<ResolvedRunTarget>> {
    const modelExists = await providerStore.modelExists(input.profileId, input.target.providerId, input.target.modelId);
    if (!modelExists) {
        return errRunExecution(
            'provider_model_not_available',
            `Model "${input.target.modelId}" is not available for provider "${input.target.providerId}".`
        );
    }

    return okRunExecution(input.target);
}

import { providerStore } from '@/app/backend/persistence/stores';
import { providerIds } from '@/app/backend/runtime/contracts';
import type {
    ComposerImageAttachmentInput,
    ModeDefinition,
    RuntimeRunOptions,
    TopLevelTab,
} from '@/app/backend/runtime/contracts';
import { errRunExecution, okRunExecution, type RunExecutionResult } from '@/app/backend/runtime/services/runExecution/errors';
import { prepareRunnableCandidate } from '@/app/backend/runtime/services/runExecution/compatibility';
import type { PreparedRunnableCandidate, ResolvedRunTarget } from '@/app/backend/runtime/services/runExecution/types';

interface ResolveRunnableRunTargetInput {
    profileId: string;
    topLevelTab: TopLevelTab;
    mode: ModeDefinition;
    runtimeOptions: RuntimeRunOptions;
    attachments?: ComposerImageAttachmentInput[];
    preferredTarget?: ResolvedRunTarget;
}

async function* enumerateRunTargetCandidates(input: ResolveRunnableRunTargetInput): AsyncGenerator<ResolvedRunTarget> {
    if (input.preferredTarget) {
        yield input.preferredTarget;
    }

    for (const providerId of providerIds) {
        const models = await providerStore.listModels(input.profileId, providerId);
        for (const model of models) {
            if (
                input.preferredTarget &&
                input.preferredTarget.providerId === providerId &&
                input.preferredTarget.modelId === model.id
            ) {
                continue;
            }

            yield {
                providerId,
                modelId: model.id,
            };
        }
    }
}

export async function resolveFirstRunnableRunTarget(
    input: ResolveRunnableRunTargetInput
): Promise<RunExecutionResult<PreparedRunnableCandidate | null>> {
    for await (const candidateTarget of enumerateRunTargetCandidates(input)) {
        const preparedCandidateResult = await prepareRunnableCandidate({
            profileId: input.profileId,
            providerId: candidateTarget.providerId,
            modelId: candidateTarget.modelId,
            topLevelTab: input.topLevelTab,
            mode: input.mode,
            runtimeOptions: input.runtimeOptions,
            ...(input.attachments ? { attachments: input.attachments } : {}),
        });
        if (preparedCandidateResult.isErr()) {
            return errRunExecution(preparedCandidateResult.error.code, preparedCandidateResult.error.message, {
                ...(preparedCandidateResult.error.action ? { action: preparedCandidateResult.error.action } : {}),
            });
        }

        if (preparedCandidateResult.value.kind === 'prepared') {
            return okRunExecution(preparedCandidateResult.value.candidate);
        }
    }

    return okRunExecution(null);
}

