                    };

                    if (signal?.aborted) {
                        rejectAbort();
                        return;
                    }

                    signal?.addEventListener('abort', rejectAbort, { once: true });
                    pendingFetchResolvers.push(() => {
                        resolve({
                            ok: true,
                            status: 200,
                            statusText: 'OK',
                            json: () => ({
                                choices: [
                                    {
                                        message: {
                                            content: 'Parallel child completed before abort.',
                                        },
                                    },
                                ],
                                usage: {
                                    prompt_tokens: 8,
                                    completion_tokens: 10,
                                    total_tokens: 18,
                                },
                            }),
