                                        output_modalities: ['text'],
                                    },
                                    opencode: {
                                        prompt: 'anthropic',
                                    },
                                    pricing: {},
                                },
                            ],
                        }),
                    });
                }

                if (url.endsWith('/providers')) {
                    return Promise.resolve({
                        ok: true,
                        status: 200,
                        statusText: 'OK',
                        json: () => ({
                            data: [
                                { id: 'anthropic', label: 'Anthropic' },
                                { id: 'openai', label: 'OpenAI' },
                            ],
                        }),
                    });
                }

                if (url.endsWith('/models-by-provider')) {
                    return Promise.resolve({
                        ok: true,
                        status: 200,
                        statusText: 'OK',
                        json: () => ({
