import { observable } from '@trpc/server/observable';

import type { RuntimeEventRecordV1 } from '@/app/backend/persistence/types';
import { workspaceRootStore } from '@/app/backend/persistence/stores';
import {
    neonObservabilitySubscriptionInputSchema,
    runtimeInspectWorkspaceEnvironmentInputSchema,
    type NeonObservabilitySubscriptionInput,
    type NeonObservabilityEvent,
    profileInputSchema,
    runtimeFactoryResetInputSchema,
    type RuntimeInspectWorkspaceEnvironmentInput,
    runtimeEventsSubscriptionInputSchema,
    runtimeRegisterWorkspaceRootInputSchema,
    runtimeResetInputSchema,
    runtimeSetWorkspacePreferenceInputSchema,
} from '@/app/backend/runtime/contracts';
import { runtimeEventBus } from '@/app/backend/runtime/services/runtimeEventBus';
import { runtimeResetEvent } from '@/app/backend/runtime/services/runtimeEventEnvelope';
import { runtimeEventLogService } from '@/app/backend/runtime/services/runtimeEventLog';
import {
    findRegisteredWorkspaceFingerprintByPath,
    workspaceEnvironmentService,
} from '@/app/backend/runtime/services/environment/service';
import { neonObservabilityService } from '@/app/backend/runtime/services/observability/service';
import { runtimeFactoryResetService } from '@/app/backend/runtime/services/runtimeFactoryReset';
import { runtimeResetService } from '@/app/backend/runtime/services/runtimeReset';
import { runtimeShellBootstrapService } from '@/app/backend/runtime/services/runtimeShellBootstrap';
import { runtimeSnapshotService } from '@/app/backend/runtime/services/runtimeSnapshot';
import {
    getWorkspacePreference,
    setWorkspacePreference,
} from '@/app/backend/runtime/services/workspace/preferences';
import { publicProcedure, router } from '@/app/backend/trpc/init';
import { raiseMappedTrpcError, toTrpcError } from '@/app/backend/trpc/trpcErrorMap';

function waitForNextRuntimeEvent(cursor: number, signal: AbortSignal): Promise<RuntimeEventRecordV1 | null> {
    return new Promise((resolve) => {
        const unsubscribe = runtimeEventBus.subscribe((event) => {
            if (event.sequence <= cursor) {
                return;
            }

            cleanup();
            resolve(event);
        });

        const onAbort = () => {
            cleanup();
            resolve(null);
        };

        const cleanup = () => {
            unsubscribe();
            signal.removeEventListener('abort', onAbort);
        };

        signal.addEventListener('abort', onAbort, { once: true });
    });
}

function waitForNextNeonObservabilityEvent(
    cursor: number,
    filter: Pick<NeonObservabilitySubscriptionInput, 'profileId' | 'sessionId' | 'runId'>,
    signal: AbortSignal
): Promise<NeonObservabilityEvent | null> {
    return new Promise((resolve) => {
        const unsubscribe = neonObservabilityService.subscribe((event) => {
            if (event.sequence <= cursor) {
                return;
            }

            cleanup();
            resolve(event);
        }, filter);

        const onAbort = () => {
            cleanup();
            resolve(null);
        };

        const cleanup = () => {
            unsubscribe();
            signal.removeEventListener('abort', onAbort);
        };

        signal.addEventListener('abort', onAbort, { once: true });
    });
}

async function inspectWorkspaceEnvironment(
    input: RuntimeInspectWorkspaceEnvironmentInput
) {
    const workspaceRoots = await workspaceRootStore.listByProfile(input.profileId);
    const resolvedFingerprint =
        'workspaceFingerprint' in input
            ? input.workspaceFingerprint
            : findRegisteredWorkspaceFingerprintByPath({
                  absolutePath: input.absolutePath,
                  workspaceRoots,
              });
    const resolvedWorkspaceRoot =
        resolvedFingerprint
            ? workspaceRoots.find((workspaceRoot) => workspaceRoot.fingerprint === resolvedFingerprint)
            : undefined;

    if ('workspaceFingerprint' in input && !resolvedWorkspaceRoot) {
        throw raiseMappedTrpcError(
            {
                code: 'not_found',
                message: `Workspace "${input.workspaceFingerprint}" was not found.`,
            },
            toTrpcError
        );
    }

    const workspacePreference = resolvedFingerprint
        ? await getWorkspacePreference(input.profileId, resolvedFingerprint)
        : undefined;
    const workspaceRootPath =
        resolvedWorkspaceRoot?.absolutePath ??
        ('absolutePath' in input ? input.absolutePath : undefined);

    if (!workspaceRootPath) {
        throw raiseMappedTrpcError(
            {
                code: 'not_found',
                message: 'Workspace path could not be resolved for environment inspection.',
            },
            toTrpcError
        );
    }

    const inspectionResult = await workspaceEnvironmentService.inspectWorkspaceEnvironment({
        workspaceRootPath,
        ...(workspacePreference
            ? {
                  overrides: {
                      ...(workspacePreference.preferredVcs
                          ? { preferredVcs: workspacePreference.preferredVcs }
                          : {}),
                      ...(workspacePreference.preferredPackageManager
                          ? { preferredPackageManager: workspacePreference.preferredPackageManager }
                          : {}),
                  },
              }
            : {}),
    });

    return inspectionResult.match(
        (snapshot) => ({
            snapshot,
        }),
        (error) => raiseMappedTrpcError(error, toTrpcError)
    );
}

export const runtimeRouter = router({
    // Diagnostic-only whole-runtime inspection. Normal app rendering should use scoped reads.
    getDiagnosticSnapshot: publicProcedure.input(profileInputSchema).query(async ({ input }) => {
        return (await runtimeSnapshotService.getSnapshot(input.profileId)).match(
            (value) => value,
            (error) => raiseMappedTrpcError(error, toTrpcError)
        );
    }),
    getShellBootstrap: publicProcedure.input(profileInputSchema).query(async ({ input }) => {
        return runtimeShellBootstrapService.getShellBootstrap(input.profileId);
    }),
    inspectWorkspaceEnvironment: publicProcedure
        .input(runtimeInspectWorkspaceEnvironmentInputSchema)
        .query(async ({ input }) => {
            return await inspectWorkspaceEnvironment(input);
        }),
    listWorkspaceRoots: publicProcedure.input(profileInputSchema).query(async ({ input }) => {
        const shellBootstrap = await runtimeShellBootstrapService.getShellBootstrap(input.profileId);
        return {
            workspaceRoots: shellBootstrap.workspaceRoots,
        };
    }),
    registerWorkspaceRoot: publicProcedure.input(runtimeRegisterWorkspaceRootInputSchema).mutation(async ({ input }) => {
        const workspaceRoot = await workspaceRootStore.resolveOrCreate(
            input.profileId,
            input.absolutePath,
            input.label
        );

        return {
            workspaceRoot,
        };
    }),
    setWorkspacePreference: publicProcedure.input(runtimeSetWorkspacePreferenceInputSchema).mutation(async ({ input }) => {
        const workspacePreference = (await setWorkspacePreference(input)).match(
            (value) => value,
            (error) => raiseMappedTrpcError(error, toTrpcError)
        );
        return {
            workspacePreference,
        };
    }),
    subscribeEvents: publicProcedure.input(runtimeEventsSubscriptionInputSchema).subscription(({ input, signal }) =>
        observable<RuntimeEventRecordV1>((emit) => {
            let active = true;
            let unsubscribeAbort: (() => void) | null = null;

            const run = async () => {
                let cursor = input.afterSequence ?? 0;
                try {
                    const replayEvents = await runtimeEventLogService.getEvents(cursor, 500);
                    for (const event of replayEvents) {
                        if (!active || signal?.aborted) {
                            return;
                        }

                        cursor = Math.max(cursor, event.sequence);
                        emit.next(event);
                    }

                    if (!signal) {
                        return;
                    }

                    const onAbort = () => {
                        active = false;
                        emit.complete();
                    };
                    signal.addEventListener('abort', onAbort, { once: true });
                    unsubscribeAbort = () => {
                        signal.removeEventListener('abort', onAbort);
                    };

                    while (active && !signal.aborted) {
                        const nextEvent = await waitForNextRuntimeEvent(cursor, signal);
                        if (!active || !nextEvent) {
                            break;
                        }

                        cursor = Math.max(cursor, nextEvent.sequence);
                        emit.next(nextEvent);
                    }
                } catch (error) {
                    emit.error(error instanceof Error ? error : new Error('Runtime event subscription failed.'));
                    return;
                }

                emit.complete();
            };

            void run();

            return () => {
                active = false;
                unsubscribeAbort?.();
            };
        })
    ),
    subscribeObservability: publicProcedure
        .input(neonObservabilitySubscriptionInputSchema)
        .subscription(({ input, signal }) =>
            observable<NeonObservabilityEvent>((emit) => {
                if (!neonObservabilityService.isEnabled()) {
                    emit.complete();
                    return () => undefined;
                }

                let active = true;
                let unsubscribeAbort: (() => void) | null = null;

                const run = async () => {
                    let cursor = input.afterSequence ?? 0;
                    try {
                        const replayEvents = neonObservabilityService.list(input, 500);
                        for (const event of replayEvents) {
                            if (!active || signal?.aborted) {
                                return;
                            }

                            cursor = Math.max(cursor, event.sequence);
                            emit.next(event);
                        }

                        if (!signal) {
                            return;
                        }

                        const onAbort = () => {
                            active = false;
                            emit.complete();
                        };
                        signal.addEventListener('abort', onAbort, { once: true });
                        unsubscribeAbort = () => {
                            signal.removeEventListener('abort', onAbort);
                        };

                        while (active && !signal.aborted) {
                            const filter: Pick<NeonObservabilitySubscriptionInput, 'profileId' | 'sessionId' | 'runId'> = {};
                            if (input.profileId) {
                                filter.profileId = input.profileId;
                            }
                            if (input.sessionId) {
                                filter.sessionId = input.sessionId;
                            }
                            if (input.runId) {
                                filter.runId = input.runId;
                            }

                            const nextEvent = await waitForNextNeonObservabilityEvent(
                                cursor,
                                filter,
                                signal
                            );
                            if (!active || !nextEvent) {
                                break;
                            }

                            cursor = Math.max(cursor, nextEvent.sequence);
                            emit.next(nextEvent);
                        }
                    } catch (error) {
                        emit.error(error instanceof Error ? error : new Error('Neon observability subscription failed.'));
                        return;
                    }

                    emit.complete();
                };

                void run();

                return () => {
                    active = false;
                    unsubscribeAbort?.();
                };
            })
        ),
    factoryReset: publicProcedure.input(runtimeFactoryResetInputSchema).mutation(async ({ input }) => {
        const factoryResetResult = (await runtimeFactoryResetService.reset(input)).match(
            (value) => value,
            (error) => raiseMappedTrpcError(error, toTrpcError)
        );
        await runtimeEventLogService.append(
            runtimeResetEvent({
                entityType: 'runtime',
                domain: 'runtime',
                entityId: 'runtime',
                eventType: 'runtime.reset.applied',
                payload: {
                    target: 'full',
                    counts: factoryResetResult.counts,
                    dryRun: false,
                    profileId: factoryResetResult.resetProfileId,
                    workspaceFingerprint: null,
                },
            })
        );

        return factoryResetResult;
    }),
    reset: publicProcedure.input(runtimeResetInputSchema).mutation(async ({ input }) => {
        const resetResult = (await runtimeResetService.reset(input)).match(
            (value) => value,
            (error) => raiseMappedTrpcError(error, toTrpcError)
        );

        if (resetResult.applied) {
            await runtimeEventLogService.append(
                runtimeResetEvent({
                entityType: 'runtime',
                domain: 'runtime',
                entityId: 'runtime',
                eventType: 'runtime.reset.applied',
                payload: {
                    target: resetResult.target,
                    counts: resetResult.counts,
                    dryRun: resetResult.dryRun,
                    profileId: input.profileId ?? null,
                    workspaceFingerprint: input.workspaceFingerprint ?? null,
                },
                })
            );
        }

        return resetResult;
    }),
});

import { messageMediaStore, messageStore, runStore, sessionStore, threadStore } from '@/app/backend/persistence/stores';
import {
    profileInputSchema,
    sessionBranchFromMessageInputSchema,
    sessionBranchFromMessageWithWorkflowInputSchema,
    sessionByIdInputSchema,
    sessionCreateInputSchema,
    sessionEditInputSchema,
    sessionGetAttachedRulesInputSchema,
    sessionGetAttachedSkillsInputSchema,
    sessionGetMessageMediaInputSchema,
    sessionListMessagesInputSchema,
    sessionListRunsInputSchema,
    sessionRevertInputSchema,
    sessionSetAttachedRulesInputSchema,
    sessionSetAttachedSkillsInputSchema,
    sessionStartRunInputSchema,
    type SessionAttachedRulesResult,
    type SessionAttachedSkillsResult,
} from '@/app/backend/runtime/contracts';
import { eventMetadata } from '@/app/backend/runtime/services/common/logContext';
import { runExecutionService } from '@/app/backend/runtime/services/runExecution/service';
import { runtimeStatusEvent, runtimeUpsertEvent } from '@/app/backend/runtime/services/runtimeEventEnvelope';
import { runtimeEventLogService } from '@/app/backend/runtime/services/runtimeEventLog';
import { sessionBranchService } from '@/app/backend/runtime/services/sessionBranch/service';
import { sessionEditService } from '@/app/backend/runtime/services/sessionEdit/service';
import { sessionHistoryService } from '@/app/backend/runtime/services/sessionHistory/service';
import { getAttachedRules, setAttachedRules } from '@/app/backend/runtime/services/sessionRules/service';
import { getAttachedSkills, setAttachedSkills } from '@/app/backend/runtime/services/sessionSkills/service';
import { publicProcedure, router } from '@/app/backend/trpc/init';
import { raiseMappedTrpcError, toTrpcError, unwrapResultOrThrow } from '@/app/backend/trpc/trpcErrorMap';

export const sessionRouter = router({
    create: publicProcedure.input(sessionCreateInputSchema).mutation(async ({ input, ctx }) => {
        const session = await sessionStore.create(input.profileId, input.threadId, input.kind);
        if (!session.created) {
            return {
                created: false as const,
                reason: session.reason,
            };
        }
        await runtimeEventLogService.append(
            runtimeUpsertEvent({
                entityType: 'session',
                domain: 'session',
                entityId: session.session.id,
                eventType: 'session.created',
                payload: {
                    session: session.session,
                },
                ...eventMetadata({
                    requestId: ctx.requestId,
                    correlationId: ctx.correlationId,
                    origin: 'trpc.session.create',
                }),
            })
        );

        const thread = await threadStore.getListRecordById(input.profileId, session.session.threadId);

        return {
            created: true as const,
            session: session.session,
            ...(thread ? { thread } : {}),
        };
    }),
    list: publicProcedure.input(profileInputSchema).query(async ({ input }) => {
        return { sessions: await sessionStore.list(input.profileId) };
    }),
    status: publicProcedure.input(sessionByIdInputSchema).query(async ({ input }) => {
        return sessionStore.status(input.profileId, input.sessionId);
    }),
    getAttachedRules: publicProcedure.input(sessionGetAttachedRulesInputSchema).query(async ({ input }) => {
        const result = await getAttachedRules(input);
        return unwrapResultOrThrow(result, toTrpcError);
    }),
    getAttachedSkills: publicProcedure.input(sessionGetAttachedSkillsInputSchema).query(async ({ input }) => {
        const result = await getAttachedSkills(input);
        return unwrapResultOrThrow(result, toTrpcError);
    }),
    setAttachedRules: publicProcedure.input(sessionSetAttachedRulesInputSchema).mutation(async ({ input, ctx }) => {
        const attachedRules = (await setAttachedRules(input)).match(
            (value: SessionAttachedRulesResult) => value,
            (error: Parameters<typeof raiseMappedTrpcError>[0]) => raiseMappedTrpcError(error, toTrpcError)
        );
        await runtimeEventLogService.append(
            runtimeUpsertEvent({
                entityType: 'session',
                domain: 'session',
                entityId: input.sessionId,
                eventType: 'session.attached_rules.updated',
                payload: {
                    profileId: input.profileId,
                    sessionId: input.sessionId,
                    assetKeys: attachedRules.rulesets.map((ruleset) => ruleset.assetKey),
                    presetKeys: attachedRules.presetKeys,
                    ...(attachedRules.missingAssetKeys ? { missingAssetKeys: attachedRules.missingAssetKeys } : {}),
                },
                ...eventMetadata({
                    requestId: ctx.requestId,
                    correlationId: ctx.correlationId,
                    origin: 'trpc.session.setAttachedRules',
                }),
            })
        );

        return attachedRules;
    }),
    setAttachedSkills: publicProcedure.input(sessionSetAttachedSkillsInputSchema).mutation(async ({ input, ctx }) => {
        const attachedSkills = (await setAttachedSkills(input)).match(
            (value: SessionAttachedSkillsResult) => value,
            (error: Parameters<typeof raiseMappedTrpcError>[0]) => raiseMappedTrpcError(error, toTrpcError)
        );
        await runtimeEventLogService.append(
            runtimeUpsertEvent({
                entityType: 'session',
                domain: 'session',
                entityId: input.sessionId,
                eventType: 'session.attached_skills.updated',
                payload: {
                    profileId: input.profileId,
                    sessionId: input.sessionId,
                    assetKeys: attachedSkills.skillfiles.map((skillfile: { assetKey: string }) => skillfile.assetKey),
                    ...(attachedSkills.missingAssetKeys ? { missingAssetKeys: attachedSkills.missingAssetKeys } : {}),
                },
                ...eventMetadata({
                    requestId: ctx.requestId,
                    correlationId: ctx.correlationId,
                    origin: 'trpc.session.setAttachedSkills',
                }),
            })
        );

        return attachedSkills;
    }),
    startRun: publicProcedure.input(sessionStartRunInputSchema).mutation(async ({ input, ctx }) => {
        const result = await runExecutionService.startRun({
            ...input,
            requestId: ctx.requestId,
            correlationId: ctx.correlationId,
        });

        if (result.accepted) {
            await runtimeEventLogService.append(
                runtimeStatusEvent({
                    entityType: 'session',
                    domain: 'session',
                    entityId: input.sessionId,
                    eventType: 'session.run.started',
                    payload: {
                        runId: result.runId,
                        profileId: input.profileId,
                        topLevelTab: input.topLevelTab,
                        modeKey: input.modeKey,
                        workspaceFingerprint: input.workspaceFingerprint ?? null,
                    },
                    ...eventMetadata({
                        requestId: ctx.requestId,
                        correlationId: ctx.correlationId,
                        origin: 'trpc.session.startRun',
                    }),
                })
            );
        }

        return result;
    }),
    listRuns: publicProcedure.input(sessionListRunsInputSchema).query(async ({ input }) => {
        return {
            runs: await runStore.listBySession(input.profileId, input.sessionId),
        };
    }),
    listMessages: publicProcedure.input(sessionListMessagesInputSchema).query(async ({ input }) => {
        const [messages, messageParts] = await Promise.all([
            messageStore.listMessagesBySession(input.profileId, input.sessionId, input.runId),
            messageStore.listPartsBySession(input.profileId, input.sessionId, input.runId),
        ]);

        return {
            messages,
            messageParts,
        };
    }),
    getMessageMedia: publicProcedure.input(sessionGetMessageMediaInputSchema).query(async ({ input }) => {
        const media = await messageMediaStore.getPayloadForProfile(input.profileId, input.mediaId);

        return {
            found: media !== null,
            ...(media ?? {}),
        };
    }),
    abort: publicProcedure.input(sessionByIdInputSchema).mutation(async ({ input, ctx }) => {
        const result = await runExecutionService.abortRun(input.profileId, input.sessionId);
        if (result.aborted) {
            await runtimeEventLogService.append(
                runtimeStatusEvent({
                    entityType: 'session',
                    domain: 'session',
                    entityId: input.sessionId,
                    eventType: 'session.aborted',
                    payload: {
                        runId: result.runId,
                        profileId: input.profileId,
                    },
                    ...eventMetadata({
                        requestId: ctx.requestId,
                        correlationId: ctx.correlationId,
                        origin: 'trpc.session.abort',
                    }),
                })
            );
        }

        return result;
    }),
    revert: publicProcedure.input(sessionRevertInputSchema).mutation(async ({ input, ctx }) => {
        if (input.topLevelTab === 'chat') {
            return {
                reverted: false as const,
                reason: 'unsupported_tab' as const,
                message: 'Checkpoint-style revert is only supported in agent and orchestrator tabs.',
            };
        }
        const sessionThread = await threadStore.getBySessionId(input.profileId, input.sessionId);
        if (!sessionThread) {
            return {
                reverted: false as const,
                reason: 'not_found' as const,
            };
        }
        if (sessionThread.thread.topLevelTab !== input.topLevelTab) {
            return {
                reverted: false as const,
                reason: 'thread_tab_mismatch' as const,
                message: `Thread belongs to "${sessionThread.thread.topLevelTab}" tab.`,
            };
        }

        const result = await sessionHistoryService.revert(input.profileId, input.sessionId);
        if (result.reverted) {
            await runtimeEventLogService.append(
                runtimeUpsertEvent({
                    entityType: 'session',
                    domain: 'session',
                    entityId: input.sessionId,
                    eventType: 'session.reverted',
                    payload: {
                        session: result.session,
                        profileId: input.profileId,
                    },
                    ...eventMetadata({
                        requestId: ctx.requestId,
                        correlationId: ctx.correlationId,
                        origin: 'trpc.session.revert',
                    }),
                })
            );
        }

        return result;
    }),
    edit: publicProcedure.input(sessionEditInputSchema).mutation(async ({ input, ctx }) => {
        const sessionThread = await threadStore.getBySessionId(input.profileId, input.sessionId);
        if (!sessionThread) {
            return {
                edited: false as const,
                reason: 'session_not_found' as const,
            };
        }
        if (sessionThread.thread.topLevelTab !== input.topLevelTab) {
            return {
                edited: false as const,
                reason: 'thread_tab_mismatch' as const,
            };
        }

        const result = await sessionEditService.edit(input);
        if (result.edited) {
            await runtimeEventLogService.append(
                runtimeUpsertEvent({
                    entityType: 'session',
                    domain: 'session',
                    entityId: result.sessionId,
                    eventType: 'session.edited',
                    payload: {
                        profileId: input.profileId,
                        sourceSessionId: result.sourceSessionId,
                        sessionId: result.sessionId,
                        editMode: result.editMode,
                        started: result.started,
                        runId: result.runId ?? null,
                    },
                    ...eventMetadata({
                        requestId: ctx.requestId,
                        correlationId: ctx.correlationId,
                        origin: 'trpc.session.edit',
                    }),
                })
            );
        }

        return result;
    }),
    branchFromMessage: publicProcedure.input(sessionBranchFromMessageInputSchema).mutation(async ({ input, ctx }) => {
        const result = await sessionBranchService.branchFromMessage(input);
        if (result.branched) {
            await runtimeEventLogService.append(
                runtimeUpsertEvent({
                    entityType: 'session',
                    domain: 'session',
                    entityId: result.sessionId,
                    eventType: 'session.branched_from_message',
                    payload: {
                        profileId: input.profileId,
                        sourceSessionId: result.sourceSessionId,
                        sessionId: result.sessionId,
                        sourceThreadId: result.sourceThreadId,
                        threadId: result.threadId,
                        messageId: input.messageId,
                    },
                    ...eventMetadata({
                        requestId: ctx.requestId,
                        correlationId: ctx.correlationId,
                        origin: 'trpc.session.branchFromMessage',
                    }),
                })
            );
        }

        return result;
    }),
    branchFromMessageWithWorkflow: publicProcedure
        .input(sessionBranchFromMessageWithWorkflowInputSchema)
        .mutation(async ({ input, ctx }) => {
            const result = await sessionBranchService.branchFromMessageWithWorkflow(input);
            if (result.branched) {
                await runtimeEventLogService.append(
                    runtimeUpsertEvent({
                        entityType: 'session',
                        domain: 'session',
                        entityId: result.sessionId,
                        eventType: 'session.branched_from_message',
                        payload: {
                            profileId: input.profileId,
                            sourceSessionId: result.sourceSessionId,
                            sessionId: result.sessionId,
                            sourceThreadId: result.sourceThreadId,
                            threadId: result.threadId,
                            messageId: input.messageId,
                            workflowId: input.workflowId ?? null,
                            workflowExecution: result.workflowExecution,
                        },
                        ...eventMetadata({
                            requestId: ctx.requestId,
                            correlationId: ctx.correlationId,
                            origin: 'trpc.session.branchFromMessageWithWorkflow',
                        }),
                    })
                );
            }

            return result;
        }),
});

