import { app, BrowserWindow, Menu, dialog, ipcMain, type OpenDialogOptions } from 'electron';
import { createIPCHandler, type CreateContextOptions } from 'electron-trpc-experimental/main';

import { closePersistence, initializePersistence } from '@/app/backend/persistence/db';
import { getSecretStoreInfo, initializeSecretStore } from '@/app/backend/secrets/store';
import { PICK_DIRECTORY_CHANNEL } from '@/app/shared/desktopBridgeContract';
import type { Context } from '@/app/backend/trpc/context';
import type { AppRouter } from '@/app/backend/trpc/router';
import { registerWindowStateBridge } from '@/app/backend/trpc/routers/system/windowControls';
import { handleStartupFailure } from '@/app/main/bootstrap/startupFailure';
import { appLog, flushAppLogger, initAppLogger } from '@/app/main/logging';
import { devServerUrl, getMainDirname, isDev } from '@/app/main/runtime/env';
import { resolveDesktopStorage, resolveDesktopStoragePaths } from '@/app/main/runtime/storage';
import { attachCspHeaders } from '@/app/main/security/cspHeaders';
import { registerBootWindows, reportMainBootStatus } from '@/app/main/window/bootCoordinator';
import { BOOT_STUCK_WARNING_DEV_MS } from '@/app/shared/splashContract';
import { createMainWindow } from '@/app/main/window/factory';
import { createSplashWindow } from '@/app/main/window/splash';

interface BootstrapDeps {
    createContext: (opts: CreateContextOptions) => Promise<Context>;
    appRouter: AppRouter;
    initAutoUpdater: () => void;
    resolvePersistenceChannel: () => 'stable' | 'beta' | 'alpha';
}

export function bootstrapMainProcess(deps: BootstrapDeps, importMetaUrl: string): void {
    const { createContext, appRouter, initAutoUpdater, resolvePersistenceChannel } = deps;
    const mainDirname = getMainDirname(importMetaUrl);
    const defaultUserDataPath = app.getPath('userData');
    const initialStorage = resolveDesktopStorage({
        defaultUserDataPath,
        isDev,
        packagedRuntimeNamespace: 'stable',
    });

    if (initialStorage.userDataPath !== defaultUserDataPath) {
        app.setPath('userData', initialStorage.userDataPath);
    }

    let mainWindow: BrowserWindow | null = null;
    let ipcHandler: ReturnType<typeof createIPCHandler> | null = null;
    const runtimeWindowOptions = {
        isDev,
        mainDirname,
        ...(devServerUrl ? { devServerUrl } : {}),
    };
    const splashWindowOptions = {
        appPath: app.getAppPath(),
        ...(devServerUrl ? { devServerUrl } : {}),
        isPackaged: app.isPackaged,
        mainDirname,
        resourcesPath: process.resourcesPath,
    };
    const runtimeCspOptions = {
        isDev,
        ...(devServerUrl ? { devServerUrl } : {}),
    };

    function createBootManagedMainWindow(): BrowserWindow {
        const nextMainWindow = createMainWindow(runtimeWindowOptions);
        const splashWindow = createSplashWindow(splashWindowOptions);
        registerBootWindows({
            mainWindow: nextMainWindow,
            splashWindow,
            ...(isDev ? { warningMs: BOOT_STUCK_WARNING_DEV_MS } : {}),
        });
        reportMainBootStatus({
            stage: 'windows_ready',
        });
        return nextMainWindow;
    }

    void app
        .whenReady()
        .then(() => {
            initAppLogger({
                isDev,
                version: app.getVersion(),
            });
            reportMainBootStatus({
                stage: 'main_initializing',
            });

            const resolvedStorage = resolveDesktopStorage({
                defaultUserDataPath,
                isDev,
                packagedRuntimeNamespace: isDev ? 'stable' : resolvePersistenceChannel(),
            });
            const storagePaths = resolveDesktopStoragePaths(resolvedStorage);
            process.env['NEONCONDUCTOR_USER_DATA_PATH'] = resolvedStorage.userDataPath;
            process.env['NEONCONDUCTOR_RUNTIME_NAMESPACE'] = resolvedStorage.runtimeNamespace;
            process.env['NEONCONDUCTOR_PERSISTENCE_CHANNEL'] = resolvedStorage.runtimeNamespace;
            appLog.info({
                tag: 'runtime',
                message: 'Runtime storage resolved.',
                runtimeNamespace: resolvedStorage.runtimeNamespace,
                userDataPath: resolvedStorage.userDataPath,
                dbPath: storagePaths.dbPath,
                isDevIsolatedStorage: resolvedStorage.isDevIsolatedStorage,
            });
            reportMainBootStatus({
                stage: 'storage_ready',
            });

            initializePersistence({
                dbPath: storagePaths.dbPath,
            });
            reportMainBootStatus({
                stage: 'persistence_ready',
            });
            initializeSecretStore();
            const secretStoreInfo = getSecretStoreInfo();
            appLog.info({
                tag: 'secrets',
                message: 'Provider secrets initialized.',
                backend: secretStoreInfo.backend,
            });
            reportMainBootStatus({
                stage: 'secrets_ready',
            });

            // Remove default menu bar (File, Edit, View, Help)
            Menu.setApplicationMenu(null);

            // Set up Content Security Policy via HTTP headers.
            attachCspHeaders(runtimeCspOptions);

            if (process.platform === 'win32') {
                app.setAppUserModelId('com.neonsy.neonconductor');
            }

            mainWindow = createBootManagedMainWindow();
            registerWindowStateBridge(mainWindow);

            // Wire up tRPC to handle IPC calls from the renderer
            ipcHandler = createIPCHandler({
                router: appRouter,
                windows: [mainWindow],
                createContext,
            });
            ipcMain.handle(PICK_DIRECTORY_CHANNEL, async () => {
                const ownerWindow = BrowserWindow.getFocusedWindow() ?? mainWindow ?? undefined;
                const dialogOptions: OpenDialogOptions = {
                    title: 'Choose Workspace Folder',
                    properties: ['openDirectory', 'createDirectory', 'dontAddToRecent'],
                };
                const result = ownerWindow
                    ? await dialog.showOpenDialog(ownerWindow, dialogOptions)
                    : await dialog.showOpenDialog(dialogOptions);
                const absolutePath = result.filePaths[0];

                if (result.canceled || !absolutePath) {
                    return { canceled: true } as const;
                }

                return {
                    canceled: false as const,
                    absolutePath,
                };
            });
            reportMainBootStatus({
                stage: 'renderer_connecting',
                blockingPrerequisite: 'renderer_first_report',
            });

            app.on('browser-window-created', (_event, window) => {
                ipcHandler?.attachWindow(window);
                registerWindowStateBridge(window);
            });

            initAutoUpdater();
        })
        .catch((error: unknown) => handleStartupFailure(error));

    app.on('before-quit', () => {
        ipcMain.removeHandler(PICK_DIRECTORY_CHANNEL);
        closePersistence();
        void flushAppLogger();
    });

    // Standard quit behavior: exit when all windows closed (except macOS)
    app.on('window-all-closed', () => {
        if (process.platform !== 'darwin') {
            app.quit();
        }
    });

    // macOS: re-create window when dock icon clicked with no windows open
    app.on('activate', () => {
        if (BrowserWindow.getAllWindows().length === 0) {
            mainWindow = createBootManagedMainWindow();
            registerWindowStateBridge(mainWindow);
        }
    });
}

/**
 * Preload script - runs in isolated context before renderer loads.
 * Exposes only the tRPC IPC bridge to the renderer (minimal attack surface).
 */

import { contextBridge, ipcRenderer } from 'electron';
import { exposeElectronTRPC } from 'electron-trpc-experimental/preload';

import {
    PICK_DIRECTORY_CHANNEL,
    isPickDirectoryResult,
    type PickDirectoryResult,
} from '@/app/shared/desktopBridgeContract';

contextBridge.exposeInMainWorld('neonDesktop', {
    async pickDirectory(): Promise<PickDirectoryResult> {
        const result = await ipcRenderer.invoke(PICK_DIRECTORY_CHANNEL);
        return isPickDirectoryResult(result) ? result : { canceled: true };
    },
});

// 'loaded' fires after preload executes but before renderer scripts run
process.once('loaded', () => {
    exposeElectronTRPC();
});

import { beforeEach, describe, expect, it, vi } from 'vitest';

import type { BootStatusSnapshot } from '@/app/shared/splashContract';

const {
    exposeInMainWorldSpy,
    ipcOnSpy,
    ipcPhaseHandlerState,
} = vi.hoisted(() => ({
    exposeInMainWorldSpy: vi.fn(),
    ipcOnSpy: vi.fn(),
    ipcPhaseHandlerState: {
        handler: undefined as ((event: unknown, phase: unknown) => void) | undefined,
    },
}));

vi.mock('electron', () => ({
    contextBridge: {
        exposeInMainWorld: exposeInMainWorldSpy,
    },
    ipcRenderer: {
        on: (channel: string, handler: (event: unknown, phase: unknown) => void) => {
            ipcOnSpy(channel, handler);
            ipcPhaseHandlerState.handler = handler;
        },
    },
}));

describe('splash preload bridge', () => {
    const originalProcessArgv = [...process.argv];

    beforeEach(() => {
        vi.resetModules();
        vi.clearAllMocks();
        ipcPhaseHandlerState.handler = undefined;
        process.argv = originalProcessArgv.filter(
            (argument) => !argument.startsWith('--neon-splash-mascot-source=')
        );
    });

    it('exposes bootstrap payload and an onStatusChange bridge that replays the latest boot status', async () => {
        process.argv.push('--neon-splash-mascot-source=file%3A%2F%2F%2FC%3A%2Frepo%2FProject%2Fsrc%2Fassets%2Fappicon.png');

        await import('@/app/main/preload/splash');

        expect(exposeInMainWorldSpy).toHaveBeenCalledTimes(1);
        const splashBridge = exposeInMainWorldSpy.mock.calls[0]?.[1] as {
            getBootstrapPayload: () => {
                mascotSource: string | null;
                status: BootStatusSnapshot;
            };
            onStatusChange: (listener: (status: BootStatusSnapshot) => void) => () => void;
        };

        expect(splashBridge.getBootstrapPayload()).toMatchObject({
            mascotSource: 'file:///C:/repo/Project/src/assets/appicon.png',
            status: expect.objectContaining({
                stage: 'main_initializing',
            }),
        });

        const statusListener = vi.fn();
        splashBridge.onStatusChange(statusListener);

        expect(statusListener).toHaveBeenCalledWith(
            expect.objectContaining({
                stage: 'main_initializing',
            })
        );

        ipcPhaseHandlerState.handler?.({}, {
            stage: 'profile_resolving',
            headline: 'Resolving the active profile',
            detail: 'Resolving the active workspace profile.',
            isStuck: false,
            blockingPrerequisite: 'resolved_profile',
            elapsedMs: 100,
            source: 'renderer',
        });

        expect(statusListener).toHaveBeenLastCalledWith(
            expect.objectContaining({
                stage: 'profile_resolving',
                blockingPrerequisite: 'resolved_profile',
            })
        );
    });
});

import { app, type BrowserWindow } from 'electron';

import { appLog } from '@/app/main/logging';
import { updateSplashWindowStatus } from '@/app/main/window/splash';
import {
    BOOT_FORCE_SHOW_MS,
    BOOT_STUCK_WARNING_MS,
    type BootBlockingPrerequisite,
    type BootStage,
    createBootStatusSnapshot,
    getBootStatusDisplaySignature,
    getBootStatusSignature,
    type BootStatusSnapshot,
} from '@/app/shared/splashContract';

interface BootWindowState {
    mainWindow: BrowserWindow | null;
    splashWindow: BrowserWindow | null;
    warningTimer: ReturnType<typeof setTimeout> | null;
    forceTimer: ReturnType<typeof setTimeout> | null;
    handoffCompleted: boolean;
    handoffForced: boolean;
    lateReadyLogged: boolean;
    bootStartedAtMs: number;
    warningMs: number;
    lastProgressAtMs: number;
    lastProgressSignature: string | null;
    latestStatus: BootStatusSnapshot;
    latestStatusSignature: string;
    latestStatusDisplaySignature: string;
}

interface BootStatusUpdateInput {
    stage: BootStage;
    source: 'main' | 'renderer';
    isStuck?: boolean;
    blockingPrerequisite?: BootBlockingPrerequisite | null;
    headline?: string;
    detail?: string;
    elapsedMs?: number;
}

const bootWindowState: BootWindowState = {
    mainWindow: null,
    splashWindow: null,
    warningTimer: null,
    forceTimer: null,
    handoffCompleted: false,
    handoffForced: false,
    lateReadyLogged: false,
    bootStartedAtMs: 0,
    warningMs: BOOT_STUCK_WARNING_MS,
    lastProgressAtMs: 0,
    lastProgressSignature: null,
    latestStatus: createBootStatusSnapshot({
        stage: 'main_initializing',
        source: 'main',
        elapsedMs: 0,
    }),
    latestStatusSignature: '',
    latestStatusDisplaySignature: '',
};

function ensureBootStart(): void {
    if (bootWindowState.bootStartedAtMs === 0) {
        bootWindowState.bootStartedAtMs = Date.now();
    }
}

function getElapsedMs(): number {
    ensureBootStart();
    return Math.max(0, Date.now() - bootWindowState.bootStartedAtMs);
}

function clearBootTimers(): void {
    if (bootWindowState.warningTimer) {
        clearTimeout(bootWindowState.warningTimer);
        bootWindowState.warningTimer = null;
    }
    if (bootWindowState.forceTimer) {
        clearTimeout(bootWindowState.forceTimer);
        bootWindowState.forceTimer = null;
    }
}

const bootProgressOrdinals: Record<string, number> = {
    'renderer_connecting:main': 1,
    'renderer_connecting:renderer': 2,
    profile_resolving: 3,
    mode_resolving: 4,
    shell_bootstrap_loading: 5,
    ready_to_show: 6,
};

function getBootProgressSignature(input: Pick<BootStatusSnapshot, 'stage' | 'source'>): string | null {
    switch (input.stage) {
        case 'renderer_connecting':
            return `${input.stage}:${input.source}`;
        case 'profile_resolving':
        case 'mode_resolving':
        case 'shell_bootstrap_loading':
        case 'ready_to_show':
            return input.stage;
        default:
            return null;
    }
}

function recordBootProgress(status: Pick<BootStatusSnapshot, 'stage' | 'source'>, atMs: number): void {
    const progressSignature = getBootProgressSignature(status);
    if (!progressSignature) {
        return;
    }

    bootWindowState.lastProgressSignature = progressSignature;
    bootWindowState.lastProgressAtMs = atMs;
}

function hasMeaningfulBootProgress(status: Pick<BootStatusSnapshot, 'stage' | 'source'>): boolean {
    const nextProgressSignature = getBootProgressSignature(status);
    if (!nextProgressSignature) {
        return false;
    }

    if (bootWindowState.lastProgressSignature === nextProgressSignature) {
        return false;
    }

    const previousProgressOrdinal =
        bootWindowState.lastProgressSignature === null
            ? 0
            : (bootProgressOrdinals[bootWindowState.lastProgressSignature] ?? 0);
    const nextProgressOrdinal = bootProgressOrdinals[nextProgressSignature] ?? 0;
    return nextProgressOrdinal > previousProgressOrdinal;
}

function scheduleBootWarningTimer(): void {
    if (bootWindowState.warningTimer || bootWindowState.handoffCompleted) {
        return;
    }

    bootWindowState.warningTimer = setTimeout(() => {
        bootWindowState.warningTimer = null;
        if (bootWindowState.handoffCompleted) {
            return;
        }

        const stuckStatus = createBootStatusSnapshot({
            stage: 'boot_stuck',
            source: 'main',
            elapsedMs: getElapsedMs(),
            isStuck: true,
            blockingPrerequisite: bootWindowState.latestStatus.blockingPrerequisite,
        });
        publishBootStatus(stuckStatus);
        appLog.warn({
            tag: 'runtime.boot',
            message: 'Boot warning threshold reached.',
            blockingPrerequisite: stuckStatus.blockingPrerequisite,
            elapsedMs: stuckStatus.elapsedMs,
        });
    }, bootWindowState.warningMs);
}

function maybeResetBootWarningTimerForProgress(status: BootStatusSnapshot): void {
    if (!hasMeaningfulBootProgress(status)) {
        return;
    }

    recordBootProgress(status, Date.now());

    if (!bootWindowState.warningTimer) {
        return;
    }

    clearTimeout(bootWindowState.warningTimer);
    bootWindowState.warningTimer = null;
    scheduleBootWarningTimer();
}

function startBootTimers(warningMs: number, forceShowMs: number): void {
    if (bootWindowState.warningTimer || bootWindowState.forceTimer || bootWindowState.handoffCompleted) {
        return;
    }

    bootWindowState.warningMs = warningMs;
    bootWindowState.lastProgressAtMs = Date.now();
    bootWindowState.lastProgressSignature = getBootProgressSignature(bootWindowState.latestStatus);

    scheduleBootWarningTimer();

    bootWindowState.forceTimer = setTimeout(() => {
        bootWindowState.forceTimer = null;
        forceBootWindowHandoff();
    }, forceShowMs);
}

function resetBootWindowState(): void {
    clearBootTimers();
    bootWindowState.mainWindow = null;
    bootWindowState.splashWindow = null;
    bootWindowState.handoffCompleted = false;
    bootWindowState.handoffForced = false;
    bootWindowState.lateReadyLogged = false;
    bootWindowState.bootStartedAtMs = 0;
    bootWindowState.warningMs = BOOT_STUCK_WARNING_MS;
    bootWindowState.lastProgressAtMs = 0;
    bootWindowState.lastProgressSignature = null;
    bootWindowState.latestStatus = createBootStatusSnapshot({
        stage: 'main_initializing',
        source: 'main',
        elapsedMs: 0,
    });
    bootWindowState.latestStatusSignature = '';
    bootWindowState.latestStatusDisplaySignature = '';
}

function isSameWindow(left: BrowserWindow | null, right: BrowserWindow | null): boolean {
    if (!left || !right) {
        return false;
    }

    return left.id === right.id;
}

function logBootStatusTransition(status: BootStatusSnapshot): void {
    appLog.info({
        tag: 'runtime.boot',
        message: 'Boot status updated.',
        stage: status.stage,
        source: status.source,
        elapsedMs: status.elapsedMs,
        isStuck: status.isStuck,
        blockingPrerequisite: status.blockingPrerequisite,
        headline: status.headline,
        detail: status.detail,
    });
}

function publishBootStatus(status: BootStatusSnapshot): void {
    const statusSignature = getBootStatusSignature(status);
    const statusDisplaySignature = getBootStatusDisplaySignature(status);
    if (statusDisplaySignature === bootWindowState.latestStatusDisplaySignature) {
        bootWindowState.latestStatus = status;
        return;
    }

    const didTransition = statusSignature !== bootWindowState.latestStatusSignature;
    bootWindowState.latestStatus = status;
    bootWindowState.latestStatusSignature = statusSignature;
    bootWindowState.latestStatusDisplaySignature = statusDisplaySignature;
    if (didTransition) {
        logBootStatusTransition(status);
    }

    maybeResetBootWarningTimerForProgress(status);

    if (bootWindowState.splashWindow && !bootWindowState.splashWindow.isDestroyed()) {
        void updateSplashWindowStatus(bootWindowState.splashWindow, status);
    }
}

function updateBootStatus(input: BootStatusUpdateInput): void {
    publishBootStatus(
        createBootStatusSnapshot({
            ...input,
            elapsedMs: input.elapsedMs ?? getElapsedMs(),
        })
    );
}

function forceBootWindowHandoff(): void {
    if (bootWindowState.handoffCompleted) {
        return;
    }

    bootWindowState.handoffCompleted = true;
    bootWindowState.handoffForced = true;
    clearBootTimers();

    const forcedStatus = createBootStatusSnapshot({
        stage: 'handoff_forced',
        source: 'main',
        elapsedMs: getElapsedMs(),
        isStuck: true,
        blockingPrerequisite: bootWindowState.latestStatus.blockingPrerequisite,
    });
    publishBootStatus(forcedStatus);
    appLog.warn({
        tag: 'runtime.boot',
        message: 'Forced boot handoff after startup timeout.',
        blockingPrerequisite: bootWindowState.latestStatus.blockingPrerequisite,
        elapsedMs: forcedStatus.elapsedMs,
    });

    if (bootWindowState.splashWindow && !bootWindowState.splashWindow.isDestroyed()) {
        bootWindowState.splashWindow.close();
    }

    if (bootWindowState.mainWindow && !bootWindowState.mainWindow.isDestroyed()) {
        if (!bootWindowState.mainWindow.isVisible()) {
            bootWindowState.mainWindow.show();
        }
        if (!bootWindowState.mainWindow.isMaximized()) {
            bootWindowState.mainWindow.maximize();
        }
    }

    bootWindowState.splashWindow = null;
}

export function reportMainBootStatus(input: Omit<BootStatusUpdateInput, 'source'>): void {
    updateBootStatus({
        ...input,
        source: 'main',
    });
}

export function reportRendererBootStatus(
    window: BrowserWindow | null,
    input: Omit<BootStatusUpdateInput, 'source'>
): { accepted: boolean } {
    if (!window || (bootWindowState.mainWindow && !isSameWindow(window, bootWindowState.mainWindow))) {
        return { accepted: false };
    }

    updateBootStatus({
        ...input,
        source: 'renderer',
        elapsedMs: input.elapsedMs ?? getElapsedMs(),
    });
    return { accepted: true };
}

export function registerBootWindows(input: {
    mainWindow: BrowserWindow;
    splashWindow: BrowserWindow;
    warningMs?: number;
    forceShowMs?: number;
}): void {
    ensureBootStart();
    clearBootTimers();
    bootWindowState.mainWindow = input.mainWindow;
    bootWindowState.splashWindow = input.splashWindow;
    bootWindowState.handoffCompleted = false;
    bootWindowState.handoffForced = false;
    bootWindowState.lateReadyLogged = false;

    publishBootStatus(bootWindowState.latestStatus);

    input.splashWindow.once('closed', () => {
        if (bootWindowState.handoffCompleted) {
            bootWindowState.splashWindow = null;
            return;
        }

        clearBootTimers();

        if (bootWindowState.mainWindow && !bootWindowState.mainWindow.isDestroyed()) {
            bootWindowState.mainWindow.close();
        }

        resetBootWindowState();
        app.quit();
    });

    if (typeof input.mainWindow.webContents?.once === 'function') {
        input.mainWindow.webContents.once('did-finish-load', () => {
            startBootTimers(input.warningMs ?? BOOT_STUCK_WARNING_MS, input.forceShowMs ?? BOOT_FORCE_SHOW_MS);
        });
        return;
    }

    startBootTimers(input.warningMs ?? BOOT_STUCK_WARNING_MS, input.forceShowMs ?? BOOT_FORCE_SHOW_MS);
}

export function completeBootWindowHandoff(window: BrowserWindow | null): { success: boolean } {
    if (!window) {
        return { success: false };
    }

    if (bootWindowState.mainWindow && !isSameWindow(window, bootWindowState.mainWindow)) {
        return { success: false };
    }

    if (bootWindowState.handoffCompleted) {
        if (bootWindowState.handoffForced && !bootWindowState.lateReadyLogged) {
            bootWindowState.lateReadyLogged = true;
            appLog.info({
                tag: 'runtime.boot',
                message: 'Renderer ready signal arrived after forced handoff.',
                elapsedMs: getElapsedMs(),
            });
        }
        return { success: true };
    }

    bootWindowState.handoffCompleted = true;
    clearBootTimers();

    if (bootWindowState.splashWindow && !bootWindowState.splashWindow.isDestroyed()) {
        bootWindowState.splashWindow.close();
    }

    if (!window.isVisible()) {
        window.show();
    }
    if (!window.isMaximized()) {
        window.maximize();
    }

    bootWindowState.splashWindow = null;
    return { success: true };
}

export function resetBootWindowStateForTests(): void {
    resetBootWindowState();
}

