import path from 'node:path';
import { pathToFileURL } from 'node:url';

import { scriptLog } from '@/scripts/logger';

import {
    refreshStaleReviewEntries,
    removeReviewManifestEntry,
    setReviewManifestEntry,
} from './reviewManifest';
import type { ReviewManifestStatus } from './types';

function isDirectExecution(importMetaUrl: string): boolean {
    const entryPath = process.argv[1];
    if (!entryPath) {
        return false;
    }

    return importMetaUrl === pathToFileURL(path.resolve(entryPath)).href;
}

function readOption(args: string[], name: string): string | undefined {
    const prefix = `${name}=`;
    const exactMatch = args.find((argument) => argument.startsWith(prefix));
    if (exactMatch) {
        return exactMatch.slice(prefix.length);
    }

    const optionIndex = args.findIndex((argument) => argument === name);
    if (optionIndex === -1) {
        return undefined;
    }

    return args[optionIndex + 1];
}

function assertPresent(value: string | undefined, label: string): string {
    if (!value) {
        throw new Error(`Missing required option: ${label}`);
    }

    return value;
}

function isReviewStatus(value: string): value is ReviewManifestStatus {
    return value === 'reviewed-clean' || value === 'accepted-risk' || value === 'needs-refactor';
}

export function runAuditReviewCommand(): void {
    runAuditReviewCommandWithArgs({
        args: process.argv.slice(2),
        rootDir: process.cwd(),
    });
}

export function runAuditReviewCommandWithArgs(input: {
    args: string[];
    rootDir: string;
}): void {
    if (input.args.includes('--refresh-stale')) {
        const manifest = refreshStaleReviewEntries(input.rootDir);
        scriptLog.info({
            tag: 'agents.audit.review',
            message: 'Refreshed stale review entries.',
            entries: manifest.entries.length,
        });
        return;
    }

    const targetPath = assertPresent(readOption(input.args, '--path'), '--path');
    const category = assertPresent(readOption(input.args, '--category'), '--category');

    if (input.args.includes('--remove')) {
        const manifest = removeReviewManifestEntry({
            rootDir: input.rootDir,
            path: targetPath,
            category,
        });
        scriptLog.info({
            tag: 'agents.audit.review',
            message: 'Removed review entry.',
            path: targetPath,
            category,
            entries: manifest.entries.length,
        });
        return;
    }

    const statusValue = assertPresent(readOption(input.args, '--status'), '--status');
    if (!isReviewStatus(statusValue)) {
        throw new Error(`Invalid review status: ${statusValue}`);
    }

    const note = readOption(input.args, '--note');
    const manifestInput: {
        rootDir: string;
        path: string;
        category: string;
        status: ReviewManifestStatus;
        note?: string;
    } = {
        rootDir: input.rootDir,
        path: targetPath,
        category,
        status: statusValue,
    };
    if (note !== undefined) {
        manifestInput.note = note;
    }

    const manifest = setReviewManifestEntry(manifestInput);

    scriptLog.info({
        tag: 'agents.audit.review',
        message: 'Recorded review entry.',
        path: targetPath,
        category,
        status: statusValue,
        entries: manifest.entries.length,
    });
}

if (isDirectExecution(import.meta.url)) {
    runAuditReviewCommand();
}

import { createHash } from 'node:crypto';
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

import { collectSourceFiles } from './sourceFiles';
import type {
    AuditCategoryReport,
    AuditSourceFile,
    ReviewManifestEntry,
    ReviewManifestFile,
    ReviewedAuditViolation,
    ReviewManifestStatus,
    ReviewStatus,
} from './types';

export const REVIEW_MANIFEST_RELATIVE_PATH = 'scripts/audit/agents-review-manifest.json';

export function buildContentHash(content: string): string {
    return createHash('sha256').update(content).digest('hex').slice(0, 16);
}

export function getReviewManifestPath(rootDir: string): string {
    return path.join(rootDir, REVIEW_MANIFEST_RELATIVE_PATH);
}

export function loadReviewManifest(rootDir: string): ReviewManifestFile {
    const manifestPath = getReviewManifestPath(rootDir);
    if (!existsSync(manifestPath)) {
        return { entries: [] };
    }

    const rawContent = readFileSync(manifestPath, 'utf8').trim();
    if (rawContent.length === 0) {
        return { entries: [] };
    }

    const parsedValue = JSON.parse(rawContent) as Partial<ReviewManifestFile>;
    return {
        entries: Array.isArray(parsedValue.entries) ? parsedValue.entries : [],
    };
}

export function saveReviewManifest(rootDir: string, manifest: ReviewManifestFile): void {
    const normalizedEntries = [...manifest.entries].sort((leftEntry, rightEntry) => {
        const leftKey = buildManifestKey(leftEntry);
        const rightKey = buildManifestKey(rightEntry);
        return leftKey.localeCompare(rightKey);
    });

    writeFileSync(
        getReviewManifestPath(rootDir),
        `${JSON.stringify({ entries: normalizedEntries }, null, 2)}\n`,
        'utf8'
    );
}

function buildManifestKey(entry: Pick<ReviewManifestEntry, 'path' | 'category'>): string {
    return `${entry.category}::${entry.path}`;
}

function classifyReviewStatus(
    manifestEntry: ReviewManifestEntry | undefined,
    currentContentHash: string
): { reviewStatus: ReviewStatus; reviewNote?: string; reviewDate?: string } {
    if (!manifestEntry) {
        return { reviewStatus: 'new' };
    }

    if (manifestEntry.contentHash !== currentContentHash) {
        const staleResult: { reviewStatus: ReviewStatus; reviewNote?: string; reviewDate?: string } = {
            reviewStatus: 'stale',
        };
        if (manifestEntry.note !== undefined) {
            staleResult.reviewNote = manifestEntry.note;
        }
        if (manifestEntry.reviewedAt !== undefined) {
            staleResult.reviewDate = manifestEntry.reviewedAt;
        }
        return staleResult;
    }

    const reviewedResult: { reviewStatus: ReviewStatus; reviewNote?: string; reviewDate?: string } = {
        reviewStatus: manifestEntry.status,
    };
    if (manifestEntry.note !== undefined) {
        reviewedResult.reviewNote = manifestEntry.note;
    }
    if (manifestEntry.reviewedAt !== undefined) {
        reviewedResult.reviewDate = manifestEntry.reviewedAt;
    }
    return reviewedResult;
}

export function getCurrentFileContentHash(rootDir: string, relativePath: string): string {
    const sourceFiles = collectSourceFiles(rootDir);
    const targetFile = sourceFiles.find((sourceFile) => sourceFile.relativePath === relativePath);
    if (!targetFile) {
        throw new Error(`Cannot review missing source file: ${relativePath}`);
    }

    return buildContentHash(targetFile.content);
}

export function setReviewManifestEntry(input: {
    rootDir: string;
    path: string;
    category: string;
    status: ReviewManifestStatus;
    note?: string;
    reviewedAt?: string;
}): ReviewManifestFile {
    const manifest = loadReviewManifest(input.rootDir);
    const currentContentHash = getCurrentFileContentHash(input.rootDir, input.path);
    const reviewedAt = input.reviewedAt ?? new Date().toISOString().slice(0, 10);

    const nextEntry: ReviewManifestEntry = {
        path: input.path,
        category: input.category,
        contentHash: currentContentHash,
        status: input.status,
        reviewedAt,
    };
    if (input.note !== undefined) {
        nextEntry.note = input.note;
    }

    const entryIndex = manifest.entries.findIndex(
        (entry) => entry.path === input.path && entry.category === input.category
    );
    if (entryIndex === -1) {
        manifest.entries.push(nextEntry);
    } else {
        manifest.entries[entryIndex] = nextEntry;
    }

    saveReviewManifest(input.rootDir, manifest);
    return manifest;
}

export function removeReviewManifestEntry(input: {
    rootDir: string;
    path: string;
    category: string;
}): ReviewManifestFile {
    const manifest = loadReviewManifest(input.rootDir);
    const nextEntries = manifest.entries.filter(
        (entry) => !(entry.path === input.path && entry.category === input.category)
    );

    const nextManifest: ReviewManifestFile = { entries: nextEntries };
    saveReviewManifest(input.rootDir, nextManifest);
    return nextManifest;
}

export function refreshStaleReviewEntries(rootDir: string): ReviewManifestFile {
    const manifest = loadReviewManifest(rootDir);
    const sourceFiles = collectSourceFiles(rootDir);
    const fileHashByPath = new Map(
        sourceFiles.map((file) => [file.relativePath, buildContentHash(file.content)] as const)
    );

    const refreshedEntries = manifest.entries
        .filter((entry) => fileHashByPath.has(entry.path))
        .map((entry) => {
            const currentContentHash = fileHashByPath.get(entry.path);
            if (!currentContentHash || currentContentHash === entry.contentHash) {
                return entry;
            }

            return {
                ...entry,
                contentHash: currentContentHash,
                reviewedAt: new Date().toISOString().slice(0, 10),
            };
        });

    const nextManifest: ReviewManifestFile = { entries: refreshedEntries };
    saveReviewManifest(rootDir, nextManifest);
    return nextManifest;
}

export function annotateReviewCategories(input: {
    rootDir: string;
    sourceFiles: AuditSourceFile[];
    categories: AuditCategoryReport[];
}): AuditCategoryReport[] {
    const manifest = loadReviewManifest(input.rootDir);
    const manifestEntries = new Map(
        manifest.entries.map((entry) => [buildManifestKey(entry), entry] as const)
    );
    const fileHashByPath = new Map(
        input.sourceFiles.map((file) => [file.relativePath, buildContentHash(file.content)] as const)
    );

    return input.categories.map((category) => {
        if (category.lane !== 'manual-review' && category.lane !== 'actionable-review') {
            return category;
        }

        const reviewedViolations: ReviewedAuditViolation[] = category.violations.map((violation) => {
            const contentHash = fileHashByPath.get(violation.path) ?? '';
            const manifestEntry = manifestEntries.get(
                buildManifestKey({ path: violation.path, category: category.key })
            );
            const reviewMetadata = classifyReviewStatus(manifestEntry, contentHash);

            return {
                ...violation,
                contentHash,
                ...reviewMetadata,
            };
        });

        return {
            ...category,
            violations: reviewedViolations,
        };
    });
}

import ts from 'typescript';

import { isRendererSourceFile, isTestFile } from '../sourceFiles';
import type { AuditSourceFile, AuditViolation } from '../types';

function getLineNumber(sourceFile: ts.SourceFile, node: ts.Node): number {
    return sourceFile.getLineAndCharacterOfPosition(node.getStart(sourceFile)).line + 1;
}

function pushUniqueViolation(target: AuditViolation[], nextViolation: AuditViolation): void {
    const alreadyExists = target.some(
        (violation) =>
            violation.path === nextViolation.path &&
            violation.line === nextViolation.line &&
            violation.message === nextViolation.message
    );
    if (!alreadyExists) {
        target.push(nextViolation);
    }
}

type NamedAsyncDeclaration =
    | ts.FunctionDeclaration
    | ts.ArrowFunction
    | ts.FunctionExpression;

function collectNamedAsyncDeclarations(sourceFile: ts.SourceFile): Map<string, NamedAsyncDeclaration> {
    const asyncDeclarations = new Map<string, NamedAsyncDeclaration>();

    function visit(node: ts.Node): void {
        if (
            ts.isFunctionDeclaration(node) &&
            node.name &&
            node.modifiers?.some((modifier) => modifier.kind === ts.SyntaxKind.AsyncKeyword)
        ) {
            asyncDeclarations.set(node.name.text, node);
        }

        if (ts.isVariableDeclaration(node) && ts.isIdentifier(node.name) && node.initializer) {
            if (
                (ts.isArrowFunction(node.initializer) || ts.isFunctionExpression(node.initializer)) &&
                node.initializer.modifiers?.some((modifier) => modifier.kind === ts.SyntaxKind.AsyncKeyword)
            ) {
                asyncDeclarations.set(node.name.text, node.initializer);
            }
        }

        ts.forEachChild(node, visit);
    }

    visit(sourceFile);
    return asyncDeclarations;
}

function getPropertyAccessName(callExpression: ts.CallExpression): string | undefined {
    if (ts.isPropertyAccessExpression(callExpression.expression)) {
        return callExpression.expression.name.text;
    }

    return undefined;
}

function isPromiseChainHandled(callExpression: ts.CallExpression): boolean {
    const propertyAccessName = getPropertyAccessName(callExpression);
    if (propertyAccessName === 'catch') {
        return true;
    }

    if (propertyAccessName === 'then' && callExpression.arguments.length >= 2) {
        return true;
    }

    if (propertyAccessName === 'finally' && ts.isPropertyAccessExpression(callExpression.expression)) {
        const chainRoot = callExpression.expression.expression;
        if (ts.isCallExpression(chainRoot)) {
            return isPromiseChainHandled(chainRoot);
        }
    }

    return false;
}

function containsMissingSentinel(node: ts.Node): boolean {
    if (ts.isStringLiteralLike(node)) {
        return node.text.endsWith('_missing');
    }

    if (ts.isIdentifier(node)) {
        return node.text.includes('MISSING') || node.text.endsWith('MissingId');
    }

    let foundMissingSentinel = false;
    ts.forEachChild(node, (childNode) => {
        if (!foundMissingSentinel && containsMissingSentinel(childNode)) {
            foundMissingSentinel = true;
        }
    });

    return foundMissingSentinel;
}

function containsCallSiteCast(node: ts.Node): boolean {
    if (ts.isAsExpression(node) || ts.isTypeAssertionExpression(node)) {
        return true;
    }

    let foundCallSiteCast = false;
    ts.forEachChild(node, (childNode) => {
        if (!foundCallSiteCast && containsCallSiteCast(childNode)) {
            foundCallSiteCast = true;
        }
    });

    return foundCallSiteCast;
}

function isQueryLikeCall(callExpression: ts.CallExpression): boolean {
    const propertyAccessName = getPropertyAccessName(callExpression);
    if (!propertyAccessName) {
        return false;
    }

    return (
        propertyAccessName === 'useQuery' ||
        propertyAccessName === 'useInfiniteQuery' ||
        propertyAccessName === 'prefetch' ||
        propertyAccessName === 'prefetchQuery' ||
        propertyAccessName === 'ensureQueryData'
    );
}

function isBoundaryCall(callExpression: ts.CallExpression): boolean {
    const propertyAccessName = getPropertyAccessName(callExpression);
    if (!propertyAccessName) {
        return false;
    }

    return new Set([
        'useQuery',
        'useInfiniteQuery',
        'prefetch',
        'prefetchQuery',
        'ensureQueryData',
        'mutate',
        'mutateAsync',
        'invalidate',
        'invalidateQueries',
        'refetch',
    ]).has(propertyAccessName);
}

function isKnownRiskyCall(callExpression: ts.CallExpression): boolean {
    const propertyAccessName = getPropertyAccessName(callExpression);
    if (propertyAccessName === 'mutateAsync' || propertyAccessName === 'refetch') {
        return true;
    }

    if (
        ts.isPropertyAccessExpression(callExpression.expression) &&
        callExpression.expression.getText() === 'navigator.clipboard.writeText'
    ) {
        return true;
    }

    return false;
}

function functionBodyCanRejectOutward(
    declaration: NamedAsyncDeclaration,
    asyncDeclarations: Map<string, NamedAsyncDeclaration>,
    seenDeclarations: Set<string>
): boolean {
    const declarationName =
        ts.isFunctionDeclaration(declaration) && declaration.name
            ? declaration.name.text
            : declaration.parent && ts.isVariableDeclaration(declaration.parent) && ts.isIdentifier(declaration.parent.name)
              ? declaration.parent.name.text
              : undefined;

    if (declarationName && seenDeclarations.has(declarationName)) {
        return false;
    }

    const nextSeenDeclarations = new Set(seenDeclarations);
    if (declarationName) {
        nextSeenDeclarations.add(declarationName);
    }

    if (!declaration.body || !ts.isBlock(declaration.body)) {
        return true;
    }

    function nodeCanRejectOutward(node: ts.Node, protectedByCatch: boolean): boolean {
        if (ts.isTryStatement(node) && node.catchClause) {
            if (nodeCanRejectOutward(node.tryBlock, true)) {
                return true;
            }

            if (node.finallyBlock && nodeCanRejectOutward(node.finallyBlock, protectedByCatch)) {
                return true;
            }

            return false;
        }

        if ((ts.isAwaitExpression(node) || ts.isReturnStatement(node) || ts.isExpressionStatement(node)) && protectedByCatch) {
            let childCanReject = false;
            ts.forEachChild(node, (childNode) => {
                if (!childCanReject && nodeCanRejectOutward(childNode, true)) {
                    childCanReject = true;
                }
            });
            return childCanReject;
        }

        if (ts.isCallExpression(node)) {
            if (isKnownRiskyCall(node)) {
                return !protectedByCatch;
            }

            if (getPropertyAccessName(node) === 'then' && !isPromiseChainHandled(node)) {
                return !protectedByCatch;
            }

            if (ts.isIdentifier(node.expression)) {
                const localAsyncDeclaration = asyncDeclarations.get(node.expression.text);
                if (localAsyncDeclaration) {
                    return functionBodyCanRejectOutward(
                        localAsyncDeclaration,
                        asyncDeclarations,
                        nextSeenDeclarations
                    );
                }
            }
        }

        let childCanReject = false;
        ts.forEachChild(node, (childNode) => {
            if (!childCanReject && nodeCanRejectOutward(childNode, protectedByCatch)) {
                childCanReject = true;
            }
        });

        return childCanReject;
    }

    return nodeCanRejectOutward(declaration.body, false);
}

export function collectAsyncOwnershipViolations(files: AuditSourceFile[]): AuditViolation[] {
    const violations: AuditViolation[] = [];

    for (const file of files) {
        if (isTestFile(file.relativePath) || !isRendererSourceFile(file.relativePath)) {
            continue;
        }

        const sourceFile = ts.createSourceFile(
            file.relativePath,
            file.content,
            ts.ScriptTarget.Latest,
            true,
            ts.ScriptKind.TSX
        );
        const asyncDeclarations = collectNamedAsyncDeclarations(sourceFile);

        function visit(node: ts.Node): void {
            if (ts.isVoidExpression(node) && ts.isCallExpression(node.expression)) {
                const callExpression = node.expression;
                const propertyAccessName = getPropertyAccessName(callExpression);

                const discardsAsyncMutation = propertyAccessName === 'mutateAsync' || propertyAccessName === 'refetch';
                const discardsUnhandledThen = propertyAccessName === 'then' && !isPromiseChainHandled(callExpression);
                const discardsRejectingLocalAsyncCall =
                    ts.isIdentifier(callExpression.expression) &&
                    (() => {
                        const localAsyncDeclaration = asyncDeclarations.get(callExpression.expression.text);
                        if (!localAsyncDeclaration) {
                            return false;
                        }

                        return functionBodyCanRejectOutward(localAsyncDeclaration, asyncDeclarations, new Set());
                    })();

                if (discardsAsyncMutation || discardsUnhandledThen || discardsRejectingLocalAsyncCall) {
                    pushUniqueViolation(violations, {
                        path: file.relativePath,
                        line: getLineNumber(sourceFile, node),
                        message: 'Review discarded async action and own the rejection path with await/catch or a fail-closed helper.',
                    });
                }
            }

            ts.forEachChild(node, visit);
        }

        visit(sourceFile);
    }

    return violations;
}

export function collectPlaceholderQueryInputViolations(files: AuditSourceFile[]): AuditViolation[] {
    const violations: AuditViolation[] = [];

    for (const file of files) {
        if (isTestFile(file.relativePath) || !isRendererSourceFile(file.relativePath)) {
            continue;
        }

        const sourceFile = ts.createSourceFile(
            file.relativePath,
            file.content,
            ts.ScriptTarget.Latest,
            true,
            ts.ScriptKind.TSX
        );

        function visit(node: ts.Node): void {
            if (ts.isCallExpression(node) && isQueryLikeCall(node) && node.arguments.some((argument) => containsMissingSentinel(argument))) {
                pushUniqueViolation(violations, {
                    path: file.relativePath,
                    line: getLineNumber(sourceFile, node),
                    message: 'Review placeholder query input and replace fake sentinel IDs with skipToken or mounted-only query ownership.',
                });
            }

            ts.forEachChild(node, visit);
        }

        visit(sourceFile);
    }

    return violations;
}

export function collectCallSiteCastViolations(files: AuditSourceFile[]): AuditViolation[] {
    const violations: AuditViolation[] = [];

    for (const file of files) {
        if (isTestFile(file.relativePath) || !isRendererSourceFile(file.relativePath)) {
            continue;
        }

        const sourceFile = ts.createSourceFile(
            file.relativePath,
            file.content,
            ts.ScriptTarget.Latest,
            true,
            ts.ScriptKind.TSX
        );

        function visit(node: ts.Node): void {
            if (ts.isCallExpression(node) && isBoundaryCall(node) && node.arguments.some((argument) => containsCallSiteCast(argument))) {
                pushUniqueViolation(violations, {
                    path: file.relativePath,
                    line: getLineNumber(sourceFile, node),
                    message: 'Review call-site cast at a query or mutation boundary and replace it with validated narrowing before the call.',
                });
            }

            ts.forEachChild(node, visit);
        }

        visit(sourceFile);
    }

    return violations;
}

import { existsSync, readdirSync, readFileSync, statSync } from 'node:fs';
import path from 'node:path';

import type { AuditSourceFile } from './types';

const SOURCE_FILE_EXTENSIONS = new Set(['.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs']);
const REPOSITORY_TEXT_FILE_EXTENSIONS = new Set([
    '.ts',
    '.tsx',
    '.js',
    '.jsx',
    '.mjs',
    '.cjs',
    '.md',
    '.json',
    '.json5',
    '.yml',
    '.yaml',
]);
const SKIPPED_DIRECTORIES = new Set(['node_modules', 'dist', 'dist-electron', '.git', '.turbo', 'release']);
const SOURCE_ROOT_DIRECTORIES = ['src', 'electron', 'scripts'];

function normalizeRelativePath(rootDir: string, absolutePath: string): string {
    return path.relative(rootDir, absolutePath).replaceAll('\\', '/');
}

function shouldSkipDirectory(name: string): boolean {
    return SKIPPED_DIRECTORIES.has(name);
}

function isSourceFile(absolutePath: string): boolean {
    return SOURCE_FILE_EXTENSIONS.has(path.extname(absolutePath));
}

function isRepositoryTextFile(absolutePath: string): boolean {
    return REPOSITORY_TEXT_FILE_EXTENSIONS.has(path.extname(absolutePath));
}

export function isTestFile(relativePath: string): boolean {
    return (
        relativePath.includes('/__tests__/') ||
        relativePath.endsWith('.test.ts') ||
        relativePath.endsWith('.test.tsx') ||
        relativePath.endsWith('.test.js') ||
        relativePath.endsWith('.test.jsx') ||
        relativePath.endsWith('.spec.ts') ||
        relativePath.endsWith('.spec.tsx') ||
        relativePath.endsWith('.spec.js') ||
        relativePath.endsWith('.spec.jsx')
    );
}

export function isGeneratedSourceFile(relativePath: string, content: string): boolean {
    const fileName = path.basename(relativePath).toLowerCase();
    return (
        relativePath.includes('/__generated__/') ||
        relativePath.includes('/generated/') ||
        fileName.startsWith('generated') ||
        fileName.includes('.gen.') ||
        fileName.includes('.generated.') ||
        content.includes('@generated')
    );
}

export function isCanonicalAlphaBaselineMigration(relativePath: string): boolean {
    return relativePath === 'electron/backend/persistence/migrations/001_runtime_baseline.sql';
}

export function isSizeReviewException(relativePath: string, content: string): boolean {
    return isGeneratedSourceFile(relativePath, content) || isCanonicalAlphaBaselineMigration(relativePath);
}

export function isParserSourceFile(relativePath: string): boolean {
    return relativePath.includes('/parsers/') || relativePath.includes('/parse/');
}

export function isRendererSourceFile(relativePath: string): boolean {
    return relativePath.startsWith('src/');
}

export function isPreloadSourceFile(relativePath: string): boolean {
    return relativePath.startsWith('electron/main/preload/');
}

export function isElectronSourceFile(relativePath: string): boolean {
    return relativePath.startsWith('electron/');
}

function collectFilesFromRoots(input: {
    rootDir: string;
    roots: string[];
    shouldIncludeFile: (absolutePath: string) => boolean;
}): AuditSourceFile[] {
    const files: AuditSourceFile[] = [];
    const seenAbsolutePaths = new Set<string>();

    function walk(currentDirectory: string): void {
        for (const entry of readdirSync(currentDirectory, { withFileTypes: true })) {
            if (entry.isDirectory()) {
                if (shouldSkipDirectory(entry.name)) {
                    continue;
                }

                walk(path.join(currentDirectory, entry.name));
                continue;
            }

            const absolutePath = path.join(currentDirectory, entry.name);
            if (!input.shouldIncludeFile(absolutePath) || seenAbsolutePaths.has(absolutePath)) {
                continue;
            }

            const content = readFileSync(absolutePath, 'utf8');
            const relativePath = normalizeRelativePath(input.rootDir, absolutePath);
            const lineCount = content.length === 0 ? 0 : content.split(/\r?\n/).length;
            seenAbsolutePaths.add(absolutePath);

            files.push({
                absolutePath,
                relativePath,
                content,
                lineCount,
            });
        }
    }

    for (const absoluteRoot of input.roots) {
        try {
            if (!existsSync(absoluteRoot)) {
                continue;
            }

            const rootStat = statSync(absoluteRoot);
            if (rootStat.isDirectory()) {
                walk(absoluteRoot);
                continue;
            }

            if (!input.shouldIncludeFile(absoluteRoot) || seenAbsolutePaths.has(absoluteRoot)) {
                continue;
            }

            const content = readFileSync(absoluteRoot, 'utf8');
            const relativePath = normalizeRelativePath(input.rootDir, absoluteRoot);
            const lineCount = content.length === 0 ? 0 : content.split(/\r?\n/).length;
            seenAbsolutePaths.add(absoluteRoot);

            files.push({
                absolutePath: absoluteRoot,
                relativePath,
                content,
                lineCount,
            });
        } catch (error) {
            if (
                typeof error === 'object' &&
                error !== null &&
                'code' in error &&
                error.code === 'ENOENT'
            ) {
                continue;
            }

            throw error;
        }
    }

    return files;
}

function resolveRepositoryRoot(rootDir: string): string {
    const parentDir = path.resolve(rootDir, '..');
    const parentMarkers = ['AGENTS.md', '.git', 'Markdown', '.github'];
    return parentMarkers.some((marker) => existsSync(path.join(parentDir, marker))) ? parentDir : rootDir;
}

export function collectSourceFiles(rootDir: string): AuditSourceFile[] {
    return collectFilesFromRoots({
        rootDir,
        roots: SOURCE_ROOT_DIRECTORIES.map((sourceRoot) => path.join(rootDir, sourceRoot)),
        shouldIncludeFile: isSourceFile,
    });
}

export function collectRepositoryTextFiles(rootDir: string): AuditSourceFile[] {
    const repositoryRoot = resolveRepositoryRoot(rootDir);
    const roots = [rootDir];

    if (repositoryRoot !== rootDir) {
        roots.push(
            path.join(repositoryRoot, 'AGENTS.md'),
            path.join(repositoryRoot, 'CLAUDE.md'),
            path.join(repositoryRoot, 'Markdown'),
            path.join(repositoryRoot, '.github'),
            path.join(repositoryRoot, 'README.md')
        );
    }

    return collectFilesFromRoots({
        rootDir,
        roots,
        shouldIncludeFile: isRepositoryTextFile,
    });
}

