import { useState } from 'react';

import type { ConversationUiState } from '@/web/components/conversation/hooks/useConversationUiState';
import type { MessageFlowMessage } from '@/web/components/conversation/messages/messageFlowModel';
import { buildBranchSelectionTransition } from '@/web/components/conversation/shell/editFlowSelection';
import { toBranchFailureMessage } from '@/web/components/conversation/shell/editFlow';
import { isEntityId } from '@/web/components/conversation/shell/workspace/helpers';
import { trpc } from '@/web/trpc/client';

import type {
    SessionBranchFromMessageInput,
    SessionBranchFromMessageWithWorkflowInput,
} from '@/app/backend/runtime/contracts';
import type { SessionSummaryRecord, ThreadListRecord } from '@/app/backend/persistence/types';

import type { EntityId, TopLevelTab } from '@/shared/contracts';

interface PendingBranchWorkflowSelection {
    messageId: EntityId<'msg'>;
    workspaceFingerprint: string;
}

interface UseConversationShellBranchWorkflowFlowInput {
    profileId: string;
    topLevelTab: TopLevelTab;
    modeKey: string;
    selectedSessionId: string | undefined;
    selectedThread: ThreadListRecord | undefined;
    uiState: ConversationUiState;
    branchFromMessage: (input: SessionBranchFromMessageInput) => Promise<
        | { branched: false; reason: string }
        | {
              branched: true;
              sourceSessionId: string;
              sessionId: string;
              session: SessionSummaryRecord;
              sourceThreadId: string;
              threadId: string;
              thread: ThreadListRecord;
              topLevelTab: TopLevelTab;
          }
    >;
    branchFromMessageWithWorkflow: (input: SessionBranchFromMessageWithWorkflowInput) => Promise<
        | { branched: false; reason: string }
        | {
              branched: true;
              sourceSessionId: string;
              sessionId: string;
              session: SessionSummaryRecord;
              sourceThreadId: string;
              threadId: string;
              thread: ThreadListRecord;
              topLevelTab: TopLevelTab;
              workflowExecution:
                  | { status: 'not_requested' }
                  | { status: 'succeeded' }
                  | { status: 'approval_required'; requestId: string; message: string }
                  | { status: 'failed'; message: string };
          }
    >;
    onTopLevelTabChange: (nextTab: TopLevelTab) => void;
    onClearError: () => void;
    onError: (message: string) => void;
    onPromptReset: () => void;
    onComposerFocusRequest: () => void;
    onSessionEdited: (input: {
        sessionId: string;
        session: SessionSummaryRecord;
        thread?: ThreadListRecord;
    }) => void;
}

export function shouldUseWorkflowBranchChooser(input: {
    topLevelTab: TopLevelTab;
    selectedThread: ThreadListRecord | undefined;
}): input is {
    topLevelTab: 'agent' | 'orchestrator';
    selectedThread: ThreadListRecord & {
        scope: 'workspace';
        workspaceFingerprint: string;
    };
} {
    return (
        (input.topLevelTab === 'agent' || input.topLevelTab === 'orchestrator') &&
        input.selectedThread?.scope === 'workspace' &&
        typeof input.selectedThread.workspaceFingerprint === 'string' &&
        input.selectedThread.workspaceFingerprint.length > 0
    );
}

function toWorkflowExecutionMessage(result: {
    workflowExecution:
        | { status: 'not_requested' }
        | { status: 'succeeded' }
        | { status: 'approval_required'; requestId: string; message: string }
        | { status: 'failed'; message: string };
}): string | undefined {
    if (result.workflowExecution.status === 'approval_required') {
        return `Branch created. ${result.workflowExecution.message}`;
    }
    if (result.workflowExecution.status === 'failed') {
        return `Branch created, but the workflow failed: ${result.workflowExecution.message}`;
    }

    return undefined;
}

export function useConversationShellBranchWorkflowFlow(input: UseConversationShellBranchWorkflowFlowInput) {
    const [pendingBranchSelection, setPendingBranchSelection] = useState<PendingBranchWorkflowSelection | undefined>(
        undefined
    );
    const utils = trpc.useUtils();

    const applyBranchSelection = (result: {
        sessionId: string;
        threadId: string;
        topLevelTab: TopLevelTab;
        session: SessionSummaryRecord;
        thread: ThreadListRecord;
    }) => {
        const selectionTransition = buildBranchSelectionTransition({
            currentTopLevelTab: input.topLevelTab,
            result,
        });

        if (selectionTransition.selectedThreadId) {
            input.uiState.setSelectedThreadId(selectionTransition.selectedThreadId);
        }
        if (selectionTransition.nextTopLevelTab) {
            input.onTopLevelTabChange(selectionTransition.nextTopLevelTab);
        }
        input.uiState.setSelectedSessionId(selectionTransition.selectedSessionId);
        input.uiState.setSelectedRunId(undefined);
        input.onPromptReset();
        input.onComposerFocusRequest();
        input.onSessionEdited({
            sessionId: result.sessionId,
            session: result.session,
            thread: result.thread,
        });
    };

    const runPlainBranch = async (messageId: EntityId<'msg'>) => {
        if (!isEntityId(input.selectedSessionId, 'sess')) {
            input.onError('Select a session before creating a branch.');
            return;
        }

        input.onClearError();
        try {
            const result = await input.branchFromMessage({
                profileId: input.profileId,
                sessionId: input.selectedSessionId,
                topLevelTab: input.topLevelTab,
                messageId,
            });
            if (!result.branched) {
                input.onError(toBranchFailureMessage(result.reason));
                return;
            }

            applyBranchSelection(result);
        } catch (error) {
            const message = error instanceof Error ? error.message : String(error);
            input.onError(`Branch failed: ${message}`);
        }
    };

    const selectedWorkflowSessionId = isEntityId(input.selectedSessionId, 'sess') ? input.selectedSessionId : undefined;
    const workflowDialogProps =
        pendingBranchSelection && selectedWorkflowSessionId
            ? {
                  open: true,
                  profileId: input.profileId,
                  workspaceFingerprint: pendingBranchSelection.workspaceFingerprint,
                  onClose: () => {
                      setPendingBranchSelection(undefined);
                  },
                  onBranch: async (workflowId?: string) => {
                      input.onClearError();
                      const result = await input.branchFromMessageWithWorkflow({
                          profileId: input.profileId,
                          sessionId: selectedWorkflowSessionId,
                          topLevelTab: input.topLevelTab,
                          messageId: pendingBranchSelection.messageId,
                          modeKey: input.modeKey,
                          ...(workflowId ? { workflowId } : {}),
                      });
                      if (!result.branched) {
                          input.onError(toBranchFailureMessage(result.reason));
                          return;
                      }

                      setPendingBranchSelection(undefined);
                      applyBranchSelection(result);
                      const workflowExecutionMessage = toWorkflowExecutionMessage(result);
                      if (workflowExecutionMessage) {
                          input.onError(workflowExecutionMessage);
                          if (result.workflowExecution.status === 'approval_required') {
                              await utils.permission.listPending.invalidate();
                          }
                          return;
                      }
                      input.onClearError();
                  },
              }
            : {
                  open: false,
                  profileId: input.profileId,
                  workspaceFingerprint: '',
                  onClose: () => undefined,
                  onBranch: async () => undefined,
              };

    return {
        onBranchFromMessage: (entry: MessageFlowMessage) => {
            if (!isEntityId(entry.id, 'msg')) {
                input.onError('Select a message before creating a branch.');
                return;
            }
            if (!isEntityId(input.selectedSessionId, 'sess')) {
                input.onError('Select a session before creating a branch.');
                return;
            }

            const selectedThread = input.selectedThread;
            if (
                selectedThread &&
                shouldUseWorkflowBranchChooser({
                    topLevelTab: input.topLevelTab,
                    selectedThread,
                })
            ) {
                const workspaceFingerprint = selectedThread.workspaceFingerprint;
                if (!workspaceFingerprint) {
                    input.onError('Select a workspace-bound session before creating a workflow branch.');
                    return;
                }
                setPendingBranchSelection({
                    messageId: entry.id,
                    workspaceFingerprint,
                });
                input.onClearError();
                return;
            }

            void runPlainBranch(entry.id);
        },
        dialogProps: workflowDialogProps,
    };
}

import { err, ok } from 'neverthrow';
import { describe, expect, it, vi } from 'vitest';

import { preparePendingComposerImage } from '@/web/components/conversation/hooks/useConversationShellComposer';
import { composerImageCompressionError } from '@/web/components/conversation/hooks/composerImageCompressionErrors';

describe('preparePendingComposerImage', () => {
    it('marks the image failed and progresses the queue when preparation throws', async () => {
        const onPreparedImage = vi.fn();
        const onFailedImage = vi.fn();
        const onAttachmentError = vi.fn();
        const onQueueProgressed = vi.fn();

        await preparePendingComposerImage({
            clientId: 'client_1',
            sourceFile: new File(['image'], 'broken.png', { type: 'image/png' }),
            prepareImageAttachment: vi.fn(() => Promise.reject(new Error('Worker crashed.'))),
            onPreparedImage,
            onFailedImage,
            onAttachmentError,
            onQueueProgressed,
        });

        expect(onPreparedImage).not.toHaveBeenCalled();
        expect(onFailedImage).toHaveBeenCalledWith('client_1', 'Worker crashed.');
        expect(onAttachmentError).toHaveBeenCalledWith('Worker crashed.');
        expect(onQueueProgressed).toHaveBeenCalledOnce();
    });

    it('keeps the success path intact and still progresses the queue', async () => {
        const prepared = {
            attachment: {
                clientId: 'client_1',
                mimeType: 'image/png' as const,
                bytesBase64: 'aGVsbG8=',
                width: 1,
                height: 1,
                sha256: 'abc',
            },
            byteSize: 5,
            previewUrl: 'blob:preview',
        };
        const onPreparedImage = vi.fn();
        const onFailedImage = vi.fn();
        const onAttachmentError = vi.fn();
        const onQueueProgressed = vi.fn();

        await preparePendingComposerImage({
            clientId: 'client_1',
            sourceFile: new File(['image'], 'ok.png', { type: 'image/png' }),
            prepareImageAttachment: vi.fn(() => Promise.resolve(ok(prepared))),
            onPreparedImage,
            onFailedImage,
            onAttachmentError,
            onQueueProgressed,
        });

        expect(onPreparedImage).toHaveBeenCalledWith('client_1', prepared);
        expect(onFailedImage).not.toHaveBeenCalled();
        expect(onAttachmentError).not.toHaveBeenCalled();
        expect(onQueueProgressed).toHaveBeenCalledOnce();
    });

    it('converts typed compression failures into failed pending images', async () => {
        const onPreparedImage = vi.fn();
        const onFailedImage = vi.fn();
        const onAttachmentError = vi.fn();
        const onQueueProgressed = vi.fn();

        await preparePendingComposerImage({
            clientId: 'client_1',
            sourceFile: new File(['image'], 'too-large.png', { type: 'image/png' }),
            prepareImageAttachment: vi.fn(() =>
                Promise.resolve(
                    err(composerImageCompressionError('size_limit_exceeded', 'Image is too large.'))
                )
            ),
            onPreparedImage,
            onFailedImage,
            onAttachmentError,
            onQueueProgressed,
        });

        expect(onPreparedImage).not.toHaveBeenCalled();
        expect(onFailedImage).toHaveBeenCalledWith('client_1', 'Image is too large.');
        expect(onAttachmentError).toHaveBeenCalledWith('Image is too large.');
        expect(onQueueProgressed).toHaveBeenCalledOnce();
    });
});

import { useEffect, useRef, useState } from 'react';

import {
    type PreparedComposerImageAttachment,
    createPendingImage,
    prepareComposerImageAttachment,
    releasePendingImageResources,
    type ComposerPendingImage,
} from '@/web/components/conversation/hooks/composerImageAttachments';
import {
    failComposerPendingImage,
    pumpComposerPendingImages,
    queueComposerPendingImageForRetry,
    resolvePreparedComposerPendingImage,
} from '@/web/components/conversation/hooks/conversationComposerPendingImageQueue';
import type { OptimisticConversationUserMessage } from '@/web/components/conversation/messages/optimisticUserMessage';
import { submitPrompt as submitPromptFromComposer } from '@/web/components/conversation/shell/actions/promptSubmit';

import type {
    EntityId,
    PlanStartInput,
    PlanRecordView,
    RuntimeProviderId,
    RuntimeRunOptions,
    SessionStartRunInput,
    TopLevelTab,
} from '@/shared/contracts';

interface ProviderAuthView {
    label: string;
    authState: string;
    authMethod: string;
}

interface UseConversationShellComposerInput<
    TPlanStartResult extends { plan: PlanRecordView },
    TRunStartAcceptedResult extends { accepted: true },
    TRunStartRejectedResult extends { accepted: false; message?: string },
> {
    profileId: string;
    selectedSessionId: string | undefined;
    isPlanningMode: boolean;
    topLevelTab: TopLevelTab;
    modeKey: string;
    workspaceFingerprint: string | undefined;
    sandboxId?: EntityId<'sb'>;
    resolvedRunTarget:
        | {
              providerId: RuntimeProviderId;
              modelId: string;
          }
        | undefined;
    providerById: Map<RuntimeProviderId, ProviderAuthView>;
    runtimeOptions: RuntimeRunOptions;
    isStartingRun: boolean;
    canAttachImages: boolean;
    maxImageAttachmentsPerMessage: number;
    imageCompressionConcurrency: number;
    imageAttachmentBlockedReason?: string;
    submitBlockedReason?: string;
    startPlan: (input: PlanStartInput) => Promise<TPlanStartResult>;
    startRun: (input: SessionStartRunInput) => Promise<TRunStartAcceptedResult | TRunStartRejectedResult>;
    onPlanStarted: (result: TPlanStartResult) => void;
    onRunStarted: (result: TRunStartAcceptedResult) => void;
}

function readComposerImagePreparationErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : 'Image preparation failed.';
}

export async function preparePendingComposerImage(input: {
    clientId: string;
    sourceFile: File;
    prepareImageAttachment: typeof prepareComposerImageAttachment;
    onPreparedImage: (clientId: string, prepared: PreparedComposerImageAttachment) => void;
    onFailedImage: (clientId: string, message: string) => void;
    onAttachmentError: (message: string) => void;
    onQueueProgressed: () => void;
}): Promise<void> {
    try {
        const preparedResult = await input.prepareImageAttachment(input.sourceFile, input.clientId);
        if (preparedResult.isErr()) {
            const message = preparedResult.error.message;
            input.onFailedImage(input.clientId, message);
            input.onAttachmentError(message);
            return;
        }

        input.onPreparedImage(input.clientId, preparedResult.value);
    } catch (error) {
        const message = readComposerImagePreparationErrorMessage(error);
        input.onFailedImage(input.clientId, message);
        input.onAttachmentError(message);
    } finally {
        input.onQueueProgressed();
    }
}

export function useConversationShellComposer<
    TPlanStartResult extends { plan: PlanRecordView },
    TRunStartAcceptedResult extends { accepted: true },
    TRunStartRejectedResult extends { accepted: false; message?: string },
>(input: UseConversationShellComposerInput<TPlanStartResult, TRunStartAcceptedResult, TRunStartRejectedResult>) {
    const [pendingImages, setPendingImages] = useState<ComposerPendingImage[]>([]);
    const [optimisticUserMessage, setOptimisticUserMessage] = useState<OptimisticConversationUserMessage | undefined>(
        undefined
    );
    const [runSubmitError, setRunSubmitError] = useState<string | undefined>(undefined);
    const [promptResetKey, setPromptResetKey] = useState(0);
    const pendingImagesRef = useRef<ComposerPendingImage[]>([]);
    const promptRef = useRef('');

    useEffect(() => {
        return () => {
            for (const image of pendingImagesRef.current) {
                releasePendingImageResources(image);
            }
        };
    }, []);

    function replacePendingImages(nextImages: ComposerPendingImage[]) {
        pendingImagesRef.current = nextImages;
        setPendingImages(nextImages);
    }

    function updatePendingImages(updater: (current: ComposerPendingImage[]) => ComposerPendingImage[]) {
        const nextImages = updater(pendingImagesRef.current);
        replacePendingImages(nextImages);
        return nextImages;
    }

    function clearPendingImages() {
        for (const image of pendingImagesRef.current) {
            releasePendingImageResources(image);
        }
        replacePendingImages([]);
    }

    function failImageAttachment(message: string) {
        setRunSubmitError(message);
    }

    function pumpPendingImageCompressionQueue() {
        const pumpResult = pumpComposerPendingImages(pendingImagesRef.current, input.imageCompressionConcurrency);
        if (pumpResult.imagesToStart.length === 0) {
            return;
        }

        replacePendingImages(pumpResult.nextImages);
        for (const image of pumpResult.imagesToStart) {
            startCompressingImage(image.clientId, image.sourceFile);
        }
    }

    function resolvePreparedImage(clientId: string, prepared: PreparedComposerImageAttachment) {
        let replacedImage: ComposerPendingImage | undefined;
        let errorMessage: string | undefined;

        updatePendingImages((current) => {
            const preparedResult = resolvePreparedComposerPendingImage(current, clientId, prepared);
            replacedImage = preparedResult.replacedImage;
            errorMessage = preparedResult.errorMessage;
            return preparedResult.nextImages;
        });

        if (replacedImage) {
            releasePendingImageResources(replacedImage);
        }
        if (errorMessage) {
            failImageAttachment(errorMessage);
        }
    }

    function startCompressingImage(clientId: string, sourceFile: File) {
        preparePendingComposerImage({
            clientId,
            sourceFile,
            prepareImageAttachment: prepareComposerImageAttachment,
            onPreparedImage: resolvePreparedImage,
            onFailedImage: (failedClientId, message) => {
                updatePendingImages((current) => failComposerPendingImage(current, failedClientId, message));
            },
            onAttachmentError: failImageAttachment,
            onQueueProgressed: pumpPendingImageCompressionQueue,
        });
    }

    function onAddImageFiles(inputFiles: FileList | File[]) {
        setRunSubmitError(undefined);

        if (!input.canAttachImages) {
            failImageAttachment(
                input.imageAttachmentBlockedReason ?? 'Select a vision-capable run target to attach images.'
            );
            return;
        }

        const allFiles = Array.from(inputFiles);
        const imageFiles = allFiles.filter((file) => file.type.startsWith('image/'));
        if (imageFiles.length === 0) {
            failImageAttachment('Only image files can be attached to a prompt.');
            return;
        }

        const availableSlots = Math.max(0, input.maxImageAttachmentsPerMessage - pendingImagesRef.current.length);
        if (availableSlots === 0) {
            failImageAttachment(
                `You can attach up to ${String(input.maxImageAttachmentsPerMessage)} images per message.`
            );
            return;
        }

        const acceptedFiles = imageFiles.slice(0, availableSlots);
        if (acceptedFiles.length < imageFiles.length) {
            failImageAttachment(`Only the first ${String(input.maxImageAttachmentsPerMessage)} images were kept.`);
        }

        const nextImages = acceptedFiles.map((file) => createPendingImage(file));
        updatePendingImages((current) => [...current, ...nextImages]);
        pumpPendingImageCompressionQueue();
    }

    function removePendingImage(clientId: string) {
        setRunSubmitError(undefined);
        const removedImage = pendingImagesRef.current.find((candidate) => candidate.clientId === clientId);
        if (!removedImage) {
            return;
        }

        releasePendingImageResources(removedImage);
        replacePendingImages(pendingImagesRef.current.filter((candidate) => candidate.clientId !== clientId));
        pumpPendingImageCompressionQueue();
    }

    function retryPendingImage(clientId: string) {
        setRunSubmitError(undefined);
        const image = pendingImagesRef.current.find((candidate) => candidate.clientId === clientId);
        if (!image) {
            return;
        }

        updatePendingImages((current) => queueComposerPendingImageForRetry(current, clientId));
        pumpPendingImageCompressionQueue();
    }

    useEffect(() => {
        pumpPendingImageCompressionQueue();
    }, [input.imageCompressionConcurrency]);

    const readyAttachments = pendingImages.flatMap((image) =>
        image.status === 'ready' && image.attachment ? [image.attachment] : []
    );
    const hasBlockingPendingImages = pendingImages.some((image) => image.status !== 'ready');

    function createOptimisticUserMessage(
        sessionId: OptimisticConversationUserMessage['sessionId'],
        prompt: string
    ): OptimisticConversationUserMessage {
        const seed = `${Date.now()}_${Math.round(Math.random() * 1000)}`;
        return {
            id: `optimistic_msg_${seed}`,
            runId: `optimistic_run_${seed}`,
            sessionId,
            createdAt: new Date().toISOString(),
            prompt,
        };
    }

    return {
        pendingImages,
        optimisticUserMessage,
        promptResetKey,
        hasBlockingPendingImages,
        runSubmitError,
        setRunSubmitError,
        clearRunSubmitError: () => {
            setRunSubmitError(undefined);
        },
        resetComposer: () => {
            promptRef.current = '';
            setPromptResetKey((current) => current + 1);
            clearPendingImages();
            setRunSubmitError(undefined);
        },
        onPromptEdited: () => {
            setRunSubmitError(undefined);
        },
        onAddImageFiles,
        onRemovePendingImage: removePendingImage,
        onRetryPendingImage: retryPendingImage,
        onSubmitPrompt: (prompt: string) => {
            promptRef.current = prompt;
            const hasPromptContent = prompt.trim().length > 0;
            const hasSubmittableComposerContent = hasPromptContent || readyAttachments.length > 0;

            if (!hasSubmittableComposerContent) {
                return;
            }
            if (hasBlockingPendingImages) {
                failImageAttachment('Wait until all attached images are ready, or remove the failed ones.');
                return;
            }
            if (readyAttachments.length > 0 && !input.canAttachImages) {
                failImageAttachment(
                    input.imageAttachmentBlockedReason ?? 'Select a vision-capable run target to attach images.'
                );
                return;
            }
            if (input.submitBlockedReason) {
                setRunSubmitError(input.submitBlockedReason);
                return;
            }

            void submitPromptFromComposer<TPlanStartResult, TRunStartAcceptedResult>({
                prompt: promptRef.current,
                ...(readyAttachments.length > 0 ? { attachments: readyAttachments } : {}),
                isStartingRun: input.isStartingRun,
                selectedSessionId: input.selectedSessionId,
                isPlanningMode: input.isPlanningMode,
                profileId: input.profileId,
                topLevelTab: input.topLevelTab,
                modeKey: input.modeKey,
                workspaceFingerprint: input.workspaceFingerprint,
                ...(input.sandboxId ? { sandboxId: input.sandboxId } : {}),
                resolvedRunTarget: input.resolvedRunTarget,
                runtimeOptions: input.runtimeOptions,
                providerById: input.providerById,
                startPlan: input.startPlan,
                startRun: input.startRun,
                onPromptCleared: () => {
                    setRunSubmitError(undefined);
                    promptRef.current = '';
                    setPromptResetKey((current) => current + 1);
                    clearPendingImages();
                },
                onPlanStarted: (result) => {
                    input.onPlanStarted(result);
                },
                onRunStarted: (result) => {
                    setOptimisticUserMessage(undefined);
                    input.onRunStarted(result);
                },
                onRunStartRequested: ({ sessionId, prompt }) => {
                    setOptimisticUserMessage(createOptimisticUserMessage(sessionId, prompt));
                },
                onRunStartFinished: () => {
                    setOptimisticUserMessage(undefined);
                },
                onError: (message) => {
                    setOptimisticUserMessage(undefined);
                    setRunSubmitError(message);
                },
            });
        },
    };
}

