import { useState } from 'react';

import type { ConversationUiState } from '@/web/components/conversation/hooks/useConversationUiState';
import type { MessageFlowMessage } from '@/web/components/conversation/messages/messageFlowModel';
import { buildEditSelectionTransition } from '@/web/components/conversation/shell/editFlowSelection';
import {
    toEditFailureMessage,
    type PendingMessageEdit,
} from '@/web/components/conversation/shell/editFlow';
import { createPendingMessageEdit } from '@/web/components/conversation/shell/pendingMessageEdit';
import { isEntityId } from '@/web/components/conversation/shell/workspace/helpers';
import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { trpc } from '@/web/trpc/client';

import type { RunRecord, SessionSummaryRecord, ThreadListRecord } from '@/app/backend/persistence/types';

import type {
    RuntimeProviderId,
    RuntimeRunOptions,
    SessionEditInput,
    TopLevelTab,
} from '@/shared/contracts';

interface UseConversationShellEditFlowInput {
    profileId: string;
    topLevelTab: TopLevelTab;
    modeKey: string;
    selectedSessionId: string | undefined;
    selectedThread: ThreadListRecord | undefined;
    resolvedRunTarget:
        | {
              providerId: RuntimeProviderId;
              modelId: string;
          }
        | undefined;
    runtimeOptions: RuntimeRunOptions;
    editSession: (input: SessionEditInput) => Promise<
        | { edited: false; reason: string }
        | {
              edited: true;
              sessionId: string;
              session: SessionSummaryRecord;
              sourceSessionId: string;
              editMode: 'truncate' | 'branch';
              started: boolean;
              runId?: string;
              run?: RunRecord;
              thread?: ThreadListRecord;
              threadId?: string;
              topLevelTab?: TopLevelTab;
          }
    >;
    setEditPreference: (input: { profileId: string; value: 'truncate' | 'branch' }) => Promise<void>;
    uiState: ConversationUiState;
    onTopLevelTabChange: (nextTab: TopLevelTab) => void;
    onClearError: () => void;
    onError: (message: string) => void;
    onPromptReset: () => void;
    onComposerFocusRequest: () => void;
    onSessionEdited: (input: {
        sessionId: string;
        session: SessionSummaryRecord;
        runId?: string;
        run?: RunRecord;
        thread?: ThreadListRecord;
    }) => void;
}

export function useConversationShellEditFlow(input: UseConversationShellEditFlowInput) {
    const [pendingMessageEdit, setPendingMessageEdit] = useState<PendingMessageEdit | undefined>(undefined);
    const utils = trpc.useUtils();
    const editPreferenceQuery = trpc.conversation.getEditPreference.useQuery(
        {
            profileId: input.profileId,
        },
        PROGRESSIVE_QUERY_OPTIONS
    );

    const editPreference: 'ask' | 'truncate' | 'branch' =
        editPreferenceQuery.data?.value === 'truncate' || editPreferenceQuery.data?.value === 'branch'
            ? editPreferenceQuery.data.value
            : 'ask';

    return {
        pendingMessageEdit,
        editPreference,
        resetEditFlow: () => {
            setPendingMessageEdit(undefined);
        },
        onEditMessage: (entry: MessageFlowMessage) => {
            const pendingEdit = createPendingMessageEdit(entry);
            if (pendingEdit) {
                setPendingMessageEdit(pendingEdit);
            }
        },
        dialogProps: {
            open: Boolean(pendingMessageEdit),
            initialText: pendingMessageEdit?.initialText ?? '',
            preferredResolution: editPreference,
            ...(pendingMessageEdit?.forcedMode ? { forcedMode: pendingMessageEdit.forcedMode } : {}),
            onCancel: () => {
                setPendingMessageEdit(undefined);
            },
            onSave: (dialogInput: {
                replacementText: string;
                editMode: 'truncate' | 'branch';
                rememberChoice: boolean;
            }) => {
                if (!pendingMessageEdit) {
                    return;
                }
                if (!isEntityId(input.selectedSessionId, 'sess')) {
                    input.onError('Select a session before editing a message.');
                    return;
                }

                input.onClearError();
                void input
                    .editSession({
                        profileId: input.profileId,
                        sessionId: input.selectedSessionId,
                        topLevelTab: input.topLevelTab,
                        modeKey: input.modeKey,
                        messageId: pendingMessageEdit.messageId,
                        replacementText: dialogInput.replacementText,
                        editMode: dialogInput.editMode,
                        autoStartRun: true,
                        runtimeOptions: input.runtimeOptions,
                        ...(input.resolvedRunTarget ? { providerId: input.resolvedRunTarget.providerId } : {}),
                        ...(input.resolvedRunTarget ? { modelId: input.resolvedRunTarget.modelId } : {}),
                        ...(input.selectedThread?.workspaceFingerprint
                            ? { workspaceFingerprint: input.selectedThread.workspaceFingerprint }
                            : {}),
                        ...(input.selectedThread?.sandboxId ? { sandboxId: input.selectedThread.sandboxId } : {}),
                    })
                    .then(async (result) => {
                        if (!result.edited) {
                            input.onError(toEditFailureMessage(result.reason));
                            return;
                        }

                        if (dialogInput.rememberChoice && editPreference === 'ask') {
                            await input.setEditPreference({
                                profileId: input.profileId,
                                value: dialogInput.editMode,
                            });
                            utils.conversation.getEditPreference.setData(
                                {
                                    profileId: input.profileId,
                                },
                                {
                                    value: dialogInput.editMode,
                                }
                            );
                        }

                        const selectionTransition = buildEditSelectionTransition({
                            currentTopLevelTab: input.topLevelTab,
                            result,
                        });

                        if (selectionTransition.selectedThreadId) {
                            input.uiState.setSelectedThreadId(selectionTransition.selectedThreadId);
                        }
                        if (selectionTransition.nextTopLevelTab) {
                            input.onTopLevelTabChange(selectionTransition.nextTopLevelTab);
                        }
                        input.uiState.setSelectedSessionId(selectionTransition.selectedSessionId);
                        input.uiState.setSelectedRunId(selectionTransition.selectedRunId);
                        setPendingMessageEdit(undefined);
                        input.onPromptReset();
                        input.onSessionEdited({
                            sessionId: result.sessionId,
                            session: result.session,
                            ...(result.runId ? { runId: result.runId } : {}),
                            ...(result.run ? { run: result.run } : {}),
                            ...(result.thread ? { thread: result.thread } : {}),
                        });
                    })
                    .catch((error: unknown) => {
                        const message = error instanceof Error ? error.message : String(error);
                        input.onError(`Edit failed: ${message}`);
                    });
            },
        },
    };
}

import { describe, expect, it, vi } from 'vitest';

import { submitConversationSessionCreate } from '@/web/components/conversation/hooks/useConversationShellSessionActions';

describe('submitConversationSessionCreate', () => {
    it('reports missing-thread results through the existing error path', async () => {
        const onError = vi.fn();
        const onSelectSessionId = vi.fn();
        const onSelectRunId = vi.fn();
        const onClearError = vi.fn();
        const onSessionCreated = vi.fn();

        await submitConversationSessionCreate({
            profileId: 'profile_default',
            selectedThreadId: 'thr_123',
            createSession: async () => ({ created: false as const, reason: 'missing_thread' }),
            onClearError,
            onError,
            onSelectSessionId,
            onSelectRunId,
            onSessionCreated,
        });

        expect(onError).toHaveBeenCalledWith('Selected thread no longer exists.');
        expect(onSelectSessionId).not.toHaveBeenCalled();
        expect(onSessionCreated).not.toHaveBeenCalled();
    });

    it('reports rejected create-session requests through the existing error path', async () => {
        const onError = vi.fn();

        await submitConversationSessionCreate({
            profileId: 'profile_default',
            selectedThreadId: 'thr_123',
            createSession: async () => {
                throw new Error('Session service unavailable');
            },
            onClearError: vi.fn(),
            onError,
            onSelectSessionId: vi.fn(),
            onSelectRunId: vi.fn(),
            onSessionCreated: vi.fn(),
        });

        expect(onError).toHaveBeenCalledWith('Session service unavailable');
    });
});

import { useConversationQueries } from '@/web/components/conversation/shell/queries/useConversationQueries';
import type { WorkspaceExecutionScope } from '@/web/components/conversation/shell/deriveConversationWorkspaceExecutionScope';
import type { useConversationShellSelectionState } from '@/web/components/conversation/shell/useConversationShellSelectionState';
import type { useConversationRunTarget } from '@/web/components/conversation/shell/workspace/useConversationRunTarget';
import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { trpc } from '@/web/trpc/client';

import type { TopLevelTab } from '@/shared/contracts';

export function useConversationShellViewModel(input: {
    profileId: string;
    topLevelTab: TopLevelTab;
    modeKey: string;
    queries: ReturnType<typeof useConversationQueries>;
    selectionState: ReturnType<typeof useConversationShellSelectionState>;
    runTargetState: ReturnType<typeof useConversationRunTarget>;
    workspaceScope: WorkspaceExecutionScope;
}) {
    const selectedThread = input.selectionState.selectedThread;
    const effectiveSelectedSandboxId =
        input.workspaceScope.kind === 'sandbox' ? input.workspaceScope.sandboxId : undefined;
    const registryResolvedQuery = trpc.registry.listResolved.useQuery(
        {
            profileId: input.profileId,
            ...(selectedThread?.workspaceFingerprint
                ? { workspaceFingerprint: selectedThread.workspaceFingerprint }
                : {}),
            ...(effectiveSelectedSandboxId ? { sandboxId: effectiveSelectedSandboxId } : {}),
        },
        {
            enabled: input.topLevelTab !== 'chat',
            ...PROGRESSIVE_QUERY_OPTIONS,
        }
    );
    const pendingPermissions =
        input.queries.pendingPermissionsQuery.data?.requests.filter((request) => request.profileId === input.profileId) ?? [];
    const permissionWorkspaces = Object.fromEntries(
        (input.queries.shellBootstrapQuery.data?.workspaceRoots ?? []).map((workspaceRoot) => [
            workspaceRoot.fingerprint,
            { label: workspaceRoot.label, absolutePath: workspaceRoot.absolutePath },
        ])
    );
    const visibleManagedSandboxes = selectedThread?.workspaceFingerprint
        ? (input.queries.shellBootstrapQuery.data?.sandboxes ?? []).filter(
              (sandbox) => sandbox.workspaceFingerprint === selectedThread.workspaceFingerprint
          )
        : [];
    const selectedProviderStatus = input.runTargetState.selectedProviderIdForComposer
        ? input.runTargetState.providerById.get(input.runTargetState.selectedProviderIdForComposer)
        : undefined;
    const selectedModelLabel =
        input.runTargetState.selectedProviderIdForComposer && input.runTargetState.selectedModelIdForComposer
            ? input.runTargetState.modelsByProvider
                  .get(input.runTargetState.selectedProviderIdForComposer)
                  ?.find((model) => model.id === input.runTargetState.selectedModelIdForComposer)?.label
            : undefined;
    const selectedUsageSummary = input.queries.usageSummaryQuery.data?.summaries.find(
        (summary) => summary.providerId === input.runTargetState.selectedProviderIdForComposer
    );
    const attachedRules = input.queries.attachedRulesQuery.data?.rulesets ?? [];
    const missingAttachedRuleKeys = input.queries.attachedRulesQuery.data?.missingAssetKeys ?? [];
    const attachedSkills = input.queries.attachedSkillsQuery.data?.skillfiles ?? [];
    const missingAttachedSkillKeys = input.queries.attachedSkillsQuery.data?.missingAssetKeys ?? [];
    const activeModeLabel =
        registryResolvedQuery.data?.resolved.modes.find(
            (resolvedMode) => resolvedMode.topLevelTab === input.topLevelTab && resolvedMode.modeKey === input.modeKey
        )?.label ?? input.modeKey;

    return {
        selectedThread,
        registryResolvedQuery,
        pendingPermissions,
        permissionWorkspaces,
        visibleManagedSandboxes,
        sessionRunSelection: input.selectionState.sessionRunSelection,
        effectiveSelectedSandboxId,
        selectedProviderStatus,
        selectedModelLabel,
        selectedUsageSummary,
        attachedRules,
        missingAttachedRuleKeys,
        attachedSkills,
        missingAttachedSkillKeys,
        activeModeLabel,
        workspaceScope: input.workspaceScope,
    };
}

import { describe, expect, it } from 'vitest';

import {
    applyRuntimeEventsToConversationTranscript,
    buildConversationTranscriptBaselineKey,
    projectConversationTranscriptMessages,
} from '@/web/components/conversation/messages/conversationTanstackTranscriptController';
import { hydrateTanstackTranscriptState } from '@/web/components/conversation/messages/tanstackTranscriptState';

import type { MessagePartRecord, MessageRecord, RuntimeEventRecordV1 } from '@/app/backend/persistence/types';

function createMessage(input: {
    id: string;
    sessionId?: string;
    runId?: string;
    role: MessageRecord['role'];
    createdAt?: string;
    updatedAt?: string;
}): MessageRecord {
    return {
        id: input.id as MessageRecord['id'],
        profileId: 'profile_test',
        sessionId: (input.sessionId ?? 'sess_test') as MessageRecord['sessionId'],
        runId: (input.runId ?? 'run_test') as MessageRecord['runId'],
        role: input.role,
        createdAt: input.createdAt ?? '2026-01-01T00:00:00.000Z',
        updatedAt: input.updatedAt ?? input.createdAt ?? '2026-01-01T00:00:00.000Z',
    };
}

function createPart(input: {
    id: string;
    messageId: string;
    sequence?: number;
    partType: MessagePartRecord['partType'];
    payload: Record<string, unknown>;
}): MessagePartRecord {
    return {
        id: input.id as MessagePartRecord['id'],
        messageId: input.messageId as MessagePartRecord['messageId'],
        sequence: input.sequence ?? 0,
        partType: input.partType,
        payload: input.payload,
        createdAt: '2026-01-01T00:00:00.000Z',
    };
}

function createRuntimeEvent(input: {
    sequence: number;
    domain: RuntimeEventRecordV1['domain'];
    operation: RuntimeEventRecordV1['operation'];
    eventType: string;
    entityType: RuntimeEventRecordV1['entityType'];
    entityId: string;
    payload: Record<string, unknown>;
}): RuntimeEventRecordV1 {
    return {
        sequence: input.sequence,
        eventId: `evt_${String(input.sequence)}` as RuntimeEventRecordV1['eventId'],
        entityType: input.entityType,
        domain: input.domain,
        operation: input.operation,
        entityId: input.entityId,
        eventType: input.eventType,
        payload: input.payload,
        createdAt: '2026-01-01T00:00:00.000Z',
    };
}

describe('conversation tanstack transcript controller', () => {
    it('builds a stable baseline key from session and digest', () => {
        const state = hydrateTanstackTranscriptState([createMessage({ id: 'msg_1', role: 'user' })], new Map());

        expect(buildConversationTranscriptBaselineKey(state)).toContain('sess_test');
        expect(buildConversationTranscriptBaselineKey(state)).toContain(state.digest);
    });

    it('applies incremental runtime events without resetting when the sequence is contiguous', () => {
        const assistantMessage = createMessage({ id: 'msg_assistant', role: 'assistant' });
        const baselineState = hydrateTanstackTranscriptState([assistantMessage], new Map());

        const result = applyRuntimeEventsToConversationTranscript({
            currentState: baselineState,
            baselineState,
            lastAppliedSequence: 0,
            runtimeEvents: [
                createRuntimeEvent({
                    sequence: 1,
                    domain: 'messagePart',
                    operation: 'upsert',
                    entityType: 'messagePart',
                    entityId: 'part_text',
                    eventType: 'messagePart.upserted',
                    payload: {
                        part: createPart({
                            id: 'part_text',
                            messageId: assistantMessage.id,
                            partType: 'text',
                            payload: { text: 'Hello live stream' },
                        }),
                    },
                }),
            ],
        });

        expect(result.resetToBaseline).toBe(false);
        expect(result.didChange).toBe(true);
        expect(result.lastAppliedSequence).toBe(1);
        expect(
            projectConversationTranscriptMessages({ transcriptState: result.nextState })[0]?.uiMessage.parts
        ).toEqual([
            {
                type: 'text',
                content: 'Hello live stream',
            },
        ]);
    });

    it('forces a resync when runtime event sequences skip ahead', () => {
        const assistantMessage = createMessage({ id: 'msg_assistant', role: 'assistant' });
        const baselineState = hydrateTanstackTranscriptState([assistantMessage], new Map());

        const result = applyRuntimeEventsToConversationTranscript({
            currentState: baselineState,
            baselineState,
            lastAppliedSequence: 1,
            runtimeEvents: [
                createRuntimeEvent({
                    sequence: 3,
                    domain: 'messagePart',
                    operation: 'upsert',
                    entityType: 'messagePart',
                    entityId: 'part_text',
                    eventType: 'messagePart.upserted',
                    payload: {
                        part: createPart({
                            id: 'part_text',
                            messageId: assistantMessage.id,
                            partType: 'text',
                            payload: { text: 'Hello live stream' },
                        }),
                    },
                }),
            ],
        });

        expect(result.resetToBaseline).toBe(true);
        expect(result.nextState).toBe(baselineState);
        expect(result.lastAppliedSequence).toBe(3);
    });

    it('appends optimistic user messages only when the optimistic session matches the transcript session', () => {
        const transcriptState = hydrateTanstackTranscriptState(
            [createMessage({ id: 'msg_1', role: 'user' })],
            new Map()
        );

        const matchingMessages = projectConversationTranscriptMessages({
            transcriptState,
            optimisticUserMessage: {
                id: 'optimistic_msg_1',
                runId: 'optimistic_run_1',
                sessionId: 'sess_test',
                createdAt: '2026-03-12T09:00:00.000Z',
                prompt: 'Ship it',
            },
        });
        const mismatchedMessages = projectConversationTranscriptMessages({
            transcriptState,
            optimisticUserMessage: {
                id: 'optimistic_msg_2',
                runId: 'optimistic_run_2',
                sessionId: 'sess_other',
                createdAt: '2026-03-12T09:00:00.000Z',
                prompt: 'Do not append',
            },
        });

        expect(matchingMessages).toHaveLength(2);
        expect(matchingMessages[1]?.deliveryState).toBe('sending');
        expect(mismatchedMessages).toHaveLength(1);
    });
});

