import {
    type ConversationTanstackMessage,
    projectOptimisticConversationUserMessage,
} from '@/web/components/conversation/messages/tanstackMessageBridge';
import type { OptimisticConversationUserMessage } from '@/web/components/conversation/messages/optimisticUserMessage';
import {
    applyRuntimeEventToTanstackTranscriptState,
    projectTanstackTranscriptState,
    type TanstackTranscriptState,
} from '@/web/components/conversation/messages/tanstackTranscriptState';

import type { RuntimeEventRecordV1 } from '@/app/backend/persistence/types';

export interface ApplyRuntimeEventsToConversationTranscriptInput {
    currentState: TanstackTranscriptState;
    baselineState: TanstackTranscriptState;
    runtimeEvents: RuntimeEventRecordV1[];
    lastAppliedSequence: number;
}

export interface ApplyRuntimeEventsToConversationTranscriptResult {
    nextState: TanstackTranscriptState;
    lastAppliedSequence: number;
    didChange: boolean;
    resetToBaseline: boolean;
}

export function buildConversationTranscriptBaselineKey(state: TanstackTranscriptState): string {
    return `${state.sessionId ?? 'sess_detached'}:${state.digest}`;
}

export function applyRuntimeEventsToConversationTranscript(
    input: ApplyRuntimeEventsToConversationTranscriptInput
): ApplyRuntimeEventsToConversationTranscriptResult {
    const { baselineState, currentState, lastAppliedSequence: initialLastAppliedSequence, runtimeEvents } = input;

    if (
        baselineState.sessionId === null ||
        runtimeEvents.length === 0 ||
        currentState.sessionId !== baselineState.sessionId
    ) {
        return {
            nextState: currentState,
            lastAppliedSequence: initialLastAppliedSequence,
            didChange: false,
            resetToBaseline: false,
        };
    }

    let nextState = currentState;
    let lastAppliedSequence = initialLastAppliedSequence;

    for (const event of runtimeEvents) {
        if (event.sequence <= lastAppliedSequence) {
            continue;
        }

        if (lastAppliedSequence > 0 && event.sequence > lastAppliedSequence + 1) {
            return {
                nextState: baselineState,
                lastAppliedSequence: runtimeEvents.at(-1)?.sequence ?? lastAppliedSequence,
                didChange: baselineState !== currentState,
                resetToBaseline: true,
            };
        }

        const appliedState = applyRuntimeEventToTanstackTranscriptState(nextState, event);
        if (appliedState === 'resync') {
            return {
                nextState: baselineState,
                lastAppliedSequence: runtimeEvents.at(-1)?.sequence ?? event.sequence,
                didChange: baselineState !== currentState,
                resetToBaseline: true,
            };
        }

        nextState = appliedState;
        lastAppliedSequence = event.sequence;
    }

    if (lastAppliedSequence === initialLastAppliedSequence) {
        return {
            nextState: currentState,
            lastAppliedSequence,
            didChange: false,
            resetToBaseline: false,
        };
    }

    return {
        nextState,
        lastAppliedSequence,
        didChange: nextState !== currentState,
        resetToBaseline: false,
    };
}

export function projectConversationTranscriptMessages(input: {
    transcriptState: TanstackTranscriptState;
    requestedSessionId?: string;
    optimisticUserMessage?: OptimisticConversationUserMessage;
}): ConversationTanstackMessage[] {
    const projectedMessages = projectTanstackTranscriptState(input.transcriptState);
    const resolvedSessionId = input.transcriptState.sessionId ?? input.requestedSessionId ?? null;

    if (!input.optimisticUserMessage || resolvedSessionId !== input.optimisticUserMessage.sessionId) {
        return projectedMessages;
    }

    return [...projectedMessages, projectOptimisticConversationUserMessage(input.optimisticUserMessage)];
}

import { useState } from 'react';

import {
    FlowAssistantMessageActionBar,
    FlowUserMessageActionBar,
} from '@/web/components/conversation/messages/flow/messageFlowActionBar';
import { MessageFlowBody } from '@/web/components/conversation/messages/flow/messageFlowBody';
import { readRelatedTargetNode } from '@/web/lib/dom/readRelatedTargetNode';

import type { MessageFlowMessage } from '@/web/components/conversation/messages/messageFlowModel';
import type { FocusEvent } from 'react';

import type { RunRecord } from '@/app/backend/persistence/types';

interface FlowMessageViewProps {
    profileId: string;
    message: MessageFlowMessage;
    run: RunRecord | undefined;
    onEditMessage?: (entry: MessageFlowMessage) => void;
    onBranchFromMessage?: (entry: MessageFlowMessage) => void;
}

export function FlowMessageView({
    profileId,
    message,
    run,
    onEditMessage,
    onBranchFromMessage,
}: FlowMessageViewProps) {
    const [copyFeedback, setCopyFeedback] = useState<string | undefined>(undefined);
    const [isPinnedVisible, setIsPinnedVisible] = useState(false);
    const isUserMessage = message.role === 'user';
    const isAssistantMessage = message.role === 'assistant';

    function handleUserMessageBlur(event: FocusEvent<HTMLElement>) {
        if (event.currentTarget.contains(readRelatedTargetNode(event.relatedTarget))) {
            return;
        }

        setIsPinnedVisible(false);
    }

    const userActionRailClassName = [
        'pointer-events-none absolute right-0 bottom-0 flex translate-y-1 items-center gap-2 opacity-0 transition duration-150',
        'group-hover:pointer-events-auto group-hover:translate-y-0 group-hover:opacity-100',
        'group-focus-within:pointer-events-auto group-focus-within:translate-y-0 group-focus-within:opacity-100',
        isPinnedVisible ? 'pointer-events-auto translate-y-0 opacity-100' : '',
    ].join(' ');

    if (isUserMessage) {
        return (
            <div className='flex justify-end'>
                <article
                    className='group focus-visible:ring-ring focus-visible:ring-offset-background relative max-w-[min(40rem,82%)] rounded-[1.6rem] focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:outline-none'
                    tabIndex={0}
                    onClick={() => {
                        setIsPinnedVisible(true);
                    }}
                    onFocus={() => {
                        setIsPinnedVisible(true);
                    }}
                    onBlur={handleUserMessageBlur}>
                    <div className='bg-card/85 border-border/70 rounded-[1.4rem] border px-4 py-3 shadow-[0_18px_48px_rgba(4,8,18,0.12)]'>
                        <MessageFlowBody profileId={profileId} message={message} run={run} />
                    </div>
                    <div className='relative min-h-14 pt-3'>
                        <div className={userActionRailClassName}>
                            <FlowUserMessageActionBar
                                message={message}
                                copyFeedback={copyFeedback}
                                onCopyFeedbackChange={setCopyFeedback}
                                isPinnedVisible={isPinnedVisible}
                                {...(onEditMessage ? { onEditMessage } : {})}
                                {...(onBranchFromMessage ? { onBranchFromMessage } : {})}
                            />
                        </div>
                    </div>
                </article>
            </div>
        );
    }

    return (
        <article className='space-y-4'>
            <div className='max-w-[min(52rem,100%)] space-y-4'>
                <MessageFlowBody profileId={profileId} message={message} run={run} />
            </div>
            {isAssistantMessage ? (
                <FlowAssistantMessageActionBar
                    message={message}
                    copyFeedback={copyFeedback}
                    onCopyFeedbackChange={setCopyFeedback}
                    {...(onBranchFromMessage ? { onBranchFromMessage } : {})}
                />
            ) : null}
        </article>
    );
}

import { Copy, GitBranch, PencilLine } from 'lucide-react';

import { copyText } from '@/web/lib/copy';

import type { MessageFlowMessage } from '@/web/components/conversation/messages/messageFlowModel';
import type { MouseEvent, ReactNode } from 'react';

function MessageActionButton({
    label,
    ariaLabel,
    icon,
    tabIndex,
    title,
    onClick,
}: {
    label: string;
    ariaLabel: string;
    icon: ReactNode;
    tabIndex?: number;
    title?: string;
    onClick: (event: MouseEvent<HTMLButtonElement>) => void;
}) {
    return (
        <button
            type='button'
            aria-label={ariaLabel}
            tabIndex={tabIndex}
            title={title}
            className='border-border bg-background/80 text-foreground hover:bg-accent inline-flex min-h-10 items-center gap-2 rounded-full border px-3 text-xs font-medium transition-colors'
            onClick={onClick}>
            {icon}
            <span>{label}</span>
        </button>
    );
}

export function MessageCopyFeedback({ feedback }: { feedback: string | undefined }) {
    if (!feedback) {
        return null;
    }

    return <span className='text-muted-foreground text-[11px]'>{feedback}</span>;
}

interface FlowMessageActionBarProps {
    message: MessageFlowMessage;
    copyFeedback: string | undefined;
    onCopyFeedbackChange: (value: string | undefined) => void;
    onEditMessage?: (entry: MessageFlowMessage) => void;
    onBranchFromMessage?: (entry: MessageFlowMessage) => void;
    isPinnedVisible?: boolean;
}

export function getFlowMessageCapabilities(message: MessageFlowMessage) {
    const hasBranchableAssistantContent = message.body.some((item) => item.type !== 'assistant_status');

    return {
        canCopy:
            !message.isOptimistic && typeof message.plainCopyText === 'string' && message.plainCopyText.length > 0,
        canEdit:
            !message.isOptimistic &&
            message.role === 'user' &&
            typeof message.editableText === 'string' &&
            message.editableText.length > 0,
        canBranch:
            !message.isOptimistic &&
            (message.role === 'user' || (message.role === 'assistant' && hasBranchableAssistantContent)),
    };
}

export async function copyFlowMessage(
    message: MessageFlowMessage,
    sourceMode: 'plain' | 'raw',
    onCopyFeedbackChange: (value: string | undefined) => void
) {
    const payload = sourceMode === 'raw' ? message.rawCopyText : message.plainCopyText;
    if (!payload) {
        return;
    }

    const copied = await copyText(payload);
    onCopyFeedbackChange(copied ? (sourceMode === 'raw' ? 'Source copied' : 'Copied') : 'Copy failed');
    window.setTimeout(() => {
        onCopyFeedbackChange(undefined);
    }, 1400);
}

export function FlowUserMessageActionBar({
    message,
    copyFeedback,
    onCopyFeedbackChange,
    onEditMessage,
    onBranchFromMessage,
    isPinnedVisible = false,
}: FlowMessageActionBarProps) {
    const capabilities = getFlowMessageCapabilities(message);

    return (
        <>
            <MessageCopyFeedback feedback={copyFeedback} />
            {capabilities.canEdit ? (
                <MessageActionButton
                    label='Edit'
                    ariaLabel='Edit message'
                    icon={<PencilLine className='h-3.5 w-3.5' />}
                    tabIndex={isPinnedVisible ? 0 : -1}
                    onClick={() => {
                        onEditMessage?.(message);
                    }}
                />
            ) : null}
            {capabilities.canCopy ? (
                <MessageActionButton
                    label='Copy'
                    ariaLabel='Copy message'
                    icon={<Copy className='h-3.5 w-3.5' />}
                    tabIndex={isPinnedVisible ? 0 : -1}
                    title='Copy rendered text. Shift-click to copy source markdown.'
                    onClick={(event) => {
                        void copyFlowMessage(message, event.shiftKey ? 'raw' : 'plain', onCopyFeedbackChange);
                    }}
                />
            ) : null}
            {capabilities.canBranch && onBranchFromMessage ? (
                <MessageActionButton
                    label='Branch'
                    ariaLabel='Branch from message'
                    icon={<GitBranch className='h-3.5 w-3.5' />}
                    tabIndex={isPinnedVisible ? 0 : -1}
                    onClick={() => {
                        onBranchFromMessage(message);
                    }}
                />
            ) : null}
        </>
    );
}

export function FlowAssistantMessageActionBar({
    message,
    copyFeedback,
    onCopyFeedbackChange,
    onBranchFromMessage,
}: FlowMessageActionBarProps) {
    const capabilities = getFlowMessageCapabilities(message);

    return (
        <div className='flex flex-wrap items-center gap-3'>
            <MessageCopyFeedback feedback={copyFeedback} />
            {capabilities.canCopy ? (
                <MessageActionButton
                    label='Copy'
                    ariaLabel='Copy message'
                    icon={<Copy className='h-3.5 w-3.5' />}
                    title='Copy rendered text. Shift-click to copy source markdown.'
                    onClick={(event) => {
                        void copyFlowMessage(message, event.shiftKey ? 'raw' : 'plain', onCopyFeedbackChange);
                    }}
                />
            ) : null}
            {capabilities.canBranch && onBranchFromMessage ? (
                <MessageActionButton
                    label='Branch'
                    ariaLabel='Branch from message'
                    icon={<GitBranch className='h-3.5 w-3.5' />}
                    onClick={() => {
                        onBranchFromMessage(message);
                    }}
                />
            ) : null}
        </div>
    );
}

