import type { MessagePart, ToolCallPart, ToolResultPart, UIMessage } from '@tanstack/ai';

import { buildMessageCopyPayloads } from '@/web/components/conversation/messages/messageCopy';
import type { OptimisticConversationUserMessage } from '@/web/components/conversation/messages/optimisticUserMessage';
import { isEntityId } from '@/web/components/conversation/shell/workspace/helpers';

import type { MessagePartRecord, MessageRecord } from '@/app/backend/persistence/types';
import { parseAssistantStatusPartPayload } from '@/shared/contracts/types/messagePart';
import { readImageMimeType } from '@/app/shared/imageMimeType';

import type { EntityId } from '@/shared/contracts';

export interface ConversationTanstackMessage {
    id: string;
    runId: string;
    role: MessageRecord['role'];
    createdAt: string;
    uiMessage: UIMessage;
    renderParts: ConversationTanstackRenderPart[];
    plainCopyText?: string;
    rawCopyText?: string;
    editableText?: string;
    deliveryState?: 'sending';
    isOptimistic?: boolean;
}

export type ConversationTanstackRenderPart =
    | {
          key: string;
          kind: 'text';
          text: string;
      }
    | {
          key: string;
          kind: 'image';
          mediaId: EntityId<'media'>;
          mimeType: 'image/jpeg' | 'image/png' | 'image/webp';
          width: number;
          height: number;
      }
    | {
          key: string;
          kind: 'reasoning';
          text: string;
          providerLimitedReasoning: boolean;
      }
    | {
          key: string;
          kind: 'tool_call';
          callId: string;
          toolName: string;
          argumentsText: string;
      }
    | {
          key: string;
          kind: 'tool_result';
          callId: string;
          outputText: string;
      }
    | {
          key: string;
          kind: 'status';
          code: 'received' | 'stalled' | 'failed_before_output';
          label: string;
          elapsedMs?: number;
      };

interface ConversationImageMetadata {
    mediaId: EntityId<'media'>;
    mimeType: 'image/jpeg' | 'image/png' | 'image/webp';
    width: number;
    height: number;
}

function readTextPayload(part: MessagePartRecord): string | null {
    const text = part.payload['text'];
    if (typeof text !== 'string') {
        return null;
    }

    return text.trim().length > 0 ? text : null;
}

function buildProjectedParts(message: MessageRecord, parts: MessagePartRecord[]): ConversationTanstackRenderPart[] {
    const projected: ConversationTanstackRenderPart[] = [];

    for (const part of parts) {
        if (part.partType === 'reasoning_encrypted') {
            continue;
        }

        if (part.partType === 'image') {
            const rawMediaId = part.payload['mediaId'];
            const mimeType = part.payload['mimeType'];
            const width = part.payload['width'];
            const height = part.payload['height'];
            const mediaId = typeof rawMediaId === 'string' ? rawMediaId : undefined;
            const normalizedMimeType = readImageMimeType(mimeType);

            if (
                isEntityId(mediaId, 'media') &&
                normalizedMimeType &&
                typeof width === 'number' &&
                typeof height === 'number'
            ) {
                projected.push({
                    key: part.id,
                    kind: 'image',
                    mediaId,
                    mimeType: normalizedMimeType,
                    width,
                    height,
                });
            }
            continue;
        }

        if (part.partType === 'reasoning' || part.partType === 'reasoning_summary') {
            const text = readTextPayload(part);
            if (!text) {
                continue;
            }

            projected.push({
                key: part.id,
                kind: 'reasoning',
                text,
                providerLimitedReasoning: part.partType === 'reasoning_summary',
            });
            continue;
        }

        if (part.partType === 'status' && message.role === 'assistant') {
            const statusPayload = parseAssistantStatusPartPayload(part.payload);
            if (!statusPayload) {
                continue;
            }

            projected.push({
                key: part.id,
                kind: 'status',
                code: statusPayload.code,
                label: statusPayload.label,
                ...(statusPayload.elapsedMs !== undefined ? { elapsedMs: statusPayload.elapsedMs } : {}),
            });
            continue;
        }

        if (part.partType === 'tool_call' && message.role === 'assistant') {
            const toolName = typeof part.payload['toolName'] === 'string' ? part.payload['toolName'] : 'tool';
            const argumentsText = typeof part.payload['argumentsText'] === 'string' ? part.payload['argumentsText'] : '';
            const callId = typeof part.payload['callId'] === 'string' ? part.payload['callId'] : part.id;

            projected.push({
                key: part.id,
                kind: 'tool_call',
                callId,
                toolName,
                argumentsText,
            });
            continue;
        }

        if (part.partType === 'tool_result' && message.role === 'tool') {
            const callId = typeof part.payload['callId'] === 'string' ? part.payload['callId'] : part.id;
            const outputText = typeof part.payload['outputText'] === 'string' ? part.payload['outputText'] : '';

            projected.push({
                key: part.id,
                kind: 'tool_result',
                callId,
                outputText,
            });
            continue;
        }

        const text = readTextPayload(part);
        if (!text) {
            continue;
        }

        projected.push({
            key: part.id,
            kind: 'text',
            text,
        });
    }

    return projected;
}

function buildMessageParts(projectedParts: ConversationTanstackRenderPart[]): MessagePart[] {
    const projected: MessagePart[] = [];

    for (const part of projectedParts) {
        if (part.kind === 'image') {
            const metadata: ConversationImageMetadata = {
                mediaId: part.mediaId,
                mimeType: part.mimeType,
                width: part.width,
                height: part.height,
            };

            projected.push({
                type: 'image',
                source: {
                    type: 'url',
                    value: `neonconductor://media/${String(part.mediaId)}`,
                    mimeType: part.mimeType,
                },
                metadata,
            });
            continue;
        }

        if (part.kind === 'reasoning') {
            projected.push({
                type: 'thinking',
                content: part.text,
            });
            continue;
        }

        if (part.kind === 'tool_call') {
            projected.push({
                type: 'tool-call',
                id: part.callId,
                name: part.toolName,
                arguments: part.argumentsText,
                state: 'input-complete',
            } satisfies ToolCallPart);
            continue;
        }

        if (part.kind === 'tool_result') {
            projected.push({
                type: 'tool-result',
                toolCallId: part.callId,
                content: part.outputText,
                state: 'complete',
            } satisfies ToolResultPart);
            continue;
        }

        if (part.kind !== 'text') {
            continue;
        }

        projected.push({
            type: 'text',
            content: part.text,
        });
    }

    return projected;
}

function buildEditableText(message: MessageRecord, uiMessage: UIMessage): string | undefined {
    if (message.role !== 'user') {
        return undefined;
    }

    const editableText = uiMessage.parts
        .filter((part): part is Extract<MessagePart, { type: 'text' }> => part.type === 'text')
        .map((part) => part.content)
        .join('\n\n');

    return editableText.trim().length > 0 ? editableText : undefined;
}

type CopyPayloadBodyEntry =
    Parameters<typeof buildMessageCopyPayloads>[0]['body'][number];

function buildCopyPayloadBody(
    message: MessageRecord,
    renderParts: ConversationTanstackRenderPart[]
): CopyPayloadBodyEntry[] {
    const body: CopyPayloadBodyEntry[] = [];

    for (const part of renderParts) {
        if (part.kind === 'text') {
            body.push({
                id: part.key,
                type:
                    message.role === 'assistant'
                        ? 'assistant_text'
                        : message.role === 'user'
                          ? 'user_text'
                          : 'system_text',
                text: part.text,
                providerLimitedReasoning: false,
            });
            continue;
        }

        if (part.kind === 'reasoning') {
            body.push({
                id: part.key,
                type: 'assistant_reasoning',
                text: part.text,
                providerLimitedReasoning: part.providerLimitedReasoning,
            });
            continue;
        }

        if (part.kind === 'tool_call') {
            body.push({
                id: part.key,
                type: 'assistant_tool_call',
                text: part.argumentsText.length > 0 ? `\`\`\`json\n${part.argumentsText}\n\`\`\`` : '',
                providerLimitedReasoning: false,
                displayLabel: `Tool Call: ${part.toolName}`,
            });
            continue;
        }

        if (part.kind === 'tool_result') {
            body.push({
                id: part.key,
                type: 'tool_result',
                text: part.outputText,
                providerLimitedReasoning: false,
                displayLabel: 'Tool Result',
            });
        }
    }

    return body;
}

export function projectOptimisticConversationUserMessage(
    input: OptimisticConversationUserMessage
): ConversationTanstackMessage {
    const prompt = input.prompt.trim();
    const textPartKey = `${input.id}_text`;
    const renderParts: ConversationTanstackRenderPart[] =
        prompt.length > 0
            ? [
                  {
                      key: textPartKey,
                      kind: 'text',
                      text: prompt,
                  },
              ]
            : [];
    const uiMessage: UIMessage = {
        id: input.id,
        role: 'user',
        createdAt: new Date(input.createdAt),
        parts: buildMessageParts(renderParts),
    };
    const copyPayloads = buildMessageCopyPayloads({
        body:
            prompt.length > 0
                ? [
                      {
                          id: textPartKey,
                          type: 'user_text',
                          text: prompt,
                          providerLimitedReasoning: false,
                      },
                  ]
                : [],
    });

    return {
        id: input.id,
        runId: input.runId,
        role: 'user',
        createdAt: input.createdAt,
        uiMessage,
        renderParts,
        ...(copyPayloads.plainText ? { plainCopyText: copyPayloads.plainText } : {}),
        ...(copyPayloads.rawText ? { rawCopyText: copyPayloads.rawText } : {}),
        ...(prompt.length > 0 ? { editableText: prompt } : {}),
        deliveryState: 'sending',
        isOptimistic: true,
    };
}

export function projectConversationTanstackMessage(
    message: MessageRecord,
    messageParts: MessagePartRecord[]
): ConversationTanstackMessage {
    const renderParts = buildProjectedParts(message, messageParts);
    const uiMessage: UIMessage = {
        id: message.id,
        role: message.role === 'tool' ? 'assistant' : message.role,
        createdAt: new Date(message.createdAt),
        parts: buildMessageParts(renderParts),
    };
    const editableText = buildEditableText(message, uiMessage);
    const copyPayloads = buildMessageCopyPayloads({
        body: buildCopyPayloadBody(message, renderParts),
    });

    return {
        id: message.id,
        runId: message.runId,
        role: message.role,
        createdAt: message.createdAt,
        uiMessage,
        renderParts,
        ...(copyPayloads.plainText ? { plainCopyText: copyPayloads.plainText } : {}),
        ...(copyPayloads.rawText ? { rawCopyText: copyPayloads.rawText } : {}),
        ...(editableText ? { editableText } : {}),
    };
}

export function projectConversationTanstackMessages(
    messages: MessageRecord[],
    partsByMessageId: Map<string, MessagePartRecord[]>
): ConversationTanstackMessage[] {
    return messages.map((message) => projectConversationTanstackMessage(message, partsByMessageId.get(message.id) ?? []));
}

import { describe, expect, it } from 'vitest';

import {
    applyMessagePartUpsertToTanstackTranscriptState,
    applyRuntimeEventToTanstackTranscriptState,
    hydrateTanstackTranscriptState,
    projectTanstackTranscriptState,
} from '@/web/components/conversation/messages/tanstackTranscriptState';

import type { MessagePartRecord, MessageRecord, RuntimeEventRecordV1 } from '@/app/backend/persistence/types';

function createMessage(input: {
    id: string;
    sessionId?: string;
    runId?: string;
    role: MessageRecord['role'];
    createdAt?: string;
    updatedAt?: string;
}): MessageRecord {
    return {
        id: input.id as MessageRecord['id'],
        profileId: 'profile_test',
        sessionId: (input.sessionId ?? 'sess_test') as MessageRecord['sessionId'],
        runId: (input.runId ?? 'run_test') as MessageRecord['runId'],
        role: input.role,
        createdAt: input.createdAt ?? '2026-01-01T00:00:00.000Z',
        updatedAt: input.updatedAt ?? input.createdAt ?? '2026-01-01T00:00:00.000Z',
    };
}

function createPart(input: {
    id: string;
    messageId: string;
    sequence?: number;
    partType: MessagePartRecord['partType'];
    payload: Record<string, unknown>;
}): MessagePartRecord {
    return {
        id: input.id as MessagePartRecord['id'],
        messageId: input.messageId as MessagePartRecord['messageId'],
        sequence: input.sequence ?? 0,
        partType: input.partType,
        payload: input.payload,
        createdAt: '2026-01-01T00:00:00.000Z',
    };
}

function createRuntimeEvent(input: {
    sequence: number;
    domain: RuntimeEventRecordV1['domain'];
    operation: RuntimeEventRecordV1['operation'];
    eventType: string;
    entityType: RuntimeEventRecordV1['entityType'];
    entityId: string;
    payload: Record<string, unknown>;
}): RuntimeEventRecordV1 {
    return {
        sequence: input.sequence,
        eventId: `evt_${String(input.sequence)}` as RuntimeEventRecordV1['eventId'],
        entityType: input.entityType,
        domain: input.domain,
        operation: input.operation,
        entityId: input.entityId,
        eventType: input.eventType,
        payload: input.payload,
        createdAt: '2026-01-01T00:00:00.000Z',
    };
}

describe('tanstack transcript state', () => {
    it('hydrates transcript messages from persisted backend state', () => {
        const userMessage = createMessage({ id: 'msg_user', role: 'user' });
        const assistantMessage = createMessage({
            id: 'msg_assistant',
            role: 'assistant',
            createdAt: '2026-01-01T00:00:01.000Z',
        });
        const assistantParts = [
            createPart({
                id: 'part_reasoning',
                messageId: assistantMessage.id,
                partType: 'reasoning_summary',
                payload: { text: 'Reasoning summary' },
            }),
            createPart({
                id: 'part_text',
                messageId: assistantMessage.id,
                sequence: 1,
                partType: 'text',
                payload: { text: 'Assistant reply' },
            }),
        ];

        const state = hydrateTanstackTranscriptState(
            [userMessage, assistantMessage],
            new Map([
                [
                    assistantMessage.id,
                    assistantParts,
                ],
            ])
        );

        const projected = projectTanstackTranscriptState(state);
        expect(projected).toHaveLength(2);
        expect(projected[1]?.renderParts.map((part) => part.kind)).toEqual(['reasoning', 'text']);
        expect(projected[1]?.uiMessage.parts.map((part) => part.type)).toEqual(['thinking', 'text']);
    });

    it('upserts message parts without rebuilding unrelated transcript entries', () => {
        const assistantMessage = createMessage({ id: 'msg_assistant', role: 'assistant' });
        const initialState = hydrateTanstackTranscriptState([assistantMessage], new Map());

        const nextState = applyMessagePartUpsertToTanstackTranscriptState(
            initialState,
            createPart({
                id: 'part_text',
                messageId: assistantMessage.id,
                partType: 'text',
                payload: { text: 'Streaming body' },
            })
        );

        const projected = projectTanstackTranscriptState(nextState);
        expect(projected[0]?.renderParts).toEqual([
            {
                key: 'part_text',
                kind: 'text',
                text: 'Streaming body',
            },
        ]);
    });

    it('applies runtime message and messagePart events for the active session', () => {
        const state = hydrateTanstackTranscriptState([], new Map());
        const assistantMessage = createMessage({ id: 'msg_assistant', role: 'assistant' });

        const afterMessage = applyRuntimeEventToTanstackTranscriptState(
            hydrateTanstackTranscriptState([assistantMessage], new Map()),
            createRuntimeEvent({
                sequence: 1,
                domain: 'messagePart',
                operation: 'upsert',
                entityType: 'messagePart',
                entityId: 'part_text',
                eventType: 'messagePart.upserted',
                payload: {
                    part: createPart({
                        id: 'part_text',
                        messageId: assistantMessage.id,
                        partType: 'text',
                        payload: { text: 'Hello live stream' },
                    }),
                },
            })
        );

        expect(afterMessage).not.toBe('resync');
        const projected = projectTanstackTranscriptState(afterMessage as ReturnType<typeof hydrateTanstackTranscriptState>);
        expect(projected[0]?.uiMessage.parts).toEqual([
            {
                type: 'text',
                content: 'Hello live stream',
            },
        ]);

        const ignoredState = applyRuntimeEventToTanstackTranscriptState(
            state,
            createRuntimeEvent({
                sequence: 2,
                domain: 'message',
                operation: 'upsert',
                entityType: 'message',
                entityId: 'msg_other',
                eventType: 'message.upserted',
                payload: {
                    message: createMessage({
                        id: 'msg_other',
                        sessionId: 'sess_other',
                        role: 'assistant',
                    }),
                },
            })
        );

        expect(projectTanstackTranscriptState(ignoredState as ReturnType<typeof hydrateTanstackTranscriptState>)).toHaveLength(0);
    });

    it('requests a resync for runtime reset events', () => {
        const assistantMessage = createMessage({ id: 'msg_assistant', role: 'assistant' });
        const state = hydrateTanstackTranscriptState([assistantMessage], new Map());

        const nextState = applyRuntimeEventToTanstackTranscriptState(
            state,
            createRuntimeEvent({
                sequence: 10,
                domain: 'runtime',
                operation: 'reset',
                entityType: 'runtime',
                entityId: 'runtime',
                eventType: 'runtime.reset',
                payload: {},
            })
        );

        expect(nextState).toBe('resync');
    });
});

import {
    projectConversationTanstackMessage,
    type ConversationTanstackMessage,
} from '@/web/components/conversation/messages/tanstackMessageBridge';
import { isEntityId } from '@/web/components/conversation/shell/workspace/helpers';

import type { MessagePartRecord, MessageRecord, RuntimeEventRecordV1, RunRecord } from '@/app/backend/persistence/types';

interface TranscriptStateMaps {
    messagesById: Map<string, MessageRecord>;
    partsByMessageId: Map<string, MessagePartRecord[]>;
    projectedByMessageId: Map<string, ConversationTanstackMessage>;
}

export interface TanstackTranscriptState extends TranscriptStateMaps {
    sessionId: MessageRecord['sessionId'] | null;
    orderedMessageIds: string[];
    digest: string;
}

function sortMessages(messages: MessageRecord[]): MessageRecord[] {
    return [...messages].sort((left, right) => {
        if (left.createdAt !== right.createdAt) {
            return left.createdAt.localeCompare(right.createdAt);
        }

        return left.id.localeCompare(right.id);
    });
}

function sortMessageParts(messageParts: MessagePartRecord[]): MessagePartRecord[] {
    return [...messageParts].sort((left, right) => {
        if (left.createdAt !== right.createdAt) {
            return left.createdAt.localeCompare(right.createdAt);
        }

        if (left.sequence !== right.sequence) {
            return left.sequence - right.sequence;
        }

        return left.id.localeCompare(right.id);
    });
}

function buildDigest(state: {
    orderedMessageIds: string[];
    messagesById: Map<string, MessageRecord>;
    partsByMessageId: Map<string, MessagePartRecord[]>;
}): string {
    return state.orderedMessageIds
        .map((messageId) => {
            const message = state.messagesById.get(messageId);
            const messageParts = state.partsByMessageId.get(messageId) ?? [];

            return [
                messageId,
                message?.updatedAt ?? '',
                message?.createdAt ?? '',
                message?.role ?? '',
                ...messageParts.map((part) => `${part.id}:${part.sequence}:${part.createdAt}:${part.partType}`),
            ].join('|');
        })
        .join('||');
}

function cloneStateMaps(state: TanstackTranscriptState): TranscriptStateMaps {
    return {
        messagesById: new Map(state.messagesById),
        partsByMessageId: new Map(state.partsByMessageId),
        projectedByMessageId: new Map(state.projectedByMessageId),
    };
}

function buildProjectedMessage(
    message: MessageRecord,
    partsByMessageId: Map<string, MessagePartRecord[]>
): ConversationTanstackMessage {
    return projectConversationTanstackMessage(message, partsByMessageId.get(message.id) ?? []);
}

function readMessageRecord(value: unknown): MessageRecord | undefined {
    if (value === null || typeof value !== 'object' || Array.isArray(value)) {
        return undefined;
    }

    const candidate = value as Record<string, unknown>;
    const id = typeof candidate['id'] === 'string' ? candidate['id'] : undefined;
    const profileId = typeof candidate['profileId'] === 'string' ? candidate['profileId'] : undefined;
    const sessionId = typeof candidate['sessionId'] === 'string' ? candidate['sessionId'] : undefined;
    const runId = typeof candidate['runId'] === 'string' ? candidate['runId'] : undefined;
    const role = candidate['role'];
    const createdAt = typeof candidate['createdAt'] === 'string' ? candidate['createdAt'] : undefined;
    const updatedAt = typeof candidate['updatedAt'] === 'string' ? candidate['updatedAt'] : undefined;

    if (
        !id ||
        !isEntityId(id, 'msg') ||
        !profileId ||
        !sessionId ||
        !isEntityId(sessionId, 'sess') ||
        !runId ||
        !isEntityId(runId, 'run') ||
        (role !== 'assistant' && role !== 'user' && role !== 'system' && role !== 'tool') ||
        !createdAt ||
        !updatedAt
    ) {
        return undefined;
    }

    return {
        id,
        profileId,
        sessionId,
        runId,
        role,
        createdAt,
        updatedAt,
    };
}

function readMessagePartRecord(value: unknown): MessagePartRecord | undefined {
    if (value === null || typeof value !== 'object' || Array.isArray(value)) {
        return undefined;
    }

    const candidate = value as Record<string, unknown>;
    const id = typeof candidate['id'] === 'string' ? candidate['id'] : undefined;
    const messageId = typeof candidate['messageId'] === 'string' ? candidate['messageId'] : undefined;
    const sequence = typeof candidate['sequence'] === 'number' ? candidate['sequence'] : undefined;
    const partType = candidate['partType'];
    const payload = candidate['payload'];
    const createdAt = typeof candidate['createdAt'] === 'string' ? candidate['createdAt'] : undefined;

    if (
        !id ||
        !messageId ||
        !isEntityId(messageId, 'msg') ||
        sequence === undefined ||
        typeof partType !== 'string' ||
        payload === null ||
        typeof payload !== 'object' ||
        Array.isArray(payload) ||
        !createdAt
    ) {
        return undefined;
    }

    return {
        id: id as MessagePartRecord['id'],
        messageId: messageId as MessagePartRecord['messageId'],
        sequence,
        partType: partType as MessagePartRecord['partType'],
        payload: payload as MessagePartRecord['payload'],
        createdAt,
    };
}

function readRunRecord(value: unknown): RunRecord | undefined {
    if (value === null || typeof value !== 'object' || Array.isArray(value)) {
        return undefined;
    }

    const candidate = value as Record<string, unknown>;
    const id = typeof candidate['id'] === 'string' ? candidate['id'] : undefined;
    const sessionId = typeof candidate['sessionId'] === 'string' ? candidate['sessionId'] : undefined;
    const profileId = typeof candidate['profileId'] === 'string' ? candidate['profileId'] : undefined;
    const prompt = typeof candidate['prompt'] === 'string' ? candidate['prompt'] : undefined;
    const status = candidate['status'];
    const createdAt = typeof candidate['createdAt'] === 'string' ? candidate['createdAt'] : undefined;
    const updatedAt = typeof candidate['updatedAt'] === 'string' ? candidate['updatedAt'] : undefined;

    if (
        !id ||
        !isEntityId(id, 'run') ||
        !sessionId ||
        !isEntityId(sessionId, 'sess') ||
        !profileId ||
        prompt === undefined ||
        typeof status !== 'string' ||
        !createdAt ||
        !updatedAt
    ) {
        return undefined;
    }

    return {
        id,
        sessionId,
        profileId,
        prompt,
        status: status as RunRecord['status'],
        createdAt,
        updatedAt,
    };
}

export function hydrateTanstackTranscriptState(
    messages: MessageRecord[],
    partsByMessageId: Map<string, MessagePartRecord[]>
): TanstackTranscriptState {
    const sortedMessages = sortMessages(messages);
    const messagesById = new Map(sortedMessages.map((message) => [message.id, message]));
    const normalizedPartsByMessageId = new Map<string, MessagePartRecord[]>();

    for (const message of sortedMessages) {
        normalizedPartsByMessageId.set(message.id, sortMessageParts(partsByMessageId.get(message.id) ?? []));
    }

    const projectedByMessageId = new Map(
        sortedMessages.map((message) => [message.id, buildProjectedMessage(message, normalizedPartsByMessageId)])
    );
    const orderedMessageIds = sortedMessages.map((message) => message.id);

    return {
        sessionId: sortedMessages[0]?.sessionId ?? null,
        orderedMessageIds,
        messagesById,
        partsByMessageId: normalizedPartsByMessageId,
        projectedByMessageId,
        digest: buildDigest({
            orderedMessageIds,
            messagesById,
            partsByMessageId: normalizedPartsByMessageId,
        }),
    };
}

export function projectTanstackTranscriptState(state: TanstackTranscriptState): ConversationTanstackMessage[] {
    return state.orderedMessageIds
        .map((messageId) => state.projectedByMessageId.get(messageId))
        .filter((message): message is ConversationTanstackMessage => message !== undefined);
}

export function applyMessageUpsertToTanstackTranscriptState(
    state: TanstackTranscriptState,
    message: MessageRecord
): TanstackTranscriptState {
    const nextState = cloneStateMaps(state);
    nextState.messagesById.set(message.id, message);

    if (!nextState.partsByMessageId.has(message.id)) {
        nextState.partsByMessageId.set(message.id, []);
    }

    const orderedMessages = sortMessages([...nextState.messagesById.values()]);
    const orderedMessageIds = orderedMessages.map((candidate) => candidate.id);
    nextState.projectedByMessageId.set(message.id, buildProjectedMessage(message, nextState.partsByMessageId));

    return {
        sessionId: message.sessionId,
        orderedMessageIds,
        ...nextState,
        digest: buildDigest({
            orderedMessageIds,
            messagesById: nextState.messagesById,
            partsByMessageId: nextState.partsByMessageId,
        }),
    };
}

export function applyMessagePartUpsertToTanstackTranscriptState(
    state: TanstackTranscriptState,
    messagePart: MessagePartRecord
): TanstackTranscriptState {
    const message = state.messagesById.get(messagePart.messageId);
    if (!message) {
        return state;
    }

    const nextState = cloneStateMaps(state);
    const currentParts = nextState.partsByMessageId.get(messagePart.messageId) ?? [];
    const nextParts = sortMessageParts([...currentParts.filter((part) => part.id !== messagePart.id), messagePart]);
    nextState.partsByMessageId.set(messagePart.messageId, nextParts);
    nextState.projectedByMessageId.set(message.id, buildProjectedMessage(message, nextState.partsByMessageId));

    return {
        ...state,
        ...nextState,
        digest: buildDigest({
            orderedMessageIds: state.orderedMessageIds,
            messagesById: nextState.messagesById,
            partsByMessageId: nextState.partsByMessageId,
        }),
    };
}

export function applyRuntimeEventToTanstackTranscriptState(
    state: TanstackTranscriptState,
    event: RuntimeEventRecordV1
): TanstackTranscriptState | 'resync' {
    if (event.operation === 'reset') {
        return 'resync';
    }

    if (state.sessionId === null) {
        return state;
    }

    if (event.domain === 'message') {
        const message = readMessageRecord(event.payload['message']);
        if (!message) {
            return state;
        }

        return message.sessionId === state.sessionId ? applyMessageUpsertToTanstackTranscriptState(state, message) : state;
    }

    if (event.domain === 'messagePart') {
        const messagePart = readMessagePartRecord(event.payload['part']);
        if (!messagePart) {
            return state;
        }

        return applyMessagePartUpsertToTanstackTranscriptState(state, messagePart);
    }

    if (event.domain === 'run') {
        const run = readRunRecord(event.payload['run']);
        if (!run) {
            return state;
        }

        return run.sessionId === state.sessionId ? state : state;
    }

    return state;
}

import { MarkdownContent } from '@/web/components/content/markdown/markdownContent';
