                        id: 'google/gemini-2.5-flash-lite',
                        label: 'Gemini 2.5 Flash Lite',
                        providerId: 'kilo',
                        providerLabel: 'Kilo',
                    }),
                ],
                runErrorMessage: undefined,
                onProviderChange: () => {},
                onModelChange: () => {},
                onReasoningEffortChange: () => {},
                onModeChange: () => {},
                onPromptEdited: () => {},
