interface ContextSummaryCardProps {
    hasUsageNumbers: boolean;
    totalTokens: number | undefined;
    usableInputBudgetTokens: number | undefined;
    remainingInputTokens: number | undefined;
    usagePercent: string | undefined;
    countingModeLabel: string;
    missingReason: 'missing_model_limits' | 'feature_disabled' | 'multimodal_counting_unavailable' | string | undefined;
    countingMode: string | undefined;
    thresholdTokens: number | undefined;
    limitsSource: string;
    limitsOverrideReason: string | undefined;
    compactionRecord:
        | {
              source: string;
              updatedAt: string;
          }
        | undefined;
    contextFeedback:
        | {
              message: string;
              tone: 'success' | 'error' | 'info';
          }
        | undefined;
    canCompactContext: boolean;
    isCompactingContext: boolean;
    onCompactContext: (() => void) | undefined;
    formatTokenCount: (value: number) => string;
    formatCompactionTimestamp: (value: string) => string;
}

export function ContextSummaryCard({
    hasUsageNumbers,
    totalTokens,
    usableInputBudgetTokens,
    remainingInputTokens,
    usagePercent,
    countingModeLabel,
    missingReason,
    countingMode,
    thresholdTokens,
    limitsSource,
    limitsOverrideReason,
    compactionRecord,
    contextFeedback,
    canCompactContext,
    isCompactingContext,
    onCompactContext,
    formatTokenCount,
    formatCompactionTimestamp,
}: ContextSummaryCardProps) {
    return (
        <div className='border-border bg-card/40 space-y-1 rounded-md border px-3 py-2'>
            <div className='flex flex-wrap items-center justify-between gap-2'>
                <div className='space-y-0.5'>
                    <p className='text-[11px] font-semibold tracking-[0.14em] uppercase'>Context</p>
                    {hasUsageNumbers && totalTokens !== undefined && usableInputBudgetTokens !== undefined ? (
                        <>
                            <p className='text-xs font-medium'>
                                {formatTokenCount(totalTokens)} used of {formatTokenCount(usableInputBudgetTokens)} usable input tokens
                            </p>
                            <div className='text-muted-foreground grid gap-1 text-[11px] sm:grid-cols-3'>
                                <p>Remaining {formatTokenCount(remainingInputTokens ?? 0)}</p>
                                <p>Usage {usagePercent}</p>
                                <p>{countingModeLabel} counting</p>
                            </div>
                        </>
                    ) : missingReason === 'missing_model_limits' ? (
                        <p className='text-muted-foreground text-xs'>
                            Current thread usage is unavailable because this model has no known context limit yet.
                        </p>
                    ) : missingReason === 'feature_disabled' ? (
                        <p className='text-muted-foreground text-xs'>
                            Current thread usage is unavailable because context management is disabled for this profile.
                        </p>
                    ) : missingReason === 'multimodal_counting_unavailable' ? (
                        <p className='text-muted-foreground text-xs'>
                            Current thread usage is unavailable for image sessions because multimodal token counting is not implemented yet.
                        </p>
                    ) : (
                        <p className='text-muted-foreground text-xs'>
                            Current thread usage is active with {countingMode} counting for this model.
                        </p>
                    )}
                </div>
                {onCompactContext ? (
                    <Button type='button' size='sm' variant='outline' disabled={!canCompactContext || isCompactingContext} onClick={onCompactContext}>
                        {isCompactingContext ? 'Compacting...' : 'Compact now'}
                    </Button>
                ) : null}
            </div>
            {compactionRecord ? (
                <p className='text-muted-foreground text-[11px]'>
                    Last compacted {compactionRecord.source} at {formatCompactionTimestamp(compactionRecord.updatedAt)}.
                </p>
            ) : null}
            {thresholdTokens !== undefined ? (
                <p className='text-muted-foreground text-[11px]'>
                    Compaction threshold: {formatTokenCount(thresholdTokens)} tokens.
                </p>
            ) : null}
            <p className='text-muted-foreground text-[11px]'>
                Limit source: {limitsSource}
                {limitsOverrideReason ? ` · Override: ${limitsOverrideReason}` : ''}
            </p>
            {contextFeedback ? (
                <p
                    className={`text-xs ${
                        contextFeedback.tone === 'error'
                            ? 'text-destructive'
                            : contextFeedback.tone === 'success'
                              ? 'text-primary'
                              : 'text-muted-foreground'
                    }`}>
                    {contextFeedback.message}
                </p>
            ) : null}
        </div>
    );
}

import { describe, expect, it } from 'vitest';

import {
    buildComposerSlashCommandEntries,
    filterComposerSlashCommandEntries,
    moveComposerSlashHighlight,
    parseComposerSlashDraft,
    shouldInterceptSlashSubmit,
} from '@/web/components/conversation/panels/composerSlashCommands';

describe('composerSlashCommands', () => {
    it('parses known commands and inline query text from leading slash drafts', () => {
        expect(parseComposerSlashDraft('/skills debugger helpers')).toEqual({
            hasLeadingSlash: true,
            token: 'skills',
            normalizedToken: 'skills',
            query: 'debugger helpers',
            exactCommandId: 'skills',
        });

        expect(parseComposerSlashDraft('/rules   manual')).toEqual({
            hasLeadingSlash: true,
            token: 'rules',
            normalizedToken: 'rules',
            query: 'manual',
            exactCommandId: 'rules',
        });
    });

    it('keeps unknown slash drafts outside the exact-command path', () => {
        expect(parseComposerSlashDraft('/workflow branch')).toEqual({
            hasLeadingSlash: true,
            token: 'workflow',
            normalizedToken: 'workflow',
            query: 'branch',
        });
        expect(parseComposerSlashDraft('normal prompt')).toEqual({
            hasLeadingSlash: false,
            token: '',
            normalizedToken: '',
            query: '',
        });
    });

    it('gates slash commands to agent and orchestrator sessions', () => {
        const chatEntries = buildComposerSlashCommandEntries({
            topLevelTab: 'chat',
            selectedSessionId: 'sess_test',
        });
        const missingSessionEntries = buildComposerSlashCommandEntries({
            topLevelTab: 'agent',
        });
        const availableEntries = buildComposerSlashCommandEntries({
            topLevelTab: 'agent',
            selectedSessionId: 'sess_test',
        });

        expect(chatEntries.every((entry) => entry.available === false)).toBe(true);
        expect(chatEntries[0]?.unavailableReason).toBe('Available only for agent and orchestrator sessions.');
        expect(missingSessionEntries.every((entry) => entry.available === false)).toBe(true);
        expect(missingSessionEntries[0]?.unavailableReason).toBe('Select a session before using slash commands.');
        expect(availableEntries.every((entry) => entry.available)).toBe(true);
    });

    it('filters known commands by typed token text', () => {
        const entries = buildComposerSlashCommandEntries({
            topLevelTab: 'agent',
            selectedSessionId: 'sess_test',
        });

        expect(filterComposerSlashCommandEntries(entries, 'skill').map((entry) => entry.id)).toEqual(['skills']);
        expect(filterComposerSlashCommandEntries(entries, 'manual').map((entry) => entry.id)).toEqual(['rules']);
    });

    it('cycles slash highlight state through visible items', () => {
        expect(
            moveComposerSlashHighlight({
                currentIndex: -1,
                itemCount: 3,
                direction: 'next',
            })
        ).toBe(0);
        expect(
            moveComposerSlashHighlight({
                currentIndex: 0,
                itemCount: 3,
                direction: 'previous',
            })
        ).toBe(2);
        expect(
            moveComposerSlashHighlight({
                currentIndex: 2,
                itemCount: 3,
                direction: 'next',
            })
        ).toBe(0);
    });

    it('intercepts enter only for real slash popup states', () => {
        expect(shouldInterceptSlashSubmit({ popupState: { kind: 'hidden' } })).toBe(false);
        expect(
            shouldInterceptSlashSubmit({
                popupState: {
                    kind: 'commands',
                    typedQuery: 'workflow',
                    items: [],
                    highlightIndex: -1,
                    emptyMessage: 'No slash commands match.',
                },
            })
        ).toBe(false);
        expect(
            shouldInterceptSlashSubmit({
                popupState: {
                    kind: 'commands',
                    typedQuery: 'skills',
                    exactCommandId: 'skills',
                    items: [],
                    highlightIndex: -1,
                    emptyMessage: '',
                },
            })
        ).toBe(true);
        expect(
            shouldInterceptSlashSubmit({
                popupState: {
                    kind: 'results',
                    commandId: 'rules',
                    query: 'manual',
                    items: [],
                    highlightIndex: -1,
                    emptyMessage: 'No manual rules available.',
                },
            })
        ).toBe(true);
    });
});

import type { RulesetDefinition, SkillfileDefinition, TopLevelTab } from '@/shared/contracts';

export type ComposerSlashCommandId = 'skills' | 'rules';

export interface ComposerSlashCommandDefinition {
    id: ComposerSlashCommandId;
    label: string;
    description: string;
}

export interface ParsedComposerSlashDraft {
    hasLeadingSlash: boolean;
    token: string;
    normalizedToken: string;
    query: string;
    exactCommandId?: ComposerSlashCommandId;
}

export interface ComposerSlashCommandEntry extends ComposerSlashCommandDefinition {
    available: boolean;
    unavailableReason?: string;
}

export interface ComposerSlashResultItemBase {
    key: string;
    label: string;
    description?: string;
    attached: boolean;
}

export interface ComposerSlashSkillItem extends ComposerSlashResultItemBase {
    kind: 'skill';
    assetKey: string;
    scope: SkillfileDefinition['scope'];
    presetKey?: SkillfileDefinition['presetKey'];
}

export interface ComposerSlashRuleItem extends ComposerSlashResultItemBase {
    kind: 'rule';
    assetKey: string;
    scope: RulesetDefinition['scope'];
    presetKey?: RulesetDefinition['presetKey'];
}

export type ComposerSlashResultItem = ComposerSlashSkillItem | ComposerSlashRuleItem;

export type ComposerSlashPopupState =
    | { kind: 'hidden' }
    | {
          kind: 'commands';
          typedQuery: string;
          exactCommandId?: ComposerSlashCommandId;
          items: ComposerSlashCommandEntry[];
          highlightIndex: number;
          emptyMessage: string;
      }
    | {
          kind: 'results';
          commandId: ComposerSlashCommandId;
          query: string;
          items: ComposerSlashResultItem[];
          highlightIndex: number;
          emptyMessage: string;
          warningMessage?: string;
      };

export const composerSlashCommandDefinitions: ComposerSlashCommandDefinition[] = [
    {
        id: 'skills',
        label: '/skills',
        description: 'Attach or remove session skills for the current agent/orchestrator run.',
    },
    {
        id: 'rules',
        label: '/rules',
        description: 'Attach or remove manual rules for the current agent/orchestrator session.',
    },
];

export function parseComposerSlashDraft(draftPrompt: string): ParsedComposerSlashDraft {
    if (!draftPrompt.startsWith('/')) {
        return {
            hasLeadingSlash: false,
            token: '',
            normalizedToken: '',
            query: '',
        };
    }

    const withoutSlash = draftPrompt.slice(1);
    const firstWhitespaceIndex = withoutSlash.search(/\s/);
    const token = firstWhitespaceIndex === -1 ? withoutSlash : withoutSlash.slice(0, firstWhitespaceIndex);
    const query =
        firstWhitespaceIndex === -1 ? '' : withoutSlash.slice(firstWhitespaceIndex + 1).replace(/^\s+/, '');
    const normalizedToken = token.trim().toLowerCase();
    const exactCommand = composerSlashCommandDefinitions.find((command) => command.id === normalizedToken);

    return {
        hasLeadingSlash: true,
        token,
        normalizedToken,
        query,
        ...(exactCommand ? { exactCommandId: exactCommand.id } : {}),
    };
}

export function buildComposerSlashCommandEntries(input: {
    topLevelTab: TopLevelTab;
    selectedSessionId?: string;
}): ComposerSlashCommandEntry[] {
    const available = input.topLevelTab !== 'chat' && input.selectedSessionId !== undefined;
    const unavailableReason =
        input.topLevelTab === 'chat'
            ? 'Available only for agent and orchestrator sessions.'
            : input.selectedSessionId === undefined
              ? 'Select a session before using slash commands.'
              : undefined;

    return composerSlashCommandDefinitions.map((command) => ({
        ...command,
        available,
        ...(unavailableReason ? { unavailableReason } : {}),
    }));
}

export function filterComposerSlashCommandEntries(
    entries: ComposerSlashCommandEntry[],
    typedQuery: string
): ComposerSlashCommandEntry[] {
    const normalizedQuery = typedQuery.trim().toLowerCase();
    if (normalizedQuery.length === 0) {
        return entries;
    }

    return entries.filter((entry) => {
        const haystacks = [entry.id, entry.label, entry.description].map((value) => value.toLowerCase());
        return haystacks.some((value) => value.includes(normalizedQuery));
    });
}

export function getFirstSelectableSlashIndex<T extends { available?: boolean }>(items: T[]): number {
    return items.findIndex((item) => item.available !== false);
}

export function moveComposerSlashHighlight(input: {
    currentIndex: number;
    itemCount: number;
    direction: 'next' | 'previous';
}): number {
    if (input.itemCount <= 0) {
        return -1;
    }

    if (input.currentIndex < 0 || input.currentIndex >= input.itemCount) {
        return input.direction === 'next' ? 0 : input.itemCount - 1;
    }

    if (input.direction === 'next') {
        return (input.currentIndex + 1) % input.itemCount;
    }

    return (input.currentIndex - 1 + input.itemCount) % input.itemCount;
}

export function shouldInterceptSlashSubmit(input: {
    popupState: ComposerSlashPopupState;
}): boolean {
    if (input.popupState.kind === 'hidden') {
        return false;
    }

    if (input.popupState.kind === 'results') {
        return true;
    }

    if (input.popupState.exactCommandId) {
        return true;
    }

    return input.popupState.highlightIndex >= 0;
}

import { useState } from 'react';

import { Button } from '@/web/components/ui/button';
import { useDebouncedQueryValue } from '@/web/lib/hooks/useDebouncedQueryValue';
import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { trpc } from '@/web/trpc/client';

import type { EntityId, RulesetDefinition, SkillfileDefinition, TopLevelTab } from '@/shared/contracts';

interface ContextAssetsPanelProps {
    profileId: string;
    sessionId: EntityId<'sess'>;
    topLevelTab: TopLevelTab;
    modeKey: string;
    workspaceFingerprint?: string;
    sandboxId?: EntityId<'sb'>;
    attachedRules: RulesetDefinition[];
    missingAttachedRuleKeys: string[];
