                                    }}>
                                    {attached ? 'Attached' : 'Attach'}
                                </Button>
                            </div>
                        );
                    })
                ) : (
                    <p className='text-muted-foreground rounded-xl border border-dashed px-3 py-3 text-sm'>
                        {debouncedQuery.length > 0 ? 'No resolved skills match this search.' : 'No resolved skills available.'}
                    </p>
                )}
            </div>
        </section>
    );
}

