function RollbackPreviewSection(input: {
    profileId: string;
    checkpointId: CheckpointRecord['id'];
    rollbackPending: boolean;
    revertChangesetPending: boolean;
    rollbackTargetId: CheckpointRecord['id'] | undefined;
    onRestoreCheckpoint: (checkpointId: CheckpointRecord['id']) => void;
    onRevertChangeset: (checkpointId: CheckpointRecord['id']) => void;
    onCloseCheckpointActions: () => void;
    buildRollbackWarningState: (preview: RollbackPreview | undefined) => RollbackWarningState | null;
    executionTargetLabel: string;
}) {
    const rollbackPreviewQuery = trpc.checkpoint.previewRollback.useQuery(
        {
            profileId: input.profileId,
            checkpointId: input.checkpointId,
        },
        PROGRESSIVE_QUERY_OPTIONS
    );
    const rollbackPreviewPending = rollbackPreviewQuery.isPending;
    const selectedPreview =
        rollbackPreviewQuery.data?.found && rollbackPreviewQuery.data.preview.checkpointId === input.checkpointId
            ? rollbackPreviewQuery.data.preview
            : undefined;
    const rollbackWarningState = selectedPreview ? input.buildRollbackWarningState(selectedPreview) : null;

    return (
        <div className='border-border bg-background/60 mt-3 rounded-md border p-3'>
            <p className='text-sm'>
                Choose how to go back from <span className='font-medium'>{input.checkpointId}</span>.
            </p>
            <p className='text-muted-foreground mt-1 text-xs'>
                Backend guidance is based on the current shared-target risk for{' '}
                <span className='font-medium'>{input.executionTargetLabel}</span>.
            </p>
            <div className='mt-2 space-y-1 text-xs'>
                {selectedPreview?.changeset ? (
                    <p className='text-muted-foreground'>Changeset: {selectedPreview.changeset.summary}</p>
                ) : null}
                {rollbackPreviewPending ? (
                    <p className='text-muted-foreground'>Checking whether other chats share this target…</p>
                ) : null}
                {rollbackWarningState
                    ? rollbackWarningState.lines.map((line) => (
                          <p
                              key={line}
                              className={
                                  rollbackWarningState.tone === 'warning'
                                      ? 'text-destructive'
                                      : 'text-emerald-700 dark:text-emerald-400'
                              }>
                              {line}
                          </p>
                      ))
                    : null}
            </div>
            <div className='mt-3 flex flex-wrap gap-2'>
                <Button
                    type='button'
                    size='sm'
                    variant={selectedPreview?.recommendedAction === 'restore_checkpoint' ? 'default' : 'outline'}
                    className='h-11'
                    disabled={input.rollbackPending || input.revertChangesetPending || rollbackPreviewPending}
                    onClick={() => {
                        input.onRestoreCheckpoint(input.checkpointId);
                    }}>
                    {input.rollbackPending && input.rollbackTargetId === input.checkpointId
                        ? 'Restoring…'
                        : 'Restore Checkpoint'}
                </Button>
                {selectedPreview?.hasChangeset ? (
                    <Button
                        type='button'
                        size='sm'
                        variant={selectedPreview.recommendedAction === 'revert_changeset' ? 'default' : 'outline'}
                        className='h-11'
                        disabled={
                            input.rollbackPending ||
                            input.revertChangesetPending ||
                            rollbackPreviewPending ||
                            !selectedPreview.canRevertSafely
                        }
                        onClick={() => {
                            input.onRevertChangeset(input.checkpointId);
                        }}>
                        {input.revertChangesetPending && input.rollbackTargetId === input.checkpointId
                            ? 'Reverting…'
                            : 'Revert Changeset'}
                    </Button>
                ) : null}
                <Button
                    type='button'
                    size='sm'
                    variant='outline'
                    className='h-11'
                    disabled={input.rollbackPending || input.revertChangesetPending}
                    onClick={input.onCloseCheckpointActions}>
                    Keep Current State
                </Button>
            </div>
        </div>
    );
}

function CleanupPreviewSection(input: {
    profileId: string;
    selectedSessionId: CheckpointRecord['sessionId'];
    applyCleanupPending: boolean;
    onApplyCleanup: () => void;
}) {
    const cleanupPreviewQuery = trpc.checkpoint.previewCleanup.useQuery(
        {
            profileId: input.profileId,
            sessionId: input.selectedSessionId,
        },
        PROGRESSIVE_QUERY_OPTIONS
    );
    const cleanupPreviewPending = cleanupPreviewQuery.isPending;
    const cleanupPreviewData = cleanupPreviewQuery.data;

    return (
        <div className='border-border border-t p-3'>
            <p className='text-sm font-medium'>Retention Cleanup</p>
            <p className='text-muted-foreground mt-1 text-xs'>
                Cleanup affects retained checkpoint history only. It does not modify current workspace or sandbox files.
            </p>
            {cleanupPreviewPending ? (
                <p className='text-muted-foreground mt-3 text-sm'>Loading cleanup preview…</p>
            ) : cleanupPreviewData ? (
                <div className='mt-3 space-y-3'>
                    <div className='grid gap-2 text-xs text-muted-foreground sm:grid-cols-3'>
                        <p>Milestones kept: {String(cleanupPreviewData.milestoneCount)}</p>
                        <p>Recent checkpoints kept: {String(cleanupPreviewData.protectedRecentCount)}</p>
                        <p>Cleanup candidates: {String(cleanupPreviewData.eligibleCount)}</p>
                    </div>
                    {cleanupPreviewData.candidates.length === 0 ? (
                        <p className='text-muted-foreground text-sm'>No cleanup-eligible checkpoints in this session.</p>
                    ) : (
                        <div className='max-h-48 space-y-2 overflow-y-auto'>
                            {cleanupPreviewData.candidates.map((candidate) => (
                                <div key={candidate.checkpointId} className='border-border rounded-md border px-3 py-2 text-xs'>
                                    <p className='font-medium'>{candidate.summary}</p>
                                    <p className='text-muted-foreground mt-1'>
                                        {candidate.snapshotFileCount} snapshot files · {candidate.changesetChangeCount} changeset entries
                                    </p>
                                </div>
                            ))}
                        </div>
                    )}
                    <Button
                        type='button'
                        size='sm'
                        className='h-11'
                        disabled={input.applyCleanupPending || cleanupPreviewData.candidates.length === 0}
                        onClick={input.onApplyCleanup}>
                        {input.applyCleanupPending ? 'Cleaning Up…' : 'Apply Cleanup'}
                    </Button>
                </div>
            ) : null}
        </div>
    );
}

export function CheckpointHistorySection({
    visibleCheckpoints,
    checkpointStorage,
    selectedSessionId,
    disabled,
    cleanupPreviewOpen,
    forceCompactPending,
    applyCleanupPending,
    rollbackPending,
    revertChangesetPending,
    promoteMilestonePending,
    renameMilestonePending,
    deleteMilestonePending,
    confirmRollbackId,
    rollbackTargetId,
    milestoneDrafts,
    profileId,
    onToggleCheckpointActions,
    onCloseCheckpointActions,
    onMilestoneDraftChange,
    onRestoreCheckpoint,
    onRevertChangeset,
    onPromoteMilestone,
    onRenameMilestone,
    onDeleteMilestone,
    onApplyCleanup,
    onForceCompact,
}: CheckpointHistorySectionProps) {
    const lastCompactionRun = checkpointStorage?.lastCompactionRun;

    return (
        <section className='border-border rounded-lg border'>
            {checkpointStorage ? (
                <div className='border-border border-b p-3'>
                    <p className='text-sm font-medium'>Storage</p>
                    <p className='text-muted-foreground mt-1 text-xs'>
                        Compaction affects checkpoint storage only. It does not modify live workspace or sandbox files.
                    </p>
                    <div className='mt-3 grid gap-2 text-xs text-muted-foreground sm:grid-cols-2'>
                        <p>
                            Loose blobs: {String(checkpointStorage.looseReferencedBlobCount)} ·{' '}
                            {formatCheckpointByteSize(checkpointStorage.looseReferencedByteSize)}
                        </p>
                        <p>
                            Packed blobs: {String(checkpointStorage.packedReferencedBlobCount)} ·{' '}
                            {formatCheckpointByteSize(checkpointStorage.packedReferencedByteSize)}
                        </p>
                        <p>
                            Total referenced: {String(checkpointStorage.totalReferencedBlobCount)} ·{' '}
                            {formatCheckpointByteSize(checkpointStorage.totalReferencedByteSize)}
                        </p>
                        <p>{describeCompactionRun(lastCompactionRun)}</p>
                    </div>
                    <div className='mt-3 flex flex-wrap items-center gap-2'>
                        <Button type='button' size='sm' className='h-11' disabled={forceCompactPending || !selectedSessionId} onClick={onForceCompact}>
                            {forceCompactPending ? 'Compacting…' : 'Force Compact'}
                        </Button>
                        {lastCompactionRun ? (
                            <span className='text-muted-foreground text-xs'>
                                {lastCompactionRun.status} · {lastCompactionRun.completedAt}
                            </span>
                        ) : null}
                    </div>
                </div>
            ) : null}
            <div className='max-h-72 overflow-y-auto p-2'>
                {visibleCheckpoints.length === 0 ? (
                    <p className='text-muted-foreground rounded-xl border border-dashed p-3 text-sm'>No checkpoints for this session yet.</p>
                ) : (
                    <div className='space-y-2'>
                        {visibleCheckpoints.map((checkpoint) => (
                            <div key={checkpoint.id} className='border-border rounded-md border p-3'>
                                <div className='flex items-start justify-between gap-3'>
                                    <div className='min-w-0'>
                                        <div className='flex flex-wrap items-center gap-2'>
                                            <p className='text-sm font-medium'>{checkpoint.summary}</p>
                                            {checkpoint.checkpointKind === 'named' ? (
                                                <span className='rounded-full bg-primary/10 px-2 py-0.5 text-[11px] font-medium text-primary'>
                                                    Milestone
                                                </span>
                                            ) : null}
                                            {describeRetentionDisposition(checkpoint.retentionDisposition) ? (
                                                <span className='rounded-full bg-muted px-2 py-0.5 text-[11px] font-medium text-muted-foreground'>
                                                    {describeRetentionDisposition(checkpoint.retentionDisposition)}
                                                </span>
                                            ) : null}
                                        </div>
                                        <p className='text-muted-foreground text-xs'>
                                            {checkpoint.topLevelTab}.{checkpoint.modeKey} · {checkpoint.runId}
                                        </p>
                                    </div>
                                    <Button
                                        type='button'
                                        size='sm'
                                        className='h-11'
                                        disabled={disabled || rollbackPending || revertChangesetPending}
                                        onClick={() => {
                                            onToggleCheckpointActions(checkpoint.id);
                                        }}>
                                        {rollbackPending && rollbackTargetId === checkpoint.id
                                            ? 'Restoring…'
                                            : revertChangesetPending && rollbackTargetId === checkpoint.id
                                              ? 'Reverting…'
                                              : confirmRollbackId === checkpoint.id
                                                ? 'Cancel'
                                                : 'Actions'}
                                    </Button>
                                </div>
                                {confirmRollbackId === checkpoint.id ? (
                                    <RollbackPreviewSection
                                        profileId={profileId}
                                        checkpointId={checkpoint.id}
                                        rollbackPending={rollbackPending}
                                        revertChangesetPending={revertChangesetPending}
                                        rollbackTargetId={rollbackTargetId}
                                        executionTargetLabel={checkpoint.executionTargetLabel}
                                        buildRollbackWarningState={buildRollbackWarningLines}
                                        onRestoreCheckpoint={onRestoreCheckpoint}
                                        onRevertChangeset={onRevertChangeset}
                                        onCloseCheckpointActions={onCloseCheckpointActions}
                                    />
                                ) : null}
                                <div className='border-border bg-background/60 mt-3 rounded-md border p-3'>
                                    <p className='text-xs font-medium uppercase tracking-[0.12em] text-muted-foreground'>
                                        {checkpoint.checkpointKind === 'named' ? 'Milestone' : 'Promote to Milestone'}
                                    </p>
                                    <div className='mt-2 flex flex-wrap gap-2'>
                                        <input
                                            type='text'
                                            value={milestoneDrafts[checkpoint.id] ?? checkpoint.milestoneTitle ?? ''}
                                            onChange={(event) => {
                                                onMilestoneDraftChange(checkpoint.id, event.target.value);
                                            }}
                                            placeholder='Milestone title'
                                            className='border-border bg-background min-h-11 min-w-[14rem] flex-1 rounded-md border px-3 text-sm'
                                        />
                                        {checkpoint.checkpointKind === 'named' ? (
                                            <>
                                                <Button
                                                    type='button'
                                                    size='sm'
                                                    className='h-11'
                                                    disabled={renameMilestonePending || (milestoneDrafts[checkpoint.id] ?? checkpoint.milestoneTitle ?? '').trim().length === 0}
                                                    onClick={() => {
                                                        onRenameMilestone(checkpoint.id, (milestoneDrafts[checkpoint.id] ?? checkpoint.milestoneTitle ?? '').trim());
                                                    }}>
                                                    {renameMilestonePending ? 'Renaming…' : 'Rename Milestone'}
                                                </Button>
                                                <Button
                                                    type='button'
                                                    size='sm'
                                                    variant='outline'
                                                    className='h-11'
                                                    disabled={deleteMilestonePending}
                                                    onClick={() => {
                                                        onDeleteMilestone(checkpoint.id);
                                                    }}>
                                                    {deleteMilestonePending ? 'Deleting…' : 'Delete Milestone'}
                                                </Button>
                                            </>
                                        ) : (
                                            <Button
                                                type='button'
                                                size='sm'
                                                className='h-11'
                                                disabled={promoteMilestonePending || (milestoneDrafts[checkpoint.id] ?? '').trim().length === 0}
                                                onClick={() => {
                                                    onPromoteMilestone(checkpoint.id, (milestoneDrafts[checkpoint.id] ?? '').trim());
                                                }}>
                                                {promoteMilestonePending ? 'Promoting…' : 'Promote to Milestone'}
                                            </Button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
            {cleanupPreviewOpen && selectedSessionId ? (
                <CleanupPreviewSection
                    profileId={profileId}
                    selectedSessionId={selectedSessionId}
                    applyCleanupPending={applyCleanupPending}
                    onApplyCleanup={onApplyCleanup}
                />
            ) : null}
        </section>
    );
}

import { CheckpointHistorySection, type CheckpointHistorySectionProps } from '@/web/components/conversation/panels/diffCheckpointPanel/checkpointHistorySection';

export interface CheckpointMaintenanceActionsProps extends CheckpointHistorySectionProps {}

export function CheckpointMaintenanceActions(input: CheckpointMaintenanceActionsProps) {
    return <CheckpointHistorySection {...input} />;
}

import { skipToken } from '@tanstack/react-query';
import { useState } from 'react';

import {
    filterVisibleCheckpoints,
    resolveSelectedDiffPath,
} from '@/web/components/conversation/panels/diffCheckpointPanelState';
import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { trpc } from '@/web/trpc/client';

import type { CheckpointRecord, DiffRecord } from '@/app/backend/persistence/types';
import type { CheckpointStorageSummary } from '@/app/backend/runtime/contracts';

import type { ChangedFilesSectionProps } from './changedFilesSection';
import type { CheckpointMaintenanceActionsProps } from './checkpointMaintenanceActions';

export interface DiffCheckpointPanelProps {
    profileId: string;
    selectedRunId?: CheckpointRecord['runId'];
    selectedSessionId?: CheckpointRecord['sessionId'];
    diffs: DiffRecord[];
    checkpoints: CheckpointRecord[];
    checkpointStorage?: CheckpointStorageSummary;
    disabled: boolean;
}

export function buildDiffPatchPreviewQueryInput(input: {
    profileId: string;
    selectedDiff: DiffRecord | undefined;
    resolvedSelectedPath: string | undefined;
}) {
    return input.selectedDiff && input.resolvedSelectedPath
        ? {
              profileId: input.profileId,
              diffId: input.selectedDiff.id,
              path: input.resolvedSelectedPath,
          }
        : skipToken;
}

export function useDiffCheckpointPanelController({
    profileId,
    selectedRunId,
    selectedSessionId,
    diffs,
    checkpoints,
    checkpointStorage,
    disabled,
}: DiffCheckpointPanelProps) {
    const selectedDiff = diffs[0];
    const [preferredPath, setPreferredPath] = useState<string | undefined>(undefined);
    const [confirmRollbackId, setConfirmRollbackId] = useState<CheckpointRecord['id'] | undefined>(undefined);
    const [rollbackTargetId, setRollbackTargetId] = useState<CheckpointRecord['id'] | undefined>(undefined);
    const [feedbackMessage, setFeedbackMessage] = useState<string | undefined>(undefined);
    const [milestoneTitle, setMilestoneTitle] = useState('');
    const [milestoneDrafts, setMilestoneDrafts] = useState<Record<string, string>>({});
    const [milestonesOnly, setMilestonesOnly] = useState(false);
    const [cleanupPreviewOpen, setCleanupPreviewOpen] = useState(false);
    const resolvedSelectedPath = resolveSelectedDiffPath({
        selectedDiff,
        preferredPath,
    });
    const utils = trpc.useUtils();

    const invalidateCheckpointList = () => {
        if (!selectedSessionId) {
            return Promise.resolve();
        }

        return utils.checkpoint.list.invalidate({
            profileId,
            sessionId: selectedSessionId,
        });
    };

    const patchQuery = trpc.diff.getFilePatch.useQuery(
        buildDiffPatchPreviewQueryInput({
            profileId,
            selectedDiff,
            resolvedSelectedPath,
        }),
        PROGRESSIVE_QUERY_OPTIONS
    );
    const openPathMutation = trpc.system.openPath.useMutation();
    const rollbackMutation = trpc.checkpoint.rollback.useMutation({
        onSuccess: async (result) => {
            if (!result.rolledBack) {
                setFeedbackMessage(result.message ?? 'Rollback could not be completed.');
                return;
            }

            setFeedbackMessage('Checkpoint rollback completed.');
            setConfirmRollbackId(undefined);
            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
        onSettled: () => {
            setRollbackTargetId(undefined);
        },
    });
    const createMilestoneMutation = trpc.checkpoint.create.useMutation({
        onSuccess: async (result) => {
            if (!result.created) {
                setFeedbackMessage('Milestone could not be saved.');
                return;
            }

            setFeedbackMessage('Milestone saved.');
            setMilestoneTitle('');
            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
    });
    const promoteMilestoneMutation = trpc.checkpoint.promoteToMilestone.useMutation({
        onSuccess: async (result) => {
            if (!result.promoted) {
                setFeedbackMessage('Checkpoint could not be promoted to a milestone.');
                return;
            }

            setFeedbackMessage('Checkpoint promoted to milestone.');
            setMilestoneDrafts((current) => {
                const nextDrafts = { ...current };
                if (result.checkpoint) {
                    delete nextDrafts[result.checkpoint.id];
                }
                return nextDrafts;
            });
            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
    });
    const renameMilestoneMutation = trpc.checkpoint.renameMilestone.useMutation({
        onSuccess: async (result) => {
            if (!result.renamed) {
                setFeedbackMessage('Milestone could not be renamed.');
                return;
            }

            setFeedbackMessage('Milestone renamed.');
            setMilestoneDrafts((current) => {
                const nextDrafts = { ...current };
                if (result.checkpoint) {
                    delete nextDrafts[result.checkpoint.id];
                }
                return nextDrafts;
            });
            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
    });
    const deleteMilestoneMutation = trpc.checkpoint.deleteMilestone.useMutation({
        onSuccess: async (result) => {
            if (!result.deleted) {
                setFeedbackMessage('Milestone could not be deleted.');
                return;
            }

            setFeedbackMessage('Milestone deleted.');
            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
    });
    const applyCleanupMutation = trpc.checkpoint.applyCleanup.useMutation({
        onSuccess: async (result) => {
            if (!result.cleanedUp) {
                setFeedbackMessage(result.message ?? 'Cleanup requires explicit confirmation.');
                return;
            }

            setFeedbackMessage(
                `Cleanup removed ${String(result.deletedCount ?? 0)} checkpoints and pruned ${String(result.prunedBlobCount ?? 0)} snapshot blobs.`
            );
            await Promise.all([invalidateCheckpointList(), utils.checkpoint.previewCleanup.invalidate()]);
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
    });
    const revertChangesetMutation = trpc.checkpoint.revertChangeset.useMutation({
        onSuccess: async (result) => {
            if (!result.reverted) {
                setFeedbackMessage(result.message ?? 'Changeset revert could not be completed.');
                return;
            }

            setFeedbackMessage('Changeset revert completed.');
            setConfirmRollbackId(undefined);
            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
        onSettled: () => {
            setRollbackTargetId(undefined);
        },
    });
    const forceCompactMutation = trpc.checkpoint.forceCompact.useMutation({
        onSuccess: async (result) => {
            if (!result.compacted) {
                setFeedbackMessage(result.message ?? 'Compaction requires explicit confirmation.');
            } else if (result.run?.status === 'failed') {
                setFeedbackMessage(result.run.message ?? 'Checkpoint compaction failed.');
            } else if (result.run?.status === 'noop') {
                setFeedbackMessage(result.run.message ?? 'No checkpoint blobs were eligible for compaction.');
            } else {
                setFeedbackMessage(result.run?.message ?? 'Checkpoint storage compaction completed.');
            }

            await invalidateCheckpointList();
        },
        onError: (error) => {
            setFeedbackMessage(error.message);
        },
    });

    const prefetchPatch = (path: string) => {
        if (!selectedDiff) {
            return;
        }

        void utils.diff.getFilePatch.prefetch({
            profileId,
            diffId: selectedDiff.id,
            path,
        });
    };

    const patchMarkdown = patchQuery.data?.found && patchQuery.data.patch ? `\`\`\`diff\n${patchQuery.data.patch}\n\`\`\`` : '';
    const visibleCheckpoints = filterVisibleCheckpoints(checkpoints, milestonesOnly);

    async function handleRestoreCheckpoint(checkpointId: CheckpointRecord['id']) {
        setRollbackTargetId(checkpointId);
        setFeedbackMessage(undefined);
        try {
            await rollbackMutation.mutateAsync({
                profileId,
                checkpointId,
                confirm: true,
            });
        } catch {}
    }

    async function handleRevertChangeset(checkpointId: CheckpointRecord['id']) {
        setRollbackTargetId(checkpointId);
        setFeedbackMessage(undefined);
        try {
            await revertChangesetMutation.mutateAsync({
                profileId,
                checkpointId,
                confirm: true,
            });
        } catch {}
    }

    async function handlePromoteMilestone(checkpointId: CheckpointRecord['id'], title: string) {
        if (title.length === 0) {
            return;
        }

        setFeedbackMessage(undefined);
        try {
            await promoteMilestoneMutation.mutateAsync({
                profileId,
                checkpointId,
                milestoneTitle: title,
            });
        } catch {}
    }

    async function handleRenameMilestone(checkpointId: CheckpointRecord['id'], title: string) {
        if (title.length === 0) {
            return;
        }

        setFeedbackMessage(undefined);
        try {
            await renameMilestoneMutation.mutateAsync({
                profileId,
                checkpointId,
                milestoneTitle: title,
            });
        } catch {}
    }

    async function handleDeleteMilestone(checkpointId: CheckpointRecord['id']) {
        setFeedbackMessage(undefined);
        try {
            await deleteMilestoneMutation.mutateAsync({
                profileId,
                checkpointId,
                confirm: true,
            });
        } catch {}
    }

    async function handleApplyCleanup() {
        if (!selectedSessionId) {
            return;
        }

        setFeedbackMessage(undefined);
        try {
            await applyCleanupMutation.mutateAsync({
                profileId,
                sessionId: selectedSessionId,
                confirm: true,
            });
        } catch {}
    }

    async function handleForceCompact() {
        if (!selectedSessionId) {
            return;
        }

        setFeedbackMessage(undefined);
        try {
            await forceCompactMutation.mutateAsync({
                profileId,
                sessionId: selectedSessionId,
                confirm: true,
            });
        } catch {}
    }

    async function handleSaveMilestone() {
        if (!selectedRunId || milestoneTitle.trim().length === 0) {
            return;
        }

        setFeedbackMessage(undefined);
        try {
            await createMilestoneMutation.mutateAsync({
                profileId,
                runId: selectedRunId,
                milestoneTitle: milestoneTitle.trim(),
            });
        } catch {}
    }

    async function handleOpenPath() {
        if (!selectedDiff || selectedDiff.artifact.kind !== 'git' || !resolvedSelectedPath) {
            return;
        }

        try {
            await openPathMutation.mutateAsync({
                path: `${selectedDiff.artifact.workspaceRootPath}\\${resolvedSelectedPath.replaceAll('/', '\\')}`,
            });
        } catch {}
    }

    const changedFilesSectionProps: ChangedFilesSectionProps | undefined = selectedDiff
        ? {
              selectedDiff,
              resolvedSelectedPath,
              milestonesOnly,
              checkpointsCount: checkpoints.length,
              cleanupPreviewOpen,
              onToggleMilestonesOnly: () => {
                  setMilestonesOnly((current) => !current);
              },
              onToggleCleanupPreview: () => {
                  if (!selectedSessionId) {
                      return;
                  }

                  setCleanupPreviewOpen((current) => !current);
              },
              onPrefetchPatch: prefetchPatch,
              onSelectPath: setPreferredPath,
          }
        : undefined;

    const maintenanceActionsProps: CheckpointMaintenanceActionsProps = {
        visibleCheckpoints,
        checkpointStorage,
        selectedSessionId,
        disabled,
        cleanupPreviewOpen,
        forceCompactPending: forceCompactMutation.isPending,
        applyCleanupPending: applyCleanupMutation.isPending,
        rollbackPending: rollbackMutation.isPending,
        revertChangesetPending: revertChangesetMutation.isPending,
        promoteMilestonePending: promoteMilestoneMutation.isPending,
        renameMilestonePending: renameMilestoneMutation.isPending,
        deleteMilestonePending: deleteMilestoneMutation.isPending,
        confirmRollbackId,
        rollbackTargetId,
        milestoneDrafts,
        profileId,
        onToggleCheckpointActions: (checkpointId) => {
            setFeedbackMessage(undefined);
            setConfirmRollbackId((current) => (current === checkpointId ? undefined : checkpointId));
        },
        onCloseCheckpointActions: () => {
            setConfirmRollbackId(undefined);
        },
        onMilestoneDraftChange: (checkpointId, value) => {
            setMilestoneDrafts((current) => ({
                ...current,
                [checkpointId]: value,
            }));
        },
        onRestoreCheckpoint: (checkpointId) => {
            void handleRestoreCheckpoint(checkpointId);
        },
        onRevertChangeset: (checkpointId) => {
            void handleRevertChangeset(checkpointId);
        },
        onPromoteMilestone: (checkpointId, title) => {
            void handlePromoteMilestone(checkpointId, title);
        },
        onRenameMilestone: (checkpointId, title) => {
            void handleRenameMilestone(checkpointId, title);
        },
        onDeleteMilestone: (checkpointId) => {
            void handleDeleteMilestone(checkpointId);
        },
        onToggleCleanupPreview: () => {
            setCleanupPreviewOpen((current) => !current);
        },
        onApplyCleanup: () => {
            void handleApplyCleanup();
        },
        onForceCompact: () => {
            void handleForceCompact();
        },
    };

    return {
        selectedDiff,
        feedbackMessage,
        milestoneTitle,
        isSavingMilestone: createMilestoneMutation.isPending,
        onMilestoneTitleChange: setMilestoneTitle,
        onSaveMilestone: () => {
            void handleSaveMilestone();
        },
        changedFilesSectionProps,
        maintenanceActionsProps,
        diffPatchPreviewProps: {
            selectedDiff,
            resolvedSelectedPath,
            patchMarkdown,
            isLoadingPatch: patchQuery.isPending,
            isRefreshingPatch: patchQuery.isFetching,
            canOpenPath: Boolean(selectedDiff?.artifact.kind === 'git' && resolvedSelectedPath),
            isOpeningPath: openPathMutation.isPending,
            onOpenPath: () => {
                void handleOpenPath();
            },
        },
    };
}

