    ComposerImageAttachmentInput,
    EntityId,
    PlanStartInput,
    PlanRecordView,
    RuntimeProviderId,
    SessionStartRunInput,
    TopLevelTab,
} from '@/shared/contracts';
import type { OptimisticConversationUserMessage } from '@/web/components/conversation/messages/optimisticUserMessage';

interface ProviderAuthView {
    label: string;
    authState: string;
    authMethod: string;
}

type PlanStartSuccessResult = { plan: PlanRecordView };
type RunStartAcceptedResult = { accepted: true };
type RunStartRejectedResult = RunStartRejectedResultLike;

function isAcceptedRunResult<
    TRunStartAcceptedResult extends RunStartAcceptedResult,
>(
    result: TRunStartAcceptedResult | RunStartRejectedResult
): result is TRunStartAcceptedResult {
    return result.accepted;
}

interface SubmitPromptInput<
    TPlanStartResult extends PlanStartSuccessResult,
    TRunStartAcceptedResult extends RunStartAcceptedResult,
> {
    prompt: string;
    attachments?: ComposerImageAttachmentInput[];
    isStartingRun: boolean;
    selectedSessionId: string | undefined;
    isPlanningMode: boolean;
    profileId: string;
    topLevelTab: TopLevelTab;
    modeKey: string;
    workspaceFingerprint: string | undefined;
    sandboxId?: EntityId<'sb'>;
    resolvedRunTarget: RunTargetSelection | undefined;
    runtimeOptions: RuntimeRunOptions;
    providerById: Map<RuntimeProviderId, ProviderAuthView>;
    startPlan: (input: PlanStartInput) => Promise<TPlanStartResult>;
    startRun: (input: SessionStartRunInput) => Promise<TRunStartAcceptedResult | RunStartRejectedResult>;
    onPromptCleared: () => void;
    onPlanStarted: (result: TPlanStartResult) => void;
    onRunStarted: (result: TRunStartAcceptedResult) => void;
    onRunStartRequested?: (input: Pick<OptimisticConversationUserMessage, 'sessionId' | 'prompt'>) => void;
    onRunStartFinished?: () => void;
    onError: (message: string) => void;
}

export async function submitPrompt<
    TPlanStartResult extends PlanStartSuccessResult,
    TRunStartAcceptedResult extends RunStartAcceptedResult,
>(
    input: SubmitPromptInput<TPlanStartResult, TRunStartAcceptedResult>
): Promise<void> {
    const trimmedPrompt = input.prompt.trim();
    const attachments = input.attachments ?? [];
    if ((trimmedPrompt.length === 0 && attachments.length === 0) || input.isStartingRun) {
        return;
    }

    if (!isEntityId(input.selectedSessionId, 'sess')) {
        return;
    }

    if (input.isPlanningMode) {
        if (trimmedPrompt.length === 0) {
            input.onError('Planning runs require a text prompt.');
            return;
        }

        try {
            const result = await input.startPlan({
                profileId: input.profileId,
                sessionId: input.selectedSessionId,
                topLevelTab: input.topLevelTab,
                modeKey: input.modeKey,
                prompt: trimmedPrompt,
                ...(input.workspaceFingerprint ? { workspaceFingerprint: input.workspaceFingerprint } : {}),
            });
            input.onPromptCleared();
            input.onPlanStarted(result);
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : String(error);
            input.onError(`Plan start failed: ${message}`);
        }
        return;
    }

    if (!input.resolvedRunTarget) {
        input.onError('No runnable provider/model found. Open Settings > Providers to configure one.');
        return;
    }

    const selectedProvider = input.providerById.get(input.resolvedRunTarget.providerId);
    if (selectedProvider && !isProviderRunnable(selectedProvider.authState, selectedProvider.authMethod)) {
        input.onError(
            formatRunStartRejection({
                rejection: {
                    accepted: false,
                    message: `Provider "${input.resolvedRunTarget.providerId}" is not authenticated/configured.`,
                    action: {
                        code: 'provider_not_runnable',
                        providerId: input.resolvedRunTarget.providerId,
                    },
                },
                providerById: input.providerById,
            })
        );
        return;
    }

    try {
        input.onRunStartRequested?.({
            sessionId: input.selectedSessionId,
            prompt: trimmedPrompt,
        });
        const result = await input.startRun({
            profileId: input.profileId,
            sessionId: input.selectedSessionId,
            prompt: trimmedPrompt,
            topLevelTab: input.topLevelTab,
            modeKey: input.modeKey,
            providerId: input.resolvedRunTarget.providerId,
            modelId: input.resolvedRunTarget.modelId,
            ...(attachments.length > 0 ? { attachments } : {}),
            ...(input.workspaceFingerprint ? { workspaceFingerprint: input.workspaceFingerprint } : {}),
            ...(input.sandboxId ? { sandboxId: input.sandboxId } : {}),
            runtimeOptions: input.runtimeOptions,
        });
        if (!isAcceptedRunResult(result)) {
            input.onRunStartFinished?.();
            input.onError(
                formatRunStartRejection({
                    rejection: result,
                    providerById: input.providerById,
                })
            );
            return;
        }
        input.onPromptCleared();
        input.onRunStarted(result);
    } catch (error: unknown) {
        input.onRunStartFinished?.();
        const message = error instanceof Error ? error.message : String(error);
        input.onError(`Run failed: ${message}`);
    }
}

import { describe, expect, it, vi } from 'vitest';

import { runConversationPlanMutation } from '@/web/components/conversation/shell/composition/buildConversationPlanOrchestrator';

describe('runConversationPlanMutation', () => {
    it('applies successful mutation results', async () => {
        const applyResult = vi.fn();
        const onError = vi.fn();

        await runConversationPlanMutation({
            mutation: {
                mutateAsync: async () => ({ found: true as const }),
            },
            applyResult,
            onError,
            errorPrefix: 'Plan answer failed',
        });

        expect(applyResult).toHaveBeenCalledWith({ found: true });
        expect(onError).not.toHaveBeenCalled();
    });

    it('routes rejected mutation errors through the provided error handler', async () => {
        const applyResult = vi.fn();
        const onError = vi.fn();

        await runConversationPlanMutation({
            mutation: {
                mutateAsync: async () => {
                    throw new Error('network down');
                },
            },
            applyResult,
            onError,
            errorPrefix: 'Plan revision failed',
        });

        expect(applyResult).not.toHaveBeenCalled();
        expect(onError).toHaveBeenCalledWith('Plan revision failed: network down');
    });
});

import type { ModeExecutionPanelProps } from '@/web/components/conversation/panels/modeExecutionPanel';
import type { RunTargetSelection } from '@/web/components/conversation/shell/workspace/helpers';

import type { OrchestratorRunRecord, OrchestratorStepRecord } from '@/app/backend/persistence/types';

import type {
    EntityId,
    OrchestratorExecutionStrategy,
    PlanRecordView,
    RuntimeProviderId,
    RuntimeRunOptions,
} from '@/shared/contracts';

interface MutationLike<TInput, TResult> {
    isPending: boolean;
    mutateAsync: (input: TInput) => Promise<TResult>;
}

interface BuildConversationPlanOrchestratorInput {
    profileId: string;
    applyPlanWorkspaceUpdate: (result: { found: false } | { found: true; plan: PlanRecordView }) => void;
    applyOrchestratorWorkspaceUpdate: (
        result: { found: false } | { found: true; run: OrchestratorRunRecord; steps: OrchestratorStepRecord[] }
    ) => void;
    onError: (message: string) => void;
    resolvedRunTarget: RunTargetSelection | undefined;
    runtimeOptions: RuntimeRunOptions;
    workspaceFingerprint: string | undefined;
    activePlan: ModeExecutionPanelProps['activePlan'];
    orchestratorView: ModeExecutionPanelProps['orchestratorView'];
    selectedExecutionStrategy: OrchestratorExecutionStrategy;
    planStartMutation: MutationLike<
        {
            profileId: string;
            sessionId: EntityId<'sess'>;
            topLevelTab: 'chat' | 'agent' | 'orchestrator';
            modeKey: string;
            prompt: string;
            workspaceFingerprint?: string;
        },
        { plan: PlanRecordView }
    >;
    planAnswerMutation: MutationLike<
        {
            profileId: string;
            planId: EntityId<'plan'>;
            questionId: string;
            answer: string;
        },
        { found: false } | { found: true; plan: PlanRecordView }
    >;
    planReviseMutation: MutationLike<
        {
            profileId: string;
            planId: EntityId<'plan'>;
            summaryMarkdown: string;
            items: Array<{ description: string }>;
        },
        { found: false } | { found: true; plan: PlanRecordView }
    >;
    planApproveMutation: MutationLike<
        {
            profileId: string;
            planId: EntityId<'plan'>;
        },
        { found: false } | { found: true; plan: PlanRecordView }
    >;
    planImplementMutation: MutationLike<
        {
            profileId: string;
            planId: EntityId<'plan'>;
            runtimeOptions: RuntimeRunOptions;
            providerId?: RuntimeProviderId;
            modelId?: string;
            workspaceFingerprint?: string;
            executionStrategy?: OrchestratorExecutionStrategy;
        },
        | { found: false }
        | { found: true; plan: PlanRecordView }
        | { found: true; plan: PlanRecordView; started: true; mode: 'agent.code' | 'orchestrator.orchestrate' }
    >;
    orchestratorAbortMutation: MutationLike<
        {
            profileId: string;
            orchestratorRunId: EntityId<'orch'>;
        },
        | { aborted: false; reason: 'not_found' }
        | {
              aborted: true;
              runId: EntityId<'orch'>;
              latest: { found: false } | { found: true; run: OrchestratorRunRecord; steps: OrchestratorStepRecord[] };
          }
    >;
}

function readActionErrorMessage(prefix: string, error: unknown): string {
    const message = error instanceof Error ? error.message : String(error);
    return `${prefix}: ${message}`;
}

export async function runConversationPlanMutation<TResult>(input: {
    mutation: {
        mutateAsync: () => Promise<TResult>;
    };
    applyResult: (result: TResult) => void;
    onError: (message: string) => void;
    errorPrefix: string;
}): Promise<void> {
    try {
        const result = await input.mutation.mutateAsync();
        input.applyResult(result);
    } catch (error) {
        input.onError(readActionErrorMessage(input.errorPrefix, error));
    }
}

export function buildConversationPlanOrchestrator(input: BuildConversationPlanOrchestratorInput): {
    isPlanMutating: boolean;
    isOrchestratorMutating: boolean;
    activePlan: ModeExecutionPanelProps['activePlan'];
    orchestratorView: ModeExecutionPanelProps['orchestratorView'];
    selectedExecutionStrategy: ModeExecutionPanelProps['selectedExecutionStrategy'];
    onAnswerQuestion: ModeExecutionPanelProps['onAnswerQuestion'];
    onRevisePlan: ModeExecutionPanelProps['onRevisePlan'];
    onApprovePlan: ModeExecutionPanelProps['onApprovePlan'];
    onImplementPlan: ModeExecutionPanelProps['onImplementPlan'];
    onAbortOrchestrator: ModeExecutionPanelProps['onAbortOrchestrator'];
} {
    return {
        isPlanMutating:
            input.planStartMutation.isPending ||
            input.planAnswerMutation.isPending ||
            input.planReviseMutation.isPending ||
            input.planApproveMutation.isPending ||
            input.planImplementMutation.isPending,
        isOrchestratorMutating: input.orchestratorAbortMutation.isPending,
        activePlan: input.activePlan,
        orchestratorView: input.orchestratorView,
        selectedExecutionStrategy: input.selectedExecutionStrategy,
        onAnswerQuestion: (planId, questionId, answer) => {
            void runConversationPlanMutation({
                mutation: {
                    mutateAsync: () =>
                        input.planAnswerMutation.mutateAsync({
                            profileId: input.profileId,
                            planId,
                            questionId,
                            answer,
                        }),
                },
                applyResult: (result) => {
                    input.applyPlanWorkspaceUpdate(result);
                },
                onError: input.onError,
                errorPrefix: 'Plan answer failed',
            });
        },
        onRevisePlan: (planId, summaryMarkdown, items) => {
            void runConversationPlanMutation({
                mutation: {
                    mutateAsync: () =>
                        input.planReviseMutation.mutateAsync({
                            profileId: input.profileId,
                            planId,
                            summaryMarkdown,
                            items: items.map((description) => ({ description })),
                        }),
                },
                applyResult: (result) => {
                    input.applyPlanWorkspaceUpdate(result);
                },
                onError: input.onError,
                errorPrefix: 'Plan revision failed',
            });
        },
        onApprovePlan: (planId) => {
            void runConversationPlanMutation({
                mutation: {
                    mutateAsync: () =>
                        input.planApproveMutation.mutateAsync({
                            profileId: input.profileId,
                            planId,
                        }),
                },
                applyResult: (result) => {
                    input.applyPlanWorkspaceUpdate(result);
                },
                onError: input.onError,
                errorPrefix: 'Plan approval failed',
            });
        },
        onImplementPlan: (planId, executionStrategy) => {
            void runConversationPlanMutation({
                mutation: {
                    mutateAsync: () =>
                        input.planImplementMutation.mutateAsync({
                            profileId: input.profileId,
                            planId,
                            runtimeOptions: input.runtimeOptions,
                            ...(input.resolvedRunTarget ? { providerId: input.resolvedRunTarget.providerId } : {}),
                            ...(input.resolvedRunTarget ? { modelId: input.resolvedRunTarget.modelId } : {}),
                            ...(input.workspaceFingerprint ? { workspaceFingerprint: input.workspaceFingerprint } : {}),
                            ...(executionStrategy ? { executionStrategy } : {}),
                        }),
                },
                applyResult: (result) => {
                    input.applyPlanWorkspaceUpdate(
                        result.found
                            ? {
                                  found: true,
                                  plan: result.plan,
                              }
                            : { found: false }
                    );
                },
                onError: input.onError,
                errorPrefix: 'Plan implementation failed',
            });
        },
        onAbortOrchestrator: (orchestratorRunId) => {
            void runConversationPlanMutation({
                mutation: {
                    mutateAsync: () =>
                        input.orchestratorAbortMutation.mutateAsync({
                            profileId: input.profileId,
                            orchestratorRunId,
                        }),
                },
                applyResult: (result) => {
                    if (result.aborted) {
                        input.applyOrchestratorWorkspaceUpdate(result.latest);
                    }
                },
                onError: input.onError,
                errorPrefix: 'Orchestrator abort failed',
            });
        },
    };
}

