import { useState } from 'react';

import {
    createDraftFromServer,
    createEmptyDraft,
    parseArgs,
    parseTimeout,
    type McpServerDraft,
} from '@/web/components/settings/appSettings/mcpSection.shared';
import { trpc } from '@/web/trpc/client';

import type { McpServerRecord } from '@/app/backend/runtime/contracts/types/mcp';

interface McpSettingsControllerInput {
    profileId: string;
    currentWorkspaceFingerprint?: string;
}

export function useMcpSettingsController({
    profileId,
    currentWorkspaceFingerprint,
}: McpSettingsControllerInput) {
    const utils = trpc.useUtils();
    const serversQuery = trpc.mcp.listServers.useQuery();
    const [editorMode, setEditorMode] = useState<'create' | 'edit'>('create');
    const [editingServerId, setEditingServerId] = useState<string | undefined>(undefined);
    const [draft, setDraft] = useState<McpServerDraft>(() => createEmptyDraft());
    const [statusMessage, setStatusMessage] = useState<string | undefined>(undefined);
    const [deleteTarget, setDeleteTarget] = useState<{ id: string; label: string } | undefined>(undefined);

    const servers = serversQuery.data?.servers ?? [];
    const selectedServer = editingServerId
        ? servers.find((server) => server.id === editingServerId)
        : undefined;

    async function invalidateMcpQueries() {
        await Promise.all([utils.mcp.listServers.invalidate(), utils.mcp.getServer.invalidate()]);
    }

    function startCreateServerDraft(options?: { preserveStatusMessage?: boolean }) {
        setEditorMode('create');
        setEditingServerId(undefined);
        setDraft(createEmptyDraft());
        if (!options?.preserveStatusMessage) {
            setStatusMessage(undefined);
        }
    }

    function startEditServerDraft(server: McpServerRecord) {
        setEditorMode('edit');
        setEditingServerId(server.id);
        setDraft(createDraftFromServer(server));
        setStatusMessage(undefined);
    }

    const createServerMutation = trpc.mcp.createServer.useMutation();
    const updateServerMutation = trpc.mcp.updateServer.useMutation();
    const deleteServerMutation = trpc.mcp.deleteServer.useMutation();
    const connectMutation = trpc.mcp.connect.useMutation();
    const disconnectMutation = trpc.mcp.disconnect.useMutation();
    const setEnvSecretsMutation = trpc.mcp.setEnvSecrets.useMutation();

    const isBusy =
        createServerMutation.isPending ||
        updateServerMutation.isPending ||
        deleteServerMutation.isPending ||
        connectMutation.isPending ||
        disconnectMutation.isPending ||
        setEnvSecretsMutation.isPending;

    async function submitDraft() {
        try {
            const parsedTimeout = parseTimeout(draft.timeoutText);
            const payload = {
                label: draft.label.trim(),
                command: draft.command.trim(),
                args: parseArgs(draft.argsText),
                workingDirectoryMode: draft.workingDirectoryMode,
                ...(draft.workingDirectoryMode === 'fixed_path'
                    ? { fixedWorkingDirectory: draft.fixedWorkingDirectory.trim() }
                    : {}),
                ...(parsedTimeout !== undefined ? { timeoutMs: parsedTimeout } : {}),
                enabled: draft.enabled,
            } as const;
            const values = draft.envEntries
                .map((entry) => ({ key: entry.key.trim(), value: entry.value.trim() }))
                .filter((entry) => entry.key.length > 0 && entry.value.length > 0);

            if (editorMode === 'create') {
                const created = await createServerMutation.mutateAsync(payload);
                if (values.length > 0) {
                    await setEnvSecretsMutation.mutateAsync({ serverId: created.server.id, values });
                }
                await invalidateMcpQueries();
                startCreateServerDraft({ preserveStatusMessage: true });
                setStatusMessage(`Created "${created.server.label}".`);
                return;
            }

            if (!selectedServer) {
                return;
            }

            const clearKeys = selectedServer.envKeys.filter(
                (existingKey) => !draft.envEntries.some((entry) => entry.key.trim() === existingKey)
            );
            const updated = await updateServerMutation.mutateAsync({ serverId: selectedServer.id, ...payload });
            if (!updated.updated) {
                setStatusMessage('Selected MCP server no longer exists.');
                return;
            }
            if (values.length > 0 || clearKeys.length > 0) {
                await setEnvSecretsMutation.mutateAsync({
                    serverId: selectedServer.id,
                    values,
                    ...(clearKeys.length > 0 ? { clearKeys } : {}),
                });
            }
            await invalidateMcpQueries();
            setStatusMessage(`Updated "${updated.server.label}".`);
        } catch (error) {
            setStatusMessage(error instanceof Error ? error.message : 'MCP server could not be saved.');
        }
    }

    async function connectServer(server: McpServerRecord) {
        try {
            await connectMutation.mutateAsync({
                profileId,
                serverId: server.id,
                ...(currentWorkspaceFingerprint ? { workspaceFingerprint: currentWorkspaceFingerprint } : {}),
            });
            await invalidateMcpQueries();
        } catch {}
    }

    async function disconnectServer(serverId: string) {
        try {
            await disconnectMutation.mutateAsync({ serverId });
            await invalidateMcpQueries();
        } catch {}
    }

    async function confirmDeleteServer() {
        if (!deleteTarget) {
            return;
        }

        try {
            await deleteServerMutation.mutateAsync({ serverId: deleteTarget.id });
            await invalidateMcpQueries();
            if (editingServerId === deleteTarget.id) {
                startCreateServerDraft();
            }
            setDeleteTarget(undefined);
        } catch {}
    }

    return {
        servers,
        editorMode,
        draft,
        statusMessage,
        deleteTarget,
        isBusy,
        currentWorkspaceFingerprint,
        deletePending: deleteServerMutation.isPending,
        setDraft,
        setDeleteTarget,
        startCreateServerDraft,
        startEditServerDraft,
        submitDraft,
        connectServer,
        disconnectServer,
        confirmDeleteServer,
    };
}

import { useState } from 'react';

import { McpSettingsSection } from '@/web/components/settings/appSettings/mcpSection';
import { SettingsSelectionRail } from '@/web/components/settings/shared/settingsSelectionRail';
import { APP_SETTINGS_SUBSECTIONS, type AppSettingsSubsectionId } from '@/web/components/settings/settingsNavigation';
import PrivacyModeToggle from '@/web/components/window/privacyModeToggle';
import { ConfirmDialog } from '@/web/components/ui/confirmDialog';
import { trpc } from '@/web/trpc/client';

import { FACTORY_RESET_CONFIRMATION_TEXT } from '@/shared/contracts';

interface AppSettingsViewProps {
    profileId: string;
    subsection?: AppSettingsSubsectionId;
    currentWorkspaceFingerprint?: string;
    onSubsectionChange?: (subsection: AppSettingsSubsectionId) => void;
}

function AppSectionHeader({
    title,
    description,
}: {
    title: string;
    description: string;
}) {
    return (
        <div className='space-y-2'>
            <p className='text-primary text-[11px] font-semibold tracking-[0.16em] uppercase'>App</p>
            <div className='space-y-1'>
                <h4 className='text-xl font-semibold text-balance'>{title}</h4>
                <p className='text-muted-foreground max-w-3xl text-sm leading-6'>{description}</p>
            </div>
        </div>
    );
}

export function AppSettingsView({
    profileId,
    subsection = 'privacy',
    currentWorkspaceFingerprint,
    onSubsectionChange,
}: AppSettingsViewProps) {
    const [confirmOpen, setConfirmOpen] = useState(false);
    const [confirmationText, setConfirmationText] = useState('');
    const factoryResetMutation = trpc.runtime.factoryReset.useMutation({
        onSuccess: () => {
            setConfirmOpen(false);
            setConfirmationText('');
        },
    });

    async function handleConfirmFactoryReset() {
        try {
            await factoryResetMutation.mutateAsync({
                confirm: true,
                confirmationText,
            });
        } catch {}
    }

    return (
        <section className='grid h-full min-h-0 min-w-0 overflow-hidden xl:grid-cols-[280px_minmax(0,1fr)]'>
            <SettingsSelectionRail
                title='App'
                ariaLabel='App settings sections'
                selectedId={subsection}
                onSelect={(itemId) => {
                    const nextSection = APP_SETTINGS_SUBSECTIONS.find((candidate) => candidate.id === itemId);
                    if (!nextSection) {
                        return;
                    }

                    onSubsectionChange?.(nextSection.id);
                }}
                items={APP_SETTINGS_SUBSECTIONS.map((item) => ({
                    id: item.id,
                    title: item.label,
                    subtitle: item.description,
                }))}
            />

            <div className='min-h-0 min-w-0 overflow-y-auto p-5 md:p-6'>
                <div className='mx-auto flex max-w-4xl flex-col gap-5'>
                    {subsection === 'privacy' ? (
                        <>
                            <AppSectionHeader
                                title='Privacy'
                                description='Keep sensitive value redaction in a dedicated app scope instead of scattering privacy controls across account pages.'
                            />

                            <section className='border-border/70 bg-card/55 space-y-4 rounded-[24px] border p-5'>
                                <div className='space-y-1'>
                                    <p className='text-sm font-semibold'>Privacy mode</p>
                                    <p className='text-muted-foreground text-xs leading-5'>
                                        Redact sensitive account and usage values across the app when you are sharing
                                        your screen or capturing screenshots.
                                    </p>
                                </div>

                                <div className='flex items-center justify-between gap-3 rounded-2xl border border-border/70 bg-background/70 px-4 py-3'>
                                    <div className='space-y-1'>
                                        <p className='text-sm font-medium'>Redact sensitive values</p>
                                        <p className='text-muted-foreground text-xs'>
                                            Applies immediately across account and usage surfaces.
                                        </p>
                                    </div>
                                    <PrivacyModeToggle />
                                </div>
                            </section>
                        </>
                    ) : null}

                    {subsection === 'mcp' ? (
                        <>
                            <AppSectionHeader
                                title='MCP'
                                description='Manage backend-owned stdio MCP servers, secret-backed env keys, and live tool discovery for agent.code and agent.debug.'
                            />

                            <McpSettingsSection
                                profileId={profileId}
                                {...(currentWorkspaceFingerprint ? { currentWorkspaceFingerprint } : {})}
                            />
                        </>
                    ) : null}

                    {subsection === 'maintenance' ? (
                        <>
                            <AppSectionHeader
                                title='Maintenance'
                                description='Keep destructive app-wide maintenance actions separate from ordinary privacy controls.'
                            />

                            <section className='border-destructive/30 bg-destructive/5 space-y-4 rounded-[24px] border p-5'>
                                <div className='space-y-1'>
                                    <p className='text-sm font-semibold'>Factory reset app data</p>
                                    <p className='text-muted-foreground text-xs leading-5'>
                                        Deletes all app-owned chats, profiles, permissions, provider state, managed
                                        sandboxes, registry assets, and logs. Workspace-local{' '}
                                        <code className='rounded bg-black/5 px-1 py-0.5 text-[11px]'>
                                            .neonconductor
                                        </code>{' '}
                                        files are not removed.
                                    </p>
                                </div>

                                <div className='flex justify-end'>
                                    <button
                                        type='button'
                                        className='rounded-full border border-destructive/40 bg-destructive/10 px-4 py-2 text-sm font-medium text-destructive disabled:cursor-not-allowed disabled:opacity-60'
                                        disabled={factoryResetMutation.isPending}
                                        onClick={() => {
                                            setConfirmOpen(true);
                                        }}>
                                        Factory reset app data
                                    </button>
                                </div>
                            </section>
                        </>
                    ) : null}
                </div>
            </div>

            <ConfirmDialog
                open={confirmOpen}
                title='Factory Reset App Data'
                message='This removes all app-owned data and recreates a fresh default profile. Type the confirmation phrase to continue.'
                confirmLabel='Reset app data'
                destructive
                busy={factoryResetMutation.isPending}
                confirmDisabled={confirmationText !== FACTORY_RESET_CONFIRMATION_TEXT}
                onCancel={() => {
                    setConfirmOpen(false);
                    setConfirmationText('');
                }}
                onConfirm={() => {
                    void handleConfirmFactoryReset();
                }}>
                <div className='space-y-2'>
                    <p className='text-muted-foreground text-xs'>
                        Enter <span className='font-semibold'>{FACTORY_RESET_CONFIRMATION_TEXT}</span> to confirm.
                    </p>
                    <input
                        type='text'
                        value={confirmationText}
                        onChange={(event) => {
                            setConfirmationText(event.target.value);
                        }}
                        className='border-border bg-background h-9 w-full rounded-md border px-2 text-sm'
                        placeholder={FACTORY_RESET_CONFIRMATION_TEXT}
                    />
                </div>
            </ConfirmDialog>
        </section>
    );
}

