import { useState } from 'react';

import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { trpc } from '@/web/trpc/client';

import type { PromptSettingsSnapshot } from '@/web/components/settings/modesSettings/modesInstructionsControllerShared';
import { useModesInstructionsBuiltInModesController } from '@/web/components/settings/modesSettings/useModesInstructionsBuiltInModesController';
import { useModesInstructionsCustomModesController } from '@/web/components/settings/modesSettings/useModesInstructionsCustomModesController';
import { useModesInstructionsGlobalController } from '@/web/components/settings/modesSettings/useModesInstructionsGlobalController';

export function useModesInstructionsSettingsController(input: {
    profileId: string;
    workspaceFingerprint?: string;
    selectedWorkspaceLabel?: string;
}) {
    const { profileId, workspaceFingerprint, selectedWorkspaceLabel } = input;
    const utils = trpc.useUtils();
    const [feedbackMessage, setFeedbackMessage] = useState<string | undefined>(undefined);
    const [feedbackTone, setFeedbackTone] = useState<'success' | 'error' | 'info'>('info');

    const settingsQueryInput = {
        profileId,
        ...(workspaceFingerprint ? { workspaceFingerprint } : {}),
    };
    const settingsQuery = trpc.prompt.getSettings.useQuery(settingsQueryInput, PROGRESSIVE_QUERY_OPTIONS);

    function applySettings(settings: PromptSettingsSnapshot) {
        utils.prompt.getSettings.setData(settingsQueryInput, { settings });
    }

    function clearFeedback(): void {
        setFeedbackMessage(undefined);
        setFeedbackTone('info');
    }

    const setSuccessFeedback = (message: string) => {
        setFeedbackTone('success');
        setFeedbackMessage(message);
    };
    const setErrorFeedback = (message: string) => {
        setFeedbackTone('error');
        setFeedbackMessage(message);
    };

    const persistedSettings = settingsQuery.data?.settings;
    const globalController = useModesInstructionsGlobalController({
        profileId,
        persistedSettings,
        applySettings,
        clearFeedback,
        setErrorFeedback,
        setSuccessFeedback,
    });
    const builtInModesController = useModesInstructionsBuiltInModesController({
        profileId,
        persistedSettings,
        applySettings,
        clearFeedback,
        setErrorFeedback,
        setSuccessFeedback,
    });
    const customModesController = useModesInstructionsCustomModesController({
        profileId,
        ...(workspaceFingerprint ? { workspaceFingerprint } : {}),
        ...(selectedWorkspaceLabel ? { selectedWorkspaceLabel } : {}),
        persistedSettings,
        applySettings,
        clearFeedback,
        setErrorFeedback,
        setSuccessFeedback,
    });

    return {
        feedback: {
            message: feedbackMessage,
            tone: feedbackTone,
            clear: clearFeedback,
        },
        query: settingsQuery,
        workspace: {
            fingerprint: workspaceFingerprint,
            selectedLabel: selectedWorkspaceLabel,
        },
        ...globalController,
        ...builtInModesController,
        ...customModesController,
    };
}

import { ModesInstructionsScreen } from '@/web/components/settings/modesSettings/modesInstructionsScreen';
import { SettingsSelectionRail } from '@/web/components/settings/shared/settingsSelectionRail';
import { MODES_SETTINGS_SUBSECTIONS, type ModesSettingsSubsectionId } from '@/web/components/settings/settingsNavigation';

interface ModesSettingsViewProps {
    profileId: string;
    subsection?: ModesSettingsSubsectionId;
    onSubsectionChange?: (subsection: ModesSettingsSubsectionId) => void;
    workspaceFingerprint?: string;
    selectedWorkspaceLabel?: string;
}

export function ModesSettingsView({
    profileId,
    subsection = 'instructions',
    onSubsectionChange,
    workspaceFingerprint,
    selectedWorkspaceLabel,
}: ModesSettingsViewProps) {
    return (
        <section className='grid h-full min-h-0 min-w-0 overflow-hidden xl:grid-cols-[280px_minmax(0,1fr)]'>
            <SettingsSelectionRail
                title='Modes & Instructions'
                ariaLabel='Modes and instructions settings sections'
                selectedId={subsection}
                onSelect={(itemId) => {
                    const nextSection = MODES_SETTINGS_SUBSECTIONS.find((candidate) => candidate.id === itemId);
                    if (!nextSection || nextSection.availability !== 'available') {
                        return;
                    }

                    onSubsectionChange?.(nextSection.id);
                }}
                items={MODES_SETTINGS_SUBSECTIONS.map((item) => ({
                    id: item.id,
                    title: item.label,
                    subtitle: item.description,
                }))}
            />

            <div className='min-h-0 min-w-0 overflow-y-auto p-5 md:p-6'>
                {subsection === 'instructions' ? (
                    <ModesInstructionsScreen
                        profileId={profileId}
                        {...(workspaceFingerprint ? { workspaceFingerprint } : {})}
                        {...(selectedWorkspaceLabel ? { selectedWorkspaceLabel } : {})}
                    />
                ) : null}
            </div>
        </section>
    );
}

