                openAISubscriptionRateLimits={controller.providerStatus.openAISubscriptionRateLimits}
                isLoadingAccountContext={controller.providerStatus.isLoadingAccountContext}
                isLoadingUsageSummary={controller.providerStatus.isLoadingUsageSummary}
                isLoadingOpenAIUsage={controller.providerStatus.isLoadingOpenAIUsage}
                isLoadingOpenAIRateLimits={controller.providerStatus.isLoadingOpenAIRateLimits}
                isRefreshingOpenAICodexUsage={controller.providerStatus.isRefreshingOpenAICodexUsage}
                onRefreshOpenAICodexUsage={controller.providerStatus.refreshOpenAICodexUsage}
            />

            <ProviderAuthenticationSection
                key={`${profileId}:${selectedProvider.id}`}
                selectedProviderId={selectedProvider.id}
                selectedProviderAuthState={selectedProvider.authState}
                selectedProviderAuthMethod={selectedProvider.authMethod}
                selectedAuthState={controller.providerStatus.authState}
                methods={controller.authentication.methods}
                connectionProfileValue={selectedProvider.connectionProfile.optionProfileId}
                connectionProfileOptions={selectedProvider.connectionProfile.options}
                supportsCustomBaseUrl={selectedProvider.features.supportsCustomBaseUrl}
                baseUrlOverrideValue={selectedProvider.connectionProfile.baseUrlOverride ?? ''}
                resolvedBaseUrl={selectedProvider.connectionProfile.resolvedBaseUrl}
                executionPreference={controller.authentication.executionPreference}
                apiKeyCta={selectedProvider.apiKeyCta}
                activeAuthFlow={controller.authentication.activeAuthFlow}
                isSavingApiKey={controller.authentication.isSavingApiKey}
                isSavingConnectionProfile={controller.authentication.isSavingConnectionProfile}
                isSavingExecutionPreference={controller.authentication.isSavingExecutionPreference}
                isStartingAuth={controller.authentication.isStartingAuth}
                isPollingAuth={controller.authentication.isPollingAuth}
                isCancellingAuth={controller.authentication.isCancellingAuth}
                isOpeningVerificationPage={controller.authentication.isOpeningVerificationPage}
                onConnectionProfileChange={controller.authentication.changeConnectionProfile}
                onExecutionPreferenceChange={controller.authentication.changeExecutionPreference}
                onSaveApiKey={(value) => {
                    return controller.authentication.saveApiKey(value);
                }}
                onSaveBaseUrlOverride={(value) => {
                    return controller.authentication.saveBaseUrlOverride(value);
                }}
                onLoadStoredCredential={controller.authentication.loadStoredCredential}
                onStartOAuthDevice={controller.authentication.startOAuthDevice}
                onStartDeviceCode={controller.authentication.startDeviceCode}
                onPollNow={controller.authentication.pollNow}
                onCancelFlow={controller.authentication.cancelFlow}
                onOpenVerificationPage={controller.authentication.openVerificationPage}
                {...(controller.authentication.credentialSummary
                    ? { credentialSummary: controller.authentication.credentialSummary }
                    : {})}
            />

            <ProviderDefaultModelSection
                selectedProviderId={selectedProvider.id}
                selectedModelId={controller.models.selectedModelId}
                models={controller.models.options}
                catalogStateReason={controller.models.catalogStateReason}
                {...(controller.models.catalogStateDetail
                    ? { catalogStateDetail: controller.models.catalogStateDetail }
                    : {})}
                isDefaultModel={controller.models.isDefaultModel}
                isSavingDefault={controller.models.isSavingDefault}
                isSyncingCatalog={controller.models.isSyncingCatalog}
                onSelectModel={(modelId) => {
                    controller.models.setSelectedModelId(modelId);
                    if (modelId === controller.models.selectedModelId && controller.models.isDefaultModel) {
                        return;
                    }

                    controller.models.setDefaultModel(modelId);
                }}
                onSyncCatalog={controller.models.syncCatalog}
            />
        </div>
    );
}

function ProviderSettingsViewBody({ profileId, selectedProviderId, onProviderChange }: ProviderSettingsViewProps) {
    const controller = useProviderSettingsController(
        profileId,
        selectedProviderId ? { initialProviderId: selectedProviderId } : undefined
    );
    const selectedProvider = controller.selection.selectedProvider;

    return (
        <section className='grid h-full min-h-0 min-w-0 overflow-hidden xl:grid-cols-[264px_minmax(0,1fr)]'>
            <ProviderSidebar
                providers={controller.selection.providerItems}
                selectedProviderId={selectedProvider?.id}
                onSelectProvider={(providerId) => {
                    if (onProviderChange) {
                        onProviderChange(providerId);
                        return;
                    }

                    controller.selection.selectProvider(providerId);
                }}
                onPreviewProvider={controller.selection.prefetchProvider}
            />

            <div className='min-h-0 min-w-0 overflow-y-auto p-4 md:p-5'>
                {selectedProvider ? (
                    selectedProvider.id === 'kilo' ? (
                        <KiloProviderContent profileId={profileId} controller={controller} />
                    ) : (
                        <DirectProviderContent profileId={profileId} controller={controller} />
                    )
                ) : (
                    <div className='border-border/70 bg-card/40 space-y-2 rounded-[24px] border p-5'>
                        <p className='text-sm font-semibold'>No provider selected</p>
                        <p className='text-muted-foreground text-sm leading-6'>
                            Choose Kilo Gateway or a direct provider from the provider rail to inspect auth, models, and
                            runtime defaults.
                        </p>
                    </div>
                )}
            </div>
        </section>
    );
}

export function ProviderSettingsView({
    profileId,
    selectedProviderId = 'kilo',
    onProviderChange,
}: ProviderSettingsViewProps) {
    return (
        <ProviderSettingsViewBody
            key={buildProviderSettingsControllerKey(profileId, selectedProviderId)}
            profileId={profileId}
            selectedProviderId={selectedProviderId}
            {...(onProviderChange ? { onProviderChange } : {})}
        />
    );
}

import { describe, expect, it, vi } from 'vitest';

import {
    applyHydratedKiloStoredCredential,
    buildProviderAuthenticationDraftKey,
    resolveCopyStoredCredentialAction,
    resolveRevealStoredCredentialAction,
    shouldHydrateKiloStoredCredential,
} from '@/web/components/settings/providerSettings/authenticationSection';

describe('provider authentication draft helpers', () => {
    it('builds a fresh draft key from provider, connection profile, and base URL override identity', () => {
        expect(
            buildProviderAuthenticationDraftKey({
                selectedProviderId: 'openai',
                connectionProfileValue: 'default',
                baseUrlOverrideValue: 'https://api.openai.com/v1',
            })
        ).toBe('openai:default:https://api.openai.com/v1');
    });

    it('hydrates the stored Kilo credential only when the draft is still empty', () => {
        expect(
            shouldHydrateKiloStoredCredential({
                selectedProviderId: 'kilo',
                credentialSource: 'access_token',
                hasLoadedStoredCredential: false,
                apiKeyInput: '',
            })
        ).toBe(true);

        expect(
            shouldHydrateKiloStoredCredential({
                selectedProviderId: 'kilo',
                credentialSource: 'access_token',
                hasLoadedStoredCredential: false,
                apiKeyInput: 'manual-user-entry',
            })
        ).toBe(false);
    });

    it('does not overwrite a user draft when stored credential hydration resolves late', () => {
        expect(
            applyHydratedKiloStoredCredential({
                draftState: {
                    apiKeyInput: 'manual-user-entry',
                    baseUrlOverrideInput: '',
                    isCredentialVisible: false,
                    hasLoadedStoredCredential: false,
                },
                selectedProviderId: 'kilo',
                credentialSource: 'access_token',
                credentialValue: 'stored-kilo-token',
            })
        ).toEqual({
            apiKeyInput: 'manual-user-entry',
            baseUrlOverrideInput: '',
            isCredentialVisible: false,
            hasLoadedStoredCredential: false,
        });
    });

    it('applies the stored Kilo credential when the untouched draft is still eligible', () => {
        expect(
            applyHydratedKiloStoredCredential({
                draftState: {
                    apiKeyInput: '',
                    baseUrlOverrideInput: '',
                    isCredentialVisible: false,
                    hasLoadedStoredCredential: false,
                },
                selectedProviderId: 'kilo',
                credentialSource: 'access_token',
                credentialValue: 'stored-kilo-token',
            })
        ).toEqual({
            apiKeyInput: 'stored-kilo-token',
            baseUrlOverrideInput: '',
            isCredentialVisible: false,
            hasLoadedStoredCredential: true,
        });
    });

    it('reveals the stored credential when loading succeeds', async () => {
        await expect(
            resolveRevealStoredCredentialAction({
                draftState: {
                    apiKeyInput: '',
                    baseUrlOverrideInput: '',
                    isCredentialVisible: false,
                    hasLoadedStoredCredential: false,
                },
                hasStoredCredential: true,
                onLoadStoredCredential: async () => 'stored-kilo-token',
            })
        ).resolves.toEqual({
            draftState: {
                apiKeyInput: 'stored-kilo-token',
                baseUrlOverrideInput: '',
                isCredentialVisible: true,
                hasLoadedStoredCredential: true,
            },
        });
    });

    it('reports a local reveal error when credential loading rejects', async () => {
        await expect(
            resolveRevealStoredCredentialAction({
                draftState: {
                    apiKeyInput: '',
                    baseUrlOverrideInput: '',
                    isCredentialVisible: false,
                    hasLoadedStoredCredential: false,
                },
                hasStoredCredential: true,
                onLoadStoredCredential: async () => {
                    throw new Error('load failed');
                },
            })
        ).resolves.toEqual({
            status: {
                tone: 'error',
                message: 'Failed to reveal the stored credential.',
            },
        });
    });

    it('copies the loaded credential and reports success', async () => {
        const writeText = vi.fn(async () => undefined);

        await expect(
            resolveCopyStoredCredentialAction({
                draftState: {
                    apiKeyInput: '',
                    baseUrlOverrideInput: '',
                    isCredentialVisible: false,
                    hasLoadedStoredCredential: false,
                },
                onLoadStoredCredential: async () => 'stored-kilo-token',
                writeText,
            })
        ).resolves.toEqual({
            draftState: {
                apiKeyInput: '',
                baseUrlOverrideInput: '',
                isCredentialVisible: false,
                hasLoadedStoredCredential: true,
            },
            status: {
                tone: 'success',
                message: 'Credential copied.',
            },
        });
        expect(writeText).toHaveBeenCalledWith('stored-kilo-token');
    });

    it('reports a local copy error when clipboard write rejects', async () => {
        await expect(
            resolveCopyStoredCredentialAction({
                draftState: {
                    apiKeyInput: 'stored-kilo-token',
                    baseUrlOverrideInput: '',
                    isCredentialVisible: true,
                    hasLoadedStoredCredential: true,
                },
                onLoadStoredCredential: async () => undefined,
                writeText: async () => {
                    throw new Error('clipboard denied');
                },
            })
        ).resolves.toEqual({
            status: {
                tone: 'error',
                message: 'Failed to copy the stored credential.',
            },
        });
    });
});

import { useEffect, useState } from 'react';

import { ProviderAuthFlowSection } from '@/web/components/settings/providerSettings/authentication/providerAuthFlowSection';
import { ProviderConnectionDetailsSection } from '@/web/components/settings/providerSettings/authentication/providerConnectionDetailsSection';
import { ProviderCredentialSection } from '@/web/components/settings/providerSettings/authentication/providerCredentialSection';
import type { ProviderCredentialActionStatus } from '@/web/components/settings/providerSettings/authentication/providerCredentialSection';
import type { ActiveAuthFlow, ProviderAuthStateView } from '@/web/components/settings/providerSettings/types';

import type { OpenAIExecutionMode, RuntimeProviderId } from '@/shared/contracts';

interface ProviderAuthenticationSectionProps {
    selectedProviderId: RuntimeProviderId | undefined;
    selectedProviderAuthState: string;
    selectedProviderAuthMethod: string;
    selectedAuthState: ProviderAuthStateView | undefined;
    methods: string[];
    connectionProfileValue: string;
    connectionProfileOptions: Array<{ value: string; label: string }>;
    supportsCustomBaseUrl: boolean;
    baseUrlOverrideValue: string;
    resolvedBaseUrl: string | null;
    executionPreference:
        | {
              mode: OpenAIExecutionMode;
              canUseRealtimeWebSocket: boolean;
              disabledReason?: 'provider_not_supported' | 'api_key_required' | 'base_url_not_supported';
          }
        | undefined;
    apiKeyCta?: { label: string; url: string };
    credentialSummary?: {
        hasStoredCredential: boolean;
        credentialSource: 'api_key' | 'access_token' | null;
        maskedValue?: string;
    };
    activeAuthFlow: ActiveAuthFlow | undefined;
    isSavingApiKey: boolean;
    isSavingConnectionProfile: boolean;
    isSavingExecutionPreference: boolean;
    isStartingAuth: boolean;
    isPollingAuth: boolean;
    isCancellingAuth: boolean;
    isOpeningVerificationPage: boolean;
    onConnectionProfileChange: (value: string) => void;
    onExecutionPreferenceChange: (mode: OpenAIExecutionMode) => void;
    onSaveApiKey: (value: string) => Promise<void>;
    onSaveBaseUrlOverride: (value: string) => Promise<void>;
    onLoadStoredCredential: () => Promise<string | undefined>;
    onStartOAuthDevice: () => void;
    onStartDeviceCode: () => void;
    onPollNow: () => void;
    onCancelFlow: () => void;
    onOpenVerificationPage: () => void;
}

interface ProviderAuthenticationDraftState {
    apiKeyInput: string;
    baseUrlOverrideInput: string;
    isCredentialVisible: boolean;
    hasLoadedStoredCredential: boolean;
}

interface ProviderCredentialActionResult {
    draftState?: ProviderAuthenticationDraftState;
    status?: ProviderCredentialActionStatus;
}

function createProviderAuthenticationDraftState(baseUrlOverrideValue: string): ProviderAuthenticationDraftState {
    return {
        apiKeyInput: '',
        baseUrlOverrideInput: baseUrlOverrideValue,
        isCredentialVisible: false,
        hasLoadedStoredCredential: false,
    };
}

export async function resolveRevealStoredCredentialAction(input: {
    draftState: ProviderAuthenticationDraftState;
    hasStoredCredential: boolean;
    onLoadStoredCredential: () => Promise<string | undefined>;
}): Promise<ProviderCredentialActionResult> {
    try {
        if (input.draftState.apiKeyInput.trim().length === 0 && input.hasStoredCredential) {
            const credentialValue = await input.onLoadStoredCredential();
            if (!credentialValue) {
                return {};
            }

            return {
                draftState: {
                    ...input.draftState,
                    apiKeyInput: credentialValue,
                    isCredentialVisible: true,
                    hasLoadedStoredCredential: true,
                },
            };
        }

        return {
            draftState: {
                ...input.draftState,
                isCredentialVisible: true,
            },
        };
    } catch {
        return {
            status: {
                tone: 'error',
                message: 'Failed to reveal the stored credential.',
            },
        };
    }
}

export async function resolveCopyStoredCredentialAction(input: {
    draftState: ProviderAuthenticationDraftState;
    onLoadStoredCredential: () => Promise<string | undefined>;
    writeText: (value: string) => Promise<void>;
}): Promise<ProviderCredentialActionResult> {
    try {
        const credentialValue =
            input.draftState.apiKeyInput.trim().length > 0
                ? input.draftState.apiKeyInput
                : await input.onLoadStoredCredential();
        if (!credentialValue) {
            return {};
        }

        await input.writeText(credentialValue);

        return {
            draftState: {
                ...input.draftState,
                hasLoadedStoredCredential: true,
            },
            status: {
                tone: 'success',
                message: 'Credential copied.',
            },
        };
    } catch {
        return {
            status: {
                tone: 'error',
                message: 'Failed to copy the stored credential.',
            },
        };
    }
}

export function buildProviderAuthenticationDraftKey(input: {
    selectedProviderId: RuntimeProviderId | undefined;
    connectionProfileValue: string;
    baseUrlOverrideValue: string;
}): string {
    return `${input.selectedProviderId ?? 'none'}:${input.connectionProfileValue}:${input.baseUrlOverrideValue}`;
}

export function shouldHydrateKiloStoredCredential(input: {
    selectedProviderId: RuntimeProviderId | undefined;
    credentialSource: 'api_key' | 'access_token' | null | undefined;
    hasLoadedStoredCredential: boolean;
    apiKeyInput: string;
}): boolean {
    return (
        input.selectedProviderId === 'kilo' &&
        input.credentialSource === 'access_token' &&
        !input.hasLoadedStoredCredential &&
        input.apiKeyInput.trim().length === 0
    );
}

export function applyHydratedKiloStoredCredential(input: {
    draftState: ProviderAuthenticationDraftState;
    selectedProviderId: RuntimeProviderId | undefined;
    credentialSource: 'api_key' | 'access_token' | null | undefined;
    credentialValue: string | undefined;
}): ProviderAuthenticationDraftState {
    if (
        !input.credentialValue ||
        !shouldHydrateKiloStoredCredential({
            selectedProviderId: input.selectedProviderId,
            credentialSource: input.credentialSource,
            hasLoadedStoredCredential: input.draftState.hasLoadedStoredCredential,
            apiKeyInput: input.draftState.apiKeyInput,
        })
    ) {
        return input.draftState;
    }

    return {
        ...input.draftState,
        apiKeyInput: input.credentialValue,
        hasLoadedStoredCredential: true,
    };
}

function AuthStateBadge({ authState, authMethod }: { authState: string; authMethod: string }) {
    return (
        <div className='flex flex-wrap items-center gap-2 text-xs'>
            <span className='border-border/70 bg-background rounded-full border px-2.5 py-1 font-medium'>
                State {authState}
            </span>
            <span className='text-muted-foreground'>via {authMethod.replace('_', ' ')}</span>
        </div>
    );
}

export function ProviderAuthenticationSection({
    selectedProviderId,
    connectionProfileValue,
    baseUrlOverrideValue,
    ...props
}: ProviderAuthenticationSectionProps) {
    return (
        <ProviderAuthenticationDraftBoundary
            key={buildProviderAuthenticationDraftKey({
                selectedProviderId,
                connectionProfileValue,
                baseUrlOverrideValue,
            })}
            selectedProviderId={selectedProviderId}
            connectionProfileValue={connectionProfileValue}
            baseUrlOverrideValue={baseUrlOverrideValue}
            {...props}
        />
    );
}

function ProviderAuthenticationDraftBoundary({
    selectedProviderId,
    selectedProviderAuthState,
    selectedProviderAuthMethod,
    selectedAuthState,
    methods,
    connectionProfileValue,
    connectionProfileOptions,
    supportsCustomBaseUrl,
    baseUrlOverrideValue,
    resolvedBaseUrl,
    executionPreference,
    apiKeyCta,
    credentialSummary,
    activeAuthFlow,
    isSavingApiKey,
    isSavingConnectionProfile,
    isSavingExecutionPreference,
    isStartingAuth,
    isPollingAuth,
    isCancellingAuth,
    isOpeningVerificationPage,
    onConnectionProfileChange,
    onExecutionPreferenceChange,
    onSaveApiKey,
    onSaveBaseUrlOverride,
    onLoadStoredCredential,
    onStartOAuthDevice,
    onStartDeviceCode,
    onPollNow,
    onCancelFlow,
    onOpenVerificationPage,
}: ProviderAuthenticationSectionProps) {
    const [draftState, setDraftState] = useState(() => createProviderAuthenticationDraftState(baseUrlOverrideValue));
    const [credentialActionStatus, setCredentialActionStatus] = useState<ProviderCredentialActionStatus | undefined>(
        undefined
    );
    const effectiveAuthState = selectedAuthState?.authState ?? selectedProviderAuthState;
    const effectiveAuthMethod = selectedAuthState?.authMethod ?? selectedProviderAuthMethod;
    const isKilo = selectedProviderId === 'kilo';
    const canUseApiKey = methods.includes('api_key');
    const activeFlowForSelectedProvider =
        activeAuthFlow?.providerId === selectedProviderId ? activeAuthFlow : undefined;
    const isAuthenticated = effectiveAuthState === 'authenticated';
    const kiloCredentialLabel =
        credentialSummary?.credentialSource === 'access_token'
            ? 'Browser session token is stored locally for Kilo.'
            : credentialSummary?.credentialSource === 'api_key'
              ? 'An API key is stored locally for Kilo.'
              : 'Kilo account access is ready in this profile.';

    useEffect(() => {
        if (
            !shouldHydrateKiloStoredCredential({
                selectedProviderId,
                credentialSource: credentialSummary?.credentialSource,
                hasLoadedStoredCredential: draftState.hasLoadedStoredCredential,
                apiKeyInput: draftState.apiKeyInput,
            })
        ) {
            return;
        }

        let cancelled = false;
        void onLoadStoredCredential()
            .then((credentialValue) => {
                if (cancelled) {
                    return;
                }

                setDraftState((current) =>
                    applyHydratedKiloStoredCredential({
                        draftState: current,
                        selectedProviderId,
                        credentialSource: credentialSummary?.credentialSource,
                        credentialValue,
                    })
                );
            })
            .catch(() => undefined);

        return () => {
            cancelled = true;
        };
    }, [
        draftState.apiKeyInput,
        draftState.hasLoadedStoredCredential,
        credentialSummary?.credentialSource,
        onLoadStoredCredential,
        selectedProviderId,
    ]);

    const revealStoredCredential = async (): Promise<void> => {
        const result = await resolveRevealStoredCredentialAction({
            draftState,
            hasStoredCredential: credentialSummary?.hasStoredCredential ?? false,
            onLoadStoredCredential,
        });
        if (result.draftState) {
            setDraftState(result.draftState);
        }

        setCredentialActionStatus(result.status);
    };

    const copyStoredCredential = async (): Promise<void> => {
        const result = await resolveCopyStoredCredentialAction({
            draftState,
            onLoadStoredCredential,
            writeText: (value) => navigator.clipboard.writeText(value),
        });
        if (result.draftState) {
            setDraftState(result.draftState);
        }

        setCredentialActionStatus(result.status);
    };

    const saveApiKey = () => {
        void onSaveApiKey(draftState.apiKeyInput)
            .then(() => {
                setDraftState((current) => ({
                    ...current,
                    apiKeyInput: '',
                    isCredentialVisible: false,
                    hasLoadedStoredCredential: false,
                }));
            })
            .catch(() => undefined);
    };

    const saveBaseUrlOverride = () => {
        void onSaveBaseUrlOverride(draftState.baseUrlOverrideInput).catch(() => undefined);
    };

    return (
        <section className='border-border/70 bg-card/55 space-y-4 rounded-[24px] border p-5'>
            <div className='flex flex-col gap-3 md:flex-row md:items-start md:justify-between'>
                <div className='min-w-0 space-y-1'>
                    <p className='text-sm font-semibold'>{isKilo ? 'Kilo Access' : 'Authentication'}</p>
                    <p className='text-muted-foreground text-xs leading-5'>
                        {isKilo
                            ? 'Use browser sign-in for the app-first Kilo flow. API keys stay available only as an advanced fallback.'
                            : 'Connect the provider once, then keep model selection local to the active profile.'}
                    </p>
                </div>
                <div className='self-start'>
                    <AuthStateBadge authState={effectiveAuthState} authMethod={effectiveAuthMethod} />
                </div>
            </div>

            <div className='space-y-4'>
                <ProviderAuthFlowSection
                    isKilo={isKilo}
                    isAuthenticated={isAuthenticated}
                    methods={methods}
                    activeUserCode={activeFlowForSelectedProvider?.userCode}
                    activeVerificationUri={activeFlowForSelectedProvider?.verificationUri}
                    credentialLabel={kiloCredentialLabel}
                    isStartingAuth={isStartingAuth}
                    isPollingAuth={isPollingAuth}
                    isCancellingAuth={isCancellingAuth}
                    isOpeningVerificationPage={isOpeningVerificationPage}
                    onStartOAuthDevice={onStartOAuthDevice}
                    onStartDeviceCode={onStartDeviceCode}
                    onPollNow={onPollNow}
                    onCancelFlow={onCancelFlow}
                    onOpenVerificationPage={onOpenVerificationPage}
                />

                <div className='grid gap-4 xl:grid-cols-[minmax(0,1.2fr)_minmax(260px,0.8fr)]'>
                    <div className='min-w-0'>
                        <ProviderCredentialSection
                            selectedProviderId={selectedProviderId}
                            isKilo={isKilo}
                            canUseApiKey={canUseApiKey}
                            apiKeyInput={draftState.apiKeyInput}
                            isCredentialVisible={draftState.isCredentialVisible}
                            isSavingApiKey={isSavingApiKey}
                            apiKeyCta={apiKeyCta}
                            credentialSummary={credentialSummary}
                            {...(credentialActionStatus ? { credentialActionStatus } : {})}
                            onApiKeyInputChange={(apiKeyInput) => {
                                setDraftState((current) => ({
                                    ...current,
                                    apiKeyInput,
                                }));
                                setCredentialActionStatus(undefined);
                            }}
                            onSaveApiKey={saveApiKey}
                            onRevealStoredCredential={revealStoredCredential}
                            onHideStoredCredential={() => {
                                setDraftState((current) => ({
                                    ...current,
                                    isCredentialVisible: false,
                                }));
                                setCredentialActionStatus(undefined);
                            }}
                            onCopyStoredCredential={copyStoredCredential}
                        />
                    </div>

                    <ProviderConnectionDetailsSection
                        selectedProviderId={selectedProviderId}
                        connectionProfileValue={connectionProfileValue}
                        connectionProfileOptions={connectionProfileOptions}
                        supportsCustomBaseUrl={supportsCustomBaseUrl}
                        baseUrlOverrideValue={draftState.baseUrlOverrideInput}
                        resolvedBaseUrl={resolvedBaseUrl}
                        executionPreference={executionPreference}
                        isSavingConnectionProfile={isSavingConnectionProfile}
                        isSavingExecutionPreference={isSavingExecutionPreference}
                        onConnectionProfileChange={onConnectionProfileChange}
                        onExecutionPreferenceChange={onExecutionPreferenceChange}
                        onBaseUrlOverrideChange={(baseUrlOverrideInput) => {
                            setDraftState((current) => ({
                                ...current,
                                baseUrlOverrideInput,
                            }));
                        }}
                        onSaveBaseUrlOverride={saveBaseUrlOverride}
                    />
                </div>
            </div>
        </section>
    );
}

import { ExternalLink } from 'lucide-react';

import { Button } from '@/web/components/ui/button';

export interface ProviderCredentialActionStatus {
    tone: 'error' | 'success';
    message: string;
}

interface ProviderCredentialSectionProps {
    selectedProviderId: string | undefined;
    isKilo: boolean;
    canUseApiKey: boolean;
    apiKeyInput: string;
    isCredentialVisible: boolean;
    isSavingApiKey: boolean;
    apiKeyCta: { label: string; url: string } | undefined;
    credentialActionStatus?: ProviderCredentialActionStatus;
    credentialSummary:
        | {
              hasStoredCredential: boolean;
              credentialSource: 'api_key' | 'access_token' | null;
              maskedValue?: string;
          }
        | undefined;
    onApiKeyInputChange: (value: string) => void;
    onSaveApiKey: () => void;
    onRevealStoredCredential: () => void | Promise<void>;
    onHideStoredCredential: () => void;
    onCopyStoredCredential: () => void | Promise<void>;
}

function ApiKeyField({
    selectedProviderId,
    apiKeyInput,
    isCredentialVisible,
    isSavingApiKey,
    apiKeyCta,
    credentialActionStatus,
    credentialSummary,
    onApiKeyInputChange,
    onSaveApiKey,
    onRevealStoredCredential,
    onHideStoredCredential,
    onCopyStoredCredential,
    compactIntro,
}: ProviderCredentialSectionProps & { compactIntro: string }) {
    const credentialActionMessageClassName =
        propsCredentialActionToneToClassName(credentialActionStatus?.tone ?? undefined);

    return (
        <div className='border-border/70 bg-background/75 space-y-3 rounded-2xl border p-4'>
            <div className='space-y-1'>
                <p className='text-sm font-semibold'>Advanced API key access</p>
                <p className='text-muted-foreground text-xs'>{compactIntro}</p>
            </div>

            <div className='grid gap-2 sm:grid-cols-[1fr_auto]'>
                <label className='sr-only' htmlFor='provider-api-key-input'>
                    API key
                </label>
                <input
                    id='provider-api-key-input'
                    name='providerApiKey'
                    type={isCredentialVisible ? 'text' : 'password'}
                    value={apiKeyInput}
                    onChange={(event) => {
                        onApiKeyInputChange(event.target.value);
                    }}
                    className='border-border bg-card h-10 rounded-xl border px-3 text-sm'
                    autoComplete='off'
                    placeholder={credentialSummary?.maskedValue ?? 'Paste API key'}
                />
                <Button
                    type='button'
                    size='sm'
                    variant='outline'
                    disabled={apiKeyInput.trim().length === 0 || isSavingApiKey || !selectedProviderId}
                    onClick={onSaveApiKey}>
                    {isSavingApiKey ? 'Saving…' : 'Save API Key'}
                </Button>
            </div>

            {credentialSummary?.hasStoredCredential ? (
                <div className='flex flex-wrap items-center gap-2 text-xs'>
                    <span className='text-muted-foreground'>
                        Stored {credentialSummary.credentialSource === 'access_token' ? 'session token' : 'API key'}{' '}
                        {credentialSummary.maskedValue ? `(${credentialSummary.maskedValue})` : ''}
                    </span>
                    <Button
                        type='button'
                        size='sm'
                        variant='ghost'
                        onClick={isCredentialVisible ? onHideStoredCredential : onRevealStoredCredential}>
                        {isCredentialVisible ? 'Hide' : 'Reveal'}
                    </Button>
                    <Button type='button' size='sm' variant='ghost' onClick={onCopyStoredCredential}>
                        Copy
                    </Button>
                </div>
            ) : null}

            {credentialActionStatus ? (
                <p className={`text-xs ${credentialActionMessageClassName}`}>{credentialActionStatus.message}</p>
            ) : null}

            {apiKeyCta ? (
                <Button size='sm' variant='ghost' asChild>
                    <a href={apiKeyCta.url} target='_blank' rel='noreferrer'>
                        {apiKeyCta.label}
                        <ExternalLink className='h-3.5 w-3.5' />
                    </a>
                </Button>
            ) : null}
        </div>
    );
}

function propsCredentialActionToneToClassName(tone: ProviderCredentialActionStatus['tone'] | undefined): string {
    return tone === 'error' ? 'text-destructive' : 'text-muted-foreground';
}

export function ProviderCredentialSection(props: ProviderCredentialSectionProps) {
    if (!props.canUseApiKey) {
        return null;
    }

    if (props.isKilo) {
        return (
            <details className='border-border/70 bg-background/75 rounded-[24px] border p-4'>
                <summary className='cursor-pointer list-none text-sm font-semibold'>Advanced API key access</summary>
                <div className='mt-3'>
                    <ApiKeyField
                        {...props}
                        compactIntro='Keep this for manual or support-driven setups. The normal Kilo path is browser login.'
                    />
                </div>
            </details>
        );
    }

    return (
        <ApiKeyField
            {...props}
            compactIntro='Use an API key when you want direct token-based access instead of an interactive login.'
        />
    );
}

