import { methodLabel } from '@/web/components/settings/providerSettings/helpers';
import { patchProviderCache } from '@/web/components/settings/providerSettings/providerSettingsCache';
import type { ActiveAuthFlow } from '@/web/components/settings/providerSettings/types';
import { trpc } from '@/web/trpc/client';
import { isOneOf } from '@/web/lib/typeGuards/isOneOf';

import type { ProviderAuthStateRecord } from '@/app/backend/persistence/types';

import { providerIds, type RuntimeProviderId } from '@/shared/contracts';

interface UseProviderSettingsMutationsInput {
    profileId: string;
    selectedProviderId: RuntimeProviderId | undefined;
    setStatusMessage: (value: string | undefined) => void;
    setActiveAuthFlow: (value: ActiveAuthFlow | undefined) => void;
}

function isRuntimeProviderId(value: string): value is RuntimeProviderId {
    return isOneOf(value, providerIds);
}

export function useProviderSettingsMutations(input: UseProviderSettingsMutationsInput) {
    const utils = trpc.useUtils();
    const selectedProviderId = input.selectedProviderId ?? 'openai';
    type ProviderAuthStateQueryData = Awaited<ReturnType<typeof utils.provider.getAuthState.fetch>>;

    const setAuthStateCache = (providerId: RuntimeProviderId, state: ProviderAuthStateRecord) => {
        const nextAuthState: ProviderAuthStateQueryData = {
            found: true,
            state,
        };

        utils.provider.getAuthState.setData(
            {
                profileId: input.profileId,
                providerId,
            },
            nextAuthState
        );
        patchProviderCache({
            utils,
            profileId: input.profileId,
            providerId,
            authState: state,
        });
    };

    const setDefaultMutation = trpc.provider.setDefault.useMutation({
        onSuccess: (result) => {
            if (!result.success) {
                input.setStatusMessage(
                    result.reason === 'model_not_found' ? 'Selected model is not available.' : 'Default update failed.'
                );
                return;
            }

            input.setStatusMessage('Default provider/model updated.');
            if (!isRuntimeProviderId(result.defaultProviderId)) {
                input.setStatusMessage('Default update returned an unsupported provider.');
                return;
            }
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: result.defaultProviderId,
                defaults: {
                    providerId: result.defaultProviderId,
                    modelId: result.defaultModelId,
                },
            });
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const setApiKeyMutation = trpc.provider.setApiKey.useMutation({
        onSuccess: (result, variables) => {
            if (!result.success) {
                input.setStatusMessage('Provider not found.');
                return;
            }

            input.setStatusMessage('API key saved. Provider is ready.');
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: variables.providerId,
                authState: result.state,
            });
            void utils.provider.getCredentialSummary.invalidate({
                profileId: input.profileId,
                providerId: variables.providerId,
            });
            void utils.provider.getCredentialValue.invalidate({
                profileId: input.profileId,
                providerId: variables.providerId,
            });
            if (variables.providerId === 'openai_codex') {
                void utils.provider.getOpenAISubscriptionUsage.invalidate({ profileId: input.profileId });
                void utils.provider.getOpenAISubscriptionRateLimits.invalidate({ profileId: input.profileId });
            }
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const setConnectionProfileMutation = trpc.provider.setConnectionProfile.useMutation({
        onSuccess: ({ connectionProfile, defaults, models, provider }) => {
            input.setStatusMessage('Connection profile updated.');
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: selectedProviderId,
                connectionProfile,
                defaults,
                models,
                ...(provider ? { provider } : {}),
            });
        },
    });

    const syncCatalogMutation = trpc.provider.syncCatalog.useMutation({
        onSuccess: (result) => {
            if (!result.ok) {
                input.setStatusMessage(
                    result.reason ? `Catalog sync failed: ${result.reason}` : 'Catalog sync failed.'
                );
                return;
            }
            const catalogStateReason =
                result.reason === 'catalog_sync_failed' || result.reason === 'catalog_empty_after_normalization'
                    ? result.reason
                    : undefined;

            input.setStatusMessage(
                result.modelCount > 0
                    ? `Catalog synced (${String(result.modelCount)} models).`
                    : catalogStateReason === 'catalog_empty_after_normalization'
                      ? 'Catalog refreshed, but no usable models were found.'
                      : undefined
            );
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: selectedProviderId,
                defaults: result.defaults,
                models: result.models,
                ...(catalogStateReason ? { catalogStateReason } : {}),
                ...(result.detail ? { catalogStateDetail: result.detail } : {}),
                ...(result.provider ? { provider: result.provider } : {}),
            });
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const setExecutionPreferenceMutation = trpc.provider.setExecutionPreference.useMutation({
        onSuccess: ({ executionPreference, provider }) => {
            input.setStatusMessage(
                executionPreference.mode === 'realtime_websocket'
                    ? 'Realtime WebSocket enabled for OpenAI agent and orchestrator runs.'
                    : 'Standard HTTP restored for OpenAI runs.'
            );
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: 'openai',
                executionPreference,
                ...(provider ? { provider } : {}),
            });
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const setModelRoutingPreferenceMutation = trpc.provider.setModelRoutingPreference.useMutation({
        onSuccess: ({ preference, providers }) => {
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: 'kilo',
                routingPreference: preference,
                routingProviders: providers,
                routingModelId: preference.modelId,
            });
        },
    });

    const setOrganizationMutation = trpc.provider.setOrganization.useMutation({
        onSuccess: (result) => {
            input.setStatusMessage('Kilo organization updated.');
            patchProviderCache({
                utils,
                profileId: input.profileId,
                providerId: 'kilo',
                accountContext: result,
                authState: result.authState,
                defaults: result.defaults,
                models: result.models,
                ...(result.provider ? { provider: result.provider } : {}),
            });
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const openExternalUrlMutation = trpc.system.openExternalUrl.useMutation({
        onError: () => {
            input.setStatusMessage(
                'Sign-in started. Open the verification page from the auth card if your browser did not open.'
            );
        },
    });

    const startAuthMutation = trpc.provider.startAuth.useMutation({
        onSuccess: (result, variables) => {
            input.setStatusMessage(`${methodLabel(variables.method)} flow started.`);
            input.setActiveAuthFlow({
                providerId: variables.providerId,
                flowId: result.flow.id,
                ...(result.userCode ? { userCode: result.userCode } : {}),
                ...(result.verificationUri ? { verificationUri: result.verificationUri } : {}),
                pollAfterSeconds: result.pollAfterSeconds ?? 5,
            });
            setAuthStateCache(variables.providerId, {
                profileId: input.profileId,
                providerId: variables.providerId,
                authMethod: variables.method,
                authState: 'pending',
                updatedAt: new Date().toISOString(),
            });
            if (variables.providerId === 'kilo' && result.verificationUri) {
                void openExternalUrlMutation.mutateAsync({ url: result.verificationUri }).catch(() => undefined);
            }
            if (variables.providerId === 'openai_codex') {
                void utils.provider.getOpenAISubscriptionUsage.invalidate({ profileId: input.profileId });
                void utils.provider.getOpenAISubscriptionRateLimits.invalidate({ profileId: input.profileId });
            }
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const pollAuthMutation = trpc.provider.pollAuth.useMutation({
        onSuccess: (result, variables) => {
            setAuthStateCache(variables.providerId, result.state);

            if (result.flow.status === 'pending') {
                input.setStatusMessage('Waiting for authorization confirmation...');
                return;
            }

            input.setStatusMessage(`Auth flow ${result.flow.status}. State: ${result.state.authState}.`);
            input.setActiveAuthFlow(undefined);
            if (variables.providerId === 'kilo') {
                void utils.provider.getAccountContext.invalidate({
                    profileId: input.profileId,
                    providerId: 'kilo',
                });
                void syncCatalogMutation
                    .mutateAsync({
                        profileId: input.profileId,
                        providerId: 'kilo',
                        force: true,
                    })
                    .catch(() => undefined);
            }
            void utils.provider.getCredentialSummary.invalidate({
                profileId: input.profileId,
                providerId: variables.providerId,
            });
            void utils.provider.getCredentialValue.invalidate({
                profileId: input.profileId,
                providerId: variables.providerId,
            });
            if (variables.providerId === 'openai_codex') {
                void utils.provider.getOpenAISubscriptionUsage.invalidate({ profileId: input.profileId });
                void utils.provider.getOpenAISubscriptionRateLimits.invalidate({ profileId: input.profileId });
            }
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    const cancelAuthMutation = trpc.provider.cancelAuth.useMutation({
        onSuccess: (result, variables) => {
            input.setStatusMessage('Auth flow cancelled.');
            input.setActiveAuthFlow(undefined);
            setAuthStateCache(variables.providerId, result.state);
            if (variables.providerId === 'openai_codex') {
                void utils.provider.getOpenAISubscriptionUsage.invalidate({ profileId: input.profileId });
                void utils.provider.getOpenAISubscriptionRateLimits.invalidate({ profileId: input.profileId });
            }
            void utils.runtime.getShellBootstrap.invalidate({ profileId: input.profileId });
        },
    });

    return {
        setDefaultMutation,
        setApiKeyMutation,
        setConnectionProfileMutation,
        setExecutionPreferenceMutation,
        syncCatalogMutation,
        setModelRoutingPreferenceMutation,
        setOrganizationMutation,
        openExternalUrlMutation,
        startAuthMutation,
        pollAuthMutation,
        cancelAuthMutation,
    };
}

import { describe, expect, it, vi } from 'vitest';

import { patchProviderCache } from '@/web/components/settings/providerSettings/providerSettingsCache';
import { kiloFrontierModelId } from '@/shared/kiloModels';

function createSetDataSpy<T>() {
    let current: T | undefined;
    const setData = vi.fn(
        (_input: unknown, next: T | ((value: T | undefined) => T | undefined)) => {
            current = typeof next === 'function' ? (next as (value: T | undefined) => T | undefined)(current) : next;
            return current;
        }
    );

    return {
        setData,
        read: () => current,
    };
}

describe('patchProviderCache', () => {
    it('preserves explicit empty-catalog state instead of flattening empty sync results to reason null', () => {
        const listModelsStore = createSetDataSpy<{
            models: Array<{ id: string }>;
            reason: 'provider_not_found' | 'catalog_sync_failed' | 'catalog_empty_after_normalization' | null;
            detail?: string;
        }>();
        const shellBootstrapStore = createSetDataSpy<{
            providers: Array<{ id: string }>;
            defaults: { providerId: string; modelId: string };
            specialistDefaults: Array<{
                topLevelTab: 'agent' | 'orchestrator';
                modeKey: 'ask' | 'code' | 'debug' | 'orchestrate';
                providerId: string;
                modelId: string;
            }>;
            providerModels: Array<{ id: string; providerId: string }>;
        }>();

        const utils = {
            provider: {
                listModels: { setData: listModelsStore.setData },
            },
            runtime: {
                getShellBootstrap: { setData: shellBootstrapStore.setData },
            },
        } as unknown as Parameters<typeof patchProviderCache>[0]['utils'];

        shellBootstrapStore.setData(
            { profileId: 'profile_test' },
            {
                providers: [{ id: 'kilo' }],
                defaults: { providerId: 'kilo', modelId: kiloFrontierModelId },
                specialistDefaults: [],
                providerModels: [{ id: kiloFrontierModelId, providerId: 'kilo' }],
            }
        );

        patchProviderCache({
            utils,
            profileId: 'profile_test',
            providerId: 'kilo',
            models: [],
            catalogStateReason: 'catalog_empty_after_normalization',
        });

        expect(listModelsStore.read()).toEqual({
            models: [],
            reason: 'catalog_empty_after_normalization',
        });
    });
});

import { trpc } from '@/web/trpc/client';

import type { ProviderAuthStateRecord, ProviderModelRecord } from '@/app/backend/persistence/types';
import type {
    KiloModelProviderOption,
    ProviderControlEntry,
    ProviderControlSnapshot,
    ProviderConnectionProfileResult,
    ProviderListItem,
} from '@/app/backend/providers/service/types';
import type { ProviderSpecialistDefaultRecord } from '@/app/backend/runtime/contracts/types/provider';

import type {
    KiloModelRoutingPreference,
    RuntimeProviderId,
} from '@/shared/contracts';

type TrpcUtils = ReturnType<typeof trpc.useUtils>;
type ProviderListData = Awaited<ReturnType<TrpcUtils['provider']['listProviders']['fetch']>>;
type ProviderDefaultsData = Awaited<ReturnType<TrpcUtils['provider']['getDefaults']['fetch']>>;
type ProviderControlData = Awaited<ReturnType<TrpcUtils['provider']['getControlPlane']['fetch']>>;
type ProviderModelsData = Awaited<ReturnType<TrpcUtils['provider']['listModels']['fetch']>>;
type ProviderAuthStateData = Awaited<ReturnType<TrpcUtils['provider']['getAuthState']['fetch']>>;
type ProviderAccountContextData = Awaited<ReturnType<TrpcUtils['provider']['getAccountContext']['fetch']>>;
type ProviderConnectionProfileData = Awaited<ReturnType<TrpcUtils['provider']['getConnectionProfile']['fetch']>>;
type ProviderExecutionPreferenceData = Awaited<ReturnType<TrpcUtils['provider']['getExecutionPreference']['fetch']>>;
type ProviderModelProvidersData = Awaited<ReturnType<TrpcUtils['provider']['listModelProviders']['fetch']>>;
type ProviderRoutingPreferenceData = Awaited<ReturnType<TrpcUtils['provider']['getModelRoutingPreference']['fetch']>>;
type ShellBootstrapData = Awaited<ReturnType<TrpcUtils['runtime']['getShellBootstrap']['fetch']>>;
type EmptyCatalogStateReason = 'catalog_sync_failed' | 'catalog_empty_after_normalization';

function replaceProvider(
    current: ProviderListData | undefined,
    provider: ProviderListItem
): ProviderListData | undefined {
    if (!current) {
        return current;
    }

    return {
        providers: current.providers.map((candidate) => (candidate.id === provider.id ? provider : candidate)),
    };
}

function patchProviderAuthState(
    current: ProviderListData | undefined,
    input: { providerId: RuntimeProviderId; authState: ProviderAuthStateRecord }
): ProviderListData | undefined {
    if (!current) {
        return current;
    }

    return {
        providers: current.providers.map((provider) =>
            provider.id === input.providerId
                ? {
                      ...provider,
                      authState: input.authState.authState,
                      authMethod: input.authState.authMethod,
                  }
                : provider
        ),
    };
}

function patchProviderControlEntry(
    currentEntry: ProviderControlEntry,
    input: {
        providerId: RuntimeProviderId;
        provider?: ProviderListItem;
        models?: ProviderModelRecord[];
        catalogStateReason?: EmptyCatalogStateReason;
        catalogStateDetail?: string;
        authState?: ProviderAuthStateRecord;
        connectionProfile?: ProviderConnectionProfileResult;
        executionPreference?: ProviderListItem['executionPreference'];
    }
): ProviderControlEntry {
    if (currentEntry.provider.id !== input.providerId) {
        return currentEntry;
    }

    const provider =
        input.provider ??
        {
            ...currentEntry.provider,
            ...(input.connectionProfile ? { connectionProfile: input.connectionProfile } : {}),
            ...(input.executionPreference ? { executionPreference: input.executionPreference } : {}),
            ...(input.authState
                ? {
                      authState: input.authState.authState,
                      authMethod: input.authState.authMethod,
                  }
                : {}),
        };
    const models = input.models ?? currentEntry.models;
    const invalidModelCount = currentEntry.catalogState.invalidModelCount;
    const catalogState =
        input.models !== undefined
            ? models.length > 0
                ? {
                      reason: null,
                      invalidModelCount,
                  }
                : {
                      reason: input.catalogStateReason ?? 'catalog_empty_after_normalization',
                      ...(input.catalogStateDetail ? { detail: input.catalogStateDetail } : {}),
                      invalidModelCount,
                  }
            : currentEntry.catalogState;

    return {
        provider: {
            ...provider,
            isDefault: provider.id === currentEntry.provider.id ? provider.isDefault : currentEntry.provider.isDefault,
        },
        models,
        catalogState,
    };
}

function patchProviderControlSnapshot(
    current: ProviderControlSnapshot | undefined,
    input: {
        providerId: RuntimeProviderId;
        provider?: ProviderListItem;
        defaults?: { providerId: string; modelId: string };
        specialistDefaults?: ProviderSpecialistDefaultRecord[];
        models?: ProviderModelRecord[];
        catalogStateReason?: EmptyCatalogStateReason;
        catalogStateDetail?: string;
        authState?: ProviderAuthStateRecord;
        connectionProfile?: ProviderConnectionProfileResult;
        executionPreference?: ProviderListItem['executionPreference'];
    }
): ProviderControlSnapshot | undefined {
    if (!current) {
        return current;
    }

    const nextDefaults = input.defaults ?? current.defaults;
    const nextEntries = current.entries.map((entry) => {
        const nextEntry = patchProviderControlEntry(entry, input);
        return {
            ...nextEntry,
            provider: {
                ...nextEntry.provider,
                isDefault: nextEntry.provider.id === nextDefaults.providerId,
            },
        };
    });

    return {
        entries: nextEntries,
        defaults: nextDefaults,
        specialistDefaults: input.specialistDefaults ?? current.specialistDefaults,
    };
}

export function patchProviderCache(input: {
    utils: TrpcUtils;
    profileId: string;
    providerId: RuntimeProviderId;
    provider?: ProviderListItem;
    defaults?: { providerId: string; modelId: string };
    specialistDefaults?: ProviderSpecialistDefaultRecord[];
    models?: ProviderModelRecord[];
    catalogStateReason?: EmptyCatalogStateReason;
    catalogStateDetail?: string;
    authState?: ProviderAuthStateRecord;
    accountContext?: ProviderAccountContextData;
    connectionProfile?: ProviderConnectionProfileResult;
    executionPreference?: ProviderListItem['executionPreference'];
    routingPreference?: KiloModelRoutingPreference;
    routingProviders?: KiloModelProviderOption[];
    routingModelId?: string;
}) {
    const authState = input.authState;

    if (input.provider) {
        const provider = input.provider;
        input.utils.provider.listProviders.setData(
            { profileId: input.profileId },
            (current: ProviderListData | undefined) => replaceProvider(current, provider)
        );
    }

    if (authState) {
        input.utils.provider.listProviders.setData(
            { profileId: input.profileId },
            (current: ProviderListData | undefined) =>
                patchProviderAuthState(current, {
                    providerId: input.providerId,
                    authState,
                })
        );
    }

    if (input.defaults) {
        const nextDefaults = input.defaults;
        input.utils.provider.getDefaults.setData(
            { profileId: input.profileId },
            (current: ProviderDefaultsData | undefined) => ({
                defaults: nextDefaults,
                specialistDefaults: input.specialistDefaults ?? current?.specialistDefaults ?? [],
            })
        );
    }

    if (
        input.provider ||
        input.defaults ||
        input.specialistDefaults ||
        input.models ||
        authState ||
        input.connectionProfile ||
        input.executionPreference
    ) {
        const getControlPlaneCache = (input.utils.provider as {
            getControlPlane?: { setData: TrpcUtils['provider']['getControlPlane']['setData'] };
        }).getControlPlane;
        getControlPlaneCache?.setData({ profileId: input.profileId }, (current: ProviderControlData | undefined) => {
            if (!current) {
                return current;
            }

            const nextProviderControl = patchProviderControlSnapshot(current.providerControl, input);
            if (!nextProviderControl) {
                return current;
            }

            return {
                providerControl: nextProviderControl,
            } satisfies ProviderControlData;
        });
    }

    if (input.models) {
        const nextModels = input.models;
        input.utils.provider.listModels.setData(
            {
                profileId: input.profileId,
                providerId: input.providerId,
            },
            (current: ProviderModelsData | undefined) => {
                if (nextModels.length > 0) {
                    return {
                        models: nextModels,
                        reason: null,
                    } satisfies ProviderModelsData;
                }

                if (input.catalogStateReason !== undefined) {
                    return {
                        models: nextModels,
                        reason: input.catalogStateReason,
                        ...(input.catalogStateDetail ? { detail: input.catalogStateDetail } : {}),
                    } satisfies ProviderModelsData;
                }

                const preservedReason: EmptyCatalogStateReason =
                    current?.reason === 'catalog_sync_failed' || current?.reason === 'catalog_empty_after_normalization'
                        ? current.reason
                        : 'catalog_empty_after_normalization';
                const preservedDetail = preservedReason === current?.reason ? current.detail : undefined;

                return {
                    models: nextModels,
                    reason: preservedReason,
                    ...(preservedDetail ? { detail: preservedDetail } : {}),
                } satisfies ProviderModelsData;
            }
        );
    }

    if (authState) {
        input.utils.provider.getAuthState.setData(
            {
                profileId: input.profileId,
                providerId: input.providerId,
            },
            {
                found: true,
                state: authState,
            } satisfies ProviderAuthStateData
        );
    }

    if (input.accountContext && input.providerId === 'kilo') {
        input.utils.provider.getAccountContext.setData(
            {
                profileId: input.profileId,
                providerId: 'kilo',
            },
            input.accountContext
        );
    }

    if (input.connectionProfile) {
        input.utils.provider.getConnectionProfile.setData(
            {
                profileId: input.profileId,
                providerId: input.providerId,
            },
            {
                connectionProfile: input.connectionProfile,
            } satisfies ProviderConnectionProfileData
        );
    }

    if (input.executionPreference && input.providerId === 'openai') {
        input.utils.provider.getExecutionPreference.setData(
            {
                profileId: input.profileId,
                providerId: 'openai',
            },
            {
                executionPreference: input.executionPreference,
            } satisfies ProviderExecutionPreferenceData
        );
    }

    if (input.routingPreference && input.routingModelId) {
        input.utils.provider.getModelRoutingPreference.setData(
            {
                profileId: input.profileId,
                providerId: 'kilo',
                modelId: input.routingModelId,
            },
            {
                preference: input.routingPreference,
            } satisfies ProviderRoutingPreferenceData
        );
    }

    if (input.routingProviders && input.routingModelId) {
        input.utils.provider.listModelProviders.setData(
            {
                profileId: input.profileId,
                providerId: 'kilo',
                modelId: input.routingModelId,
            },
            {
                providers: input.routingProviders,
            } satisfies ProviderModelProvidersData
        );
    }

    if (
        input.provider ||
        input.defaults ||
        input.specialistDefaults ||
        input.models ||
        authState ||
        input.connectionProfile ||
        input.executionPreference
    ) {
        input.utils.runtime.getShellBootstrap.setData(
            { profileId: input.profileId },
            (current: ShellBootstrapData | undefined) => {
                if (!current) {
                    return current;
                }

                const providerControl = patchProviderControlSnapshot(current.providerControl, input);
                if (!providerControl) {
                    return current;
                }

                return {
                    ...current,
                    providerControl,
                };
            }
        );
    }
}

