import { trpc } from '@/web/trpc/client';
import {
    getProviderControlDefaults,
    listProviderControlModels,
    listProviderControlProviders,
} from '@/web/lib/providerControl/selectors';
import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { createFailClosedAsyncAction } from '@/web/lib/async/createFailClosedAsyncAction';

import type { RuntimeProviderId, TopLevelTab } from '@/shared/contracts';

interface WorkspacesSurfaceControllerInput {
    profileId: string;
    workspaceRoots: Array<{
        fingerprint: string;
        label: string;
        absolutePath: string;
        updatedAt: string;
    }>;
    selectedWorkspaceFingerprint: string | undefined;
    onSelectedWorkspaceFingerprintChange: (workspaceFingerprint: string | undefined) => void;
    onCreateThreadForWorkspace: (workspaceFingerprint: string) => void;
}

export function useWorkspacesSurfaceController(input: WorkspacesSurfaceControllerInput) {
    const wrapFailClosedAction = <TArgs extends unknown[]>(action: (...args: TArgs) => Promise<void>) =>
        createFailClosedAsyncAction(action);
    const utils = trpc.useUtils();
    const shellBootstrapQuery = trpc.runtime.getShellBootstrap.useQuery(
        { profileId: input.profileId },
        PROGRESSIVE_QUERY_OPTIONS
    );
    const sessionsQuery = trpc.session.list.useQuery({ profileId: input.profileId }, PROGRESSIVE_QUERY_OPTIONS);
    const threadsQuery = trpc.conversation.listThreads.useQuery(
        {
            profileId: input.profileId,
            activeTab: 'chat',
            showAllModes: true,
            groupView: 'workspace',
            sort: 'latest',
        },
        PROGRESSIVE_QUERY_OPTIONS
    );
    const sandboxesQuery = trpc.sandbox.list.useQuery(
        {
            profileId: input.profileId,
            ...(input.selectedWorkspaceFingerprint ? { workspaceFingerprint: input.selectedWorkspaceFingerprint } : {}),
        },
        {
            enabled: Boolean(input.selectedWorkspaceFingerprint),
            ...PROGRESSIVE_QUERY_OPTIONS,
        }
    );
    const registryQuery = trpc.registry.listResolved.useQuery(
        {
            profileId: input.profileId,
            ...(input.selectedWorkspaceFingerprint ? { workspaceFingerprint: input.selectedWorkspaceFingerprint } : {}),
        },
        {
            enabled: Boolean(input.selectedWorkspaceFingerprint),
            ...PROGRESSIVE_QUERY_OPTIONS,
        }
    );
    const setWorkspacePreferenceMutation = trpc.runtime.setWorkspacePreference.useMutation({
        onSuccess: ({ workspacePreference }) => {
            utils.runtime.getShellBootstrap.setData({ profileId: input.profileId }, (current) =>
                current
                    ? {
                          ...current,
                          workspacePreferences: [
                              workspacePreference,
                              ...current.workspacePreferences.filter(
                                  (record) => record.workspaceFingerprint !== workspacePreference.workspaceFingerprint
                              ),
                          ],
                      }
                    : current
            );
        },
    });
    const registerWorkspaceRootMutation = trpc.runtime.registerWorkspaceRoot.useMutation();
    const deleteWorkspaceThreadsMutation = trpc.conversation.deleteWorkspaceThreads.useMutation({
        onSuccess: async () => {
            await Promise.all([
                utils.conversation.listBuckets.invalidate({ profileId: input.profileId }),
                utils.conversation.listThreads.invalidate(),
                utils.session.list.invalidate({ profileId: input.profileId }),
            ]);
        },
    });
    const refreshRegistryMutation = trpc.registry.refresh.useMutation({
        onSuccess: async (_result, variables) => {
            await utils.registry.listResolved.invalidate({
                profileId: input.profileId,
                ...(variables.workspaceFingerprint ? { workspaceFingerprint: variables.workspaceFingerprint } : {}),
            });
        },
    });

    const providerControl = shellBootstrapQuery.data?.providerControl;
    const providers = listProviderControlProviders(providerControl);
    const providerModels = listProviderControlModels(providerControl);
    const workspacePreferences = shellBootstrapQuery.data?.workspacePreferences ?? [];
    const runtimeDefaults = getProviderControlDefaults(providerControl);
    const selectedWorkspace = input.selectedWorkspaceFingerprint
        ? input.workspaceRoots.find((workspaceRoot) => workspaceRoot.fingerprint === input.selectedWorkspaceFingerprint)
        : undefined;
    const selectedWorkspacePreference = input.selectedWorkspaceFingerprint
        ? workspacePreferences.find(
              (workspacePreference) => workspacePreference.workspaceFingerprint === input.selectedWorkspaceFingerprint
          )
        : undefined;
    const allThreads = threadsQuery.data?.threads ?? [];
    const allSessions = sessionsQuery.data?.sessions ?? [];
    const selectedWorkspaceThreads = input.selectedWorkspaceFingerprint
        ? allThreads.filter((thread) => thread.workspaceFingerprint === input.selectedWorkspaceFingerprint)
        : [];
    const selectedWorkspaceThreadIds = new Set(selectedWorkspaceThreads.map((thread) => thread.id));
    const selectedWorkspaceSessions = input.selectedWorkspaceFingerprint
        ? allSessions.filter((session) => selectedWorkspaceThreadIds.has(session.threadId))
        : [];

    return {
        providers,
        providerModels,
        runtimeDefaults,
        selectedWorkspace,
        selectedWorkspacePreference,
        selectedWorkspaceThreads,
        selectedWorkspaceSessions,
        selectedWorkspaceSandboxes: sandboxesQuery.data?.sandboxes ?? [],
        selectedWorkspaceRegistry: registryQuery.data,
        isCreatingWorkspace: registerWorkspaceRootMutation.isPending || setWorkspacePreferenceMutation.isPending,
        isRefreshingRegistry: refreshRegistryMutation.isPending,
        isDeletingWorkspaceConversations: deleteWorkspaceThreadsMutation.isPending,
        createWorkspace: async (createWorkspaceInput: {
            absolutePath: string;
            label: string;
            defaultTopLevelTab: TopLevelTab;
            defaultProviderId: RuntimeProviderId;
            defaultModelId: string;
        }) => {
            const result = await registerWorkspaceRootMutation.mutateAsync({
                profileId: input.profileId,
                absolutePath: createWorkspaceInput.absolutePath,
                label: createWorkspaceInput.label,
            });

            utils.runtime.listWorkspaceRoots.setData({ profileId: input.profileId }, (current) => ({
                workspaceRoots: current
                    ? [
                          result.workspaceRoot,
                          ...current.workspaceRoots.filter(
                              (workspaceRoot) => workspaceRoot.fingerprint !== result.workspaceRoot.fingerprint
                          ),
                      ]
                    : [result.workspaceRoot],
            }));
            utils.runtime.getShellBootstrap.setData({ profileId: input.profileId }, (current) =>
                current
                    ? {
                          ...current,
                          workspaceRoots: [
                              result.workspaceRoot,
                              ...current.workspaceRoots.filter(
                                  (workspaceRoot) => workspaceRoot.fingerprint !== result.workspaceRoot.fingerprint
                              ),
                          ],
                      }
                    : current
            );

            await setWorkspacePreferenceMutation.mutateAsync({
                profileId: input.profileId,
                workspaceFingerprint: result.workspaceRoot.fingerprint,
                defaultTopLevelTab: createWorkspaceInput.defaultTopLevelTab,
                defaultProviderId: createWorkspaceInput.defaultProviderId,
                defaultModelId: createWorkspaceInput.defaultModelId,
            });

            input.onSelectedWorkspaceFingerprintChange(result.workspaceRoot.fingerprint);
            input.onCreateThreadForWorkspace(result.workspaceRoot.fingerprint);
        },
        refreshRegistry: wrapFailClosedAction(async (workspaceFingerprint: string) => {
            await refreshRegistryMutation.mutateAsync({
                profileId: input.profileId,
                workspaceFingerprint,
            });
        }),
        deleteWorkspaceConversations: async (workspaceFingerprint: string) => {
            await deleteWorkspaceThreadsMutation.mutateAsync({
                profileId: input.profileId,
                workspaceFingerprint,
                includeFavorites: false,
            });
        },
    };
}

import { useDeferredValue, useState } from 'react';

import { ModelPicker } from '@/web/components/modelSelection/modelPicker';
import { DialogSurface } from '@/web/components/ui/dialogSurface';
import { WorkspaceEnvironmentPreviewCard } from '@/web/components/workspaces/workspaceEnvironmentSection';
import {
    buildWorkspaceModelOptions,
    resolveWorkspaceDefaultDraft,
    topLevelTabLabel,
} from '@/web/components/workspaces/workspacesSurfaceSections';
import { PROGRESSIVE_QUERY_OPTIONS } from '@/web/lib/query/progressiveQueryOptions';
import { isOneOf } from '@/web/lib/typeGuards/isOneOf';
import { trpc } from '@/web/trpc/client';

import type { ProviderModelRecord } from '@/app/backend/persistence/types';
import type { ProviderListItem } from '@/app/backend/providers/service/types';

import { providerIds, type RuntimeProviderId, type TopLevelTab } from '@/shared/contracts';

interface WorkspaceCreateDialogProps {
    open: boolean;
    profileId: string;
    providers: ProviderListItem[];
    providerModels: ProviderModelRecord[];
    defaults:
        | {
              providerId: string;
              modelId: string;
          }
        | undefined;
    isSaving: boolean;
    onClose: () => void;
    onCreateWorkspace: (input: {
        absolutePath: string;
        label: string;
        defaultTopLevelTab: TopLevelTab;
        defaultProviderId: RuntimeProviderId;
        defaultModelId: string;
    }) => Promise<void>;
}

function isRuntimeProviderId(value: string | undefined): value is RuntimeProviderId {
    return isOneOf(value, providerIds);
}

function readWorkspaceCreateErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : 'Workspace could not be created.';
}

export async function submitWorkspaceCreateRequest(input: {
    onCreateWorkspace: WorkspaceCreateDialogProps['onCreateWorkspace'];
    onClose: () => void;
    createWorkspaceInput: {
        absolutePath: string;
        label: string;
        defaultTopLevelTab: TopLevelTab;
        defaultProviderId: RuntimeProviderId;
        defaultModelId: string;
    };
}): Promise<string | undefined> {
    try {
        await input.onCreateWorkspace(input.createWorkspaceInput);
        input.onClose();
        return undefined;
    } catch (error) {
        return readWorkspaceCreateErrorMessage(error);
    }
}

function WorkspaceCreateDialogBody({
    profileId,
    providers,
    providerModels,
    defaults,
    isSaving,
    onClose,
    onCreateWorkspace,
}: Omit<WorkspaceCreateDialogProps, 'open'>) {
    const initialDraft = resolveWorkspaceDefaultDraft({
        providers,
        providerModels,
        defaults,
    });
    const [workspaceLabelDraft, setWorkspaceLabelDraft] = useState('');
    const [workspacePathDraft, setWorkspacePathDraft] = useState('');
    const [isPickingWorkspaceDirectory, setIsPickingWorkspaceDirectory] = useState(false);
    const [workspaceDefaultTopLevelTabDraft, setWorkspaceDefaultTopLevelTabDraft] = useState<TopLevelTab>(
        initialDraft.topLevelTab
    );
    const [workspaceDefaultProviderIdDraft, setWorkspaceDefaultProviderIdDraft] = useState<
        RuntimeProviderId | undefined
    >(initialDraft.providerId);
    const [workspaceDefaultModelIdDraft, setWorkspaceDefaultModelIdDraft] = useState(initialDraft.modelId);
    const [submitError, setSubmitError] = useState<string | undefined>(undefined);
    const deferredWorkspacePathDraft = useDeferredValue(workspacePathDraft.trim());
    const desktopBridge = typeof window !== 'undefined' ? window.neonDesktop : undefined;
    const hasDesktopDirectoryPicker = Boolean(desktopBridge);
    const environmentQuery = trpc.runtime.inspectWorkspaceEnvironment.useQuery(
        {
            profileId,
            absolutePath: deferredWorkspacePathDraft.length > 0 ? deferredWorkspacePathDraft : '.',
        },
        {
            enabled: deferredWorkspacePathDraft.length > 0,
            ...PROGRESSIVE_QUERY_OPTIONS,
        }
    );
    const createDefaultProvider = workspaceDefaultProviderIdDraft
        ? providers.find((provider) => provider.id === workspaceDefaultProviderIdDraft)
        : undefined;
    const createModelOptions = buildWorkspaceModelOptions(createDefaultProvider, providerModels);
    const createSelectedModelId =
        workspaceDefaultModelIdDraft && createModelOptions.some((option) => option.id === workspaceDefaultModelIdDraft)
            ? workspaceDefaultModelIdDraft
            : (createModelOptions[0]?.id ?? '');
    const createSelectedModelOption = createModelOptions.find((option) => option.id === createSelectedModelId);

    async function browseForWorkspaceDirectory() {
        if (!desktopBridge || isPickingWorkspaceDirectory) {
            return;
        }

        setSubmitError(undefined);
        setIsPickingWorkspaceDirectory(true);
        try {
            const result = await desktopBridge.pickDirectory();
            if (result.canceled) {
                return;
            }

            setWorkspacePathDraft(result.absolutePath);
            if (workspaceLabelDraft.trim().length === 0) {
                const nextLabel = result.absolutePath.split(/[\\/]/).filter(Boolean).at(-1);
                if (nextLabel) {
                    setWorkspaceLabelDraft(nextLabel);
                }
            }
        } catch (error) {
            setSubmitError(error instanceof Error ? error.message : 'Workspace directory could not be selected.');
        } finally {
            setIsPickingWorkspaceDirectory(false);
        }
    }

    async function handleCreateWorkspace() {
        if (!workspaceDefaultProviderIdDraft) {
            return;
        }

        setSubmitError(undefined);
        const nextError = await submitWorkspaceCreateRequest({
            onCreateWorkspace,
            onClose,
            createWorkspaceInput: {
                absolutePath: workspacePathDraft,
                label: workspaceLabelDraft,
                defaultTopLevelTab: workspaceDefaultTopLevelTabDraft,
                defaultProviderId: workspaceDefaultProviderIdDraft,
                defaultModelId: createSelectedModelId,
            },
        });
        setSubmitError(nextError);
    }

    return (
        <div className='border-border bg-background w-[min(92vw,34rem)] rounded-[28px] border p-5 shadow-xl'>
            <div className='space-y-1'>
                <h2 id='workspace-create-title' className='text-lg font-semibold'>
                    New workspace
                </h2>
                <p id='workspace-create-description' className='text-muted-foreground text-sm'>
                    Add this folder once, then reuse it for sessions, isolated runs, and workspace files.
                </p>
            </div>

            <div className='mt-4 space-y-4'>
                <label className='block space-y-2'>
                    <span className='text-sm font-medium'>Workspace name</span>
                    <input
                        type='text'
                        value={workspaceLabelDraft}
                        onChange={(event) => {
                            setSubmitError(undefined);
                            setWorkspaceLabelDraft(event.target.value);
                        }}
                        className='border-border bg-card h-10 w-full rounded-2xl border px-3 text-sm'
                        autoComplete='off'
                        placeholder='My workspace'
                    />
                </label>

                <div className='space-y-2'>
                    <span className='text-sm font-medium'>Folder path</span>
                    <div className='grid grid-cols-[minmax(0,1fr)_auto] gap-2'>
                        <input
                            type='text'
                            value={workspacePathDraft}
                            onChange={(event) => {
                                setSubmitError(undefined);
                                setWorkspacePathDraft(event.target.value);
                            }}
                            className='border-border bg-card h-10 w-full rounded-2xl border px-3 text-sm'
                            autoComplete='off'
                            placeholder=''
                        />
                        <button
                            type='button'
                            className='border-border bg-card hover:bg-accent rounded-2xl border px-4 py-2 text-sm font-medium disabled:cursor-not-allowed disabled:opacity-60'
                            disabled={isPickingWorkspaceDirectory || !hasDesktopDirectoryPicker}
                            onClick={browseForWorkspaceDirectory}>
                            {isPickingWorkspaceDirectory ? 'Opening…' : 'Browse…'}
                        </button>
                    </div>
                    <p className='text-muted-foreground text-xs'>
                        Paste a path directly or choose the folder in your OS file picker.
                    </p>
                </div>

                <WorkspaceEnvironmentPreviewCard
                    isLoading={environmentQuery.isLoading}
                    errorMessage={environmentQuery.error?.message}
                    snapshot={environmentQuery.data?.snapshot}
                    emptyMessage='Neon will use this folder for sessions, commands, rules, and skills tied to the workspace.'
                />

                <div className='border-border/70 bg-card/35 space-y-4 rounded-2xl border px-4 py-4'>
                    <div className='space-y-1'>
                        <p className='text-sm font-medium'>Workspace defaults</p>
                        <p className='text-muted-foreground text-xs leading-5'>
                            These choices become the starting mode, provider, and model for new threads in this
                            workspace.
                        </p>
                    </div>

                    <div className='grid gap-4 md:grid-cols-[minmax(0,0.26fr)_minmax(0,0.26fr)_minmax(0,0.48fr)]'>
                        <label className='space-y-2'>
                            <span className='text-sm font-medium'>Mode</span>
                            <select
                                className='border-border bg-card h-10 w-full rounded-2xl border px-3 text-sm'
                                value={workspaceDefaultTopLevelTabDraft}
                                onChange={(event) => {
                                    const nextValue = event.target.value;
                                    if (nextValue === 'chat' || nextValue === 'agent' || nextValue === 'orchestrator') {
                                        setSubmitError(undefined);
                                        setWorkspaceDefaultTopLevelTabDraft(nextValue);
                                    }
                                }}>
                                <option value='chat'>{topLevelTabLabel('chat')}</option>
                                <option value='agent'>{topLevelTabLabel('agent')}</option>
                                <option value='orchestrator'>{topLevelTabLabel('orchestrator')}</option>
                            </select>
                        </label>

                        <label className='space-y-2'>
                            <span className='text-sm font-medium'>Provider</span>
                            <select
                                className='border-border bg-card h-10 w-full rounded-2xl border px-3 text-sm'
                                value={workspaceDefaultProviderIdDraft ?? ''}
                                onChange={(event) => {
                                    setSubmitError(undefined);
                                    const nextProviderId = providers.find(
                                        (provider) => provider.id === event.target.value
                                    )?.id;
                                    setWorkspaceDefaultProviderIdDraft(nextProviderId);
                                    const nextProvider = nextProviderId
                                        ? providers.find((provider) => provider.id === nextProviderId)
                                        : undefined;
                                    const nextModelId =
                                        buildWorkspaceModelOptions(nextProvider, providerModels)[0]?.id ?? '';
                                    setWorkspaceDefaultModelIdDraft(nextModelId);
                                }}>
                                {providers.map((provider) => (
                                    <option key={provider.id} value={provider.id}>
                                        {provider.label}
                                    </option>
                                ))}
                            </select>
                        </label>

                        <label className='space-y-2'>
                            <span className='text-sm font-medium'>Model</span>
                            <ModelPicker
                                providerId={workspaceDefaultProviderIdDraft}
                                selectedModelId={createSelectedModelId}
                                models={createModelOptions}
                                ariaLabel='Workspace default model'
                                placeholder='Select a model'
                                onSelectModel={setWorkspaceDefaultModelIdDraft}
                                onSelectOption={(option: { providerId?: string; id: string }) => {
                                    setSubmitError(undefined);
                                    if (
                                        option.providerId &&
                                        option.providerId !== workspaceDefaultProviderIdDraft &&
                                        isRuntimeProviderId(option.providerId)
                                    ) {
                                        setWorkspaceDefaultProviderIdDraft(option.providerId);
                                    }
                                    setWorkspaceDefaultModelIdDraft(option.id);
                                }}
                            />
                            {createSelectedModelOption?.compatibilityReason &&
                            createSelectedModelOption.compatibilityScope !== 'provider' ? (
                                <p className='text-muted-foreground text-xs'>
                                    {createSelectedModelOption.compatibilityReason}
                                </p>
                            ) : null}
                        </label>
                    </div>
                </div>
                {submitError ? <p className='text-destructive text-sm'>{submitError}</p> : null}
            </div>

            <div className='border-border/70 mt-5 flex items-center justify-end gap-2 border-t pt-4'>
                <button
                    type='button'
                    className='border-border bg-card hover:bg-accent rounded-full border px-4 py-2 text-sm font-medium'
                    onClick={onClose}>
                    Cancel
                </button>
                <button
                    type='button'
                    className='border-primary/40 bg-primary/10 text-primary rounded-full border px-4 py-2 text-sm font-medium disabled:cursor-not-allowed disabled:opacity-60'
                    disabled={
                        isSaving ||
                        workspacePathDraft.trim().length === 0 ||
                        workspaceLabelDraft.trim().length === 0 ||
                        !workspaceDefaultProviderIdDraft ||
                        createSelectedModelId.length === 0
                    }
                    onClick={() => {
                        handleCreateWorkspace();
                    }}>
                    {isSaving ? 'Saving…' : 'Add workspace'}
                </button>
            </div>
        </div>
    );
}

export function WorkspaceCreateDialog(props: WorkspaceCreateDialogProps) {
    return (
        <DialogSurface
            open={props.open}
            titleId='workspace-create-title'
            descriptionId='workspace-create-description'
            onClose={props.onClose}>
            {props.open ? <WorkspaceCreateDialogBody {...props} /> : null}
        </DialogSurface>
    );
}

import { WorkspaceDefaultsSection, formatTimestamp } from '@/web/components/workspaces/workspacesSurfaceSections';
import { WorkspaceEnvironmentSection } from '@/web/components/workspaces/workspaceEnvironmentSection';

import type { ProviderModelRecord } from '@/app/backend/persistence/types';
import type { ProviderListItem } from '@/app/backend/providers/service/types';
import type { WorkspacePreferenceRecord } from '@/app/backend/runtime/contracts/types/runtime';

export function WorkspaceDetailsPanel(input: {
    profileId: string;
    selectedWorkspace: {
        fingerprint: string;
        label: string;
        absolutePath: string;
        updatedAt: string;
    };
    selectedWorkspaceThreads: Array<{ id: string }>;
    selectedWorkspaceSessions: Array<{ id: string; updatedAt: string; runStatus: string }>;
    selectedWorkspaceSandboxes: unknown[];
    selectedWorkspaceRegistry:
        | {
              resolved: {
                  modes: unknown[];
                  rulesets: unknown[];
                  skillfiles: unknown[];
              };
          }
        | undefined;
    selectedWorkspacePreference?: WorkspacePreferenceRecord;
    providers: ProviderListItem[];
    providerModels: ProviderModelRecord[];
    defaults:
        | {
              providerId: string;
              modelId: string;
          }
        | undefined;
    isRefreshingRegistry: boolean;
    isDeletingWorkspaceConversations: boolean;
    onOpenSessions: () => void;
    onRefreshRegistry: () => void;
    onRequestDeleteConversations: () => void;
}) {
    return (
        <div className='mx-auto flex max-w-5xl flex-col gap-5'>
            <div className='flex flex-wrap items-start justify-between gap-3'>
                <div className='space-y-1'>
                    <h3 className='text-2xl font-semibold text-balance'>{input.selectedWorkspace.label}</h3>
                    <p className='text-muted-foreground text-sm leading-6 break-all'>
                        {input.selectedWorkspace.absolutePath}
                    </p>
                </div>

                <div className='flex flex-wrap gap-2'>
                    <button
                        type='button'
