import { log } from 'evlog';

import type { NeonObservabilityEvent } from '@/app/backend/runtime/contracts';
import {
    isNeonObservabilityEvent,
    isSubscriptionControlPayload,
    normalizeSubscriptionPayload,
} from '@/web/lib/providers/subscriptionPayloads';

export interface ApplyNeonObservabilitySubscriptionPayloadInput {
    payload: unknown;
    setLive: () => void;
    setError: (message: string) => void;
    pushEvent: (event: NeonObservabilityEvent) => void;
}

export function applyNeonObservabilitySubscriptionPayload(
    input: ApplyNeonObservabilitySubscriptionPayloadInput
): void {
    const normalizedPayload = normalizeSubscriptionPayload(input.payload);

    if (isSubscriptionControlPayload(normalizedPayload)) {
        input.setLive();
        return;
    }

    if (isNeonObservabilityEvent(normalizedPayload)) {
        input.pushEvent(normalizedPayload);
        return;
    }

    log.warn({
        tag: 'observability.stream',
        message: 'Received invalid Neon observability payload.',
    });
    input.setError('Received invalid Neon observability payload.');
}

import type { NeonObservabilityEvent, NeonObservabilitySubscriptionInput } from '@/app/backend/runtime/contracts';
import { trpcClient as runtimeClient } from '@/web/lib/trpcClient';

export interface NeonObservabilityTransportHandlers {
    onData: (event: unknown) => void;
    onError: (error: unknown) => void;
}

export interface NeonObservabilityTransportSubscription {
    unsubscribe: () => void;
}

export interface NeonObservabilityTransport {
    subscribe: (
        input: NeonObservabilitySubscriptionInput,
        handlers: NeonObservabilityTransportHandlers
    ) => NeonObservabilityTransportSubscription;
}

export function createTrpcNeonObservabilityTransport(): NeonObservabilityTransport {
    return {
        subscribe(input, handlers) {
            return runtimeClient.runtime.subscribeObservability.subscribe(input, {
                onData: handlers.onData,
                onError: handlers.onError,
            });
        },
    };
}

export type { NeonObservabilityEvent };

import type { ProviderModelRecord } from '@/app/backend/persistence/types';
import type {
    ProviderCatalogState,
    ProviderControlEntry,
    ProviderControlSnapshot,
    ProviderListItem,
} from '@/app/backend/providers/service/types';
import type { ProviderSpecialistDefaultRecord } from '@/app/backend/runtime/contracts/types/provider';
import type { RuntimeProviderId } from '@/shared/contracts';

export function listProviderControlEntries(
    snapshot: ProviderControlSnapshot | undefined
): ProviderControlEntry[] {
    return snapshot?.entries ?? [];
}

export function listProviderControlProviders(
    snapshot: ProviderControlSnapshot | undefined
): ProviderListItem[] {
    return listProviderControlEntries(snapshot).map((entry) => entry.provider);
}

export function listProviderControlModels(
    snapshot: ProviderControlSnapshot | undefined
): ProviderModelRecord[] {
    return listProviderControlEntries(snapshot).flatMap((entry) => entry.models);
}

export function findProviderControlEntry(
    snapshot: ProviderControlSnapshot | undefined,
    providerId: RuntimeProviderId | undefined
): ProviderControlEntry | undefined {
    if (!providerId) {
        return undefined;
    }

    return listProviderControlEntries(snapshot).find((entry) => entry.provider.id === providerId);
}

export function getProviderControlDefaults(
    snapshot: ProviderControlSnapshot | undefined
): ProviderControlSnapshot['defaults'] | undefined {
    return snapshot?.defaults;
}

export function getProviderControlSpecialistDefaults(
    snapshot: ProviderControlSnapshot | undefined
): ProviderSpecialistDefaultRecord[] {
    return snapshot?.specialistDefaults ?? [];
}

export function getProviderControlCatalogState(
    snapshot: ProviderControlSnapshot | undefined,
    providerId: RuntimeProviderId | undefined
): ProviderCatalogState | undefined {
    return findProviderControlEntry(snapshot, providerId)?.catalogState;
}

import {
    runtimeEventDomains,
    runtimeEventOperations,
    runtimeEntityTypes,
    type RuntimeEventRecordV1,
} from '@/app/backend/persistence/types';
import { neonObservabilityEventKinds, type NeonObservabilityEvent } from '@/app/backend/runtime/contracts';
import type { WindowStateEvent } from '@/app/backend/trpc/routers/system/windowControls';

function isRecord(value: unknown): value is Record<string, unknown> {
    return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function isOneOf<const T extends readonly string[]>(value: unknown, allowed: T): value is T[number] {
    return typeof value === 'string' && (allowed as readonly string[]).includes(value);
}

const subscriptionControlTypes = ['started', 'stopped', 'state'] as const;

function isSubscriptionDataEnvelope(value: unknown): value is { data: unknown; id?: number | string } {
    return (
        isRecord(value) &&
        'data' in value &&
        Object.keys(value).every(
            (key) => key === 'data' || (key === 'id' && (typeof value['id'] === 'number' || typeof value['id'] === 'string'))
        )
    );
}

export function normalizeSubscriptionPayload(value: unknown): unknown {
    let nextValue = value;

    while (true) {
        if (isRecord(nextValue) && isRecord(nextValue['result'])) {
            const result = nextValue['result'];
            if (isOneOf(result['type'], subscriptionControlTypes)) {
                nextValue = result;
                continue;
            }

            if ('data' in result) {
                nextValue = result['data'];
                continue;
            }
        }

        if (isSubscriptionDataEnvelope(nextValue)) {
            nextValue = nextValue.data;
            continue;
        }

        return nextValue;
    }
}

export function isSubscriptionControlPayload(value: unknown): value is null | undefined | { type: string } {
    return value == null || (isRecord(value) && isOneOf(value['type'], subscriptionControlTypes));
}

export function isRuntimeEventRecord(value: unknown): value is RuntimeEventRecordV1 {
    if (!isRecord(value) || !isRecord(value['payload'])) {
        return false;
    }

    return (
        typeof value['sequence'] === 'number' &&
        typeof value['eventId'] === 'string' &&
        isOneOf(value['entityType'], runtimeEntityTypes) &&
        isOneOf(value['domain'], runtimeEventDomains) &&
        isOneOf(value['operation'], runtimeEventOperations) &&
        typeof value['entityId'] === 'string' &&
        typeof value['eventType'] === 'string' &&
        typeof value['createdAt'] === 'string'
    );
}

export function isWindowStateEvent(value: unknown): value is WindowStateEvent {
    if (!isRecord(value) || !isRecord(value['state'])) {
        return false;
    }

    const state = value['state'];
    return (
        typeof value['sequence'] === 'number' &&
        typeof state['isMaximized'] === 'boolean' &&
        typeof state['isFullScreen'] === 'boolean' &&
        typeof state['canMaximize'] === 'boolean' &&
        typeof state['canMinimize'] === 'boolean' &&
        typeof state['platform'] === 'string'
    );
}

export function isNeonObservabilityEvent(value: unknown): value is NeonObservabilityEvent {
    if (!isRecord(value) || !isOneOf(value['kind'], neonObservabilityEventKinds)) {
        return false;
    }

    return (
        typeof value['sequence'] === 'number' &&
        typeof value['at'] === 'string' &&
        typeof value['profileId'] === 'string' &&
        typeof value['sessionId'] === 'string' &&
        typeof value['runId'] === 'string' &&
        typeof value['providerId'] === 'string' &&
        typeof value['modelId'] === 'string' &&
        typeof value['source'] === 'string'
    );
}

